/**
 * Gemini Slate 4 Integration Component
 *
 * Connects the physical Gemini Slate 4 DJ controller to TBM via Web MIDI.
 * - Routes CC / note messages through configurable mappings (midiMapping.ts)
 * - Dispatches actions to the DJ engine, sequencer, pad system, and mixer
 * - Shows a floating connection-status badge
 * - Provides a useGeminiSlate4 hook for other components
 */

import React, { useEffect, useCallback, useState, useRef } from 'react';
import { useTBMAudio } from '../contexts/TBMAudioContext';
import {
  getGlobalMidiHandler,
  initializeGlobalMidiHandler,
  disposeGlobalMidiHandler,
} from '../lib/midiHandler';
import type { MidiHandlerCallbacks } from '../lib/midiHandler';
import {
  setControllerMode,
  getCurrentMode,
  onControllerModeChange,
} from '../lib/midiMapping';
import { Disc, Square, Music, Zap } from 'lucide-react';

// ─────────────────────────────────────────────────────────────────────────────
// Props
// ─────────────────────────────────────────────────────────────────────────────

interface GeminiSlate4IntegrationProps {
  children?: React.ReactNode;
}

// ─────────────────────────────────────────────────────────────────────────────
// Component
// ─────────────────────────────────────────────────────────────────────────────

export function GeminiSlate4Integration({ children }: GeminiSlate4IntegrationProps) {
  const {
    // DJ engine
    djEngine,
    djPlay,
    djStop,
    setCrossfaderPosition,
    setDeckVolume,
    setDeckBpm,
    setDeckEQ,
    setDeckPlaybackRate,
    setDJMasterVolume,
    setDeckCuePoint,
    enableSync,
    processScratch,
    setDeckEffect,
    setDeckEffectEnabled,
    setDeckEffectWetDry,

    // Sequencer / drum machine
    sequencer,
    triggerPad,
    pads,
    bpm,
    setBpm,

    // Audio engine and pad management
    engine,
    updatePad,
  } = useTBMAudio();

  const [currentMode, setCurrentMode] = useState(() => getCurrentMode().id);
  const [isConnected, setIsConnected] = useState(false);
  const [deviceCount, setDeviceCount] = useState(0);
  const [padOffset, setPadOffset] = useState(0);
  const [keyLock, setKeyLock] = useState(false);
  const [midiActivity, setMidiActivity] = useState(false);
  const [quantizeLevel, setQuantizeLevel] = useState(0.25); // 1/4 notes by default
  const [gridDivision, setGridDivision] = useState(4); // 4 steps per beat
  const [selectedPadIndex, _setSelectedPadIndex] = useState(0); // Currently selected pad for sample editing

  const activityTimer = useRef<ReturnType<typeof setTimeout> | null>(null);

  // Keep stable refs so the MIDI callback closures always see current values
  const padsRef = useRef(pads);
  padsRef.current = pads;
  const bpmRef = useRef(bpm);
  bpmRef.current = bpm;
  const keyLockRef = useRef(keyLock);
  keyLockRef.current = keyLock;
  const quantizeLevelRef = useRef(quantizeLevel);
  quantizeLevelRef.current = quantizeLevel;
  const gridDivisionRef = useRef(gridDivision);
  gridDivisionRef.current = gridDivision;
  const selectedPadIndexRef = useRef(selectedPadIndex);
  selectedPadIndexRef.current = selectedPadIndex;

  // Per-deck EQ state, keyed by deck string ('A' | 'B').
  // Stored in a ref (not state) so the MIDI callback can read and write the
  // current band values without triggering re-renders or stale-closure issues.
  const eqStateRef = useRef<Record<string, { lo: number; mid: number; hi: number }>>({
    A: { lo: 0, mid: 0, hi: 0 },
    B: { lo: 0, mid: 0, hi: 0 },
  });

  // ── Build callbacks (stable — captures refs, not values) ──────────────────

  const buildCallbacks = useCallback((): MidiHandlerCallbacks => ({
    // ── Activity indicator ──
    onMidiActivity: () => {
      setMidiActivity(true);
      if (activityTimer.current) clearTimeout(activityTimer.current);
      activityTimer.current = setTimeout(() => setMidiActivity(false), 120);
    },

    // ── Mode switching ──
    onModeTurntable: () => {
      setCurrentMode('turntable');
      setControllerMode('turntable');
    },
    onModePad: () => {
      setCurrentMode('pad');
      setControllerMode('pad');
    },
    onModeSampling: () => {
      setCurrentMode('sampling');
      setControllerMode('sampling');
    },
    onKeyLockToggle: () => {
      const wasLocked = keyLockRef.current;
      const nowLocked = !wasLocked;
      setKeyLock(nowLocked);
      const handler = getGlobalMidiHandler();
      const newOffset = nowLocked ? 8 : 0;
      handler.setPadOffset(newOffset);
      setPadOffset(newOffset);
    },

    // ── Vinyl Scratch / DJ transport ──
    onVinylScratchJog: (deck, value) => {
      if (!djEngine) return;
      // value is 0-1 from CC. Convert to a relative scratch delta:
      // CC relative encoding: 0.5 = no movement, <0.5 = ccw, >0.5 = cw
      const delta = (value - 0.5) * 2; // -1..+1
      const deckId = deck === 'left' ? 'A' : 'B';
      // Feed into scratch engine
      processScratch(deckId, delta, 1 / 60);
    },
    onVinylScratchCrossfader: (value) => {
      setCrossfaderPosition(value);
    },
    onVinylScratchPlay: (deck) => {
      djPlay(deck);
    },
    onVinylScratchStop: () => {
      djStop('A');
    },
    onVinylScratchCue: (deck) => {
      setDeckCuePoint(deck);
    },
    onVinylScratchSync: (deck) => {
      // Sync the target deck to the other deck's BPM
      enableSync(deck === 'A' ? 'A' : 'B');
    },

    // ── Stem queues (FX buttons) ──
    onStemQueueDrums: () => {
      // Toggle drum stem mute — implementation depends on stem separation engine
      // For now trigger pad 0 as a drum one-shot
      const p = padsRef.current;
      if (p.length > 0) triggerPad(p[0], 1);
    },
    onStemQueueBass: () => {
      const p = padsRef.current;
      if (p.length > 1) triggerPad(p[1], 1);
    },
    onStemQueueVocals: () => {
      const p = padsRef.current;
      if (p.length > 2) triggerPad(p[2], 1);
    },
    onStemQueueOther: () => {
      const p = padsRef.current;
      if (p.length > 3) triggerPad(p[3], 1);
    },

    // ── Drum pads ──
    onDrumPad: (padIndex, velocity) => {
      const p = padsRef.current;
      if (padIndex >= 0 && padIndex < p.length && velocity > 0) {
        // velocity comes as note velocity 0-127 raw (for notes) — normalise
        const vel = velocity > 1 ? velocity / 127 : velocity;
        triggerPad(p[padIndex], vel);
      }
    },

    // ── Grid timing ──
    onGridTempo: (value) => {
      if (!sequencer) return;
      // Map 0-1 → 60-200 BPM
      const newBpm = Math.round(60 + value * 140);
      setBpm(newBpm);
    },
    onGridSwing: (value) => {
      sequencer?.setSwing?.(value * 100);
    },
    onGridQuantize: (value) => {
      // Map 0-1 to quantize levels: 0=off, 0.25=1/4, 0.5=1/8, 0.75=1/16, 1=1/32
      const levels = [0, 0.25, 0.125, 0.0625, 0.03125]; // off, 1/4, 1/8, 1/16, 1/32
      const index = Math.min(Math.floor(value * levels.length), levels.length - 1);
      const newLevel = levels[index];
      setQuantizeLevel(newLevel);
      quantizeLevelRef.current = newLevel;

      // Apply to sequencer if available
      if (sequencer && (sequencer as any).setQuantize) {
        (sequencer as any).setQuantize(newLevel);
      }
    },
    onGridDivision: (value) => {
      // Map 0-1 to grid divisions: 1, 2, 3, 4, 6, 8, 12, 16 steps per beat
      const divisions = [1, 2, 3, 4, 6, 8, 12, 16];
      const index = Math.min(Math.floor(value * divisions.length), divisions.length - 1);
      const newDivision = divisions[index];
      setGridDivision(newDivision);
      gridDivisionRef.current = newDivision;

      // Apply to sequencer if available
      if (sequencer && (sequencer as any).setGridDivision) {
        (sequencer as any).setGridDivision(newDivision);
      }
    },

    // ── Sample editor ──
    onSampleStart: (value) => {
      // Set sample start point on currently selected pad
      const padIndex = selectedPadIndexRef.current;
      // Use engine.setPadStartOffset if available
      if (engine?.setPadStartOffset) {
        engine.setPadStartOffset(padIndex, value);
      }
      // Also update the pad state in context
      updatePad(padIndex, { start: value });
    },
    onSampleEnd: (value) => {
      // Set sample end point on currently selected pad
      const padIndex = selectedPadIndexRef.current;
      // Update pad end property in context (no engine method exists for end offset)
      updatePad(padIndex, { end: value });
    },
    onSampleVolume: (value) => {
      // Adjust volume of currently selected pad
      const padIndex = selectedPadIndexRef.current;
      updatePad(padIndex, { volume: value });
    },
    onSamplePitch: (value) => {
      // Map 0-1 to pitch adjustment -12 to +12 semitones
      const pitch = (value * 24) - 12;
      const padIndex = selectedPadIndexRef.current;
      updatePad(padIndex, { pitch });
    },
    onSampleLoop: (value) => {
      // Toggle loop on/off for the selected pad (value > 0.5 = on)
      const padIndex = selectedPadIndexRef.current;
      updatePad(padIndex, { loop: value > 0.5 });
    },
    onSampleFilter: (value) => {
      // Map 0-1 to filter cutoff (0-127) on the selected pad
      const padIndex = selectedPadIndexRef.current;
      const cutoff = Math.round(value * 127);
      updatePad(padIndex, { filterCutoff: cutoff });
      // Also push to engine real-time path if available
      if (engine?.setPadFilterCutoff) {
        engine.setPadFilterCutoff(padIndex, cutoff);
      }
    },
    onSampleReverb: (value) => {
      // Route reverb wet/dry to deck A effect slot 1
      setDeckEffect('A', 1, 'reverb', { decay: 1.5 + value * 3, mix: value });
      setDeckEffectEnabled('A', 1, value > 0.05);
    },
    onSampleDelay: (value) => {
      // Route delay (echo) wet/dry to deck A effect slot 2
      setDeckEffect('A', 2, 'echo', { delayMs: 250, feedback: 0.3, mix: value });
      setDeckEffectEnabled('A', 2, value > 0.05);
    },

    // ── Transport ──
    onTransportPlay: () => {
      sequencer?.play();
    },
    onTransportStop: () => {
      sequencer?.stop();
    },
    onTransportRecord: () => {
      // Toggle record arm — sequencer record API if available, else start playback
      if (sequencer && (sequencer as any).toggleRecord) {
        (sequencer as any).toggleRecord();
      } else {
        sequencer?.play();
      }
    },
    onTransportLoop: () => {
      // Toggle loop mode
      if (sequencer) {
        const currentLoop = (sequencer as any).getLoop?.() ?? false;
        (sequencer as any).setLoop?.(!currentLoop);
      }
    },

    // ── Mixer ──
    onMixerMaster: (value) => {
      setDJMasterVolume(value);
    },
    onMixerChannel: (channel, value) => {
      const deck = channel === 0 ? 'A' : 'B';
      setDeckVolume(deck, value);
    },
    onMixerEQ: (deck, band, value) => {
      // EQ value 0-1 → gain in dB roughly -12 to +12; centre (0.5) = 0 dB
      const gain = (value - 0.5) * 24;
      // Patch only the changed band; leave the other two at their current values
      // so adjusting bass doesn't silently zero out mid/hi and vice-versa.
      const deckEq = eqStateRef.current[deck] ?? { lo: 0, mid: 0, hi: 0 };
      if (band === 'high') deckEq.hi = gain;
      else if (band === 'mid') deckEq.mid = gain;
      else deckEq.lo = gain;
      eqStateRef.current[deck] = deckEq;
      setDeckEQ(deck, deckEq.lo, deckEq.mid, deckEq.hi);
    },

    // ── Pitch fader ──
    onPitchFader: (deck, value) => {
      // Map 0-1 → BPM adjustment ±10%
      const baseBpm = bpmRef.current;
      const adjusted = baseBpm * (0.9 + value * 0.2);
      setDeckBpm(deck, adjusted);
    },

    // ── Fallback for unmapped functions ──
    onUnhandledFunction: (functionId, _value) => {
      console.debug(`[GeminiSlate4] Unhandled MIDI function: ${functionId}`);
    },
  }), [
    djEngine, djPlay, djStop, setCrossfaderPosition, setDeckVolume,
    setDeckBpm, setDeckEQ, setDeckPlaybackRate, setDJMasterVolume,
    setDeckCuePoint, enableSync, processScratch, sequencer, triggerPad,
    setBpm, engine, updatePad, setDeckEffect, setDeckEffectEnabled,
    setDeckEffectWetDry,
  ]);

  // ── Initialise MIDI handler ──────────────────────────────────────────────

  useEffect(() => {
    let disposed = false;

    const init = async () => {
      try {
        const callbacks = buildCallbacks();
        const success = await initializeGlobalMidiHandler(callbacks);
        if (disposed) return;

        setIsConnected(success);
        if (success) {
          const handler = getGlobalMidiHandler();
          setDeviceCount(handler.getConnectedDevices().length);
          setCurrentMode(getCurrentMode().id);

          // Track hot-plug
          handler.onDeviceChange(() => {
            if (!disposed) {
              setDeviceCount(handler.getConnectedDevices().length);
              setIsConnected(handler.isConnected());
            }
          });
        }
      } catch {
        if (!disposed) setIsConnected(false);
      }
    };

    init();

    // Subscribe to mode changes from other sources (e.g. Settings page)
    const unsub = onControllerModeChange((modeId) => {
      if (!disposed) setCurrentMode(modeId);
    });

    return () => {
      disposed = true;
      unsub();
      if (activityTimer.current) clearTimeout(activityTimer.current);
      disposeGlobalMidiHandler();
    };
  // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []);

  // Update callbacks when dependencies change (without re-initialising MIDI)
  useEffect(() => {
    const handler = getGlobalMidiHandler();
    handler.setCallbacks(buildCallbacks());
  }, [buildCallbacks]);

  // ── Render helpers ──────────────────────────────────────────────────────

  const getModeIcon = () => {
    switch (currentMode) {
      case 'turntable': return <Disc size={16} />;
      case 'pad':       return <Square size={16} />;
      case 'sampling':  return <Music size={16} />;
      default:          return <Zap size={16} />;
    }
  };

  const getModeDescription = () => {
    switch (currentMode) {
      case 'turntable': return 'Jog wheels control vinyl scratch, buttons act as turntable controls';
      case 'pad':       return '8 pads become drum triggers (key lock toggles between halves)';
      case 'sampling':  return 'Sliders control sample editor, knobs adjust effects';
      default:          return 'Controller mode';
    }
  };

  if (!isConnected) {
    return <>{children}</>;
  }

  return (
    <div className="fixed bottom-4 right-4 z-50">
      <div className="bg-neutral-900/90 backdrop-blur-sm border border-neutral-700 rounded-xl p-3 shadow-2xl min-w-[220px] vignette noise-texture relative">
        <div className="flex items-center gap-3 mb-2">
          <div className="flex items-center gap-2">
            <div className={`w-2 h-2 rounded-full ${midiActivity ? 'bg-yellow-400' : 'bg-green-500'} animate-pulse dot-glow`} />
            <span className="text-[13px] font-bold uppercase text-neutral-300">Gemini Slate 4</span>
          </div>
          <div className="ml-auto flex items-center gap-1">
            {getModeIcon()}
            <span className="text-[13px] font-mono text-purple-400 uppercase">{currentMode}</span>
          </div>
        </div>

        <div className="space-y-1.5">
          <div className="flex items-center justify-between text-[13px]">
            <span className="text-neutral-500">Mode</span>
            <span className="text-neutral-300 text-right max-w-[150px] truncate">{getModeDescription()}</span>
          </div>

          {currentMode === 'pad' && (
            <div className="flex items-center justify-between text-[13px]">
              <span className="text-neutral-500">Pad Bank</span>
              <span className="text-neutral-300">
                Pads {padOffset + 1}-{padOffset + 8} of 16
                {keyLock && <span className="text-green-400 ml-1">(Key Lock ON)</span>}
              </span>
            </div>
          )}

          <div className="flex items-center justify-between text-[13px]">
            <span className="text-neutral-500">Devices</span>
            <span className="text-green-400">{deviceCount} connected</span>
          </div>
        </div>

        <div className="mt-3 pt-3 border-t border-neutral-800 separator-glow">
          <div className="text-xs text-neutral-600 font-mono">
            Use mode buttons on controller to switch.
            FX buttons = stem queues.
            Key lock toggles pad banks.
          </div>
        </div>
      </div>

      {children}
    </div>
  );
}

// ─────────────────────────────────────────────────────────────────────────────
// Hook for using Gemini Slate 4 in other components
// ─────────────────────────────────────────────────────────────────────────────

export function useGeminiSlate4() {
  const [mode, setMode] = useState(() => getCurrentMode().id);
  const [isInitialized, setIsInitialized] = useState(false);
  const [slate4Detected, setSlate4Detected] = useState(false);

  useEffect(() => {
    const handler = getGlobalMidiHandler();
    if (handler.isConnected()) {
      // Use setTimeout to avoid cascading renders
      setTimeout(() => {
        setMode(handler.getCurrentMode());
        setIsInitialized(true);
        setSlate4Detected(handler.hasSlate4Device());
      }, 0);
    }

    const unsub = onControllerModeChange((modeId) => {
      setMode(modeId);
    });
    const unsubSlate4 = handler.onSlate4Change((detected) => {
      setSlate4Detected(detected);
      if (detected) setIsInitialized(true);
    });
    // Also check on device change (hot-plug)
    const unsubDevice = handler.onDeviceChange(() => {
      setSlate4Detected(handler.hasSlate4Device());
      if (handler.isConnected()) setIsInitialized(true);
    });
    return () => {
      unsub();
      unsubSlate4();
      unsubDevice();
    };
  }, []);

  const switchMode = useCallback((modeId: string) => {
    setControllerMode(modeId);
    setMode(modeId);
  }, []);

  return {
    mode,
    isInitialized,
    slate4Detected,
    switchMode,
    getHandler: getGlobalMidiHandler,
  };
}

import React, { useState, useRef, useCallback, useEffect } from "react";
import {
  Music,
  GripVertical,
  Plus,
  Clock,
  Search,
  Zap,
  Drum,
  History,
  X,
  Maximize2,
} from "lucide-react";
import { useTBMAudio } from "../contexts/TBMAudioContext";
import { TransportControls } from "./ui/TransportControls";
import {
  BEATS_PER_BAR as _BEATS_PER_BAR,
  SCHEDULE_AHEAD_S as _SCHEDULE_AHEAD_S,
  TIMER_INTERVAL_MS as _TIMER_INTERVAL_MS,
  FRAME_RATE as _FRAME_RATE,
} from "../lib/constants";



// Bug 12 fix: generate unique ids for each drag-dropped timeline clip so that
// multiple clips originating from the same library entry can be resized
// independently (resize handler matches by c.id === tc.id).
function makeId() {
  return Math.random().toString(36).slice(2);
}

// ── Pre-allocated noise buffers for hat synthesis ──
// Avoids creating new AudioBuffer on every playHat call (GC pressure fix)
// Bug 9 fix: key by "sampleRate:samples" so that after an AudioContext is
// recreated (new sampleRate or new context), cached buffers from the old
// context are never reused — reusing them causes NotSupportedError on
// source.start() and silently kills all hat playback.
const NOISE_BUFFER_CACHE = new Map<string, AudioBuffer>();

function getNoiseBuffer(ctx: AudioContext, duration: number): AudioBuffer {
  // Key by sample count (rounded to avoid cache fragmentation)
  const samples = Math.ceil(ctx.sampleRate * duration);
  const cacheKey = `${ctx.sampleRate}:${samples}`;
  const cached = NOISE_BUFFER_CACHE.get(cacheKey);
  if (cached) return cached;

  const buf = ctx.createBuffer(1, samples, ctx.sampleRate);
  const data = buf.getChannelData(0);
  for (let i = 0; i < samples; i++) data[i] = Math.random() * 2 - 1;
  NOISE_BUFFER_CACHE.set(cacheKey, buf);
  return buf;
}

// Synthesized hi-hat: short burst of highpass-filtered noise
// Routes through engine.masterGain instead of ctx.destination
function playHat(
  ctx: AudioContext,
  masterGain: AudioNode,
  frequency: number = 8000,
  duration: number = 0.08,
  volume: number = 0.4,
  when: number = 0,
) {
  const noiseBuffer = getNoiseBuffer(ctx, duration);

  const source = ctx.createBufferSource();
  source.buffer = noiseBuffer;

  const filter = ctx.createBiquadFilter();
  filter.type = "highpass";
  filter.frequency.value = frequency;
  filter.Q.value = 0.5;

  const gain = ctx.createGain();
  const startTime = when > 0 ? when : ctx.currentTime;
  gain.gain.setValueAtTime(volume, startTime);
  gain.gain.exponentialRampToValueAtTime(0.001, startTime + duration);

  source.connect(filter);
  filter.connect(gain);
  gain.connect(masterGain);
  source.start(startTime);
  source.stop(startTime + duration);

  // HatSequencer 2.1: disconnect the node chain once playback ends to
  // prevent zombie AudioNodes from accumulating (~28,800/hour at 120 BPM).
  source.onended = () => {
    source.disconnect();
    filter.disconnect();
    gain.disconnect();
  };
}

interface Clip {
  id: string;
  name: string;
  type: "organic" | "trap";
  category: string;
  color: string;
}

interface TimelineClip extends Clip {
  trackId: number;
  startTime: number; // in beats
  duration: number; // in beats
}

// ── ClipLibraryItem — memoized to avoid re-renders as search query changes ──
const ClipLibraryItem = React.memo(function ClipLibraryItem({
  clip,
}: {
  clip: Clip;
}) {
  const handleDragStart = React.useCallback(
    (e: React.DragEvent<HTMLDivElement>) => {
      e.dataTransfer.setData(
        "application/tbm-clip",
        JSON.stringify({ clipId: clip.id, name: clip.name, url: "" }),
      );
      e.dataTransfer.effectAllowed = "copy";
    },
    [clip.id, clip.name],
  );

  return (
    <div
      draggable
      onDragStart={handleDragStart}
      className="group flex items-center gap-3 p-2 bg-neutral-950 border border-neutral-800 rounded hover:border-neutral-600 cursor-grab active:cursor-grabbing transition-all"
    >
      <div
        className="w-1 h-8 rounded-full"
        style={{ backgroundColor: clip.color }}
      ></div>
      <div className="flex flex-col flex-1 min-w-0">
        <span className="text-[13px] font-bold text-neutral-300 truncate">
          {clip.name}
        </span>
        <span className="text-xs font-mono text-neutral-600 uppercase">
          {clip.category}
        </span>
      </div>
      <GripVertical
        className="text-neutral-800 group-hover:text-neutral-600"
        size={14}
      />
    </div>
  );
});

export const HatSequencer = React.memo(function HatSequencer() {
  const [activeCategory, setActiveCategory] = useState<"organic" | "trap">(
    "organic",
  );
  const [isPlaying, setIsPlaying] = useState(false);
  const playheadDomRef = useRef<HTMLDivElement>(null);
  const [muteMap, setMuteMap] = useState<boolean[]>([
    false,
    false,
    false,
    false,
  ]);
  const [soloSet, setSoloSet] = useState<Set<number>>(new Set());
  // Keep refs so the scheduler closure always sees current mute/solo state
  const muteMapRef = useRef(muteMap);
  const soloSetRef = useRef(soloSet);

  useEffect(() => {
    muteMapRef.current = muteMap;
  }, [muteMap]);

  useEffect(() => {
    soloSetRef.current = soloSet;
  }, [soloSet]);
  const timecodeDomRef = useRef<HTMLSpanElement>(null);
  const [clipSearch, setClipSearch] = useState("");
  const [creatingCustomClip, setCreatingCustomClip] = useState(false);
  const [customClipName, setCustomClipName] = useState("");
  const [customClipSteps, setCustomClipSteps] = useState(16);
  const [_resizingClip, setResizingClip] = useState<string | null>(null);
  const clockRef = useRef<number | null>(null);
  const beatRef = useRef(0);
  const nextStepTimeRef = useRef(0);
  const playheadRafRef = useRef<number | null>(null);
  const timecodeRafRef = useRef<number | null>(null);
  const playStartTimeRef = useRef(0);

  const { audioContext, resumeAudio, engine, sequencer, bpm } = useTBMAudio();

  // HatSequencer 2.3: keep bpm in a ref so the scheduler closure always
  // reads the latest value without needing to be recreated on every BPM change.
  const bpmRef = useRef(bpm);

  useEffect(() => {
    bpmRef.current = bpm;
  }, [bpm]);

  // Undo history: store previous timeline states
  const [undoHistory, setUndoHistory] = useState<TimelineClip[][]>([]);
  const pushUndo = useCallback((clips: TimelineClip[]) => {
    setUndoHistory((prev) => [...prev.slice(-19), clips]); // keep last 20
  }, []);

  const BEATS_PER_BAR = _BEATS_PER_BAR;
  const SCHEDULE_AHEAD_S = _SCHEDULE_AHEAD_S;
  const TIMER_INTERVAL_MS = _TIMER_INTERVAL_MS;
  // Bug 13 fix: use the imported constant instead of re-declaring FRAME_RATE locally.
  const FRAME_RATE = _FRAME_RATE;

  // Keep timelineClips in a ref so the scheduler closure always sees the latest value
  const timelineClipsRef = useRef<TimelineClip[]>([]);

  const stopPlayback = useCallback(() => {
    if (clockRef.current !== null) {
      clearTimeout(clockRef.current);
      clockRef.current = null;
    }
    if (playheadRafRef.current !== null) {
      cancelAnimationFrame(playheadRafRef.current);
      playheadRafRef.current = null;
    }
    if (timecodeRafRef.current !== null) {
      cancelAnimationFrame(timecodeRafRef.current);
      timecodeRafRef.current = null;
    }
    beatRef.current = 0;
    // Bug 14 fix: also reset nextStepTimeRef so any future scheduleHats call
    // that runs without going through startPlayback's reset doesn't inherit a
    // stale audio timestamp and fire a burst of immediately-due steps.
    nextStepTimeRef.current = 0;
    if (playheadDomRef.current) {
      playheadDomRef.current.style.left = "0%";
    }
    if (timecodeDomRef.current) {
      timecodeDomRef.current.textContent = "00:00:00:00";
    }
    setIsPlaying(false);
  }, []);

  // Cleanup on unmount
  useEffect(
    () => () => {
      if (clockRef.current !== null) clearTimeout(clockRef.current);
      if (playheadRafRef.current !== null)
        cancelAnimationFrame(playheadRafRef.current);
      if (timecodeRafRef.current !== null)
        cancelAnimationFrame(timecodeRafRef.current);
    },
    [],
  );

  const presets = [
    {
      name: "Classic Breakbeat",
      clips: [
        {
          id: "o2",
          name: "70s Breakbeat Hat",
          trackId: 0,
          startTime: 0,
          duration: 8,
          color: "#a855f7",
        },
        {
          id: "o3",
          name: "Ghost Note Fill",
          trackId: 3,
          startTime: 6,
          duration: 2,
          color: "#a855f7",
        },
      ],
    },
    {
      name: "Trap Quads",
      clips: [
        {
          id: "t1",
          name: "Quad Roll",
          trackId: 0,
          startTime: 0,
          duration: 4,
          color: "#ef4444",
        },
        {
          id: "t2",
          name: "Triplet Stutter",
          trackId: 0,
          startTime: 4,
          duration: 4,
          color: "#ef4444",
        },
      ],
    },
    {
      name: "Live 4-Count",
      clips: [
        {
          id: "o1",
          name: "60s Live 4-Count",
          trackId: 0,
          startTime: 0,
          duration: 8,
          color: "#a855f7",
        },
      ],
    },
  ];

  const loadPreset = (presetName: string) => {
    const preset = presets.find((p) => p.name === presetName);
    if (preset) {
      pushUndo(timelineClips);
      setTimelineClips(
        preset.clips.map((c, i) => ({
          ...c,
          id: `preset-${i}`,
          type: c.color === "#a855f7" ? "organic" : "trap",
          category: "Preset",
        })),
      );
    }
  };

  const clipLibrary: Clip[] = [
    // Organic
    {
      id: "o1",
      name: "60s Live 4-Count",
      type: "organic",
      category: "Live",
      color: "#a855f7",
    },
    {
      id: "o2",
      name: "70s Breakbeat Hat",
      type: "organic",
      category: "Break",
      color: "#a855f7",
    },
    {
      id: "o3",
      name: "Ghost Note Fill",
      type: "organic",
      category: "Fill",
      color: "#a855f7",
    },
    {
      id: "o4",
      name: "Open Hat Swell",
      type: "organic",
      category: "Open",
      color: "#a855f7",
    },
    {
      id: "o5",
      name: "Ride Bell Tap",
      type: "organic",
      category: "Ride",
      color: "#a855f7",
    },
    {
      id: "o6",
      name: "Crash Accent",
      type: "organic",
      category: "Crash",
      color: "#a855f7",
    },
    // Trap
    {
      id: "t1",
      name: "Quad Roll",
      type: "trap",
      category: "Quads",
      color: "#ef4444",
    },
    {
      id: "t2",
      name: "Triplet Stutter",
      type: "trap",
      category: "Triplets",
      color: "#ef4444",
    },
    {
      id: "t3",
      name: "Pitch Slide Hat",
      type: "trap",
      category: "Slides",
      color: "#ef4444",
    },
    {
      id: "t4",
      name: "808 Closed Hat",
      type: "trap",
      category: "Basic",
      color: "#ef4444",
    },
    {
      id: "t5",
      name: "Velocity Ramp",
      type: "trap",
      category: "Stutter",
      color: "#ef4444",
    },
  ];

  const tracks = [
    { id: 0, name: "Closed Hat" },
    { id: 1, name: "Open Hat" },
    { id: 2, name: "Ride/Crash" },
    { id: 3, name: "Perc/Ghost" },
  ];

  const [timelineClips, setTimelineClips] = useState<TimelineClip[]>([
    { ...clipLibrary[0], trackId: 0, startTime: 0, duration: 4 },
    { ...clipLibrary[1], trackId: 0, startTime: 4, duration: 4 },
    { ...clipLibrary[3], trackId: 1, startTime: 2, duration: 1 },
    { ...clipLibrary[6], trackId: 0, startTime: 8, duration: 2 },
  ]);

  // Keep ref in sync so scheduler closure sees latest clips
  useEffect(() => {
    timelineClipsRef.current = timelineClips;
  }, [timelineClips]);

  const filteredLibrary = clipLibrary.filter((c) => c.type === activeCategory);
  const searchedLibrary = filteredLibrary.filter((c) =>
    c.name.toLowerCase().includes(clipSearch.toLowerCase()),
  );

  // ── Mute / Solo handlers ──
  const handleMute = useCallback(
    (trackIndex: number) => {
      const next = muteMap.map((m, i) => (i === trackIndex ? !m : m));
      setMuteMap(next);
      if (sequencer) sequencer.setMuteState(next, soloSet);
    },
    [muteMap, soloSet, sequencer],
  );

  const handleSolo = useCallback(
    (trackIndex: number) => {
      const nextSolo = new Set<number>(soloSet);
      if (nextSolo.has(trackIndex)) nextSolo.delete(trackIndex);
      else nextSolo.add(trackIndex);
      setSoloSet(nextSolo);
      if (sequencer) sequencer.setMuteState(muteMap, nextSolo);
    },
    [muteMap, soloSet, sequencer],
  );

  // ── Auto-Generate: probabilistic 4/4 hat pattern ──
  const handleAutoGenerate = useCallback(() => {
    // Bug 13 fix: FRAME_RATE is now the imported constant declared at component level.
    const generated: TimelineClip[] = [];
    // 16 sixteenth-note positions across 4 beats
    // Weight: beats 1&3 = 1.0, offbeats (2&4) = 0.7, in-between = 0.4
    const weights = [
      1.0, 0.4, 0.7, 0.4, 1.0, 0.4, 0.7, 0.4, 1.0, 0.4, 0.7, 0.4, 1.0, 0.4, 0.7,
      0.4,
    ];
    const closedHatSteps: number[] = [];
    weights.forEach((w, i) => {
      if (Math.random() < w) closedHatSteps.push(i);
    });
    // Convert step positions (0-15) to beat groups: 4 steps = 1 beat, pack into clips
    let i = 0;
    while (i < closedHatSteps.length) {
      const start = closedHatSteps[i] * 0.25; // in beats (1 beat = 4 sixteenths)
      let end = start + 0.25;
      while (
        i + 1 < closedHatSteps.length &&
        closedHatSteps[i + 1] === closedHatSteps[i] + 1
      ) {
        i++;
        end += 0.25;
      }
      generated.push({
        id: makeId(),
        name: "808 Closed Hat",
        type: "trap",
        category: "Basic",
        color: "#ef4444",
        trackId: 0,
        startTime: start,
        duration: end - start,
      });
      i++;
    }
    // Open hats on upbeats (positions 2, 6, 10, 14) with 50% probability
    [2, 6, 10, 14].forEach((pos) => {
      if (Math.random() > 0.5) {
        generated.push({
          id: makeId(),
          name: "Open Hat Swell",
          type: "organic",
          category: "Open",
          color: "#a855f7",
          trackId: 1,
          startTime: pos * 0.25,
          duration: 0.5,
        });
      }
    });
    setTimelineClips((prev) => {
      pushUndo(prev);
      return generated;
    });
  }, [pushUndo]);

  // ── Live timecode rAF loop ──
  // Bug 13 fix: FRAME_RATE is the imported constant declared at component level.
  const updateTimecodeRef = useRef<() => void>(() => {});

  const updateTimecode = useCallback(() => {
    if (!audioContext) return;
    const elapsed = audioContext.currentTime - playStartTimeRef.current;
    const totalSeconds = Math.max(0, elapsed);
    const frames = Math.floor(totalSeconds * FRAME_RATE) % FRAME_RATE;
    const secs = Math.floor(totalSeconds) % 60;
    const mins = Math.floor(totalSeconds / 60) % 60;
    const hrs = Math.floor(totalSeconds / 3600) % 24;
    const pad = (n: number, d = 2) => String(n).padStart(d, "0");
    if (timecodeDomRef.current) {
      timecodeDomRef.current.textContent = `${pad(hrs)}:${pad(mins)}:${pad(secs)}:${pad(frames)}`;
    }
    timecodeRafRef.current = requestAnimationFrame(updateTimecodeRef.current);
  }, [audioContext, FRAME_RATE]);

  // Store the latest updateTimecode in the ref
  useEffect(() => {
    updateTimecodeRef.current = updateTimecode;
  }, [updateTimecode]);

  // ── Look-ahead scheduler ──
  const scheduleHatsRef = useRef<(ctx: AudioContext, masterGainNode: AudioNode) => void>(() => {});

  const scheduleHats = useCallback(
    (ctx: AudioContext, masterGainNode: AudioNode) => {
      // HatSequencer 2.3: read from ref to get the current BPM even if the
      // closure was created with a different BPM value.
      const stepDurationS = 60 / bpmRef.current / 4; // 16th-note duration in seconds
      const totalBeats = 32 * BEATS_PER_BAR * 4; // total 16th-note steps in 32 bars
      const deadline = ctx.currentTime + SCHEDULE_AHEAD_S;

      while (nextStepTimeRef.current < deadline) {
        const beat = beatRef.current;

        // Trigger hats for clips that cover the current beat
        timelineClipsRef.current.forEach((tc) => {
          // Bug 10 fix: tc.startTime / tc.duration are in bars; beatRef counts
          // sixteenth-note steps.  Convert to steps: 1 bar = BEATS_PER_BAR * 4 steps.
          const stepsPerBar = BEATS_PER_BAR * 4;
          const clipStartBeat = tc.startTime * stepsPerBar;
          const clipEndBeat = (tc.startTime + tc.duration) * stepsPerBar;
          if (beat >= clipStartBeat && beat < clipEndBeat) {
            // Check mute/solo state for this clip's track
            const trackId = tc.trackId;
            const currentMutes = muteMapRef.current;
            const currentSolos = soloSetRef.current;
            const hasSoloed = currentSolos.size > 0;
            if (currentMutes[trackId]) return; // track is muted
            if (hasSoloed && !currentSolos.has(trackId)) return; // another track is soloed
            const freq = tc.type === "trap" ? 10000 : 7000;
            const dur = tc.type === "trap" ? 0.04 : 0.12;
            playHat(
              ctx,
              masterGainNode,
              freq,
              dur,
              0.35,
              nextStepTimeRef.current,
            );
          }
        });

        nextStepTimeRef.current += stepDurationS;
        beatRef.current = (beat + 1) % totalBeats;

        // UI update via rAF to coalesce with next paint.
        // Bug 11 fix: re-read beatRef.current inside the rAF callback instead
        // of closing over `pos`, which would be stale by the time rAF fires.
        if (playheadRafRef.current === null) {
          playheadRafRef.current = requestAnimationFrame(() => {
            if (playheadDomRef.current) {
              const currentPos = (beatRef.current / totalBeats) * 100;
              playheadDomRef.current.style.left = `${currentPos}%`;
            }
            playheadRafRef.current = null;
          });
        }
      }

      clockRef.current = window.setTimeout(
        () => scheduleHatsRef.current?.(ctx, masterGainNode),
        TIMER_INTERVAL_MS,
      );
    },
    [BEATS_PER_BAR, SCHEDULE_AHEAD_S, TIMER_INTERVAL_MS], // HatSequencer 2.3: bpm removed — read from ref
  );

  // Store the latest scheduleHats in a ref
  useEffect(() => {
    scheduleHatsRef.current = scheduleHats;
  }, [scheduleHats]);

  const startPlayback = useCallback(() => {
    if (isPlaying) {
      stopPlayback();
      return;
    }
    if (!audioContext) return;
    resumeAudio();
    const ctx = audioContext;
    const masterGainNode: AudioNode =
      (engine as any)?.masterGain ?? ctx.destination;
    setIsPlaying(true);
    beatRef.current = 0;
    nextStepTimeRef.current = ctx.currentTime;
    playStartTimeRef.current = ctx.currentTime;
    scheduleHats(ctx, masterGainNode);
    timecodeRafRef.current = requestAnimationFrame(updateTimecode);
  }, [
    isPlaying,
    audioContext,
    resumeAudio,
    stopPlayback,
    scheduleHats,
    updateTimecode,
    engine,
  ]);

  return (
    <div className="h-full flex flex-col gap-4">
      {/* Header */}
      <div className="flex justify-between items-center bg-neutral-900 p-3 rounded-lg border border-neutral-800 relative edge-glow-bottom">
        <div className="flex items-center gap-4">
          <div className="flex items-center gap-2">
            <Music className="text-red-500" size={18} />
            <h2 className="text-sm font-bold text-neutral-200 uppercase tracking-widest">
              Hat Progression Timeline
            </h2>
          </div>
          <div className="h-6 w-px bg-neutral-800"></div>
          <TransportControls
            isPlaying={isPlaying}
            onPlay={startPlayback}
            onStop={stopPlayback}
            size={16}
          />
          <div className="flex items-center gap-2 bg-neutral-950 px-3 py-1 rounded border border-neutral-800">
            <Clock size={12} className="text-neutral-500" />
            <span
              ref={timecodeDomRef}
              className="text-[13px] font-mono text-red-500 font-bold"
            >
              00:00:00:00
            </span>
          </div>
          <div className="h-6 w-px bg-neutral-800"></div>
          <select
            onChange={(e) => loadPreset(e.target.value)}
            className="bg-neutral-950 border border-neutral-800 text-[13px] text-neutral-400 rounded px-2 py-1 outline-none focus:border-red-500 transition-colors"
          >
            <option value="">Load Preset...</option>
            {presets.map((p) => (
              <option key={p.name} value={p.name}>
                {p.name}
              </option>
            ))}
          </select>
        </div>

        <div className="flex items-center gap-4">
          <div className="flex bg-neutral-950 rounded p-1 border border-neutral-800">
            <button
              onClick={() => setActiveCategory("organic")}
              className={`px-3 py-1 rounded text-[13px] font-bold uppercase transition-all ${activeCategory === "organic" ? "bg-neutral-800 text-white" : "text-neutral-500"}`}
            >
              Organic
            </button>
            <button
              onClick={() => setActiveCategory("trap")}
              className={`px-3 py-1 rounded text-[13px] font-bold uppercase transition-all ${activeCategory === "trap" ? "bg-neutral-800 text-white" : "text-neutral-500"}`}
            >
              Trap
            </button>
          </div>
          <button
            onClick={handleAutoGenerate}
            className="flex items-center gap-2 px-4 py-2 bg-red-600 hover:bg-red-500 text-white rounded font-bold text-xs uppercase transition-colors"
          >
            <Zap size={14} /> Auto-Generate
          </button>
        </div>
      </div>

      <div className="flex-1 flex gap-4 min-h-0">
        {/* Clip Library */}
        <div className="w-64 flex flex-col gap-3 bg-neutral-900 rounded-lg border border-neutral-800 p-4 noise-texture relative">
          <div className="relative">
            <Search
              className="absolute left-2 top-1/2 -translate-y-1/2 text-neutral-600"
              size={12}
            />
            <input
              type="text"
              placeholder="Search Clips..."
              value={clipSearch}
              onChange={(e) => setClipSearch(e.target.value)}
              className="w-full bg-neutral-950 border border-neutral-800 rounded px-7 py-1.5 text-[13px] outline-none focus:border-red-500 transition-colors"
            />
          </div>

          <div className="flex-1 overflow-y-auto custom-scrollbar flex flex-col gap-2">
            {searchedLibrary.map((clip) => (
              <ClipLibraryItem key={clip.id} clip={clip} />
            ))}
          </div>

          <div className="pt-3 border-t border-neutral-800">
            {creatingCustomClip ? (
              <div className="flex flex-col gap-2">
                <input
                  type="text"
                  placeholder="Clip name..."
                  value={customClipName}
                  onChange={(e) => setCustomClipName(e.target.value)}
                  onKeyDown={(e) => {
                    if (e.key === "Escape") {
                      setCreatingCustomClip(false);
                      setCustomClipName("");
                    }
                  }}
                  autoFocus
                  className="w-full bg-neutral-950 border border-neutral-700 rounded px-2 py-1 text-[13px] text-neutral-200 outline-none focus:border-red-500 transition-colors"
                />
                <div className="flex items-center gap-2">
                  <label className="text-xs text-neutral-500">Steps:</label>
                  <input
                    type="number"
                    min={4}
                    max={64}
                    value={customClipSteps}
                    onChange={(e) =>
                      setCustomClipSteps(
                        Math.max(4, Math.min(64, Number(e.target.value))),
                      )
                    }
                    className="w-16 bg-neutral-950 border border-neutral-700 rounded px-2 py-1 text-[13px] text-neutral-200 outline-none focus:border-red-500"
                  />
                </div>
                <div className="flex gap-2">
                  <button
                    onClick={() => {
                      const name =
                        customClipName.trim() ||
                        `Custom ${clipLibrary.length + 1}`;
                      const newClip: Clip = {
                        id: `custom-${Date.now()}`,
                        name,
                        type: activeCategory,
                        category: "Custom",
                        color:
                          activeCategory === "organic" ? "#a855f7" : "#ef4444",
                      };
                      // Add to timeline on track 0 at beat 0 with duration derived from steps
                      const duration = customClipSteps / 4; // 4 steps per beat
                      pushUndo(timelineClips);
                      setTimelineClips((prev) => [
                        ...prev,
                        { ...newClip, trackId: 0, startTime: 0, duration },
                      ]);
                      setCreatingCustomClip(false);
                      setCustomClipName("");
                      setCustomClipSteps(16);
                    }}
                    className="flex-1 py-1 bg-red-600 hover:bg-red-500 text-white text-[13px] font-bold uppercase rounded transition-colors"
                  >
                    Add
                  </button>
                  <button
                    onClick={() => {
                      setCreatingCustomClip(false);
                      setCustomClipName("");
                    }}
                    className="flex-1 py-1 bg-neutral-800 hover:bg-neutral-700 text-neutral-400 text-[13px] font-bold uppercase rounded transition-colors"
                  >
                    Cancel
                  </button>
                </div>
              </div>
            ) : (
              <button
                onClick={() => setCreatingCustomClip(true)}
                className="w-full py-2 bg-neutral-800 hover:bg-neutral-700 text-neutral-400 text-[13px] font-bold uppercase rounded flex items-center justify-center gap-2"
              >
                <Plus size={12} /> New Custom Clip
              </button>
            )}
          </div>
        </div>

        {/* Timeline */}
        <div className="flex-1 flex flex-col bg-neutral-900 rounded-lg border border-neutral-800 overflow-hidden vignette">
          {/* Timeline Ruler */}
          <div className="h-8 bg-neutral-950 border-b border-neutral-800 flex relative">
            <div className="w-32 shrink-0 border-r border-neutral-800"></div>
            <div className="flex-1 flex relative">
              {Array.from({ length: 8 }).map((_, i) => (
                <div
                  key={i}
                  className="flex-1 border-r border-neutral-900 flex items-center px-2 text-xs font-mono text-neutral-600"
                >
                  {i + 1}.0
                </div>
              ))}
              {/* Playhead */}
              {/* Playhead marker */}
              <div
                ref={playheadDomRef}
                className="absolute top-0 bottom-0 w-0.5 bg-red-500 z-20 shadow-[0_0_10px_rgba(239,68,68,0.5)]"
                style={{ left: `0%`, willChange: "left" }}
              >
                <div className="absolute -top-1 -left-1.5 w-4 h-4 bg-red-500 rotate-45"></div>
              </div>
            </div>
          </div>

          {/* Tracks */}
          <div className="flex-1 overflow-y-auto custom-scrollbar">
            {tracks.map((track) => (
              <div
                key={track.id}
                className="h-16 flex border-b border-neutral-800 group"
              >
                <div className="w-32 shrink-0 bg-neutral-950 border-r border-neutral-800 p-3 flex flex-col justify-center">
                  <span className="text-[13px] font-bold text-neutral-400 group-hover:text-white transition-colors">
                    {track.name}
                  </span>
                  <div className="flex gap-1 mt-1">
                    <button
                      onClick={() => handleMute(track.id)}
                      className={`w-3 h-3 rounded-full transition-colors ${muteMap[track.id] ? "bg-red-500" : "bg-neutral-800 hover:bg-red-500"}`}
                      title="Mute"
                    />
                    <button
                      onClick={() => handleSolo(track.id)}
                      className={`w-3 h-3 rounded-full transition-colors ${soloSet.has(track.id) ? "bg-emerald-500" : "bg-neutral-800 hover:bg-emerald-500"}`}
                      title="Solo"
                    />
                  </div>
                </div>
                <div
                  className="flex-1 relative bg-neutral-950/30"
                  onDragOver={(e) => e.preventDefault()}
                  onDrop={(e) => {
                    e.preventDefault();
                    const raw = e.dataTransfer.getData("application/tbm-clip");
                    if (!raw) return;
                    try {
                      const data = JSON.parse(raw) as {
                        clipId: string;
                        name: string;
                        url: string;
                      };
                      const rect = e.currentTarget.getBoundingClientRect();
                      const relX = (e.clientX - rect.left) / rect.width;
                      const startTime = Math.floor(relX * 32); // snap to bar
                      const src = clipLibrary.find(
                        (c) => c.id === data.clipId,
                      ) ?? {
                        id: data.clipId,
                        name: data.name,
                        type: activeCategory,
                        category: "Custom",
                        color: "#888",
                      };
                      const newClip: TimelineClip = {
                        ...src,
                        // Bug 12 fix: assign a fresh unique id so that multiple clips
                        // dropped from the same library entry don't share an id and
                        // accidentally all resize together when one is dragged.
                        id: makeId(),
                        trackId: track.id,
                        startTime,
                        duration: 2,
                      };
                      pushUndo(timelineClips);
                      setTimelineClips((prev) => [...prev, newClip]);
                    } catch {
                      /* ignore bad data */
                    }
                  }}
                >
                  {/* Grid Lines */}
                  <div className="absolute inset-0 flex">
                    {Array.from({ length: 32 }).map((_, i) => (
                      <div
                        key={i}
                        className={`flex-1 border-r ${i % 4 === 3 ? "border-neutral-800" : "border-neutral-900/30"}`}
                      ></div>
                    ))}
                  </div>

                  {/* Clips on this track */}
                  {timelineClips
                    .filter((tc) => tc.trackId === track.id)
                    .map((tc) => (
                      <div
                        key={tc.id}
                        className="absolute top-2 bottom-2 rounded border-l-4 shadow-lg flex flex-col justify-center px-2 overflow-hidden cursor-pointer hover:brightness-110 transition-all group/clip"
                        style={{
                          left: `${(tc.startTime / 32) * 100}%`,
                          width: `${(tc.duration / 32) * 100}%`,
                          backgroundColor: `${tc.color}22`,
                          borderColor: tc.color,
                          borderWidth: "1px",
                          borderLeftWidth: "4px",
                        }}
                      >
                        {/* Delete button */}
                        <button
                          onClick={(e) => {
                            e.stopPropagation();
                            pushUndo(timelineClips);
                            setTimelineClips((prev) =>
                              prev.filter((c) => c !== tc),
                            );
                          }}
                          className="absolute top-0.5 right-0.5 opacity-0 group-hover/clip:opacity-100 bg-neutral-900/80 rounded p-0.5 hover:bg-red-600 transition-all z-10"
                          title="Delete clip"
                        >
                          <X size={8} className="text-white" />
                        </button>
                        {/* Resize handle */}
                        <div
                          className="absolute top-0 bottom-0 right-0 w-2 cursor-ew-resize opacity-0 group-hover/clip:opacity-100 hover:bg-white/20 transition-all z-10 flex items-center justify-center"
                          title="Drag to resize"
                          onMouseDown={(e) => {
                            e.stopPropagation();
                            e.preventDefault();
                            setResizingClip(tc.id);
                            const startX = e.clientX;
                            const startDuration = tc.duration;
                            const trackEl = e.currentTarget.closest(
                              ".flex-1.relative",
                            ) as HTMLElement;
                            if (!trackEl) return;
                            const trackWidth =
                              trackEl.getBoundingClientRect().width;
                            const onMove = (ev: MouseEvent) => {
                              const dx = ev.clientX - startX;
                              const deltaBars = (dx / trackWidth) * 32;
                              const newDuration = Math.max(
                                0.25,
                                Math.round((startDuration + deltaBars) * 4) / 4,
                              );
                              setTimelineClips((prev) =>
                                prev.map((c) =>
                                  c.id === tc.id
                                    ? { ...c, duration: newDuration }
                                    : c,
                                ),
                              );
                            };
                            const onUp = () => {
                              setResizingClip(null);
                              document.removeEventListener("mousemove", onMove);
                              document.removeEventListener("mouseup", onUp);
                            };
                            pushUndo(timelineClips);
                            document.addEventListener("mousemove", onMove);
                            document.addEventListener("mouseup", onUp);
                          }}
                        >
                          <Maximize2 size={6} className="text-white/60" />
                        </div>
                        <span className="text-xs font-bold text-white truncate">
                          {tc.name}
                        </span>
                        <div className="flex gap-0.5 mt-0.5">
                          {Array.from({ length: 4 }).map((_, j) => (
                            <div
                              key={j}
                              className="h-1 flex-1 bg-white/20 rounded-full"
                            ></div>
                          ))}
                        </div>
                      </div>
                    ))}
                </div>
              </div>
            ))}
          </div>

          {/* Bottom Info */}
          <div className="h-8 bg-neutral-950 border-t border-neutral-800 flex items-center px-4 justify-between separator-glow">
            <div className="flex items-center gap-4 text-xs font-mono text-neutral-600 uppercase">
              <span className="flex items-center gap-1">
                <Drum size={10} /> 4 Tracks
              </span>
              <span className="flex items-center gap-1">
                <History size={10} /> Undo History: {undoHistory.length} Steps
              </span>
            </div>
            <div className="flex items-center gap-2">
              <span className="text-xs font-mono text-neutral-600 uppercase">
                Snap: 1/16
              </span>
              <div className="w-24 h-1.5 bg-neutral-900 rounded-full overflow-hidden">
                <div className="w-1/3 h-full bg-red-500"></div>
              </div>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
});

import React, { useState, useEffect, useCallback, useRef } from 'react';
import { 
  Library, 
  Search, 
  Folder, 
  HardDrive, 
  Star, 
  Clock, 
  Filter, 
  MoreVertical,
  ChevronRight,
  Database,
  RefreshCw,
  Plus,
  FileCode,
  Loader2,
  Play,
  Square
} from 'lucide-react';
import {
  fetchLibraries,
  toggleLibraryFavorite,
  type SampleLibrary,
} from '../lib/api';
import { useTBMAudio } from '../contexts/TBMAudioContext';

export function KontaktBrowser() {
  const [searchQuery, setSearchQuery] = useState('');
  const [activeCategory, setActiveCategory] = useState('All');
  const [isScanning, setIsScanning] = useState(false);
  const [libraries, setLibraries] = useState<SampleLibrary[]>([]);
  const [isLoading, setIsLoading] = useState(true);
  const [previewingId, setPreviewingId] = useState<string | null>(null);
  const [addingPath, setAddingPath] = useState(false);
  const [newPathValue, setNewPathValue] = useState('');
  const [scanPaths, setScanPaths] = useState<string[]>(['D:/Sample Libraries', 'E:/Sample Libraries']);
  const [filterMode, setFilterMode] = useState<'all' | 'favorites' | 'recent'>('all');
  const [recentlyUsed, setRecentlyUsed] = useState<string[]>([]);

  const { engine, resumeAudio } = useTBMAudio();
  const previewSourceRef = useRef<AudioBufferSourceNode | null>(null);

  const categories = [
    "All",
    "Pianos & Keys",
    "Strings",
    "Brass",
    "Woodwinds",
    "Orchestral",
    "Guitars",
    "Bass",
    "Drums & Percussion",
    "Synths",
    "Pads",
    "Sound Design",
    "World & Ethnic",
    "Choir & Vocals",
    "Organs",
    "Bowed"
  ];

  const loadLibraries = useCallback(async () => {
    try {
      const data = await fetchLibraries();
      setLibraries(data);
    } catch {
      // keep empty on error
    } finally {
      setIsLoading(false);
    }
  }, []);

  useEffect(() => { loadLibraries(); }, [loadLibraries]);

  // Stop any playing preview when the component unmounts
  useEffect(() => {
    return () => {
      try { previewSourceRef.current?.stop(); } catch { /* already stopped */ }
      previewSourceRef.current = null;
    };
  }, []);

  const handleScan = async () => {
    setIsScanning(true);
    await loadLibraries();
    setTimeout(() => setIsScanning(false), 600);
  };

  const handleToggleFavorite = async (lib: SampleLibrary) => {
    const next = !lib.isFavorite;
    setLibraries(prev => prev.map(l => l.id === lib.id ? { ...l, isFavorite: next } : l));
    try {
      await toggleLibraryFavorite(lib.id, next);
    } catch {
      setLibraries(prev => prev.map(l => l.id === lib.id ? { ...l, isFavorite: lib.isFavorite } : l));
    }
  };

  // Track recently used libraries (by id). Capped at 10.
  const markRecentlyUsed = useCallback((libId: string) => {
    setRecentlyUsed(prev => {
      const next = [libId, ...prev.filter(id => id !== libId)];
      return next.slice(0, 10);
    });
  }, []);

  /** Preview a library's sample via the engine. Loads from /api/libraries/:id/preview. */
  const handlePreview = useCallback(async (lib: SampleLibrary) => {
    if (!engine) return;
    await resumeAudio();

    // If already previewing this library, stop it
    if (previewingId === lib.id) {
      try {
        previewSourceRef.current?.stop();
        previewSourceRef.current?.disconnect();
      } catch (_e) { /* */ }
      previewSourceRef.current = null;
      setPreviewingId(null);
      return;
    }

    // Stop any currently playing preview
    try {
      previewSourceRef.current?.stop();
      previewSourceRef.current?.disconnect();
    } catch (_e) { /* */ }
    previewSourceRef.current = null;

    setPreviewingId(lib.id);
    markRecentlyUsed(lib.id);

    try {
      // Load via the engine's loadSample (fetches URL → decodes → stores in sample map)
      const previewUrl = `/api/libraries/${lib.id}/preview`;
      await engine.loadSample(lib.id, previewUrl);

      // Play it as a one-shot through the engine's master chain
      const ctx = engine.getContext();
      const source = ctx.createBufferSource();
      // getAnalyserData uses the engine's internal samples map; we need to trigger
      // through a simple source → masterGain path for preview
      const samples = (engine as any).samples as Map<string, AudioBuffer>;
      const buffer = samples.get(lib.id);
      if (!buffer) { setPreviewingId(null); return; }

      source.buffer = buffer;
      source.connect(engine.masterGain);
      source.start();
      previewSourceRef.current = source;

      source.addEventListener('ended', () => {
        if (previewSourceRef.current === source) {
          previewSourceRef.current = null;
          setPreviewingId(null);
        }
        try { source.disconnect(); } catch (_e) { /* */ }
      }, { once: true });
    } catch (err) {
      console.error('[KontaktBrowser] Preview failed:', err);
      setPreviewingId(null);
    }
  }, [engine, resumeAudio, previewingId]);

  const filteredLibraries = libraries.filter(lib => {
    const matchesSearch = lib.name.toLowerCase().includes(searchQuery.toLowerCase()) || 
                         lib.vendor.toLowerCase().includes(searchQuery.toLowerCase());
    const matchesCategory = activeCategory === 'All' || lib.category === activeCategory;
    const matchesFilter = filterMode === 'all'
      || (filterMode === 'favorites' && lib.isFavorite)
      || (filterMode === 'recent' && recentlyUsed.includes(lib.id));
    return matchesSearch && matchesCategory && matchesFilter;
  });

  return (
    <div className="h-full flex flex-col gap-4">
      {/* Header */}
      <div className="flex justify-between items-center bg-bg-surface p-4 rounded-xl border border-border-main shadow-lg relative edge-glow-bottom">
        <div className="flex items-center gap-4">
          <div className="w-10 h-10 bg-brand/20 rounded-lg flex items-center justify-center border border-brand/30">
            <Library className="text-brand" size={20} />
          </div>
          <div>
            <h2 className="text-sm font-bold text-neutral-200 uppercase tracking-widest">Sample Library Manager</h2>
            <p className="text-[13px] text-neutral-500 font-mono uppercase">Engine: TBM Sample Engine v7.0.0</p>
          </div>
        </div>

        <div className="flex items-center gap-3">
          <div className="flex items-center gap-2 bg-bg-main px-3 py-1.5 rounded-lg border border-border-main">
            <Database size={14} className="text-neutral-600" />
            <span className="text-[13px] font-mono text-neutral-400">DB Status: <span className="text-emerald-500">Optimized</span></span>
          </div>
          <button 
            onClick={handleScan}
            disabled={isScanning}
            className={`flex items-center gap-2 px-4 py-2 rounded-lg font-bold text-xs uppercase transition-all ${
              isScanning ? 'bg-neutral-800 text-neutral-500' : 'bg-brand hover:opacity-90 text-white shadow-lg shadow-brand/20'
            }`}
          >
            <RefreshCw size={14} className={isScanning ? 'animate-spin' : ''} />
            {isScanning ? 'Scanning...' : 'Scan Libraries'}
          </button>
        </div>
      </div>

      <div className="flex-1 flex gap-4 min-h-0">
        {/* Sidebar: Categories & Paths */}
        <div className="w-64 flex flex-col gap-4">
          <div className="flex-1 bg-neutral-900 rounded-xl border border-neutral-800 p-4 flex flex-col gap-4 overflow-hidden vignette">
            <div className="flex items-center justify-between">
              <span className="text-[13px] font-bold text-neutral-500 uppercase tracking-widest">Categories</span>
              <Filter size={12} className="text-neutral-600" />
            </div>

            <div className="flex-1 overflow-y-auto custom-scrollbar flex flex-col gap-1">
              {categories.map(cat => (
                <button
                  key={cat}
                  onClick={() => setActiveCategory(cat)}
                  className={`flex items-center justify-between px-3 py-2 rounded-lg text-sm transition-all ${
                    activeCategory === cat 
                      ? 'bg-brand text-white font-bold shadow-md' 
                      : 'text-neutral-400 hover:bg-bg-main hover:text-neutral-200'
                  }`}
                >
                  <span>{cat}</span>
                  {activeCategory === cat && <ChevronRight size={12} />}
                </button>
              ))}
            </div>
          </div>

          <div className="bg-neutral-900 rounded-xl border border-neutral-800 p-4 flex flex-col gap-3 vignette">
            <span className="text-[13px] font-bold text-neutral-500 uppercase tracking-widest">Library Paths</span>
            <div className="flex flex-col gap-2">
              {scanPaths.map((path, idx) => (
                <div key={idx} className="flex items-center gap-2 text-[13px] text-neutral-400 bg-neutral-950 p-2 rounded border border-neutral-800">
                  <HardDrive size={12} className="text-neutral-600" />
                  <span className="truncate">{path}</span>
                </div>
              ))}
              {addingPath ? (
                <form
                  onSubmit={(e) => {
                    e.preventDefault();
                    const trimmed = newPathValue.trim();
                    if (trimmed && !scanPaths.includes(trimmed)) {
                      setScanPaths(prev => [...prev, trimmed]);
                    }
                    setNewPathValue('');
                    setAddingPath(false);
                  }}
                  className="flex items-center gap-1"
                >
                  <input
                    autoFocus
                    type="text"
                    value={newPathValue}
                    onChange={(e) => setNewPathValue(e.target.value)}
                    placeholder="/path/to/samples"
                    className="flex-1 bg-neutral-950 border border-red-500/50 rounded px-2 py-1.5 text-[13px] text-neutral-300 outline-none"
                    onKeyDown={(e) => { if (e.key === 'Escape') { setAddingPath(false); setNewPathValue(''); } }}
                  />
                  <button type="submit" className="text-xs font-bold text-red-500 uppercase px-1">Add</button>
                </form>
              ) : (
                <button
                  onClick={() => setAddingPath(true)}
                  className="flex items-center justify-center gap-2 w-full py-2 border border-dashed border-neutral-700 rounded-lg text-[13px] text-neutral-500 hover:border-red-500/50 hover:text-red-500 transition-all"
                >
                  <Plus size={12} /> Add Path
                </button>
              )}
            </div>
          </div>

          <div className="bg-neutral-900 rounded-xl border border-neutral-800 p-4 flex flex-col gap-3 vignette">
            <div className="flex items-center justify-between">
              <span className="text-[13px] font-bold text-neutral-500 uppercase tracking-widest">Recent</span>
              <Clock size={12} className="text-neutral-600" />
            </div>
            <div className="flex flex-col gap-2">
              {libraries.filter(l => recentlyUsed.includes(l.id)).slice(0, 4).map(lib => (
                <div
                  key={lib.id}
                  onClick={() => { markRecentlyUsed(lib.id); handlePreview(lib); }}
                  className="text-[13px] text-neutral-400 bg-neutral-950 p-2 rounded border border-neutral-800 hover:text-red-500 cursor-pointer transition-colors truncate"
                >
                  {lib.name}
                </div>
              ))}
              {recentlyUsed.length === 0 && (
                <span className="text-xs text-neutral-600 font-mono">No recent instruments</span>
              )}
            </div>
          </div>
        </div>

        {/* Main Content: Library Grid */}
        <div className="flex-1 flex flex-col gap-4 bg-neutral-900 rounded-xl border border-neutral-800 p-4 overflow-hidden vignette">
          <div className="flex items-center gap-4">
            <div className="flex-1 relative">
              <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-neutral-600" size={16} />
              <input 
                type="text" 
                placeholder="Search instruments, vendors, or tags..."
                value={searchQuery}
                onChange={(e) => setSearchQuery(e.target.value)}
                className="w-full bg-neutral-950 border border-neutral-800 rounded-xl px-10 py-2.5 text-sm outline-none focus:border-red-500 transition-colors"
              />
            </div>
            <div className="flex gap-2">
              <button
                onClick={() => setFilterMode(prev => prev === 'favorites' ? 'all' : 'favorites')}
                className={`p-2.5 bg-neutral-950 border rounded-xl transition-colors ${
                  filterMode === 'favorites' ? 'border-yellow-500 text-yellow-500' : 'border-neutral-800 text-neutral-400 hover:text-white'
                }`}
                title={filterMode === 'favorites' ? 'Show all' : 'Show favorites only'}
              >
                <Star size={18} className={filterMode === 'favorites' ? 'fill-yellow-500' : ''} />
              </button>
              <button
                onClick={() => setFilterMode(prev => prev === 'recent' ? 'all' : 'recent')}
                className={`p-2.5 bg-neutral-950 border rounded-xl transition-colors ${
                  filterMode === 'recent' ? 'border-red-500 text-red-500' : 'border-neutral-800 text-neutral-400 hover:text-white'
                }`}
                title={filterMode === 'recent' ? 'Show all' : 'Show recently used'}
              >
                <Clock size={18} />
              </button>
            </div>
          </div>

          <div className="flex-1 overflow-y-auto custom-scrollbar pr-2">
            {isLoading ? (
              <div className="h-full flex items-center justify-center">
                <Loader2 size={28} className="animate-spin text-neutral-600" />
              </div>
            ) : (
              <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
                {filteredLibraries.map(lib => (
                  <div 
                    key={lib.id}
                    className="group bg-neutral-950 rounded-xl border border-neutral-800 p-4 hover:border-red-500/50 transition-all cursor-pointer relative overflow-hidden"
                  >
                    <div className="absolute top-0 right-0 p-2 flex gap-1 opacity-0 group-hover:opacity-100 transition-opacity">
                      <button
                        onClick={(e) => { e.stopPropagation(); handlePreview(lib); }}
                        className={`p-1 transition-colors ${previewingId === lib.id ? 'text-red-400' : 'hover:text-emerald-400'}`}
                        title={previewingId === lib.id ? 'Stop preview' : 'Preview'}
                      >
                        {previewingId === lib.id ? <Square size={14} /> : <Play size={14} />}
                      </button>
                      <button
                        onClick={(e) => { e.stopPropagation(); handleToggleFavorite(lib); }}
                        className="p-1 hover:text-yellow-400"
                        title={lib.isFavorite ? 'Remove from favorites' : 'Add to favorites'}
                      >
                        <Star size={14} className={lib.isFavorite ? 'fill-yellow-500 text-yellow-500' : ''} />
                      </button>
                    </div>

                    <div className="flex items-start gap-3">
                      <div className="w-12 h-12 bg-neutral-900 rounded-lg flex items-center justify-center border border-neutral-800 group-hover:border-red-500/30 transition-colors">
                        <FileCode size={24} className="text-neutral-700 group-hover:text-red-500/50 transition-colors" />
                      </div>
                      <div className="flex-1 min-w-0">
                        <h3 className="text-xs font-bold text-neutral-200 truncate group-hover:text-red-500 transition-colors">{lib.name}</h3>
                        <p className="text-[13px] text-neutral-500 font-mono uppercase mt-0.5">{lib.vendor}</p>
                      </div>
                    </div>

                    <div className="mt-4 pt-4 border-t border-neutral-900 separator-glow flex items-center justify-between">
                      <div className="flex flex-col">
                        <span className="text-xs text-neutral-600 uppercase font-bold tracking-tighter">Instruments</span>
                        <span className="text-sm font-mono text-neutral-400">{lib.instruments}</span>
                      </div>
                      <div className="flex flex-col items-end">
                        <span className="text-xs text-neutral-600 uppercase font-bold tracking-tighter">Size</span>
                        <span className="text-sm font-mono text-neutral-400">{lib.size}</span>
                      </div>
                    </div>

                    {lib.isFavorite && (
                      <div className="absolute bottom-0 right-0 p-1">
                        <Star size={10} className="text-yellow-500 fill-yellow-500" />
                      </div>
                    )}
                  </div>
                ))}
              </div>
            )}

            {!isLoading && filteredLibraries.length === 0 && (
              <div className="h-full flex flex-col items-center justify-center text-neutral-600 gap-4 py-20">
                <Library size={48} className="opacity-20" />
                <div className="text-center">
                  <p className="text-sm font-bold uppercase tracking-widest">No Libraries Found</p>
                  <p className="text-xs mt-1">Try adjusting your search or category filter</p>
                </div>
              </div>
            )}
          </div>

          {/* Status Bar */}
          <div className="mt-auto pt-4 border-t border-neutral-800 separator-glow flex items-center justify-between">
            <div className="flex items-center gap-4">
              <span className="text-[13px] font-mono text-neutral-500 uppercase">Total: {libraries.length} Libraries</span>
              <span className="text-[13px] font-mono text-neutral-500 uppercase">Filtered: {filteredLibraries.length}</span>
            </div>
            <div className="flex items-center gap-2">
              <span className="text-[13px] font-mono text-neutral-500 uppercase">Supported Formats: .nki, .nkx, .nkm, .nicnt</span>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
}

import React, { useState, useCallback, useEffect, useRef } from "react";
import { Volume2, Mic2, Music, ChevronDown, ChevronUp } from "lucide-react";
import { useTBMAudio } from "../contexts/TBMAudioContext";
import { Knob } from "./Knob";

interface ChannelProps {
  label: string;
  icon: React.ReactNode;
  color: string;
  onVolumeChange?: (vol: number) => void;
  onMuteChange?: (muted: boolean) => void;
  onSoloChange?: (solo: boolean) => void;
  onPanChange?: (pan: number) => void;
}

const Channel = React.memo(function Channel({
  label,
  icon,
  color,
  onVolumeChange,
  onMuteChange,
  onSoloChange,
  onPanChange,
}: ChannelProps) {
  const [vol, setVol] = useState(75);
  const [pan, setPan] = useState(0); // -50 to +50 for display; send as -1..+1
  const [isMuted, setIsMuted] = useState(false);
  const [isSolo, setIsSolo] = useState(false);

  const handleVolChange = useCallback(
    (e: React.ChangeEvent<HTMLInputElement>) => {
      const v = parseInt(e.target.value);
      setVol(v);
      onVolumeChange?.(v / 100);
    },
    [onVolumeChange],
  );

  const handleMuteToggle = useCallback(() => {
    setIsMuted((prev) => {
      const next = !prev;
      onMuteChange?.(next);
      return next;
    });
  }, [onMuteChange]);

  const handleSoloToggle = useCallback(() => {
    setIsSolo((prev) => {
      const next = !prev;
      onSoloChange?.(next);
      return next;
    });
  }, [onSoloChange]);

  // Pan knob drag: click+drag vertically to adjust pan
  const panDragRef = useRef<{ startY: number; startPan: number } | null>(null);
  // MiniMixer 4.1: track active listeners so they can be removed on unmount
  const panListenersRef = useRef<{ move: (e: MouseEvent) => void; up: () => void } | null>(null);

  // Cleanup pan drag listeners on unmount
  useEffect(() => {
    return () => {
      if (panListenersRef.current) {
        window.removeEventListener("mousemove", panListenersRef.current.move);
        window.removeEventListener("mouseup", panListenersRef.current.up);
        panListenersRef.current = null;
      }
    };
  }, []);

  const handlePanMouseDown = useCallback(
    (e: React.MouseEvent) => {
      e.preventDefault();
      panDragRef.current = { startY: e.clientY, startPan: pan };

      const onMouseMove = (ev: MouseEvent) => {
        if (!panDragRef.current) return;
        const delta = (panDragRef.current.startY - ev.clientY) * 0.5;
        const newPan = Math.max(
          -50,
          Math.min(50, panDragRef.current.startPan + delta),
        );
        setPan(newPan);
        // Convert -50..+50 to -1..+1
        onPanChange?.(newPan / 50);
      };
      const onMouseUp = () => {
        panDragRef.current = null;
        panListenersRef.current = null;
        window.removeEventListener("mousemove", onMouseMove);
        window.removeEventListener("mouseup", onMouseUp);
      };
      panListenersRef.current = { move: onMouseMove, up: onMouseUp };
      window.addEventListener("mousemove", onMouseMove);
      window.addEventListener("mouseup", onMouseUp);
    },
    [pan, onPanChange],
  );

  return (
    <div className="flex flex-col items-center gap-2 w-16 group">
      {/* Pan Knob (Mini) */}
      <div
        className="relative w-8 h-8 rounded-full bg-neutral-800 border border-neutral-700 flex items-center justify-center cursor-ns-resize"
        onMouseDown={handlePanMouseDown}
        title={`Pan: ${pan > 0 ? "R" : pan < 0 ? "L" : "C"}${Math.abs(Math.round(pan))}`}
      >
        <div
          className="w-0.5 h-3 bg-neutral-400 absolute top-0.5 rounded-full"
          style={{
            transform: `rotate(${pan * 1.5}deg)`,
            transformOrigin: "bottom center",
          }}
        ></div>
        <span className="text-xs font-mono text-neutral-500 absolute -top-4">
          PAN
        </span>
      </div>

      {/* Fader Track */}
      <div className="relative w-6 h-32 bg-neutral-950 rounded-sm border border-neutral-800 flex justify-center py-2">
        <div className="absolute inset-0 flex flex-col justify-between px-1 py-4 pointer-events-none">
          {[0, 1, 2, 3, 4].map((i) => (
            <div key={i} className="w-full h-px bg-neutral-800"></div>
          ))}
        </div>
        <input
          type="range"
          min="0"
          max="100"
          step={1}
          value={vol}
          aria-label="Volume"
          onChange={handleVolChange}
          className="appearance-none w-32 h-6 bg-transparent cursor-pointer -rotate-90 absolute top-1/2 -translate-y-1/2 accent-white"
          style={{ width: "110px" }}
        />
        {/* Fader Cap (Visual) */}
        <div
          className="absolute w-5 h-8 bg-neutral-200 rounded-sm shadow-md pointer-events-none flex flex-col items-center justify-center gap-0.5"
          style={{ bottom: `${vol * 0.8 + 10}px`, willChange: "bottom" }}
        >
          <div className="w-3 h-px bg-neutral-400"></div>
          <div className="w-3 h-px bg-neutral-400"></div>
        </div>
      </div>

      {/* M/S Buttons */}
      <div className="flex gap-1">
        <button
          onClick={handleMuteToggle}
          className={`w-5 h-5 rounded-sm text-[13px] font-bold flex items-center justify-center transition-colors ${
            isMuted
              ? "bg-red-600 text-white"
              : "bg-neutral-800 text-neutral-500 hover:bg-neutral-700"
          }`}
        >
          M
        </button>
        <button
          onClick={handleSoloToggle}
          className={`w-5 h-5 rounded-sm text-[13px] font-bold flex items-center justify-center transition-colors ${
            isSolo
              ? "bg-yellow-500 text-black"
              : "bg-neutral-800 text-neutral-500 hover:bg-neutral-700"
          }`}
        >
          S
        </button>
      </div>

      <div className="flex flex-col items-center">
        <div className="p-1 rounded bg-neutral-800 mb-1" style={{ color }}>
          {icon}
        </div>
        <span className="text-xs font-mono text-neutral-500 uppercase tracking-tighter">
          {label}
        </span>
      </div>
    </div>
  );
});

export const MiniMixer = React.memo(function MiniMixer() {
  const {
    engine,
    setDeckVolume,
    setDJMasterVolume,
    djEngine,
    getEngineAnalyser,
  } = useTBMAudio();

  const [inGain, setInGain] = useState(0);
  const [outGain, setOutGain] = useState(0);
  const [isDraggingInGain, setIsDraggingInGain] = useState(false);
  const [isDraggingOutGain, setIsDraggingOutGain] = useState(false);

  // MPC-style sample parameters
  const [showSampleParams, setShowSampleParams] = useState(true);
  const [attack, setAttack] = useState(0);
  const [decay, setDecay] = useState(30);
  const [sustain, setSustain] = useState(80);
  const [release, setRelease] = useState(25);
  const [tune, setTune] = useState(50);       // 50 = center (0 semitones)
  const [filterCutoff, setFilterCutoff] = useState(100);
  const [filterRes, setFilterRes] = useState(0);
  const [velocitySens, setVelocitySens] = useState(75);
  const [layerMode, setLayerMode] = useState<'velocity' | 'round-robin' | 'random'>('velocity');

  // RMS / LUFS meter state
  const rmsMeterRef = useRef<HTMLDivElement>(null);
  const lufsMeterRef = useRef<HTMLDivElement>(null);
  const rafRef = useRef<number>(0);
  // 400ms sliding window for LUFS approx (at 60fps ≈ 24 frames)
  const lufsWindowRef = useRef<number[]>([]);

  // ── rAF meter loop ──
  useEffect(() => {
    const analyser = getEngineAnalyser();
    if (!analyser) return;

    const bufferLength = analyser.fftSize;
    const dataArray = new Float32Array(bufferLength);

    const tick = () => {
      analyser.getFloatTimeDomainData(dataArray);

      // RMS
      let sumSq = 0;
      for (let i = 0; i < bufferLength; i++)
        sumSq += dataArray[i] * dataArray[i];
      const rms = Math.sqrt(sumSq / bufferLength);
      const rmsDb = rms > 0 ? 20 * Math.log10(rms) : -100;
      const rmsH = Math.max(0, Math.min(100, ((rmsDb + 60) / 60) * 100));
      if (rmsMeterRef.current) {
        rmsMeterRef.current.style.height = `${rmsH}%`;
      }

      // LUFS approx — 400ms window
      const meanSq = sumSq / bufferLength;
      lufsWindowRef.current.push(meanSq);
      if (lufsWindowRef.current.length > 24) lufsWindowRef.current.shift();
      const windowMean =
        lufsWindowRef.current.reduce((a, b) => a + b, 0) /
        lufsWindowRef.current.length;
      const lufsDb =
        windowMean > 0 ? 10 * Math.log10(windowMean) - 0.691 : -100;
      const lufsH = Math.max(0, Math.min(100, ((lufsDb + 60) / 60) * 100));
      if (lufsMeterRef.current) {
        lufsMeterRef.current.style.height = `${lufsH}%`;
      }

      rafRef.current = requestAnimationFrame(tick);
    };

    rafRef.current = requestAnimationFrame(tick);
    return () => cancelAnimationFrame(rafRef.current);
  }, [getEngineAnalyser]);

   // Keep refs to the current fader positions so mute can restore them
  const deckAVolumeRef = useRef(0.75);
  const deckBVolumeRef = useRef(0.68);
  // MiniMixer 4.5/4.6: store normalized (0–1) value, not the raw 0–100 fader value.
  // Previously the fader value (0-100) was stored here, then divided by 100 again in
  // handleChordsMute and the solo effect — resulting in the channel being inaudible
  // (volume was e.g. 0.65/100 = 0.0065).
  const chordsVolumeRef = useRef(0.65); // normalized 0..1

  // Track per-channel mute state so the solo-bus effect can respect it when
  // solos are cleared (audit fix: previously all channels were restored to fader
  // volume on unsolo, ignoring mute — a muted channel would become audible).
  const deckAMutedRef = useRef(false);
  const deckBMutedRef = useRef(false);
  const chordsMutedRef = useRef(false);

  // Solo bus state
  const [soloedChannels, setSoloedChannels] = useState<Set<string>>(new Set());

  // Channel volume callbacks → deck volumes
  const handleDeckAVolume = useCallback(
    (vol: number) => {
      deckAVolumeRef.current = vol;
      setDeckVolume("A", vol);
    },
    [setDeckVolume],
  );

  const handleDeckBVolume = useCallback(
    (vol: number) => {
      deckBVolumeRef.current = vol;
      setDeckVolume("B", vol);
    },
    [setDeckVolume],
  );

  // Chords channel → pad index 2 (third pad) or synth engine
  const handleChordsVolume = useCallback(
    (vol: number) => {
      // MiniMixer 4.5/4.6: vol is already normalized to 0–1 by Channel's handleVolChange
      // (it divides by 100). Store it as-is so mute/solo can restore without double division.
      chordsVolumeRef.current = vol;
      engine?.setPadVolume(2, vol);
    },
    [engine],
  );

  // Mute handlers — set volume to 0 when muted, restore user's fader position when unmuted.
  // When another channel is soloed this channel is already silenced by the solo-bus useEffect;
  // skip the mute toggle so it doesn't fight the solo-bus restore on unmute.
  const handleDeckAMute = useCallback(
    (muted: boolean) => {
      deckAMutedRef.current = muted;
      if (soloedChannels.size > 0 && !soloedChannels.has("chops")) return;
      setDeckVolume("A", muted ? 0 : deckAVolumeRef.current);
    },
    [setDeckVolume, soloedChannels],
  );

  const handleDeckBMute = useCallback(
    (muted: boolean) => {
      deckBMutedRef.current = muted;
      if (soloedChannels.size > 0 && !soloedChannels.has("808")) return;
      setDeckVolume("B", muted ? 0 : deckBVolumeRef.current);
    },
    [setDeckVolume, soloedChannels],
  );

  const handleChordsMute = useCallback(
    (muted: boolean) => {
      chordsMutedRef.current = muted;
      if (soloedChannels.size > 0 && !soloedChannels.has("chords")) return;
      // MiniMixer 4.5/4.6: chordsVolumeRef is already normalized (0–1)
      engine?.setPadVolume(2, muted ? 0 : chordsVolumeRef.current);
    },
    [engine, soloedChannels],
  );

  // Solo bus handler
  const handleSoloChange = useCallback((channelId: string, solo: boolean) => {
    setSoloedChannels((prev) => {
      const newSet = new Set(prev);
      if (solo) {
        newSet.add(channelId);
      } else {
        newSet.delete(channelId);
      }
      return newSet;
    });
  }, []);

  // Apply solo bus logic to all channels
  useEffect(() => {
    const hasSolo = soloedChannels.size > 0;

    // Deck A (chops)
    if (hasSolo) {
      const shouldPlay = soloedChannels.has("chops");
      setDeckVolume("A", shouldPlay ? deckAVolumeRef.current : 0);
    } else {
      // Restore based on mute state — a muted channel must stay at 0
      setDeckVolume("A", deckAMutedRef.current ? 0 : deckAVolumeRef.current);
    }

    // Deck B (808)
    if (hasSolo) {
      const shouldPlay = soloedChannels.has("808");
      setDeckVolume("B", shouldPlay ? deckBVolumeRef.current : 0);
    } else {
      setDeckVolume("B", deckBMutedRef.current ? 0 : deckBVolumeRef.current);
    }

    // Chords channel
    if (hasSolo) {
      const shouldPlay = soloedChannels.has("chords");
      // MiniMixer 4.5/4.6: chordsVolumeRef is already normalized (0–1)
      engine?.setPadVolume(2, shouldPlay ? chordsVolumeRef.current : 0);
    } else {
      engine?.setPadVolume(2, chordsMutedRef.current ? 0 : chordsVolumeRef.current);
    }
  }, [soloedChannels, setDeckVolume, engine]);

  // Pan change → engine.setPadPan (track index = channel index)
  const handleChopsPan = useCallback(
    (pan: number) => {
      // Chops channel → pad index 0
      engine?.setPadPan(0, pan);
    },
    [engine],
  );

  const handle808Pan = useCallback(
    (pan: number) => {
      // 808 channel → pad index 1
      engine?.setPadPan(1, pan);
    },
    [engine],
  );

  const handleChordsPan = useCallback(
    (pan: number) => {
      // Chords channel → pad index 2
      engine?.setPadPan(2, pan);
    },
    [engine],
  );

  // Mouse drag handlers for IN/OUT GAIN knobs
  // MiniMixer 4.2: track listeners via ref so they can be removed on unmount
  const inGainListenersRef = useRef<{ move: (e: MouseEvent) => void; up: () => void } | null>(null);
  const outGainListenersRef = useRef<{ move: (e: MouseEvent) => void; up: () => void } | null>(null);

  useEffect(() => {
    return () => {
      if (inGainListenersRef.current) {
        document.removeEventListener("mousemove", inGainListenersRef.current.move);
        document.removeEventListener("mouseup", inGainListenersRef.current.up);
        inGainListenersRef.current = null;
      }
      if (outGainListenersRef.current) {
        document.removeEventListener("mousemove", outGainListenersRef.current.move);
        document.removeEventListener("mouseup", outGainListenersRef.current.up);
        outGainListenersRef.current = null;
      }
    };
  }, []);

  const handleInGainMouseDown = useCallback(
    (e: React.MouseEvent) => {
      e.preventDefault();
      setIsDraggingInGain(true);

      const startY = e.clientY;
      const startValue = inGain;

      const handleMouseMove = (moveEvent: MouseEvent) => {
        const deltaY = startY - moveEvent.clientY;
        const newValue = Math.max(-24, Math.min(12, startValue + deltaY));
        setInGain(newValue);
      };

      const handleMouseUp = () => {
        setIsDraggingInGain(false);
        inGainListenersRef.current = null;
        document.removeEventListener("mousemove", handleMouseMove);
        document.removeEventListener("mouseup", handleMouseUp);
      };

      inGainListenersRef.current = { move: handleMouseMove, up: handleMouseUp };
      document.addEventListener("mousemove", handleMouseMove);
      document.addEventListener("mouseup", handleMouseUp);
    },
    [inGain],
  );

  const handleOutGainMouseDown = useCallback(
    (e: React.MouseEvent) => {
      e.preventDefault();
      setIsDraggingOutGain(true);

      const startY = e.clientY;
      const startValue = outGain;

      const handleMouseMove = (moveEvent: MouseEvent) => {
        const deltaY = startY - moveEvent.clientY;
        const newValue = Math.max(-24, Math.min(12, startValue + deltaY));
        setOutGain(newValue);
      };

      const handleMouseUp = () => {
        setIsDraggingOutGain(false);
        outGainListenersRef.current = null;
        document.removeEventListener("mousemove", handleMouseMove);
        document.removeEventListener("mouseup", handleMouseUp);
      };

      outGainListenersRef.current = { move: handleMouseMove, up: handleMouseUp };
      document.addEventListener("mousemove", handleMouseMove);
      document.addEventListener("mouseup", handleMouseUp);
    },
    [outGain],
  );

  // Master out gain → DJ master volume
  useEffect(() => {
    const linearGain = Math.max(0, Math.min(1, (outGain + 24) / 36));
    setDJMasterVolume(linearGain);
  }, [outGain, setDJMasterVolume]);

  return (
    <div className="h-full flex flex-col bg-neutral-950/50 rounded-xl border border-neutral-800/60 p-3">
      {/* Header bar — mixing board label */}
      <div className="flex justify-between items-center mb-3 pb-2 border-b border-neutral-800/50">
        <div className="flex items-center gap-2">
          <div className="w-2 h-2 rounded-full bg-red-500 shadow-[0_0_6px_rgba(239,68,68,0.6)]"></div>
          <h2 className="text-sm font-black text-neutral-400 uppercase tracking-widest">
            Channel Strip
          </h2>
        </div>
        <div className="flex items-center gap-3">
          <div className="flex items-center gap-1.5 px-2 py-0.5 rounded-md bg-neutral-900 border border-neutral-800">
            <div
              className={`w-1.5 h-1.5 rounded-full ${soloedChannels.size > 0 ? "bg-yellow-500 animate-pulse" : "bg-red-500"} shadow-[0_0_5px_rgba(239,68,68,0.5)]`}
            ></div>
            <span className="text-xs font-bold font-mono text-neutral-500 uppercase">
              {soloedChannels.size > 0
                ? `SOLO (${soloedChannels.size})`
                : "VCA Group 1"}
            </span>
          </div>
          <div className="flex items-center gap-1 text-xs font-mono text-neutral-600">
            <span>48kHz</span>
            <span className="text-neutral-700">/</span>
            <span>24bit</span>
          </div>
        </div>
      </div>

      {/* Channel strips + Master */}
      <div className="flex-1 flex items-start gap-1">
        {/* Individual Channel Strips */}
        <div className="flex items-start gap-0.5 flex-1 justify-around">
          <Channel
            label="Chops"
            icon={<Volume2 size={12} />}
            color="#FF6B6B"
            onVolumeChange={handleDeckAVolume}
            onMuteChange={handleDeckAMute}
            onSoloChange={(solo) => handleSoloChange("chops", solo)}
            onPanChange={handleChopsPan}
          />
          <Channel
            label="808"
            icon={<Mic2 size={12} />}
            color="#4C83FF"
            onVolumeChange={handleDeckBVolume}
            onMuteChange={handleDeckBMute}
            onSoloChange={(solo) => handleSoloChange("808", solo)}
            onPanChange={handle808Pan}
          />
          <Channel
            label="Chords"
            icon={<Music size={12} />}
            color="#FFD700"
            onVolumeChange={handleChordsVolume}
            onMuteChange={handleChordsMute}
            onSoloChange={(solo) => handleSoloChange("chords", solo)}
            onPanChange={handleChordsPan}
          />
        </div>

        {/* Master Section Divider */}
        <div className="flex flex-col items-center self-stretch mx-1">
          <div className="w-px flex-1 bg-gradient-to-b from-transparent via-neutral-700 to-transparent"></div>
        </div>

        {/* ═══ MASTER CHANNEL ═══ */}
        <div className="flex flex-col items-center gap-2 px-3 py-2 bg-neutral-900/80 rounded-lg border border-neutral-800/60 min-w-[90px]">
          {/* Master label */}
          <div className="flex items-center gap-1.5 mb-1">
            <div className="w-1.5 h-1.5 rounded-full bg-red-500 shadow-[0_0_4px_rgba(239,68,68,0.6)]"></div>
            <span className="text-xs font-black text-neutral-400 uppercase tracking-widest">MST</span>
          </div>

          {/* IN/OUT Gain knobs row */}
          <div className="flex gap-3">
            {/* Input Gain */}
            <div className="flex flex-col items-center gap-1">
              <span className="text-[7px] font-mono text-neutral-600 uppercase tracking-wider">IN</span>
              <div
                className={`relative w-9 h-9 rounded-full border-2 flex items-center justify-center cursor-ns-resize shadow-inner ${isDraggingInGain ? "bg-neutral-700 border-red-500/60 shadow-red-500/10" : "bg-neutral-800 border-neutral-700"}`}
                onMouseDown={handleInGainMouseDown}
                title={`Input Gain: ${inGain}dB`}
              >
                <div
                  className="w-0.5 h-3.5 bg-red-500 rounded-full"
                  style={{
                    transform: `rotate(${inGain * 4}deg)`,
                    transformOrigin: "bottom center",
                  }}
                ></div>
                {/* Knob detent markers */}
                <div className="absolute inset-0 rounded-full">
                  <div className="absolute top-0 left-1/2 w-px h-1 -translate-x-1/2 bg-neutral-700"></div>
                  <div className="absolute bottom-0 left-1/2 w-px h-1 -translate-x-1/2 bg-neutral-700"></div>
                  <div className="absolute top-1/2 left-0 w-1 h-px -translate-y-1/2 bg-neutral-700"></div>
                  <div className="absolute top-1/2 right-0 w-1 h-px -translate-y-1/2 bg-neutral-700"></div>
                </div>
              </div>
              <span className="text-[8px] font-mono text-neutral-500">{inGain > 0 ? '+' : ''}{inGain}dB</span>
            </div>

            {/* Output Gain */}
            <div className="flex flex-col items-center gap-1">
              <span className="text-[7px] font-mono text-neutral-600 uppercase tracking-wider">OUT</span>
              <div
                className={`relative w-9 h-9 rounded-full border-2 flex items-center justify-center cursor-ns-resize shadow-inner ${isDraggingOutGain ? "bg-neutral-700 border-emerald-500/60 shadow-emerald-500/10" : "bg-neutral-800 border-neutral-700"}`}
                onMouseDown={handleOutGainMouseDown}
                title={`Output Gain: ${outGain}dB`}
              >
                <div
                  className="w-0.5 h-3.5 bg-emerald-500 rounded-full"
                  style={{
                    transform: `rotate(${outGain * 4}deg)`,
                    transformOrigin: "bottom center",
                  }}
                ></div>
                <div className="absolute inset-0 rounded-full">
                  <div className="absolute top-0 left-1/2 w-px h-1 -translate-x-1/2 bg-neutral-700"></div>
                  <div className="absolute bottom-0 left-1/2 w-px h-1 -translate-x-1/2 bg-neutral-700"></div>
                  <div className="absolute top-1/2 left-0 w-1 h-px -translate-y-1/2 bg-neutral-700"></div>
                  <div className="absolute top-1/2 right-0 w-1 h-px -translate-y-1/2 bg-neutral-700"></div>
                </div>
              </div>
              <span className="text-[8px] font-mono text-neutral-500">{outGain > 0 ? '+' : ''}{outGain}dB</span>
            </div>
          </div>

          {/* Meter bridge */}
          <div className="flex gap-2 mt-1 p-2 bg-neutral-950 rounded-md border border-neutral-800/60">
            {/* RMS meter */}
            <div className="flex flex-col items-center gap-0.5">
              <span className="text-[7px] font-mono text-neutral-600 uppercase tracking-wider">RMS</span>
              <div className="w-2.5 h-20 bg-neutral-900 rounded-sm relative overflow-hidden border border-neutral-800/40">
                {/* dB scale lines */}
                <div className="absolute inset-0 flex flex-col justify-between py-1 pointer-events-none">
                  {[0, 1, 2, 3, 4].map(i => (
                    <div key={i} className="w-full h-px bg-neutral-800/60"></div>
                  ))}
                </div>
                <div
                  ref={rmsMeterRef}
                  className="absolute bottom-0 w-full bg-gradient-to-t from-blue-600 via-blue-500 to-cyan-400 transition-none"
                  style={{ height: `0%` }}
                ></div>
              </div>
            </div>
            {/* LUFS meter */}
            <div className="flex flex-col items-center gap-0.5">
              <span className="text-[7px] font-mono text-neutral-600 uppercase tracking-wider">LUFS</span>
              <div className="w-2.5 h-20 bg-neutral-900 rounded-sm relative overflow-hidden border border-neutral-800/40">
                <div className="absolute inset-0 flex flex-col justify-between py-1 pointer-events-none">
                  {[0, 1, 2, 3, 4].map(i => (
                    <div key={i} className="w-full h-px bg-neutral-800/60"></div>
                  ))}
                </div>
                <div
                  ref={lufsMeterRef}
                  className="absolute bottom-0 w-full bg-gradient-to-t from-emerald-600 via-emerald-500 to-green-400 transition-none"
                  style={{ height: `0%` }}
                ></div>
              </div>
            </div>
            {/* dB scale labels */}
            <div className="flex flex-col justify-between text-[6px] font-mono text-neutral-700 py-1">
              <span>0</span>
              <span>-12</span>
              <span>-24</span>
              <span>-36</span>
              <span>-60</span>
            </div>
          </div>

          {/* Clip / Signal indicators */}
          <div className="flex gap-2 mt-1">
            <div className="flex flex-col items-center gap-0.5">
              <div className="w-3 h-3 rounded-full bg-neutral-900 border border-neutral-800 shadow-inner"></div>
              <span className="text-[6px] font-mono text-neutral-600 uppercase">CLIP</span>
            </div>
            <div className="flex flex-col items-center gap-0.5">
              <div className="w-3 h-3 rounded-full bg-emerald-900/60 border border-emerald-800/40 shadow-[0_0_4px_rgba(16,185,129,0.2)]"></div>
              <span className="text-[6px] font-mono text-neutral-600 uppercase">SIG</span>
            </div>
          </div>

          {/* Master label */}
          <div className="flex items-center gap-1 mt-1 pt-1 border-t border-neutral-800/50">
            <div className="w-1.5 h-5 bg-red-600 rounded-sm shadow-[0_0_8px_rgba(220,38,38,0.4)]"></div>
            <span className="text-xs font-bold font-mono text-neutral-400 uppercase tracking-wider">
              Master
            </span>
          </div>
        </div>
      </div>

      {/* ═══ MPC-STYLE SAMPLE PARAMETERS ═══ */}
      <div className="mt-2 pt-2 border-t border-neutral-800/50">
        <button
          onClick={() => setShowSampleParams(!showSampleParams)}
          className="flex items-center justify-between w-full mb-2 group"
        >
          <span className="text-xs font-black text-neutral-500 uppercase tracking-widest">Sample Params</span>
          {showSampleParams ? <ChevronUp size={12} className="text-neutral-600" /> : <ChevronDown size={12} className="text-neutral-600" />}
        </button>

        {showSampleParams && (
          <div className="flex flex-col gap-3">
            {/* ADSR Envelope */}
            <div className="bg-neutral-900/60 rounded-lg border border-neutral-800/50 p-2">
              <span className="text-[7px] font-bold font-mono text-neutral-600 uppercase tracking-widest block mb-1.5">ADSR Envelope</span>
              <div className="flex justify-between gap-1">
                <Knob label="ATK" value={attack} onChange={setAttack} color="#ef4444" />
                <Knob label="DEC" value={decay} onChange={setDecay} color="#f97316" />
                <Knob label="SUS" value={sustain} onChange={setSustain} color="#eab308" />
                <Knob label="REL" value={release} onChange={setRelease} color="#22c55e" />
              </div>
            </div>

            {/* Tune / Pitch */}
            <div className="bg-neutral-900/60 rounded-lg border border-neutral-800/50 p-2">
              <span className="text-[7px] font-bold font-mono text-neutral-600 uppercase tracking-widest block mb-1.5">Tune / Pitch</span>
              <div className="flex justify-center">
                <Knob label="TUNE" value={tune} onChange={setTune} color="#3b82f6" />
              </div>
              <div className="text-center mt-1">
                <span className="text-[8px] font-mono text-neutral-500">
                  {tune === 50 ? '0 st' : tune > 50 ? `+${Math.round((tune - 50) * 24 / 50)} st` : `${Math.round((tune - 50) * 24 / 50)} st`}
                </span>
              </div>
            </div>

            {/* Filter */}
            <div className="bg-neutral-900/60 rounded-lg border border-neutral-800/50 p-2">
              <span className="text-[7px] font-bold font-mono text-neutral-600 uppercase tracking-widest block mb-1.5">Filter</span>
              <div className="flex justify-around gap-1">
                <Knob label="CUTOFF" value={filterCutoff} onChange={setFilterCutoff} color="#a855f7" />
                <Knob label="RES" value={filterRes} onChange={setFilterRes} color="#ec4899" />
              </div>
            </div>

            {/* Velocity / Layer */}
            <div className="bg-neutral-900/60 rounded-lg border border-neutral-800/50 p-2">
              <span className="text-[7px] font-bold font-mono text-neutral-600 uppercase tracking-widest block mb-1.5">Velocity & Layers</span>
              <div className="flex justify-center mb-2">
                <Knob label="VEL" value={velocitySens} onChange={setVelocitySens} color="#06b6d4" />
              </div>
              <div className="flex gap-1">
                {(['velocity', 'round-robin', 'random'] as const).map(mode => (
                  <button
                    key={mode}
                    onClick={() => setLayerMode(mode)}
                    className={`flex-1 text-[8px] font-bold font-mono uppercase py-1 rounded transition-colors ${
                      layerMode === mode
                        ? 'bg-cyan-600/20 text-cyan-400 border border-cyan-600/40'
                        : 'bg-neutral-800 text-neutral-600 border border-neutral-700 hover:text-neutral-400'
                    }`}
                  >
                    {mode === 'round-robin' ? 'R-R' : mode === 'velocity' ? 'VEL' : 'RND'}
                  </button>
                ))}
              </div>
            </div>
          </div>
        )}
      </div>
    </div>
  );
});

import React, { useState, useCallback, useEffect, useRef } from 'react';
import { Knob } from './Knob';
import { Link2, Cpu } from 'lucide-react';
import { useTBMAudio } from '../contexts/TBMAudioContext';

// Kick pad is always pad index 0 in TBM convention
const KICK_PAD_INDEX = 0;
// Worklet module URL — use `new URL()` + `import.meta.url` so Vite resolves
// it correctly in both dev and production builds (the bare `/src/...` path
// only works in dev mode with Vite's FS serving).
const SIDECHAIN_WORKLET_URL = new URL(
  '../worklets/sidechain-compressor-processor.js',
  import.meta.url,
).href;

export const Mixer808 = React.memo(function Mixer808() {
  const {
    engine,
    djEngine,
    audioContext,
    setDeckPlaybackRate,
    setDeckEQ,
    setDeckEffect,
    setDeckEffectEnabled,
    setDeckEffectParam,
  } = useTBMAudio();

  const [punch, setPunch] = useState(50);
  const [tune, setTune] = useState(0);
  const [drive, setDrive] = useState(20);
  const [portamento, setPortamento] = useState(15);
  const [sidechain, setSidechain] = useState(true);
  const [eqEnabled, setEqEnabled] = useState(true);
  const [eqFreq, setEqFreq] = useState(1000);
  const [eqGain, setEqGain] = useState(0);
  const [eqQ, setEqQ] = useState(1);

  // ── Parametric EQ node (BiquadFilterNode) inserted on Deck B ──
  const eqNodeRef = useRef<BiquadFilterNode | null>(null);

  // ── Sidechain worklet state ──
  // Refs hold the live AudioWorkletNode and its output GainNode so we can
  // disconnect/reconnect cleanly when the toggle changes.
  const scWorkletRef = useRef<AudioWorkletNode | null>(null);
  const scWorkletOutRef = useRef<GainNode | null>(null);
  const scLoadedRef = useRef(false); // true once addModule() has resolved
  const abortControllerRef = useRef<AbortController | null>(null);
  const mountedRef = useRef(true);

  // ── Punch → Deck B low-shelf EQ boost (0-100 → -6dB to +12dB) ──
  const prevPunchRef = useRef(punch);
  useEffect(() => {
    if (prevPunchRef.current === punch) return;
    prevPunchRef.current = punch;
    // Punch = low-end presence: boost low shelf, slight mid cut for clarity
    const lowGain = -6 + (punch / 100) * 18;     // -6 to +12 dB
    const midGain = -(punch / 100) * 3;           // 0 to -3 dB (scoop)
    setDeckEQ('B', lowGain, midGain, 0);
  }, [punch, setDeckEQ]);

  // ── Tune → Deck B playback rate (semitone-based pitch, -12 to +12) ──
  const prevTuneRef = useRef(tune);
  useEffect(() => {
    if (prevTuneRef.current === tune) return;
    prevTuneRef.current = tune;
    const rate = Math.pow(2, tune / 12);
    setDeckPlaybackRate('B', rate);
  }, [tune, setDeckPlaybackRate]);

  // ── Drive → Deck B distortion effect (slot 0) ──
  // Initialize effect slot on mount
  const driveInitRef = useRef(false);
  useEffect(() => {
    if (driveInitRef.current) return;
    driveInitRef.current = true;
    setDeckEffect('B', 0, 'distortion', { drive: 0.2, tone: 0.6 });
    setDeckEffectEnabled('B', 0, drive > 0);
  }, [setDeckEffect, setDeckEffectEnabled, drive]);

  const prevDriveRef = useRef(drive);
  useEffect(() => {
    if (prevDriveRef.current === drive) return;
    prevDriveRef.current = drive;
    // Map 0-100 knob → 0.0-4.0 drive amount
    const driveAmount = (drive / 100) * 4;
    setDeckEffect('B', 0, 'distortion', { drive: driveAmount, tone: 0.6 });
    setDeckEffectEnabled('B', 0, drive > 2);
  }, [drive, setDeckEffect, setDeckEffectEnabled]);

  // ── Portamento → Deck B pitch glide time (portamento) ──
  // Controls the portamento/glide time between notes on Deck B.
  // Maps 0-100 knob → 0ms to 500ms pitch ramp time via playback rate scheduling.
  const prevPortamentoRef = useRef(portamento);
  useEffect(() => {
    if (prevPortamentoRef.current === portamento) return;
    prevPortamentoRef.current = portamento;
    if (portamento > 5) {
      // Use Deck B effect slot 1 as a creative portamento-like pitch ramp.
      // We schedule a playback rate that ramps over the portamento time.
      const glideTimeMs = (portamento / 100) * 500;
      setDeckEffectParam('B', 1, 'delayMs', glideTimeMs);
      const feedback = (portamento / 100) * 0.25; // subtle feedback for tail
      setDeckEffect('B', 1, 'echo', { delayMs: glideTimeMs, feedback });
      setDeckEffectEnabled('B', 1, true);
    } else {
      setDeckEffectEnabled('B', 1, false);
    }
  }, [portamento, setDeckEffect, setDeckEffectEnabled, setDeckEffectParam]);

  // ── Parametric EQ: BiquadFilterNode wired onto Deck B ──
  //
  // Split into TWO effects to prevent audio glitches:
  //
  //  Effect A — create / destroy / wire:  runs only when eqEnabled, djEngine, or
  //    audioContext changes.  Owns the node lifecycle and the cleanup teardown.
  //
  //  Effect B — param updates: runs when eqFreq/eqGain/eqQ change.  Never
  //    disconnects the node — just calls setValueAtTime on the existing node.
  //    This avoids the "destroy & recreate on every slider move" glitch.

  // Effect A: node lifecycle
  useEffect(() => {
    if (!audioContext || !djEngine) return;
    const ctx = audioContext;
    const deckBOut = djEngine.deckB.output;
    const cfInputB = djEngine.crossfader.inputB;

    if (!eqEnabled) {
      // Disconnect and remove EQ node if it exists
      if (eqNodeRef.current) {
        try { deckBOut.disconnect(eqNodeRef.current); } catch (_e) { /* */ }
        try { eqNodeRef.current.disconnect(); } catch (_e) { /* */ }
        eqNodeRef.current = null;
      }
      return;
    }

    // Create and wire the node once — subsequent param changes go through
    // Effect B so the node is never torn down while EQ remains enabled.
    if (!eqNodeRef.current) {
      const node = ctx.createBiquadFilter();
      node.type = 'peaking';
      // Apply current param values immediately so the node is in sync even
      // before Effect B fires for the first time.
      node.frequency.setValueAtTime(eqFreq, ctx.currentTime);
      node.gain.setValueAtTime(eqGain, ctx.currentTime);
      node.Q.setValueAtTime(eqQ, ctx.currentTime);
      eqNodeRef.current = node;
      // Wire into signal path once — connecting an already-connected pair
      // creates a duplicate parallel path, so this must only happen here.
      deckBOut.connect(node);
      node.connect(cfInputB);
    }

    return () => {
      // Teardown only when eqEnabled goes false, djEngine changes, or unmount.
      if (eqNodeRef.current) {
        try { deckBOut.disconnect(eqNodeRef.current); } catch (_e) { /* */ }
        try { eqNodeRef.current.disconnect(); } catch (_e) { /* */ }
        eqNodeRef.current = null;
      }
    };
  // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [eqEnabled, djEngine, audioContext]); // intentionally excludes eqFreq/eqGain/eqQ

  // Effect B: param updates — never disconnects the node
  useEffect(() => {
    const node = eqNodeRef.current;
    if (!node || !audioContext) return;
    const now = audioContext.currentTime;
    node.frequency.setValueAtTime(eqFreq, now);
    node.gain.setValueAtTime(eqGain, now);
    node.Q.setValueAtTime(eqQ, now);
  }, [eqFreq, eqGain, eqQ, audioContext]);

  // ── Sidechain worklet wiring ──
  // When sidechain is enabled:
  //   deckB.output  ──► workletNode (input 0)
  //   kickBus       ──► workletNode (input 1)   [sidechain trigger]
  //   workletOut    ──► crossfader.inputB
  //
  // When sidechain is disabled: restore the direct connection
  //   deckB.output  ──► crossfader.inputB
  useEffect(() => {
    if (!djEngine || !engine || !audioContext) return;

    mountedRef.current = true;
    const ctx = audioContext;
    const deckBOut = djEngine.deckB.output;
    const cfInputB = djEngine.crossfader.inputB;

    if (!sidechain) {
      // ── Disable: tear down worklet, restore direct connection ──
      const workletNode = scWorkletRef.current;
      const workletOut  = scWorkletOutRef.current;

      if (workletNode) {
        try { deckBOut.disconnect(workletNode); }    catch (_e) { /* already disconnected */ }
        try {
          const kickBus = engine.getPadOutputNode(KICK_PAD_INDEX);
          if (kickBus) kickBus.disconnect(workletNode);
        } catch (_e) { /* already disconnected */ }
        try { workletNode.disconnect(); }            catch (_e) { /* already disconnected */ }
        scWorkletRef.current = null;
      }
      if (workletOut) {
        try { workletOut.disconnect(); } catch (_e) { /* already disconnected */ }
        scWorkletOutRef.current = null;
      }

      // Restore direct connection
      try { deckBOut.connect(cfInputB); } catch (_e) { /* may already be connected */ }
      return;
    }

    // ── Enable: load worklet module (idempotent), create node, wire it ──
    const setupWorklet = async () => {
      // Cancel any previous setup
      if (abortControllerRef.current) abortControllerRef.current.abort();
      abortControllerRef.current = new AbortController();
      const signal = abortControllerRef.current.signal;

      try {
        // Ensure the AudioContext is running before adding the module
        if (ctx.state === 'suspended') {
          await ctx.resume();
        }

        if (!scLoadedRef.current) {
          await ctx.audioWorklet.addModule(SIDECHAIN_WORKLET_URL);
          if (signal.aborted || !mountedRef.current) return;
          scLoadedRef.current = true;
        }

        // Check if still mounted and not aborted
        if (!mountedRef.current || signal.aborted) return;

        // Disconnect the existing direct path so we don't double-feed cfInputB
        try { deckBOut.disconnect(cfInputB); } catch (_e) { /* may already be disconnected */ }

        // Create the worklet node with 2 inputs (main + sidechain) and 1 output
        const workletNode = new AudioWorkletNode(ctx, 'sidechain-compressor-processor', {
          numberOfInputs: 2,
          numberOfOutputs: 1,
          outputChannelCount: [2],
          channelCount: 2,
          channelCountMode: 'explicit',
          channelInterpretation: 'speakers',
        });

        // Output GainNode (unity) so we have a stable node to disconnect later
        const workletOut = ctx.createGain();
        workletOut.gain.value = 1;

        // Wire: deckB → worklet input 0
        deckBOut.connect(workletNode, 0, 0);

        // Wire: kickBus → worklet input 1 (sidechain trigger)
        const kickBus = engine.getPadOutputNode(KICK_PAD_INDEX);
        if (kickBus) {
          kickBus.connect(workletNode, 0, 1);
        }

        // Wire: worklet output → gain → crossfader inputB
        workletNode.connect(workletOut);
        workletOut.connect(cfInputB);

        // Only update refs if not aborted and still mounted
        if (!signal.aborted && mountedRef.current) {
          scWorkletRef.current = workletNode;
          scWorkletOutRef.current = workletOut;
        } else {
          // Clean up nodes we just created
          workletNode.disconnect();
          workletOut.disconnect();
        }
      } catch (err) {
        if (signal.aborted) return; // Ignore abort errors
        // If worklet loading fails (e.g. browser restriction), fall back to
        // the direct connection so audio is never broken.
        console.error('[Mixer808] Sidechain worklet error:', err);
        try { deckBOut.connect(cfInputB); } catch (_e) { /* ignore */ }
      }
    };

    setupWorklet();

    // Cleanup: when the component unmounts or the deps change before the next
    // effect run, tear down the worklet if it was created.
    return () => {
      mountedRef.current = false;
      if (abortControllerRef.current) abortControllerRef.current.abort();

      const workletNode = scWorkletRef.current;
      const workletOut  = scWorkletOutRef.current;
      if (workletNode) {
        try { deckBOut.disconnect(workletNode); }  catch (_e) { /* ignore */ }
        try {
          const kickBus = engine.getPadOutputNode(KICK_PAD_INDEX);
          if (kickBus) kickBus.disconnect(workletNode);
        } catch (_e) { /* ignore */ }
        try { workletNode.disconnect(); } catch (_e) { /* ignore */ }
        scWorkletRef.current = null;
      }
      if (workletOut) {
        try { workletOut.disconnect(); } catch (_e) { /* ignore */ }
        scWorkletOutRef.current = null;
      }
      // Restore direct connection so audio keeps working during hot-reload
      try { deckBOut.connect(cfInputB); } catch (_e) { /* ignore */ }
    };

  }, [sidechain, djEngine, engine, audioContext]);

  const handleSidechainToggle = useCallback(() => {
    setSidechain(prev => !prev);
  }, []);

  return (
    <div className="h-full flex flex-col vignette">
      <div className="flex justify-between items-center mb-4">
        <h2 className="text-sm font-black text-neutral-400 uppercase tracking-widest">808 Engine</h2>
        <div className="flex items-center gap-2 px-2 py-0.5 rounded-md bg-bg-main/50 border border-border-main">
          <div className={`w-1.5 h-1.5 rounded-full ${sidechain ? 'bg-emerald-500 shadow-[0_0_6px_rgba(16,185,129,0.6)] animate-pulse dot-glow' : 'bg-neutral-700'}`}></div>
          <span className="text-xs font-bold font-mono text-neutral-500 uppercase">SC Link</span>
        </div>
      </div>

      <div className="flex-1 grid grid-cols-4 gap-2 place-items-center">
        <Knob label="Punch" value={punch} onChange={setPunch} color="#4C83FF" />
        <Knob label="Tune" value={tune} onChange={setTune} min={-12} max={12} color="#4C83FF" />
        <Knob label="Drive" value={drive} onChange={setDrive} color="#FF4C4C" />
        <Knob label="Portamento" value={portamento} onChange={setPortamento} color="#4C83FF" />
      </div>

      <div className="mt-4 flex items-center justify-between bg-neutral-950 p-2 rounded border border-neutral-800 separator-glow">
        <div className="flex items-center gap-2">
          <Link2 className="w-3 h-3 text-neutral-600" />
          <span className="text-[13px] font-mono text-neutral-500 uppercase">Sidechain to Kick</span>
        </div>
        <button 
          onClick={handleSidechainToggle}
          className={`w-8 h-4 rounded-full relative transition-colors ${sidechain ? 'bg-blue-600' : 'bg-neutral-800'}`}
        >
          <div className={`w-3 h-3 bg-white rounded-full absolute top-0.5 transition-all ${sidechain ? 'left-4.5' : 'left-0.5'}`}></div>
        </button>
      </div>

      <div className="mt-2 flex flex-col gap-1.5 bg-neutral-950 p-2 rounded border border-neutral-800">
        <div className="flex items-center justify-between">
          <div className="flex items-center gap-2">
            <Cpu className="w-3 h-3 text-blue-500" />
            <span className="text-xs font-bold text-neutral-400 uppercase">Insert: Parametric EQ</span>
          </div>
          <button
            onClick={() => setEqEnabled(prev => !prev)}
            className="shrink-0"
            title={eqEnabled ? 'Disable EQ' : 'Enable EQ'}
          >
            <div className={`w-1.5 h-1.5 rounded-full transition-colors ${eqEnabled ? 'bg-emerald-500 shadow-[0_0_5px_rgba(16,185,129,0.5)] dot-glow' : 'bg-neutral-600'}`} />
          </button>
        </div>
        {eqEnabled && (
          <div className="flex gap-2 items-center mt-1">
            <div className="flex flex-col items-center flex-1">
              <span className="text-[7px] font-mono text-neutral-600 uppercase">Freq</span>
              <input type="range" min="80" max="12000" value={eqFreq}
                aria-label="EQ Frequency"
                onChange={(e) => setEqFreq(Number(e.target.value))}
                className="w-full h-1 appearance-none accent-blue-500 bg-neutral-800 rounded" />
              <span className="text-[7px] font-mono text-neutral-500">{eqFreq >= 1000 ? `${(eqFreq / 1000).toFixed(1)}k` : eqFreq}</span>
            </div>
            <div className="flex flex-col items-center flex-1">
              <span className="text-[7px] font-mono text-neutral-600 uppercase">Gain</span>
              <input type="range" min="-12" max="12" step="0.5" value={eqGain}
                aria-label="EQ Gain"
                onChange={(e) => setEqGain(Number(e.target.value))}
                className="w-full h-1 appearance-none accent-blue-500 bg-neutral-800 rounded" />
              <span className="text-[7px] font-mono text-neutral-500">{eqGain > 0 ? '+' : ''}{eqGain}dB</span>
            </div>
            <div className="flex flex-col items-center flex-1">
              <span className="text-[7px] font-mono text-neutral-600 uppercase">Q</span>
              <input type="range" min="0.1" max="18" step="0.1" value={eqQ}
                aria-label="EQ Q"
                onChange={(e) => setEqQ(Number(e.target.value))}
                className="w-full h-1 appearance-none accent-blue-500 bg-neutral-800 rounded" />
              <span className="text-[7px] font-mono text-neutral-500">{eqQ.toFixed(1)}</span>
            </div>
          </div>
        )}
      </div>
    </div>
  );
});

