source:
import React, { useState, useEffect, useCallback, useRef, useMemo } from 'react';
import {
  ZoomIn, ZoomOut, Plus,
  List, LayoutGrid, Music2, AlignLeft, Magnet
} from 'lucide-react';
import { SynthSettings } from '../lib/TBMAudioEngine';
import { useTBMAudio } from '../contexts/TBMAudioContext';
import { TransportControls } from './ui/TransportControls';
import { NOTE_NAMES as _NOTE_NAMES, BEATS_PER_BAR as _BEATS_PER_BAR, DEFAULT_BPM } from '../lib/constants';

// ─── Types ────────────────────────────────────────────────────────────────────
interface Note {
  id: string;
  pitch: number;   // 0 = C-2 … 127 = G8
  start: number;   // beat fraction (0.0 = bar 1 beat 1)
  duration: number;
  velocity: number;
}

interface Track {
  id: number;
  name: string;
  color: string;
  notes: Note[];
  muted: boolean;
  solo: boolean;
}

interface Sequence {
  id: number;
  name: string;
  color: string;
  bars: number;
  tracks: Track[];
}

// ─── Constants ────────────────────────────────────────────────────────────────
const NOTE_NAMES = [..._NOTE_NAMES];
const BLACK_KEYS = new Set([1, 3, 6, 8, 10]);
const TOTAL_PITCHES = 88; // piano range
const PITCH_OFFSET = 21; // A0 = MIDI 21
const ROW_H = 14; // px per pitch row
const BEAT_W = 48; // px per beat at zoom 1
const BEATS_PER_BAR = _BEATS_PER_BAR;

function pitchName(midi: number) {
  // Clamp to valid piano range before computing name to avoid negative modulo
  // in JS (e.g. -1 % 12 === -1), which would index NOTE_NAMES out-of-bounds.
  const clamped = Math.max(PITCH_OFFSET, midi);
  const n = clamped - PITCH_OFFSET;
  const octave = Math.floor(n / 12) + 1;
  return `${NOTE_NAMES[n % 12]}${octave}`;
}

function makeId() {
  return Math.random().toString(36).slice(2);
}

// ─── Sample data ──────────────────────────────────────────────────────────────
const TRACK_COLORS = ['#ef4444', '#3b82f6', '#f59e0b', '#10b981', '#8b5cf6', '#ec4899'];

function makeDefaultTracks(): Track[] {
  return [
    {
      id: 0, name: 'Kick 808', color: '#ef4444', muted: false, solo: false,
      notes: [
        { id: makeId(), pitch: 36, start: 0,   duration: 0.5, velocity: 100 },
        { id: makeId(), pitch: 36, start: 1,   duration: 0.5, velocity: 100 },
        { id: makeId(), pitch: 36, start: 2,   duration: 0.5, velocity: 100 },
        { id: makeId(), pitch: 36, start: 3,   duration: 0.5, velocity: 100 },
      ]
    },
    {
      id: 1, name: 'Snare', color: '#3b82f6', muted: false, solo: false,
      notes: [
        { id: makeId(), pitch: 38, start: 1,   duration: 0.5, velocity: 90 },
        { id: makeId(), pitch: 38, start: 3,   duration: 0.5, velocity: 90 },
      ]
    },
    {
      id: 2, name: 'Hi-Hat', color: '#f59e0b', muted: false, solo: false,
      notes: Array.from({ length: 8 }, (_, i) => ({
        id: makeId(), pitch: 42, start: i * 0.5, duration: 0.25, velocity: 70
      }))
    },
    {
      id: 3, name: 'Bass', color: '#10b981', muted: false, solo: false,
      notes: [
        { id: makeId(), pitch: 40, start: 0,   duration: 1, velocity: 95 },
        { id: makeId(), pitch: 43, start: 1,   duration: 1, velocity: 95 },
        { id: makeId(), pitch: 40, start: 2,   duration: 1, velocity: 95 },
        { id: makeId(), pitch: 45, start: 3,   duration: 1, velocity: 95 },
      ]
    },
  ];
}

function makeDefaultSequences(): Sequence[] {
  return [
    { id: 0, name: 'Intro',  color: '#8b5cf6', bars: 4,  tracks: makeDefaultTracks() },
    { id: 1, name: 'Verse',  color: '#3b82f6', bars: 8,  tracks: makeDefaultTracks() },
    { id: 2, name: 'Chorus', color: '#ef4444', bars: 8,  tracks: makeDefaultTracks() },
    { id: 3, name: 'Break',  color: '#f59e0b', bars: 4,  tracks: makeDefaultTracks() },
    { id: 4, name: 'Outro',  color: '#10b981', bars: 4,  tracks: makeDefaultTracks() },
  ];
}

// Song arrangement row – which sequence plays at which bar position
interface ArrangementCell {
  seqId: number | null;
}

function makeDefaultArrangement(sequences: Sequence[]): ArrangementCell[][] {
  // sequences.length rows (one per sequence) × 32 columns (bars)
  const rows: ArrangementCell[][] = sequences.map(() =>
    Array.from({ length: 32 }, () => ({ seqId: null }))
  );
  // pre-fill a simple arrangement
  const layout = [
    [0, 4],    // Intro: bar 0-3
    [4, 12],   // Verse: bar 4-11
    [12, 20],  // Chorus: bar 12-19
    [20, 24],  // Break: bar 20-23
    [24, 32],  // Outro: bar 24-31
  ];
  layout.forEach(([start, end], si) => {
    for (let b = start; b < end && b < 32; b++) {
      rows[si][b].seqId = sequences[si].id;
    }
  });
  return rows;
}

// ─── TrackListRow — memoized to avoid re-renders when other tracks update ─────
const TrackListRow = React.memo(function TrackListRow({
  track,
  isActive,
  onClick,
}: {
  track: Track;
  isActive: boolean;
  onClick: (id: number) => void;
}) {
  return (
    <div
      onClick={() => onClick(track.id)}
      className={`h-10 px-2 flex items-center gap-2 cursor-pointer border-b border-neutral-900 transition-colors ${
        isActive ? 'bg-brand/10 text-brand' : 'text-neutral-500 hover:bg-neutral-900 hover:text-neutral-300'
      }`}
    >
      <div className="w-2 h-2 rounded-full shrink-0" style={{ backgroundColor: track.color }} />
      <span className="text-[13px] font-bold uppercase truncate">{track.name}</span>
    </div>
  );
});

// ─── TrackView ────────────────────────────────────────────────────────────────
function TrackView({
  tracks,
  bars,
  zoom,
  isRecording,
  midiAccess,
  onNotesChange,
}: {
  tracks: Track[];
  bars: number;
  zoom: number;
  isRecording: boolean;
  midiAccess: MIDIAccess | null;
  onNotesChange?: (trackIndex: number, notes: Note[]) => void;
}) {
  const [activeTrack, setActiveTrack] = useState(0);
  const [tool, setTool] = useState<'pencil' | 'select'>('pencil');
  const [localTracks, setLocalTracks] = useState<Track[]>(tracks);
  const [quantizeValue, setQuantizeValue] = useState<number>(4); // 1/4 note grid
  const [selectedNotes, setSelectedNotes] = useState<Set<string>>(new Set());

  // Resize state
  const [resizing, setResizing] = useState<{ noteId: string; startX: number; origDuration: number } | null>(null);
  // Velocity drag state (Ctrl+drag vertically)
  const [velDrag, setVelDrag] = useState<{ noteId: string; startY: number; origVelocity: number } | null>(null);

  const { bpm: contextBpm } = useTBMAudio();

  // Virtualization state
  const scrollContainerRef = useRef<HTMLDivElement>(null);
  const [scrollTop, setScrollTop] = useState(0);
  const [viewportHeight, setViewportHeight] = useState(400);
  const OVERSCAN = 8; // extra rows above/below viewport

  // Sync local editable tracks when the active sequence changes
  useEffect(() => {
    // eslint-disable-next-line react-hooks/set-state-in-effect
    setLocalTracks(tracks);
    setActiveTrack(tracks[0]?.id ?? 0);
  }, [tracks]);

  // Notify parent of note changes (for synth.setSequence persistence)
  useEffect(() => {
    if (!onNotesChange) return;
    const activeIdx = localTracks.findIndex(t => t.id === activeTrack);
    if (activeIdx >= 0) {
      onNotesChange(activeIdx, localTracks[activeIdx].notes);
    }
  }, [localTracks, activeTrack, onNotesChange]);

  // ── MIDI recording ──
  const recordingRef = useRef(isRecording);
  const activeTrackRef = useRef(activeTrack);
  const contextBpmRef = useRef(contextBpm || DEFAULT_BPM);

  // Update refs in useEffect to avoid React render violations
  useEffect(() => {
    recordingRef.current = isRecording;
    activeTrackRef.current = activeTrack;
    contextBpmRef.current = contextBpm || DEFAULT_BPM;
  }, [isRecording, activeTrack, contextBpm]);
  const openNotesRef = useRef<Map<number, { startBeat: number; noteId: string }>>(new Map());
  const transportBeatRef = useRef(0);
  // Advance transport beat via rAF (approximate)
  const transportRafRef = useRef<number>(0);
  useEffect(() => {
    if (!isRecording) {
      cancelAnimationFrame(transportRafRef.current);
      openNotesRef.current.clear();
      return;
    }
    const startTime = performance.now();
    // Bug 3 fix: read from ref inside tick so BPM changes mid-record are respected
    const tick = () => {
      const elapsed = (performance.now() - startTime) / 1000;
      transportBeatRef.current = elapsed * (contextBpmRef.current / 60);
      transportRafRef.current = requestAnimationFrame(tick);
    };
    transportRafRef.current = requestAnimationFrame(tick);
    return () => cancelAnimationFrame(transportRafRef.current);
  }, [isRecording]);

  useEffect(() => {
    if (!isRecording || !midiAccess) return;

    const handleMidiMsg = (e: Event) => {
      if (!recordingRef.current) return;
      const msg = e as MIDIMessageEvent;
      const [status, pitch, velocity] = Array.from(msg.data ?? []);
      const isNoteOn  = (status & 0xF0) === 0x90 && velocity > 0;
      const isNoteOff = (status & 0xF0) === 0x80 || ((status & 0xF0) === 0x90 && velocity === 0);

      if (isNoteOn) {
        const noteId = makeId();
        openNotesRef.current.set(pitch, { startBeat: transportBeatRef.current, noteId });
        // Bug 1 fix: use prev (functional updater arg) instead of closed-over localTracks;
        // Bug 2 fix: use activeTrackRef so this handler never goes stale.
        setLocalTracks(prev => prev.map((t, i) =>
          i === prev.findIndex(lt => lt.id === activeTrackRef.current)
            ? { ...t, notes: [...t.notes, { id: noteId, pitch, start: transportBeatRef.current, duration: 0.25, velocity }] }
            : t
        ));
      } else if (isNoteOff) {
        const open = openNotesRef.current.get(pitch);
        if (open) {
          const duration = Math.max(0.0625, transportBeatRef.current - open.startBeat);
          openNotesRef.current.delete(pitch);
          setLocalTracks(prev => prev.map(t => ({
            ...t,
            notes: t.notes.map(n =>
              n.id === open.noteId ? { ...n, duration } : n
            ),
          })));
        }
      }
    };

    for (const input of (midiAccess as any).inputs.values()) {
      input.addEventListener('midimessage', handleMidiMsg);
    }
    return () => {
      for (const input of (midiAccess as any).inputs.values()) {
        input.removeEventListener('midimessage', handleMidiMsg);
      }
    };
  // Bug 2 fix: removed localTracks and activeTrack from deps — both are now
  // read via refs inside the handler, so the listener never needs to be
  // torn down and re-registered on each state update.
  }, [isRecording, midiAccess]);

  // Track scroll position for virtualization
  useEffect(() => {
    const el = scrollContainerRef.current;
    if (!el) return;
    const onScroll = () => setScrollTop(el.scrollTop);
    const onResize = () => setViewportHeight(el.clientHeight);
    el.addEventListener('scroll', onScroll, { passive: true });
    const ro = new ResizeObserver(onResize);
    ro.observe(el);
    onResize();
    return () => {
      el.removeEventListener('scroll', onScroll);
      ro.disconnect();
    };
  }, []);

  const beatWidth = BEAT_W * zoom;

  const handleGridClick = useCallback((e: React.MouseEvent<HTMLDivElement>, trackId: number) => {
    if (tool !== 'pencil') return;
    const rect = e.currentTarget.getBoundingClientRect();
    const x = e.clientX - rect.left;
    const y = e.clientY - rect.top;
    const beat = x / beatWidth;
    const pitchIdx = Math.floor(y / ROW_H);
    const midiPitch = PITCH_OFFSET + (TOTAL_PITCHES - 1 - pitchIdx);
    const snapped = Math.floor(beat * 4) / 4; // snap to 16th

    setLocalTracks(prev => prev.map(t =>
      t.id === trackId
        ? { ...t, notes: [...t.notes, { id: makeId(), pitch: midiPitch, start: snapped, duration: 0.25, velocity: 80 }] }
        : t
    ));
  }, [tool, beatWidth]);

  // ── Note deletion (right-click) ──
  const handleNoteContextMenu = useCallback((e: React.MouseEvent, noteId: string) => {
    e.preventDefault();
    e.stopPropagation();
    setLocalTracks(prev => prev.map(t =>
      t.id === activeTrack
        ? { ...t, notes: t.notes.filter(n => n.id !== noteId) }
        : t
    ));
    setSelectedNotes(prev => {
      const next = new Set(prev);
      next.delete(noteId);
      return next;
    });
  }, [activeTrack]);

  // ── Note resize (drag right edge) ──
  const handleResizeStart = useCallback((e: React.MouseEvent, noteId: string, origDuration: number) => {
    e.preventDefault();
    e.stopPropagation();
    setResizing({ noteId, startX: e.clientX, origDuration });
  }, []);

  // ── Velocity drag (Ctrl+drag vertically on a note) ──
  const handleVelDragStart = useCallback((e: React.MouseEvent, noteId: string, origVelocity: number) => {
    if (!e.ctrlKey) return;
    e.preventDefault();
    e.stopPropagation();
    setVelDrag({ noteId, startY: e.clientY, origVelocity });
  }, []);

  // Global mouse move/up for resize and velocity editing
  useEffect(() => {
    if (!resizing && !velDrag) return;
    const handleMouseMove = (e: MouseEvent) => {
      if (resizing) {
        const dx = e.clientX - resizing.startX;
        const deltaDuration = dx / beatWidth;
        const newDuration = Math.max(0.0625, resizing.origDuration + deltaDuration);
        // Snap duration to 1/16th
        const snappedDuration = Math.round(newDuration * 16) / 16;
        setLocalTracks(prev => prev.map(t =>
          t.id === activeTrack
            ? { ...t, notes: t.notes.map(n => n.id === resizing.noteId ? { ...n, duration: Math.max(0.0625, snappedDuration) } : n) }
            : t
        ));
      }
      if (velDrag) {
        const dy = velDrag.startY - e.clientY; // up = louder
        const newVel = Math.round(Math.min(127, Math.max(1, velDrag.origVelocity + dy)));
        setLocalTracks(prev => prev.map(t =>
          t.id === activeTrack
            ? { ...t, notes: t.notes.map(n => n.id === velDrag.noteId ? { ...n, velocity: newVel } : n) }
            : t
        ));
      }
    };
    const handleMouseUp = () => {
      setResizing(null);
      setVelDrag(null);
    };
    window.addEventListener('mousemove', handleMouseMove);
    window.addEventListener('mouseup', handleMouseUp);
    return () => {
      window.removeEventListener('mousemove', handleMouseMove);
      window.removeEventListener('mouseup', handleMouseUp);
    };
  }, [resizing, velDrag, beatWidth, activeTrack]);

  // ── Quantize notes ──
  const handleQuantize = useCallback(() => {
    const grid = 1 / quantizeValue; // e.g. quantizeValue=4 → grid=0.25 (quarter note)
    setLocalTracks(prev => prev.map(t =>
      t.id === activeTrack
        ? { ...t, notes: t.notes.map(n => ({ ...n, start: Math.round(n.start / grid) * grid })) }
        : t
    ));
  }, [activeTrack, quantizeValue]);

  const currentTrack = localTracks.find(t => t.id === activeTrack) ?? localTracks[0];
  const totalBars = bars;
  const totalBeats = totalBars * BEATS_PER_BAR;
  const gridWidth = totalBeats * beatWidth;
  const totalHeight = TOTAL_PITCHES * ROW_H;

  const handleTrackClick = useCallback((id: number) => setActiveTrack(id), []);

  // Compute visible row range
  const firstVisibleRow = Math.max(0, Math.floor(scrollTop / ROW_H) - OVERSCAN);
  const lastVisibleRow = Math.min(TOTAL_PITCHES - 1, Math.ceil((scrollTop + viewportHeight) / ROW_H) + OVERSCAN);

  // Memoize visible rows for piano keys and grid rows
  const visibleRows = useMemo(() => {
    const rows: { i: number; midiPitch: number; noteInOctave: number; isBlack: boolean; isC: boolean }[] = [];
    for (let i = firstVisibleRow; i <= lastVisibleRow; i++) {
      const midiPitch = PITCH_OFFSET + (TOTAL_PITCHES - 1 - i);
      const noteInOctave = (midiPitch - PITCH_OFFSET) % 12;
      rows.push({
        i,
        midiPitch,
        noteInOctave,
        isBlack: BLACK_KEYS.has(noteInOctave),
        isC: noteInOctave === 0,
      });
    }
    return rows;
  }, [firstVisibleRow, lastVisibleRow]);

  return (
    <div className="flex-1 flex flex-col min-h-0">
      {/* Toolbar */}
      <div className="flex items-center gap-3 px-4 py-2 border-b border-neutral-800 shrink-0">
        <div className="flex items-center gap-1 bg-neutral-950 rounded-md p-0.5">
          {(['pencil', 'select'] as const).map(t => (
            <button
              key={t}
              onClick={() => setTool(t)}
              className={`px-2.5 py-1 rounded text-[13px] font-bold uppercase transition-all ${tool === t ? 'bg-brand text-white' : 'text-neutral-500 hover:text-neutral-300'}`}
            >
              {t}
            </button>
          ))}
        </div>

        {/* Quantize controls */}
        <div className="flex items-center gap-1 bg-neutral-950 rounded-md p-0.5 border border-neutral-800">
          <Magnet size={11} className="text-neutral-500 ml-1" />
          <select
            value={quantizeValue}
            onChange={e => setQuantizeValue(Number(e.target.value))}
            className="bg-transparent text-[13px] font-bold text-neutral-400 outline-none cursor-pointer uppercase px-1 py-0.5"
          >
            <option value={1}>1/1</option>
            <option value={2}>1/2</option>
            <option value={4}>1/4</option>
            <option value={8}>1/8</option>
            <option value={16}>1/16</option>
            <option value={32}>1/32</option>
          </select>
          <button
            onClick={handleQuantize}
            className="px-2 py-0.5 rounded text-[13px] font-bold uppercase text-neutral-500 hover:text-white hover:bg-brand transition-all"
          >
            Quantize
          </button>
        </div>

        <span className="text-[13px] font-mono text-neutral-600 uppercase tracking-widest">
          {totalBars} bars · {currentTrack.notes.length} notes
        </span>
        <span className="text-xs font-mono text-neutral-700 ml-auto uppercase">
          Right-click note to delete · Drag edge to resize · Ctrl+drag to set velocity
        </span>
      </div>

      <div className="flex-1 flex min-h-0 overflow-hidden">
        {/* Track list */}
        <div className="w-36 shrink-0 border-r border-neutral-800 overflow-y-auto custom-scrollbar bg-neutral-950">
          {localTracks.map(t => (
            <TrackListRow
              key={t.id}
              track={t}
              isActive={activeTrack === t.id}
              onClick={handleTrackClick}
            />
          ))}
          <button
            onClick={() => {
              const newId = (localTracks.length > 0 ? Math.max(...localTracks.map(t => t.id)) : -1) + 1;
              const color = TRACK_COLORS[newId % TRACK_COLORS.length];
              setLocalTracks(prev => [...prev, { id: newId, name: `Track ${newId + 1}`, color, notes: [], muted: false, solo: false }]);
              setActiveTrack(newId);
            }}
            className="w-full h-8 flex items-center justify-center gap-1 text-neutral-700 hover:text-neutral-400 text-[13px] hover:bg-neutral-900 transition-colors"
          >
            <Plus size={11} /> Track
          </button>
        </div>

        {/* Piano keys + note grid — virtualized */}
        <div className="flex-1 flex overflow-auto custom-scrollbar" ref={scrollContainerRef}>
          {/* Piano keys */}
          <div
            className="shrink-0 w-10 bg-neutral-950 border-r border-neutral-800 relative"
            style={{ height: totalHeight }}
          >
            {visibleRows.map(({ i, midiPitch, isBlack, isC }) => (
              <div
                key={i}
                className={`absolute w-full border-b border-neutral-900 flex items-center justify-end pr-1 ${
                  isBlack ? 'bg-neutral-800' : 'bg-neutral-200/5'
                }`}
                style={{ top: i * ROW_H, height: ROW_H }}
              >
                {isC && (
                  <span className="text-[7px] font-bold text-neutral-600">{pitchName(midiPitch)}</span>
                )}
              </div>
            ))}
          </div>

          {/* Note grid */}
          <div
            className="relative bg-neutral-950 cursor-crosshair"
            style={{ width: gridWidth, height: totalHeight, minWidth: gridWidth }}
            onClick={(e) => handleGridClick(e, activeTrack)}
          >
            {/* Horizontal pitch rows — only visible ones */}
            {visibleRows.map(({ i, isBlack }) => (
              <div
                key={i}
                className={`absolute w-full border-b ${isBlack ? 'bg-neutral-900/50' : ''} border-neutral-900`}
                style={{ top: i * ROW_H, height: ROW_H }}
              />
            ))}

            {/* Vertical beat lines */}
            {Array.from({ length: totalBeats + 1 }).map((_, b) => (
              <div
                key={b}
                className={`absolute top-0 bottom-0 border-l ${b % BEATS_PER_BAR === 0 ? 'border-neutral-600' : 'border-neutral-800'}`}
                style={{ left: b * beatWidth }}
              />
            ))}

            {/* Notes for current track */}
            {currentTrack.notes.map(note => {
              const pitchIdx = PITCH_OFFSET + (TOTAL_PITCHES - 1) - note.pitch;
              const noteWidth = Math.max(note.duration * beatWidth - 2, 4);
              // Velocity → opacity: 1–127 maps to 0.3–1.0
              const velOpacity = 0.3 + (note.velocity / 127) * 0.7;
              const isSelected = selectedNotes.has(note.id);
              return (
                <div
                  key={note.id}
                  className="absolute rounded-sm border-l-2 flex items-center group"
                  style={{
                    left: note.start * beatWidth,
                    top: pitchIdx * ROW_H + 1,
                    width: noteWidth,
                    height: ROW_H - 2,
                    backgroundColor: currentTrack.color + '55',
                    borderColor: currentTrack.color,
                    opacity: velOpacity,
                    outline: isSelected ? `1px solid ${currentTrack.color}` : undefined,
                    cursor: resizing ? 'ew-resize' : velDrag ? 'ns-resize' : 'default',
                    zIndex: isSelected ? 10 : 1,
                  }}
                  onContextMenu={e => handleNoteContextMenu(e, note.id)}
                  onMouseDown={e => {
                    // Ctrl+click → velocity drag
                    if (e.ctrlKey) {
                      handleVelDragStart(e, note.id, note.velocity);
                      return;
                    }
                    // Normal click in select mode → toggle selection
                    if (tool === 'select') {
                      e.stopPropagation();
                      setSelectedNotes(prev => {
                        const next = new Set(prev);
                        if (next.has(note.id)) next.delete(note.id);
                        else next.add(note.id);
                        return next;
                      });
                    }
                  }}
                  onClick={e => e.stopPropagation()}
                >
                  <span className="text-[7px] font-bold truncate px-1 pointer-events-none select-none" style={{ color: currentTrack.color }}>
                    {pitchName(note.pitch)}
                  </span>
                  {/* Velocity indicator bar (bottom edge) */}
                  <div
                    className="absolute bottom-0 left-0 h-0.5 pointer-events-none"
                    style={{
                      width: `${(note.velocity / 127) * 100}%`,
                      backgroundColor: currentTrack.color,
                      opacity: 0.9,
                    }}
                  />
                  {/* Resize handle (right edge) */}
                  <div
                    className="absolute top-0 right-0 w-1.25 h-full cursor-ew-resize opacity-0 group-hover:opacity-100 transition-opacity"
                    style={{ backgroundColor: currentTrack.color + '88' }}
                    onMouseDown={e => handleResizeStart(e, note.id, note.duration)}
                  />
                </div>
              );
            })}
          </div>
        </div>
      </div>
    </div>
  );
}

// ─── SongMode ─────────────────────────────────────────────────────────────────
function SongMode({ sequences }: { sequences: Sequence[] }) {
  const [arrangement, setArrangement] = useState<ArrangementCell[][]>(() =>
    makeDefaultArrangement(sequences)
  );
  const [hoveredSeqId, setHoveredSeqId] = useState<number | null>(null);
  const [selectedSeqId, setSelectedSeqId] = useState<number>(sequences[0]?.id ?? 0);
  const COLS = 32;
  const CELL_W = 36;

  const toggleCell = (rowIdx: number, colIdx: number) => {
    setArrangement(prev => {
      const next = prev.map(row => [...row]);
      next[rowIdx][colIdx] = {
        seqId: next[rowIdx][colIdx].seqId !== null ? null : selectedSeqId,
      };
      return next;
    });
  };

  const selectedSeq = sequences.find(s => s.id === selectedSeqId);

  return (
    <div className="flex-1 flex flex-col min-h-0">
      {/* Toolbar */}
      <div className="flex items-center gap-4 px-4 py-2 border-b border-neutral-800 shrink-0 flex-wrap">
        <span className="text-[13px] font-bold uppercase tracking-widest text-neutral-500">Paint Sequence:</span>
        <div className="flex items-center gap-1.5 flex-wrap">
          {sequences.map(seq => (
            <button
              key={seq.id}
              onClick={() => setSelectedSeqId(seq.id)}
              className={`px-2.5 py-1 rounded text-[13px] font-bold uppercase transition-all border ${
                selectedSeqId === seq.id
                  ? 'text-white border-transparent'
                  : 'bg-neutral-900 text-neutral-500 border-neutral-800 hover:text-neutral-300'
              }`}
              style={selectedSeqId === seq.id ? { backgroundColor: seq.color + 'cc', borderColor: seq.color } : {}}
            >
              {seq.name}
            </button>
          ))}
        </div>
        <span className="ml-auto text-[13px] font-mono text-neutral-600 uppercase">
          {selectedSeq ? `${selectedSeq.bars} bars` : ''}
        </span>
      </div>

      <div className="flex-1 flex overflow-hidden">
        {/* Sequence labels */}
        <div className="w-28 shrink-0 border-r border-neutral-800 bg-neutral-950 overflow-y-auto custom-scrollbar">
          <div className="h-6 border-b border-neutral-800" /> {/* ruler spacer */}
          {sequences.map((seq) => (
            <div
              key={seq.id}
              className="h-10 px-3 flex items-center gap-2 border-b border-neutral-900"
            >
              <div className="w-2 h-2 rounded-sm shrink-0" style={{ backgroundColor: seq.color }} />
              <span className="text-[13px] font-bold uppercase text-neutral-400 truncate">{seq.name}</span>
            </div>
          ))}
        </div>

        {/* Grid */}
        <div className="flex-1 overflow-auto custom-scrollbar">
          {/* Bar ruler */}
          <div className="flex border-b border-neutral-800 sticky top-0 bg-neutral-950 z-10" style={{ width: COLS * CELL_W }}>
            {Array.from({ length: COLS }).map((_, b) => (
              <div
                key={b}
                className={`shrink-0 h-6 border-r border-neutral-800 flex items-center justify-center ${b % 4 === 0 ? 'text-neutral-400' : 'text-neutral-700'}`}
                style={{ width: CELL_W, fontSize: 8, fontWeight: 'bold', fontFamily: 'monospace' }}
              >
                {b % 4 === 0 ? b + 1 : ''}
              </div>
            ))}
          </div>

          {/* Arrangement rows */}
          {sequences.map((seq, rowIdx) => (
            <div key={seq.id} className="flex border-b border-neutral-900" style={{ height: 40 }}>
              {arrangement[rowIdx]?.map((cell, colIdx) => {
                const filled = cell.seqId !== null;
                const cellSeq = filled ? sequences.find(s => s.id === cell.seqId) : null;
                const isHovered = cell.seqId === hoveredSeqId && cell.seqId !== null;
                return (
                  <div
                    key={colIdx}
                    className={`shrink-0 border-r border-neutral-900 cursor-pointer transition-colors ${
                      filled ? '' : 'hover:bg-neutral-800/40'
                    }`}
                    style={{
                      width: CELL_W,
                      backgroundColor: filled
                        ? (cellSeq?.color ?? seq.color) + (isHovered ? 'cc' : '77')
                        : undefined,
                    }}
                    onClick={() => toggleCell(rowIdx, colIdx)}
                    onMouseEnter={() => cell.seqId !== null && setHoveredSeqId(cell.seqId)}
                    onMouseLeave={() => setHoveredSeqId(null)}
                  />
                );
              })}
            </div>
          ))}
        </div>
      </div>
    </div>
  );
}

// ─── Main Component ───────────────────────────────────────────────────────────

const DEFAULT_SYNTH_SETTINGS: SynthSettings = {
  type: 'sine',
  frequency: 440,
  attack: 0.01,
  decay: 0.1,
  sustain: 0.7,
  release: 0.3,
  filterFreq: 8000,
  filterQ: 1,
  distortion: 0,
};

export function PianoRoll() {
  const [mode, setMode] = useState<'track' | 'song'>('track');
  const [isPlaying, setIsPlaying] = useState(false);
  const [isRecording, setIsRecording] = useState(false);
  const [zoom, setZoom] = useState(1);
  const [sequences, setSequences] = useState<Sequence[]>(makeDefaultSequences);
  const [activeSequenceId, setActiveSequenceId] = useState(0);

  const { synth, midiAccess, bpm, setBpm } = useTBMAudio();
  const playTimeoutsRef = useRef<number[]>([]);
  const activeVoiceIdsRef = useRef<number[]>([]);
  // Flag cleared by handleStop so any note-off timeout that fires after stop
  // doesn't call noteOff on a voice that has already been killed (Bug 6 fix).
  const playbackActiveRef = useRef(false);
  // Always-current ref to synth so the unmount cleanup never closes over a
  // stale value (avoids re-registering the cleanup effect on every synth change).
  const synthRef = useRef(synth);

  // Update synth ref in useEffect
  useEffect(() => {
    synthRef.current = synth;
  }, [synth]);
  // Ref to handleStop so that the auto-stop timeout (scheduled inside handlePlay
  // before handleStop is defined) can call the full stop routine instead of only
  // setting isPlaying to false and leaving playbackActiveRef / activeVoiceIdsRef stale.
  const handleStopRef = useRef<() => void>(() => {});

  const activeSequence = sequences.find(s => s.id === activeSequenceId) ?? sequences[0];

  // Save piano roll state to localStorage
  const savePianoRollState = useCallback(() => {
    try {
      const state = {
        sequences,
        activeSequenceId,
        mode,
        version: '1.0.0',
        timestamp: new Date().toISOString(),
      };
      localStorage.setItem('tbm_piano_roll_state', JSON.stringify(state));
    } catch (error) {
      console.error('Failed to save piano roll state:', error);
    }
  }, [sequences, activeSequenceId, mode]);

  // Load piano roll state from localStorage on mount
  useEffect(() => {
    try {
      // eslint-disable-next-line react-hooks/set-state-in-effect
      const saved = localStorage.getItem('tbm_piano_roll_state');
      if (saved) {
        const state = JSON.parse(saved);
         if (state.sequences && Array.isArray(state.sequences)) {
           queueMicrotask(() => setSequences(state.sequences));
         }
         if (state.activeSequenceId !== undefined) {
           queueMicrotask(() => setActiveSequenceId(state.activeSequenceId));
         }
         if (state.mode === 'track' || state.mode === 'song') {
           queueMicrotask(() => setMode(state.mode));
         }
      }
    } catch (error) {
      console.error('Failed to load piano roll state:', error);
    }
  }, []);

  // Save state when it changes
  useEffect(() => {
    savePianoRollState();
  }, [savePianoRollState]);

  // Cleanup play timeouts on unmount to prevent memory leaks and setState on unmounted component
  // Bug 4 fix: dep was [synth], causing this effect to tear down and kill all active voices
  // whenever synth changed mid-session. Changed to [] (unmount only); synth accessed via ref.
  useEffect(() => {
    return () => {
      playTimeoutsRef.current.forEach(id => clearTimeout(id));
      playTimeoutsRef.current = [];
      activeVoiceIdsRef.current.forEach(voiceId => {
        try {
          synthRef.current?.noteOff(voiceId, DEFAULT_SYNTH_SETTINGS);
        } catch { /* synth may have been destroyed */ }
      });
      activeVoiceIdsRef.current = [];
    };
  }, []);

  const handlePlay = useCallback(() => {
    if (!synth) return;

    // Resume AudioContext on first user gesture
    const ctx = synth.getContext();
    if (ctx && ctx.state === 'suspended') ctx.resume();

    const beatMs = (60 / bpm) * 1000;

    // Collect notes from all non-muted tracks
    const activeTracks = activeSequence.tracks.filter(t => !t.muted);
    // Track active voice IDs so handleStop can kill them
    activeVoiceIdsRef.current = [];
    playbackActiveRef.current = true;

    activeTracks.forEach(track => {
      track.notes.forEach(note => {
        const startMs = note.start * beatMs;
        const durMs = note.duration * beatMs;

        const onId = window.setTimeout(() => {
          if (!playbackActiveRef.current) return;
          const voiceId = synth.noteOn(note.pitch, DEFAULT_SYNTH_SETTINGS, note.velocity / 127);
          activeVoiceIdsRef.current.push(voiceId);
          const offId = window.setTimeout(() => {
            // Bug 6 fix: guard against handleStop having fired before offId was
            // pushed into playTimeoutsRef (the note-on/push race window).
            if (!playbackActiveRef.current) return;
            synth.noteOff(voiceId, DEFAULT_SYNTH_SETTINGS);
            // Remove from active list
            activeVoiceIdsRef.current = activeVoiceIdsRef.current.filter(id => id !== voiceId);
          }, durMs);
          playTimeoutsRef.current.push(offId);
        }, startMs);

        playTimeoutsRef.current.push(onId);
      });
    });

    setIsPlaying(true);

    // Auto-stop after the sequence length
    const totalBeats = activeSequence.bars * BEATS_PER_BAR;
    const totalMs = totalBeats * beatMs;
    const stopId = window.setTimeout(() => {
      handleStopRef.current();
    }, totalMs + 500);
    playTimeoutsRef.current.push(stopId);
  }, [bpm, activeSequence, synth]);

  const handleStop = useCallback(() => {
    playbackActiveRef.current = false;
    playTimeoutsRef.current.forEach(id => clearTimeout(id));
    playTimeoutsRef.current = [];
    // Kill all currently sounding voices to prevent phantom oscillators
    if (synth) {
      activeVoiceIdsRef.current.forEach(voiceId => {
        synth.noteOff(voiceId, DEFAULT_SYNTH_SETTINGS);
      });
    }
    activeVoiceIdsRef.current = [];
    setIsPlaying(false);
    setIsRecording(false);
  }, [synth]);

  // Keep handleStopRef in sync so auto-stop timeout always calls the latest version.
  useEffect(() => {
    handleStopRef.current = handleStop;
  }, [handleStop]);

  const handleNotesChange = useCallback((trackIndex: number, notes: Note[]) => {
    // Forward notes to synth if available (setSequence API)
    if (synth && typeof (synth as any).setSequence === 'function') {
      (synth as any).setSequence(trackIndex, notes);
    }
  }, [synth]);

  return (
    <div className="h-full flex flex-col gap-0 bg-neutral-900 rounded-xl border border-neutral-800 overflow-hidden vignette">
      {/* ── Header ── */}
      <div className="flex items-center gap-4 px-4 py-2.5 border-b border-neutral-800 shrink-0 bg-neutral-950/60 relative edge-glow-bottom">
        <div className="flex items-center gap-1.5">
          <Music2 size={14} className="text-brand" />
          <span className="text-xs font-bold uppercase tracking-widest text-neutral-300">Piano Roll</span>
        </div>

        {/* Mode toggle */}
        <div className="flex items-center gap-0.5 bg-neutral-950 rounded-lg p-0.5 border border-neutral-800">
          <button
            onClick={() => setMode('track')}
            className={`flex items-center gap-1.5 px-3 py-1 rounded-md text-[13px] font-bold uppercase tracking-wide transition-all ${
              mode === 'track' ? 'bg-brand text-white shadow-sm shadow-brand/30' : 'text-neutral-500 hover:text-neutral-300'
            }`}
          >
            <List size={11} /> Track View
          </button>
          <button
            onClick={() => setMode('song')}
            className={`flex items-center gap-1.5 px-3 py-1 rounded-md text-[13px] font-bold uppercase tracking-wide transition-all ${
              mode === 'song' ? 'bg-brand text-white shadow-sm shadow-brand/30' : 'text-neutral-500 hover:text-neutral-300'
            }`}
          >
            <LayoutGrid size={11} /> Song Mode
          </button>
        </div>

        {/* Transport */}
        <TransportControls
          isPlaying={isPlaying}
          isRecording={isRecording}
          onPlay={handlePlay}
          onStop={handleStop}
          onRecord={() => setIsRecording(!isRecording)}
          size={14}
        />

        {/* BPM */}
        <div className="flex items-center gap-1 bg-neutral-950 px-2 py-1 rounded border border-neutral-800">
          <span className="text-xs font-mono text-neutral-600 uppercase">BPM</span>
          <input
            type="number"
            value={bpm}
            onChange={e => setBpm(parseInt(e.target.value) || bpm)}
            className="w-10 bg-transparent text-red-400 font-bold text-xs outline-none"
          />
        </div>

        {/* Zoom */}
        <div className="flex items-center gap-1 ml-auto">
          <button onClick={() => setZoom(z => Math.max(0.5, z - 0.25))} className="p-1 rounded bg-neutral-800 text-neutral-500 hover:text-white transition-colors">
            <ZoomOut size={12} />
          </button>
          <span className="text-xs font-mono text-neutral-600 w-8 text-center">{Math.round(zoom * 100)}%</span>
          <button onClick={() => setZoom(z => Math.min(3, z + 0.25))} className="p-1 rounded bg-neutral-800 text-neutral-500 hover:text-white transition-colors">
            <ZoomIn size={12} />
          </button>
        </div>
      </div>

      {/* Track mode: sequence selector strip */}
      {mode === 'track' && (
        <div className="flex items-center gap-1.5 px-4 py-1.5 border-b border-neutral-800 bg-neutral-950/40 shrink-0 overflow-x-auto custom-scrollbar">
          <AlignLeft size={11} className="text-neutral-600 shrink-0" />
          {sequences.map(seq => (
            <button
              key={seq.id}
              onClick={() => setActiveSequenceId(seq.id)}
              className={`shrink-0 px-2.5 py-0.5 rounded text-xs font-bold uppercase transition-all border ${
                activeSequenceId === seq.id
                  ? 'text-white border-transparent'
                  : 'bg-neutral-900 text-neutral-600 border-neutral-800 hover:text-neutral-400'
              }`}
              style={activeSequenceId === seq.id ? { backgroundColor: seq.color + 'cc', borderColor: seq.color } : {}}
            >
              {seq.name}
            </button>
          ))}
          <button
            onClick={() => {
              const colors = ['#8b5cf6', '#3b82f6', '#ef4444', '#f59e0b', '#10b981', '#ec4899'];
              const newId = sequences.length > 0 ? Math.max(...sequences.map(s => s.id)) + 1 : 0;
              const newSeq: Sequence = {
                id: newId,
                name: `Seq ${newId + 1}`,
                color: colors[newId % colors.length],
                bars: 4,
                tracks: makeDefaultTracks(),
              };
              setSequences(prev => [...prev, newSeq]);
              setActiveSequenceId(newId);
            }}
            className="shrink-0 flex items-center gap-1 px-2 py-0.5 rounded text-xs font-bold text-neutral-700 hover:text-neutral-400 hover:bg-neutral-900 transition-colors"
          >
            <Plus size={10} /> Seq
          </button>
        </div>
      )}

      {/* Content */}
      <div className="flex-1 flex flex-col min-h-0 overflow-hidden">
        {mode === 'track' ? (
          <TrackView
            tracks={activeSequence.tracks}
            bars={activeSequence.bars}
            zoom={zoom}
            isRecording={isRecording}
            midiAccess={midiAccess ?? null}
            onNotesChange={handleNotesChange}
          />
        ) : (
          <SongMode sequences={sequences} />
        )}
      </div>
    </div>
  );
}

import React, { useState, useEffect, useRef } from 'react';
import { 
  getBackups, 
  restoreBackup, 
  clearState, 
  getStorageInfo,
  TBMProjectState 
} from '../lib/statePersistence';
import { logger } from '../lib/logger';
import { 
  RotateCcw, 
  Trash2, 
  Download, 
  Calendar, 
  Database, 
  CheckCircle, 
  AlertCircle,
  HardDrive,
  RefreshCw
} from 'lucide-react';

interface RecoveryManagerProps {
  onRecoveryComplete?: () => void;
  onError?: (error: string) => void;
}

export function RecoveryManager({ onRecoveryComplete, onError }: RecoveryManagerProps) {
  const [backups, setBackups] = useState<Array<{timestamp: string; state: TBMProjectState}>>([]);
  const [storageInfo, setStorageInfo] = useState<ReturnType<typeof getStorageInfo>>({
    totalSize: 0,
    itemCount: 0,
    backupsCount: 0
  });
  const [isLoading, setIsLoading] = useState(false);
  const [selectedBackup, setSelectedBackup] = useState<string | null>(null);
  const reloadTimerRef = useRef<ReturnType<typeof setTimeout> | null>(null);

  // Load backups and storage info
  useEffect(() => {
    refreshData();
  }, []);

  // Cleanup timer on unmount
  useEffect(() => {
    return () => {
      if (reloadTimerRef.current) clearTimeout(reloadTimerRef.current);
    };
  }, []);

  const refreshData = () => {
    try {
      const backupList = getBackups();
      setBackups(backupList);

      const info = getStorageInfo();
      setStorageInfo(info);
    } catch (error) {
      logger.error('Failed to load recovery data', error as Error);
      onError?.('Failed to load recovery data');
    }
  };

  const handleRestoreBackup = async (timestamp: string) => {
    try {
      setIsLoading(true);
      const restored = restoreBackup(timestamp);

      if (restored) {
        logger.info('Backup restored', { timestamp });
        setSelectedBackup(timestamp);

        // Show success message
        if (onRecoveryComplete) {
          onRecoveryComplete();
        }

        // Refresh the page to apply restored state
        if (reloadTimerRef.current) clearTimeout(reloadTimerRef.current);
        reloadTimerRef.current = setTimeout(() => {
          window.location.reload();
        }, 1000);
      } else {
        throw new Error('Backup not found');
      }
    } catch (error) {
      logger.error('Failed to restore backup', error as Error, { timestamp });
      onError?.(`Failed to restore backup: ${error instanceof Error ? error.message : 'Unknown error'}`);
      if (reloadTimerRef.current) clearTimeout(reloadTimerRef.current);
    } finally {
      setIsLoading(false);
    }
  };

  const handleClearAllBackups = () => {
    if (window.confirm('Are you sure you want to delete all backups? This cannot be undone.')) {
      try {
        clearState();
        refreshData();
        logger.info('All backups cleared');
      } catch (error) {
        logger.error('Failed to clear backups', error as Error);
        onError?.('Failed to clear backups');
      }
    }
  };

  const formatBytes = (bytes: number): string => {
    if (bytes === 0) return '0 Bytes';
    const k = 1024;
    const sizes = ['Bytes', 'KB', 'MB', 'GB'];
    const i = Math.floor(Math.log(bytes) / Math.log(k));
    return parseFloat((bytes / Math.pow(k, i)).toFixed(2)) + ' ' + sizes[i];
  };

  const formatDate = (timestamp: string): string => {
    const date = new Date(timestamp);
    return date.toLocaleString();
  };

  const getTimeAgo = (timestamp: string): string => {
    const date = new Date(timestamp);
    const now = new Date();
    const diffMs = now.getTime() - date.getTime();
    const diffMins = Math.floor(diffMs / 60000);
    const diffHours = Math.floor(diffMs / 3600000);
    const diffDays = Math.floor(diffMs / 86400000);

    if (diffMins < 1) return 'Just now';
    if (diffMins < 60) return `${diffMins}m ago`;
    if (diffHours < 24) return `${diffHours}h ago`;
    return `${diffDays}d ago`;
  };

  return (
    <div className="p-6 bg-neutral-900 rounded-lg border border-neutral-800 vignette">
      <div className="flex items-center justify-between mb-6">
        <div className="flex items-center gap-3">
          <RotateCcw className="w-5 h-5 text-neutral-400" />
          <h2 className="text-lg font-semibold text-white">Recovery & Backups</h2>
        </div>
        <button
          onClick={refreshData}
          disabled={isLoading}
          className="flex items-center gap-2 px-3 py-1.5 text-sm bg-neutral-800 hover:bg-neutral-700 rounded-md transition-colors disabled:opacity-50"
        >
          <RefreshCw className={`w-4 h-4 ${isLoading ? 'animate-spin' : ''}`} />
          Refresh
        </button>
      </div>

      {/* Storage Info */}
      <div className="mb-6 p-4 bg-neutral-800 rounded-lg noise-texture relative">
        <div className="flex items-center gap-3 mb-3">
          <HardDrive className="w-5 h-5 text-neutral-400" />
          <h3 className="text-sm font-medium text-white">Storage Information</h3>
        </div>
        <div className="grid grid-cols-3 gap-4">
          <div className="text-center">
            <div className="text-2xl font-bold text-white">{storageInfo.backupsCount}</div>
            <div className="text-xs text-neutral-400">Backups</div>
          </div>
          <div className="text-center">
            <div className="text-2xl font-bold text-white">{storageInfo.itemCount}</div>
            <div className="text-xs text-neutral-400">Items</div>
          </div>
          <div className="text-center">
            <div className="text-2xl font-bold text-white">{formatBytes(storageInfo.totalSize)}</div>
            <div className="text-xs text-neutral-400">Used</div>
          </div>
        </div>
      </div>

      {/* Backups List */}
      <div className="mb-6">
        <div className="flex items-center justify-between mb-3">
          <div className="flex items-center gap-2">
            <Database className="w-4 h-4 text-neutral-400" />
            <h3 className="text-sm font-medium text-white">Available Backups</h3>
          </div>
          {backups.length > 0 && (
            <button
              onClick={handleClearAllBackups}
              className="flex items-center gap-1 px-2 py-1 text-xs text-red-400 hover:text-red-300 transition-colors"
            >
              <Trash2 className="w-3 h-3" />
              Clear All
            </button>
          )}
        </div>

        {backups.length === 0 ? (
          <div className="p-4 text-center border border-dashed border-neutral-700 rounded-lg">
            <AlertCircle className="w-8 h-8 text-neutral-600 mx-auto mb-2" />
            <p className="text-sm text-neutral-400">No backups available</p>
            <p className="text-xs text-neutral-500 mt-1">Auto-save backups will appear here</p>
          </div>
        ) : (
          <div className="space-y-2 max-h-64 overflow-y-auto">
            {backups.map((backup) => (
              <div
                key={backup.timestamp}
                className={`p-3 rounded-lg border transition-colors vignette ${
                  selectedBackup === backup.timestamp
                    ? 'bg-blue-900/20 border-blue-700'
                    : 'bg-neutral-800 border-neutral-700 hover:bg-neutral-750'
                }`}
              >
                <div className="flex items-center justify-between mb-2">
                  <div className="flex items-center gap-2">
                    <Calendar className="w-4 h-4 text-neutral-400" />
                    <span className="text-sm font-medium text-white">
                      {formatDate(backup.timestamp)}
                    </span>
                  </div>
                  <span className="text-xs text-neutral-500">
                    {getTimeAgo(backup.timestamp)}
                  </span>
                </div>

                <div className="text-xs text-neutral-400 mb-3">
                  Version: {backup.state.version} • {backup.state.pads.length} pads • BPM: {backup.state.bpm}
                </div>

                <div className="flex items-center justify-between">
                  <div className="flex items-center gap-1">
                    {selectedBackup === backup.timestamp ? (
                      <>
                        <CheckCircle className="w-3 h-3 text-green-400" />
                        <span className="text-xs text-green-400">Restored</span>
                      </>
                    ) : (
                      <span className="text-xs text-neutral-500">Click to restore</span>
                    )}
                  </div>
                  <button
                    onClick={() => handleRestoreBackup(backup.timestamp)}
                    disabled={isLoading || selectedBackup === backup.timestamp}
                    className="flex items-center gap-1 px-2 py-1 text-xs bg-neutral-700 hover:bg-neutral-600 rounded transition-colors disabled:opacity-50 disabled:cursor-not-allowed"
                  >
                    <RotateCcw className="w-3 h-3" />
                    Restore
                  </button>
                </div>
              </div>
            ))}
          </div>
        )}
      </div>

      {/* Recovery Instructions */}
      <div className="p-4 bg-neutral-800 rounded-lg noise-texture relative">
        <h3 className="text-sm font-medium text-white mb-2 flex items-center gap-2">
          <AlertCircle className="w-4 h-4 text-yellow-400" />
          Recovery Information
        </h3>
        <ul className="text-xs text-neutral-400 space-y-1">
          <li className="flex items-start gap-2">
            <div className="w-1 h-1 mt-1.5 rounded-full bg-neutral-600" />
            <span>Auto-save occurs every 30 seconds when changes are detected</span>
          </li>
          <li className="flex items-start gap-2">
            <div className="w-1 h-1 mt-1.5 rounded-full bg-neutral-600" />
            <span>Manual saves create additional backups (max 5 kept)</span>
          </li>
          <li className="flex items-start gap-2">
            <div className="w-1 h-1 mt-1.5 rounded-full bg-neutral-600" />
            <span>Restoring a backup will reload the application</span>
          </li>
          <li className="flex items-start gap-2">
            <div className="w-1 h-1 mt-1.5 rounded-full bg-neutral-600" />
            <span>Backups are stored locally in your browser</span>
          </li>
        </ul>
      </div>

      {/* Status */}
      {isLoading && (
        <div className="mt-4 p-3 bg-blue-900/20 border border-blue-700 rounded-lg">
          <div className="flex items-center gap-2">
            <RefreshCw className="w-4 h-4 animate-spin text-blue-400" />
            <span className="text-sm text-blue-300">Restoring backup...</span>
          </div>
        </div>
      )}

      {selectedBackup && (
        <div className="mt-4 p-3 bg-green-900/20 border border-green-700 rounded-lg">
          <div className="flex items-center gap-2">
            <CheckCircle className="w-4 h-4 text-green-400" />
            <span className="text-sm text-green-300">
              Backup restored! Page will reload shortly...
            </span>
          </div>
        </div>
      )}
    </div>
  );
}

import React, { useState, useEffect, useCallback, useRef } from 'react';
import {
  Brain, Play, Square, ChevronRight,
  Music, Mic2, Piano, Guitar, AudioLines, Drum,
  Sparkles, RefreshCw, Volume2, VolumeX, Sliders
} from 'lucide-react';
import { analyzeSession, type AnalysisResult } from '../lib/api';
import { useTBMAudio } from '../contexts/TBMAudioContext';
import { BandSynthesizer } from '../lib/bandSynthesis';

// ─── Option lists ─────────────────────────────────────────────────────────────
const GENRES = ['Hip-Hop', 'Jazz', 'R&B / Soul', 'Electronic', 'Pop', 'Rock', 'Classical', 'Bossa Nova', 'Funk', 'Blues'];
const STYLES = [
  { id: 'comping',  label: 'Comping',      desc: 'Rhythmic chord stabs' },
  { id: 'walking',  label: 'Walking Bass', desc: 'Jazz bass movement' },
  { id: 'arpeggio', label: 'Arpeggiated',  desc: 'Broken chord patterns' },
  { id: 'pad',      label: 'Pad / Lush',   desc: 'Long held tones' },
  { id: 'stab',     label: 'Stabs',        desc: 'Short percussive hits' },
  { id: 'lead',     label: 'Lead Fill',    desc: 'Melodic soloing' },
];
const RHYTHMS = [
  { id: 'straight', label: 'Straight 8th',  groove: 0  },
  { id: 'swing',    label: 'Swing',          groove: 50 },
  { id: 'shuffle',  label: 'Shuffle',        groove: 65 },
  { id: 'dotted',   label: 'Dotted',         groove: 40 },
  { id: 'triplet',  label: 'Triplet',        groove: 33 },
  { id: 'synco',    label: 'Syncopated',     groove: 20 },
];
const NOTATIONS = ['Diatonic', 'Pentatonic', 'Chromatic', 'Modal (Dorian)', 'Lydian', 'Mixolydian', 'Whole Tone'];
const HARMONIES = [
  { id: 'unison',   label: 'Unison'         },
  { id: 'thirds',   label: '3rds'           },
  { id: 'fifths',   label: '5ths (Power)'   },
  { id: 'octave',   label: 'Octave'         },
  { id: 'triad',    label: 'Full Triad'     },
  { id: 'seventh',  label: '7th Chord'      },
  { id: 'ninth',    label: '9th Chord'      },
];

// ─── Instruments the session band can play ───────────────────────────────────
interface Instrument {
  id: string;
  name: string;
  icon: React.ReactNode;
  color: string;
  active: boolean;
  volume: number;
}

function makeInstruments(): Instrument[] {
  return [
    { id: 'piano',   name: 'Piano',    icon: <Piano size={14} />,      color: '#8b5cf6', active: true,  volume: 80 },
    { id: 'bass',    name: 'Bass',     icon: <AudioLines size={14} />, color: '#10b981', active: true,  volume: 85 },
    { id: 'guitar',  name: 'Guitar',   icon: <Guitar size={14} />,     color: '#f59e0b', active: false, volume: 70 },
    { id: 'strings', name: 'Strings',  icon: <Music size={14} />,      color: '#3b82f6', active: false, volume: 65 },
    { id: 'brass',   name: 'Brass',    icon: <Mic2 size={14} />,       color: '#ef4444', active: false, volume: 75 },
    { id: 'drums',   name: 'Drums',    icon: <Drum size={14} />,       color: '#ec4899', active: true,  volume: 90 },
  ];
}

// ─── Detected scale / chord info (simulated analysis) ────────────────────────
// ─── Main Component ───────────────────────────────────────────────────────────
export function SessionMusician() {
  const [instruments, setInstruments] = useState<Instrument[]>(makeInstruments);
  const [activeGenre, setActiveGenre] = useState('Hip-Hop');
  const [activeStyle, setActiveStyle] = useState('comping');
  const [activeRhythm, setActiveRhythm] = useState('swing');
  const [activeNotation, setActiveNotation] = useState('Diatonic');
  const [activeHarmony, setActiveHarmony] = useState('seventh');
  const [isLearning, setIsLearning] = useState(false);
  const [isPlaying, setIsPlaying] = useState(false);
  const [analysis, setAnalysis] = useState<AnalysisResult | null>(null);
  const [analyzeError, setAnalyzeError] = useState<string | null>(null);
  const [groove, setGroove] = useState(50);
  const [intensity, setIntensity] = useState(70);
  const [complexity, setComplexity] = useState(50);

  const abortRef = useRef<AbortController | null>(null);
  // Band synthesizer ref
  const bandSynthesizerRef = useRef<BandSynthesizer | null>(null);

  const { audioContext, sequencer, synth, resumeAudio } = useTBMAudio();

  useEffect(() => {
    return () => {
      abortRef.current?.abort();
      bandSynthesizerRef.current?.dispose();
      // Stop the sequencer on unmount so it doesn't keep scheduling after the
      // component is gone (e.g. user navigates away while band is playing).
      sequencer?.stop();
    };
  // sequencer is intentionally omitted: it is a stable ref-like object from
  // context and adding it as a dep would re-register this cleanup on every
  // render, which is not what we want for a mount-only teardown.
  // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []);

  const handleLearn = useCallback(async () => {
    abortRef.current?.abort();
    abortRef.current = new AbortController();
    setIsLearning(true);
    setAnalysis(null);
    setAnalyzeError(null);
    try {
      const result = await analyzeSession({
        genre: activeGenre,
        style: activeStyle,
        rhythm: activeRhythm,
        notation: activeNotation,
      }, abortRef.current.signal);
      setAnalysis(result);
    } catch (err) {
      if ((err as Error).name !== 'AbortError') {
        setAnalyzeError((err as Error).message ?? 'Analysis failed');
      }
    } finally {
      setIsLearning(false);
    }
  }, [activeGenre, activeStyle, activeRhythm, activeNotation]);

  const toggleInstrument = (id: string) => {
    setInstruments(prev =>
      prev.map(inst => inst.id === id ? { ...inst, active: !inst.active } : inst)
    );
  };

  const setInstrumentVolume = (id: string, volume: number) => {
    setInstruments(prev =>
      prev.map(inst => inst.id === id ? { ...inst, volume } : inst)
    );
    // Update synthesizer in real-time if playing
    if (isPlaying) {
      bandSynthesizerRef.current?.updateInstrumentVolume(id, volume);
    }
  };

  // ── Play Band: real multi-voice synthesis ──
  const handlePlayBand = useCallback(() => {
    if (isPlaying) {
      // Stop
      bandSynthesizerRef.current?.stop();
      sequencer?.stop();
      setIsPlaying(false);
      return;
    }

    resumeAudio();

    // Create or reuse band synthesizer. Dispose and recreate if the AudioContext
    // has changed (e.g. after engine reinitialization) so we never hold a reference
    // to a stale/closed context.
    if (
      !bandSynthesizerRef.current ||
      (audioContext && (bandSynthesizerRef.current as any).context !== audioContext)
    ) {
      bandSynthesizerRef.current?.dispose();
      bandSynthesizerRef.current = null;
    }
    if (!bandSynthesizerRef.current && audioContext) {
      bandSynthesizerRef.current = new BandSynthesizer(audioContext, {
        bpm: analysis?.tempo ?? 92,
        groove,
        intensity,
        complexity,
        key: analysis?.key || 'C',
        scale: analysis?.scale || 'major',
        chords: analysis?.chords || ['C', 'G', 'Am', 'F']
      });
    }

    // Update synthesizer with current performance values
    if (bandSynthesizerRef.current) {
      bandSynthesizerRef.current.updatePerformance({
        groove,
        intensity,
        complexity
      });

      // Update instrument volumes
      instruments.forEach(inst => {
        bandSynthesizerRef.current?.updateInstrumentVolume(inst.id, inst.volume);
      });

      // Start playing with active instruments
      const activeInstrumentIds = instruments.filter(i => i.active).map(i => i.id);
      if (analysis) {
        bandSynthesizerRef.current.start(activeInstrumentIds, {
          tempo: analysis.tempo,
          key: analysis.key,
          scale: analysis.scale,
          chords: analysis.chords
        });
      } else {
        // Fallback if no analysis yet
        bandSynthesizerRef.current.start(activeInstrumentIds, {
          tempo: 92,
          key: 'C',
          scale: 'major',
          chords: ['C', 'G', 'Am', 'F']
        });
      }
    }

    // Apply groove/swing to sequencer
    sequencer?.setSwing(groove);

    setIsPlaying(true);
  }, [isPlaying, analysis, audioContext, sequencer, groove, intensity, complexity, instruments, resumeAudio]);

  return (
    <div className="h-full flex flex-col gap-4 overflow-y-auto custom-scrollbar">
      {/* ── Header ── */}
      <div className="flex items-center justify-between shrink-0 relative edge-glow-bottom">
        <div className="flex items-center gap-3">
          <div className="w-8 h-8 rounded-lg bg-brand/15 border border-brand/30 flex items-center justify-center">
            <Brain size={16} className="text-brand" />
          </div>
          <div>
            <h2 className="text-sm font-black uppercase tracking-widest text-neutral-200">Session Musician</h2>
            <p className="text-[13px] font-mono text-neutral-500 uppercase tracking-wide">
              MIDI · Learns & Accompanies
            </p>
          </div>
        </div>
        {/* Transport */}
        <div className="flex items-center gap-2">
          <button
            onClick={handleLearn}
            disabled={isLearning}
            className={`flex items-center gap-2 px-3 py-1.5 rounded-lg text-[13px] font-bold uppercase tracking-wider transition-all border ${
              isLearning
                ? 'bg-brand/20 text-brand border-brand/40 animate-pulse'
                : 'bg-neutral-800 text-neutral-400 border-neutral-700 hover:text-brand hover:border-brand/40'
            }`}
          >
            {isLearning ? <RefreshCw size={12} className="animate-spin" /> : <Brain size={12} />}
            {isLearning ? 'Analyzing…' : 'Learn Track'}
          </button>
          <button
            onClick={handlePlayBand}
            className={`flex items-center gap-2 px-4 py-1.5 rounded-lg text-[13px] font-bold uppercase tracking-wider transition-all shadow-lg ${
              isPlaying
                ? 'bg-emerald-600 text-white shadow-emerald-600/20'
                : 'bg-brand hover:opacity-90 text-white shadow-brand/20'
            }`}
          >
            {isPlaying ? <Square size={12} fill="currentColor" /> : <Play size={12} fill="currentColor" />}
            {isPlaying ? 'Stop' : 'Play Band'}
          </button>
        </div>
      </div>

      {/* ── Analysis result ── */}
      {analysis && (
        <div className="shrink-0 bg-brand/5 border border-brand/20 rounded-xl p-3 flex items-center gap-6 flex-wrap">
          <div className="flex items-center gap-2">
            <Sparkles size={12} className="text-brand" />
            <span className="text-[13px] font-bold uppercase tracking-widest text-neutral-400">Detected:</span>
          </div>
          <div className="flex items-center gap-4 flex-wrap text-sm font-bold font-mono">
            <span><span className="text-neutral-600">Key: </span><span className="text-brand">{analysis.key} {analysis.scale}</span></span>
            <span><span className="text-neutral-600">Tempo: </span><span className="text-emerald-400">{analysis.tempo} BPM</span></span>
            <span><span className="text-neutral-600">Chords: </span><span className="text-yellow-400">{analysis.chords.join(' → ')}</span></span>
            <span><span className="text-neutral-600">Confidence: </span><span className={analysis.confidence > 90 ? 'text-emerald-400' : 'text-yellow-400'}>{analysis.confidence}%</span></span>
          </div>
        </div>
      )}

      {analyzeError && !analysis && (
        <div className="shrink-0 bg-red-950/30 border border-red-900/40 rounded-xl p-3 flex items-center gap-3">
          <span className="text-[13px] font-bold uppercase tracking-widest text-red-400">Analysis error:</span>
          <span className="text-[13px] font-mono text-red-500">{analyzeError}</span>
        </div>
      )}

      <div className="flex gap-4 flex-1 min-h-0">
        {/* ── Left column: menus ── */}
        <div className="flex-1 flex flex-col gap-3 min-w-0">

          {/* Genre */}
          <div className="bg-neutral-900 rounded-xl border border-neutral-800 p-3 vignette">
            <span className="text-xs font-bold uppercase tracking-widest text-neutral-500 mb-2 block">Genre</span>
            <div className="flex flex-wrap gap-1.5">
              {GENRES.map(g => (
                <button
                  key={g}
                  onClick={() => setActiveGenre(g)}
                  className={`px-2.5 py-1 rounded-md text-[13px] font-bold uppercase transition-all border ${
                    activeGenre === g
                      ? 'bg-brand/20 text-brand border-brand/40'
                      : 'bg-neutral-800 text-neutral-500 border-neutral-700 hover:text-neutral-300'
                  }`}
                >
                  {g}
                </button>
              ))}
            </div>
          </div>

          {/* Style */}
          <div className="bg-neutral-900 rounded-xl border border-neutral-800 p-3 vignette">
            <span className="text-xs font-bold uppercase tracking-widest text-neutral-500 mb-2 block">Playing Style</span>
            <div className="grid grid-cols-3 gap-1.5">
              {STYLES.map(s => (
                <button
                  key={s.id}
                  onClick={() => setActiveStyle(s.id)}
                  className={`flex flex-col items-start px-2.5 py-2 rounded-md text-left transition-all border ${
                    activeStyle === s.id
                      ? 'bg-purple-500/15 text-purple-400 border-purple-500/30'
                      : 'bg-neutral-800 text-neutral-500 border-neutral-700 hover:text-neutral-300'
                  }`}
                >
                  <span className="text-[13px] font-bold uppercase">{s.label}</span>
                  <span className="text-xs text-neutral-600 mt-0.5">{s.desc}</span>
                </button>
              ))}
            </div>
          </div>

          {/* Rhythm */}
          <div className="bg-neutral-900 rounded-xl border border-neutral-800 p-3 vignette">
            <span className="text-xs font-bold uppercase tracking-widest text-neutral-500 mb-2 block">Rhythm</span>
            <div className="grid grid-cols-3 gap-1.5">
              {RHYTHMS.map(r => (
                <button
                  key={r.id}
                  onClick={() => { setActiveRhythm(r.id); setGroove(r.groove); }}
                  className={`flex flex-col items-center px-2.5 py-2 rounded-md transition-all border ${
                    activeRhythm === r.id
                      ? 'bg-yellow-500/15 text-yellow-400 border-yellow-500/30'
                      : 'bg-neutral-800 text-neutral-500 border-neutral-700 hover:text-neutral-300'
                  }`}
                >
                  <span className="text-[13px] font-bold uppercase">{r.label}</span>
                  <span className="text-xs text-neutral-600 mt-0.5">groove {r.groove}%</span>
                </button>
              ))}
            </div>
          </div>

          {/* Notation & Harmony (side by side) */}
          <div className="flex gap-3">
            <div className="flex-1 bg-neutral-900 rounded-xl border border-neutral-800 p-3 vignette">
              <span className="text-xs font-bold uppercase tracking-widest text-neutral-500 mb-2 block">Notation</span>
              <div className="flex flex-col gap-1">
                {NOTATIONS.map(n => (
                  <button
                    key={n}
                    onClick={() => setActiveNotation(n)}
                    className={`flex items-center justify-between px-2.5 py-1.5 rounded-md text-[13px] font-bold uppercase transition-all border text-left ${
                      activeNotation === n
                        ? 'bg-emerald-500/15 text-emerald-400 border-emerald-500/30'
                        : 'bg-neutral-800 text-neutral-500 border-neutral-700 hover:text-neutral-300'
                    }`}
                  >
                    {n}
                    {activeNotation === n && <ChevronRight size={10} />}
                  </button>
                ))}
              </div>
            </div>

            <div className="flex-1 bg-neutral-900 rounded-xl border border-neutral-800 p-3 vignette">
              <span className="text-xs font-bold uppercase tracking-widest text-neutral-500 mb-2 block">Harmony</span>
              <div className="flex flex-col gap-1">
                {HARMONIES.map(h => (
                  <button
                    key={h.id}
                    onClick={() => setActiveHarmony(h.id)}
                    className={`flex items-center justify-between px-2.5 py-1.5 rounded-md text-[13px] font-bold uppercase transition-all border text-left ${
                      activeHarmony === h.id
                        ? 'bg-blue-500/15 text-blue-400 border-blue-500/30'
                        : 'bg-neutral-800 text-neutral-500 border-neutral-700 hover:text-neutral-300'
                    }`}
                  >
                    {h.label}
                    {activeHarmony === h.id && <ChevronRight size={10} />}
                  </button>
                ))}
              </div>
            </div>
          </div>
        </div>

        {/* ── Right column: instruments + performance controls ── */}
        <div className="w-64 shrink-0 flex flex-col gap-3">

          {/* Instruments */}
          <div className="bg-neutral-900 rounded-xl border border-neutral-800 p-3 flex flex-col gap-2 vignette">
            <span className="text-xs font-bold uppercase tracking-widest text-neutral-500">Band Instruments</span>
            {instruments.map(inst => (
              <div key={inst.id} className="flex items-center gap-2">
                <button
                  onClick={() => toggleInstrument(inst.id)}
                  className={`w-7 h-7 rounded-lg flex items-center justify-center transition-all border shrink-0 ${
                    inst.active
                      ? 'border-transparent'
                      : 'bg-neutral-800 border-neutral-700 text-neutral-600'
                  }`}
                  style={inst.active ? { backgroundColor: inst.color + '33', borderColor: inst.color + '66', color: inst.color } : {}}
                  title={inst.active ? 'Mute' : 'Enable'}
                >
                  {inst.icon}
                </button>
                <span className={`text-[13px] font-bold uppercase w-14 shrink-0 ${inst.active ? 'text-neutral-300' : 'text-neutral-600'}`}>
                  {inst.name}
                </span>
                <input
                  type="range"
                  min={0}
                  max={100}
                  value={inst.volume}
                  onChange={e => setInstrumentVolume(inst.id, parseInt(e.target.value))}
                  disabled={!inst.active}
                  className="flex-1 h-1 appearance-none accent-brand disabled:opacity-30"
                />
                <span className="text-xs font-mono text-neutral-600 w-6 text-right">{inst.volume}</span>
                {inst.active ? (
                  <Volume2 size={10} className="text-neutral-500 shrink-0" />
                ) : (
                  <VolumeX size={10} className="text-neutral-700 shrink-0" />
                )}
              </div>
            ))}
          </div>

          {/* Performance controls */}
          <div className="bg-neutral-900 rounded-xl border border-neutral-800 p-3 flex flex-col gap-3 vignette">
            <div className="flex items-center gap-2">
              <Sliders size={12} className="text-neutral-500" />
              <span className="text-xs font-bold uppercase tracking-widest text-neutral-500">Performance</span>
            </div>
             {[
               { label: 'Groove',     value: groove,     setValue: setGroove,     color: '#f59e0b' },
               { label: 'Intensity',  value: intensity,  setValue: setIntensity,  color: '#ef4444' },
               { label: 'Complexity', value: complexity, setValue: setComplexity, color: '#8b5cf6' },
             ].map(ctrl => (
               <div key={ctrl.label} className="flex flex-col gap-1">
                 <div className="flex justify-between">
                   <span className="text-xs font-bold uppercase text-neutral-600">{ctrl.label}</span>
                   <span className="text-xs font-mono text-neutral-500">{ctrl.value}%</span>
                 </div>
                 <input
                   type="range"
                   min={0}
                   max={100}
                   value={ctrl.value}
                   onChange={e => {
                     ctrl.setValue(parseInt(e.target.value));
                     // Update synthesizer in real-time
                     if (isPlaying && bandSynthesizerRef.current) {
                       bandSynthesizerRef.current.updatePerformance({
                         [ctrl.label.toLowerCase()]: parseInt(e.target.value)
                       });
                     }
                   }}
                   className="w-full h-1.5 appearance-none rounded-full"
                   style={{ accentColor: ctrl.color }}
                 />
               </div>
             ))}
          </div>

          {/* Status */}
          <div className={`bg-neutral-900 rounded-xl border p-3 flex flex-col gap-2 transition-all vignette ${
            isPlaying ? 'border-emerald-500/40 bg-emerald-500/5' : 'border-neutral-800'
          }`}>
            <div className="flex items-center justify-between">
              <span className="text-xs font-bold uppercase tracking-widest text-neutral-500">Band Status</span>
              <div className={`w-2 h-2 rounded-full ${isPlaying ? 'bg-emerald-500 animate-pulse dot-glow' : 'bg-neutral-700'}`} />
            </div>
            <div className="flex flex-col gap-1">
              {[
                { label: 'Style',    val: STYLES.find(s => s.id === activeStyle)?.label  ?? '' },
                { label: 'Rhythm',   val: RHYTHMS.find(r => r.id === activeRhythm)?.label ?? '' },
                { label: 'Notation', val: activeNotation },
                { label: 'Harmony',  val: HARMONIES.find(h => h.id === activeHarmony)?.label ?? '' },
                { label: 'Genre',    val: activeGenre },
              ].map(row => (
                <div key={row.label} className="flex justify-between text-xs font-mono">
                  <span className="text-neutral-600 uppercase">{row.label}</span>
                  <span className={isPlaying ? 'text-emerald-400' : 'text-neutral-400'}>{row.val}</span>
                </div>
              ))}
            </div>
          </div>
        </div>
      </div>
    </div>
  );
}

import React, { useState, useEffect, useCallback, useRef } from 'react';
import { Cpu, Zap, Activity, ShieldAlert, Save, Loader2, CheckCircle2, Sliders, Radio, Plug, RotateCcw, Disc, Music, Square, AlertCircle, Palette, Check, Pipette, Brain, ChevronDown } from 'lucide-react';
import { fetchSettings, saveSettings, fetchLLMProviders, setLLMProvider } from '../lib/api';
import type { LLMProviderName, LLMProviderInfo } from '../lib/api';
import { useTBMAudio } from '../contexts/TBMAudioContext';
import { useTheme, themes } from '../contexts/ThemeContext';
import { RecoveryManager } from './RecoveryManager';
import { getGlobalMidiHandler } from '../lib/midiHandler';
import {
  getAvailableModes,
  setControllerMode,
  getCurrentMode,
  getModeMappings,
  getModeFunctionIds,
  formatMapping,
  setCustomMapping,
  removeCustomMapping,
  resetAllCustomMappings,
  getCustomMappings,
  TBM_FUNCTION_LABELS,
  onControllerModeChange,
  onCustomMappingsChange,
  type MidiMapping as Slate4MidiMapping,
} from '../lib/midiMapping';
import { ToggleSwitch } from './ui/ToggleSwitch';
import { STORAGE_KEYS } from '../lib/constants';

// Lazy-load ModMatrix for embedding in Settings
const ModMatrixLazy = React.lazy(() => import('./ModMatrix').then(m => ({ default: m.ModMatrix })));

// ── MIDI types & constants ────────────────────────────────────────────────────
type MidiDevice = {
  id: string;
  name: string;
  deviceType: 'keyboard' | 'dj_controller' | 'pad_controller' | 'unknown';
};
type MidiMapping = { type: 'cc' | 'note'; channel: number; number: number };

const DEFAULT_MIDI_MAPPINGS: Record<string, MidiMapping> = {
  jog_wheel:    { type: 'cc',   channel: 0, number: 33 },
  crossfader:   { type: 'cc',   channel: 0, number: 8  },
  play_stop:    { type: 'note', channel: 9, number: 36 },
  cycle_preset: { type: 'note', channel: 9, number: 37 },
  one_shot:     { type: 'note', channel: 9, number: 38 },
  rec_toggle:   { type: 'note', channel: 9, number: 39 },
  auto_scratch: { type: 'note', channel: 9, number: 40 },
  reset_cue:    { type: 'note', channel: 9, number: 41 },
};

const MIDI_MAPPINGS_KEY = STORAGE_KEYS.MIDI_MAPPINGS;

const DEVICE_TYPE_STYLES: Record<string, string> = {
  keyboard:       'text-purple-400 border-purple-500/30 bg-purple-500/10',
  dj_controller:  'text-brand border-brand/30 bg-brand/10',
  pad_controller: 'text-indicator border-indicator/30 bg-indicator/10',
  unknown:        'text-neutral-500 border-neutral-600/30 bg-neutral-600/10',
};
const DEVICE_TYPE_LABELS: Record<string, string> = {
  keyboard: 'Keys', dj_controller: 'DJ', pad_controller: 'Pads', unknown: 'Ctrl',
};
const MAPPING_LABELS: Record<string, string> = {
  jog_wheel: 'Jog Wheel', crossfader: 'Crossfader',
  play_stop: 'Play / Stop', cycle_preset: 'Cycle Preset',
  one_shot: 'One Shot', rec_toggle: 'Record',
  auto_scratch: 'Auto Scratch', reset_cue: 'Reset Cue',
};

function isValidMidiMapping(v: unknown): v is MidiMapping {
  if (!v || typeof v !== 'object') return false;
  const m = v as Record<string, unknown>;
  return (m.type === 'cc' || m.type === 'note')
    && typeof m.channel === 'number' && m.channel >= 0 && m.channel <= 15
    && typeof m.number === 'number' && m.number >= 0 && m.number <= 127;
}

function loadMidiMappings(): Record<string, MidiMapping> {
  try {
    const saved = localStorage.getItem(MIDI_MAPPINGS_KEY);
    if (saved) {
      const parsed = JSON.parse(saved) as Record<string, unknown>;
      // Validate every known key; fall back to defaults if any entry is invalid
      const allValid = Object.keys(DEFAULT_MIDI_MAPPINGS).every(k => isValidMidiMapping(parsed[k]));
      if (allValid) return parsed as Record<string, MidiMapping>;
      try { localStorage.removeItem(MIDI_MAPPINGS_KEY); } catch { /* storage unavailable */ }
    }
  } catch {
    try { localStorage.removeItem(MIDI_MAPPINGS_KEY); } catch { /* storage unavailable */ }
  }
  return DEFAULT_MIDI_MAPPINGS;
}

function detectDeviceType(name: string): MidiDevice['deviceType'] {
  const n = name.toLowerCase();
  if (/keyboard|piano|keys|synth|organ/.test(n)) return 'keyboard';
  if (/dj|turntable|scratch|deck|mixer|jog/.test(n)) return 'dj_controller';
  if (/pad|trigger|step|grid/.test(n)) return 'pad_controller';
  return 'unknown';
}

interface SettingsState {
  driver: string;
  bufferSize: number;
  sampleRate: string;
  multiCore: boolean;
  highPrecision: boolean;
  oversampling: boolean;
  uiScale: string;
  midiDevice: string;
  autoSaveInterval: number;
}

const DEFAULT_SETTINGS: SettingsState = {
  driver: 'ASIO v2.0',
  bufferSize: 128,
  sampleRate: '44100 Hz',
  multiCore: true,
  highPrecision: false,
  oversampling: true,
  uiScale: '100%',
  midiDevice: 'TBM Controller 49',
  autoSaveInterval: 15,
};

function settingsToState(raw: Record<string, string>): SettingsState {
  return {
    driver:           raw.driver           ?? DEFAULT_SETTINGS.driver,
    bufferSize:       Number(raw.bufferSize ?? DEFAULT_SETTINGS.bufferSize),
    sampleRate:       raw.sampleRate       ?? DEFAULT_SETTINGS.sampleRate,
    multiCore:        (raw.multiCore       ?? 'true') === 'true',
    highPrecision:    (raw.highPrecision   ?? 'false') === 'true',
    oversampling:     (raw.oversampling    ?? 'true') === 'true',
    uiScale:          raw.uiScale          ?? DEFAULT_SETTINGS.uiScale,
    midiDevice:       raw.midiDevice       ?? DEFAULT_SETTINGS.midiDevice,
    autoSaveInterval: Number(raw.autoSaveInterval ?? DEFAULT_SETTINGS.autoSaveInterval),
  };
}

function stateToRecord(s: SettingsState): Record<string, string> {
  return {
    driver:           s.driver,
    bufferSize:       String(s.bufferSize),
    sampleRate:       s.sampleRate,
    multiCore:        String(s.multiCore),
    highPrecision:    String(s.highPrecision),
    oversampling:     String(s.oversampling),
    uiScale:          s.uiScale,
    midiDevice:       s.midiDevice,
    autoSaveInterval: String(s.autoSaveInterval),
  };
}

export function SettingsView() {
  const { audioContext, engineLog, reinitializeEngine } = useTBMAudio();
  const { currentTheme, setTheme, customTheme, updateCustomTheme } = useTheme();
  const [settings, setSettings] = useState<SettingsState>(DEFAULT_SETTINGS);
  const [isLoading, setIsLoading] = useState(true);

  // ── Real AudioContext values (read-only, reported by the browser) ──────────
  const actualSampleRate = audioContext?.sampleRate ?? null;
  const actualBaseLatency = audioContext?.baseLatency ?? null;
  const [isSaving, setIsSaving] = useState(false);
  const [saveStatus, setSaveStatus] = useState<'idle' | 'saved' | 'error'>('idle');

  // ── MIDI state ─────────────────────────────────────────────────────────────
  const [midiSupported] = useState(() => 'requestMIDIAccess' in navigator);
  const [midiEnabled, setMidiEnabled] = useState(false);
  const [midiDevices, setMidiDevices] = useState<MidiDevice[]>([]);
  const [midiLearnParam, setMidiLearnParam] = useState<string | null>(null);
  const [midiMappings, setMidiMappings] = useState<Record<string, MidiMapping>>(loadMidiMappings);
  const [midiActivity, setMidiActivity] = useState(false);
  const [showRecovery, setShowRecovery] = useState(false);
  const [showModMatrix, setShowModMatrix] = useState(false);
  const [geminiSlateEnabled, setGeminiSlateEnabled] = useState(false);
  const [controllerMode, setControllerModeState] = useState('turntable');
  const [padOffset, setPadOffset] = useState(0);
  const [keyLockEnabled, setKeyLockEnabled] = useState(false);
  const [settingsNotification, setSettingsNotification] = useState<string | null>(null);
  const settingsNotifTimerRef = useRef<ReturnType<typeof setTimeout> | null>(null);
  const midiAccessRef = useRef<MIDIAccess | null>(null);
  const midiActivityTimerRef = useRef<ReturnType<typeof setTimeout> | null>(null);
  const onMidiMessageRef = useRef<(event: MIDIMessageEvent) => void>(() => {});

  // ── LLM Provider state ─────────────────────────────────────────────────────
  const [llmProviders, setLlmProviders] = useState<LLMProviderInfo[]>([]);
  const [llmActive, setLlmActive] = useState<LLMProviderName | null>(null);
  const [llmActiveModel, setLlmActiveModel] = useState<string>('');
  const [llmLoading, setLlmLoading] = useState(false);
  const [llmSwitching, setLlmSwitching] = useState(false);
  const [llmModelDropdown, setLlmModelDropdown] = useState<LLMProviderName | null>(null);

  // ── Inline notification for SettingsView ──
  const showSettingsNotification = useCallback((msg: string) => {
    if (settingsNotifTimerRef.current !== null) clearTimeout(settingsNotifTimerRef.current);
    setSettingsNotification(msg);
    settingsNotifTimerRef.current = setTimeout(() => { 
      setSettingsNotification(null); 
      settingsNotifTimerRef.current = null; 
    }, 3000);
  }, []);

  // ── Load LLM providers on mount ─────────────────────────────────────────────
  useEffect(() => {
    setLlmLoading(true);
    fetchLLMProviders()
      .then(res => {
        setLlmProviders(res.providers as LLMProviderInfo[]);
        setLlmActive(res.activeProvider as LLMProviderName);
        setLlmActiveModel(res.activeModel);
      })
      .catch(() => {
        // Server may not be reachable — leave empty
      })
      .finally(() => setLlmLoading(false));
  }, []);

  const handleLLMSwitch = useCallback(async (provider: LLMProviderName, model?: string) => {
    setLlmSwitching(true);
    try {
      const res = await setLLMProvider(provider, model);
      setLlmActive(res.activeProvider as LLMProviderName);
      setLlmActiveModel(res.activeModel);
      setLlmModelDropdown(null);
      // Refresh full provider list to update active flags
      const refreshed = await fetchLLMProviders();
      setLlmProviders(refreshed.providers as LLMProviderInfo[]);
      showSettingsNotification(`LLM switched to ${res.activeProvider} / ${res.activeModel}`);
    } catch (err) {
      showSettingsNotification(`Failed to switch LLM: ${err instanceof Error ? err.message : 'Unknown error'}`);
    } finally {
      setLlmSwitching(false);
    }
  }, [showSettingsNotification]);

  useEffect(() => {
    fetchSettings()
      .then(raw => {
        const loaded = settingsToState(raw);
        // If the live AudioContext reports a different sample rate than what was
        // persisted, update the setting to match reality so the UI is accurate.
        if (actualSampleRate !== null) {
          loaded.sampleRate = `${actualSampleRate} Hz`;
        }
        setSettings(loaded);
      })
      .catch(() => {
        // Keep defaults, but still sync sample rate from real context
        if (actualSampleRate !== null) {
          setSettings(prev => ({ ...prev, sampleRate: `${actualSampleRate} Hz` }));
        }
      })
      .finally(() => setIsLoading(false));
  // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []);

  // Reinitialize audio engine when driver, sample rate, or buffer size changes
  const isFirstRender = useRef(true);
  useEffect(() => {
    if (isFirstRender.current) { isFirstRender.current = false; return; }
    reinitializeEngine?.();
  // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [settings.driver, settings.sampleRate, settings.bufferSize]);

  // Persist MIDI mappings on change
  useEffect(() => {
    try {
      localStorage.setItem(MIDI_MAPPINGS_KEY, JSON.stringify(midiMappings));
    } catch { /* storage unavailable */ }
  }, [midiMappings]);

  // Cleanup MIDI on unmount
  useEffect(() => {
    return () => {
      if (midiActivityTimerRef.current !== null) clearTimeout(midiActivityTimerRef.current);
      midiAccessRef.current?.inputs.forEach(input => { input.onmidimessage = null; });
    };
  }, []);

  // Apply UI scale to document root
  useEffect(() => {
    const zoom = settings.uiScale.replace('%', '');
    const numericZoom = parseFloat(zoom) / 100;
    // Use CSS transform scale on body instead of non-standard zoom
    document.body.style.transform = `scale(${numericZoom})`;
    document.body.style.transformOrigin = 'top left';
    document.body.style.width = `${100 / numericZoom}%`;
    document.body.style.height = `${100 / numericZoom}%`;
    try { localStorage.setItem(STORAGE_KEYS.UI_SCALE, settings.uiScale); } catch { /* ignore */ }
    return () => {
      // Reset body transform when the Settings view unmounts so the rest of the
      // UI is not left permanently distorted if the user navigates away.
      document.body.style.transform = '';
      document.body.style.transformOrigin = '';
      document.body.style.width = '';
      document.body.style.height = '';
    };
  }, [settings.uiScale]);

  const set = <K extends keyof SettingsState>(key: K, value: SettingsState[K]) =>
    setSettings(prev => ({ ...prev, [key]: value }));

  const handleSave = useCallback(async () => {
    setIsSaving(true);
    try {
      await saveSettings(stateToRecord(settings));
      setSaveStatus('saved');
      setTimeout(() => setSaveStatus('idle'), 2000);
    } catch {
      setSaveStatus('error');
      setTimeout(() => setSaveStatus('idle'), 3000);
    } finally {
      setIsSaving(false);
    }
  }, [settings]);

  const initMidi = useCallback(async () => {
    try {
      // Clear any previous handlers before (re-)enumerating
      midiAccessRef.current?.inputs.forEach(input => { input.onmidimessage = null; });

      // Reuse existing access object to avoid requesting permission again
      const access = midiAccessRef.current ?? await navigator.requestMIDIAccess({ sysex: false });
      midiAccessRef.current = access;
      setMidiEnabled(true);

      const attachInputs = () => {
        // Clear stale handlers first, then reattach
        access.inputs.forEach(input => { input.onmidimessage = null; });
        const devs: MidiDevice[] = [];
        access.inputs.forEach(input => {
          devs.push({
            id: input.id,
            name: input.name ?? 'Unknown Device',
            deviceType: detectDeviceType(input.name ?? ''),
          });
          input.onmidimessage = (event) => onMidiMessageRef.current(event);
        });
        setMidiDevices(devs);
      };

      attachInputs();
      access.onstatechange = () => { attachInputs(); };
    } catch {
      setMidiEnabled(false);
    }
  }, []);

  // ── Slate 4 MIDI Learn state ──
  const [slate4LearnParam, setSlate4LearnParam] = useState<string | null>(null);
  const [slate4Mappings, setSlate4Mappings] = useState<Record<string, Slate4MidiMapping>>(() => getModeMappings());
  const [slate4Custom, setSlate4Custom] = useState<Record<string, Slate4MidiMapping>>(() => getCustomMappings());

  // Subscribe to mapping changes from any source
  useEffect(() => {
    const unsubMode = onControllerModeChange((modeId) => {
      setControllerModeState(modeId);
      setSlate4Mappings(getModeMappings(modeId));
    });
    const unsubMappings = onCustomMappingsChange((custom) => {
      setSlate4Custom(custom);
      setSlate4Mappings(getModeMappings());
    });
    return () => { unsubMode(); unsubMappings(); };
  }, []);

  // Check if the shared handler is already connected (from GeminiSlate4Integration)
  useEffect(() => {
    const handler = getGlobalMidiHandler();
    if (handler.isConnected()) {
      setGeminiSlateEnabled(true);
      setControllerModeState(getCurrentMode().id);
      setSlate4Mappings(getModeMappings());
    }
  }, []);

  // Toggle Gemini Slate 4 — just enables/disables the UI section.
  // The actual MIDI connection is managed by GeminiSlate4Integration component.
  const toggleGeminiSlate = useCallback(() => {
    setGeminiSlateEnabled(prev => !prev);
  }, []);

  // Handle controller mode change
  const handleModeChange = useCallback((modeId: string) => {
    setControllerModeState(modeId);
    setControllerMode(modeId);
  }, []);

  // Keep MIDI handler fresh on every render so it reads current midiLearnParam/midiMappings
  onMidiMessageRef.current = (event: MIDIMessageEvent) => {
    const data = event.data;
    if (!data || data.length < 3) return;
    const status = data[0];
    const data1 = data[1];
    const data2 = data[2];
    const msgType = status & 0xF0;
    const channel = status & 0x0F;
    setMidiActivity(true);
    if (midiActivityTimerRef.current !== null) clearTimeout(midiActivityTimerRef.current);
    midiActivityTimerRef.current = setTimeout(() => setMidiActivity(false), 150);

    // Pass to Gemini Slate 4 MIDI Learn if a Slate 4 function is being learned
    if (slate4LearnParam !== null) {
      let learnType: 'cc' | 'note' = 'cc';
      if (msgType === 0xB0) {
        learnType = 'cc';
      } else if (msgType === 0x90 && data2 > 0) {
        learnType = 'note';
      } else {
        // Ignore note-off etc. for learn
        return;
      }
      const newMapping: Slate4MidiMapping = { type: learnType, channel, number: data1 };
      setCustomMapping(slate4LearnParam, newMapping);
      setSlate4LearnParam(null);
      setSlate4Mappings(getModeMappings());
      setSlate4Custom(getCustomMappings());
      return;
    }

    if (midiLearnParam !== null) {
      if (msgType === 0xB0) {
        setMidiMappings(prev => ({ ...prev, [midiLearnParam]: { type: 'cc', channel, number: data1 } }));
      } else if (msgType === 0x90 && data2 > 0) {
        setMidiMappings(prev => ({ ...prev, [midiLearnParam]: { type: 'note', channel, number: data1 } }));
      }
      setMidiLearnParam(null);
    }
  };

  if (isLoading) {
    return (
      <div className="h-full flex items-center justify-center">
        <Loader2 size={28} className="animate-spin text-neutral-600" />
      </div>
    );
  }

  return (
    <div className="h-full flex flex-col gap-6 p-6">
      {/* Header */}
      <div className="flex items-center justify-between">
        <h2 className="text-[13px] font-black text-neutral-200 uppercase tracking-[0.2em]">Audio & System Settings</h2>
        <button
          onClick={handleSave}
          disabled={isSaving}
          className={`flex items-center gap-2 px-4 py-2 rounded-lg text-sm font-bold uppercase tracking-wider transition-all ${
            saveStatus === 'saved' ? 'bg-emerald-600/20 text-emerald-400 border border-emerald-600/40' :
            saveStatus === 'error' ? 'bg-red-600/20 text-red-400 border border-red-600/40' :
            'bg-brand hover:opacity-90 text-white border border-brand/50 shadow-lg shadow-brand/20'
          }`}
        >
          {isSaving ? <Loader2 size={13} className="animate-spin" /> :
           saveStatus === 'saved' ? <CheckCircle2 size={13} /> :
           <Save size={13} />}
          {saveStatus === 'saved' ? 'Saved!' : saveStatus === 'error' ? 'Error' : 'Save Settings'}
        </button>
      </div>

      {/* ── Inline notification toast ── */}
      {settingsNotification && (
        <div className="flex items-center justify-between gap-3 px-4 py-3 bg-neutral-900 border border-neutral-800 rounded-lg animate-fadeIn vignette">
          <div className="flex items-center gap-3">
            <AlertCircle size={16} className="text-brand" />
            <span className="text-sm font-bold uppercase tracking-widest">{settingsNotification}</span>
          </div>
          <button 
            onClick={() => setSettingsNotification(null)}
            className="text-neutral-500 hover:text-white text-[13px] font-bold uppercase transition-colors"
          >
            Dismiss
          </button>
        </div>
      )}

      <div className="grid grid-cols-2 gap-8">
        {/* ── Audio Engine ── */}
        <div className="flex flex-col gap-6">
          <div className="flex items-center gap-3 text-red-400">
            <Zap size={18} />
            <h3 className="text-sm font-bold uppercase tracking-widest">Audio Engine</h3>
          </div>

          <div className="space-y-4">
            {/* Real context readouts */}
            {actualSampleRate !== null && (
              <div className="grid grid-cols-2 gap-2">
                <div className="bg-neutral-950 p-3 rounded-lg border border-neutral-800 flex flex-col gap-1">
                  <span className="text-xs font-mono text-neutral-600 uppercase">Active Sample Rate</span>
                  <span className="text-sm font-bold text-emerald-400 font-mono">{actualSampleRate} Hz</span>
                </div>
                <div className="bg-neutral-950 p-3 rounded-lg border border-neutral-800 flex flex-col gap-1">
                  <span className="text-xs font-mono text-neutral-600 uppercase">Base Latency</span>
                  <span className="text-sm font-bold text-emerald-400 font-mono">
                    {actualBaseLatency !== null ? `${Math.round(actualBaseLatency * 1000)} ms` : '—'}
                  </span>
                </div>
              </div>
            )}

            <div className="flex flex-col gap-2">
              <label className="text-xs font-mono text-neutral-500 uppercase">
                Driver Type
                <span className="ml-2 text-xs text-neutral-700 normal-case">(target — applied on reinit)</span>
              </label>
              <select 
                value={settings.driver}
                onChange={(e) => set('driver', e.target.value)}
                className="bg-neutral-800 border border-neutral-700 text-neutral-300 text-sm rounded-md p-2 outline-none focus:border-brand"
              >
                <option>ASIO v2.0</option>
                <option>DirectSound</option>
                <option>CoreAudio (Mac)</option>
                <option>WASAPI</option>
              </select>
            </div>

            <div className="flex flex-col gap-2">
              <label className="text-xs font-mono text-neutral-500 uppercase">
                Buffer Size: {settings.bufferSize} samples
                <span className="ml-2 text-xs text-neutral-700 normal-case">(target — applied on reinit)</span>
              </label>
              <input 
                type="range" 
                min="32" 
                max="2048" 
                step="32"
                value={settings.bufferSize}
                onChange={(e) => set('bufferSize', parseInt(e.target.value))}
                className="w-full h-1 bg-neutral-800 rounded-lg appearance-none cursor-pointer accent-brand"
              />
              <div className="flex justify-between text-[13px] font-mono text-neutral-600">
                <span>32 (Low Latency)</span>
                <span>2048 (Safe)</span>
              </div>
            </div>

            <div className="flex flex-col gap-2">
              <label className="text-xs font-mono text-neutral-500 uppercase">
                Sample Rate
                <span className="ml-2 text-xs text-neutral-700 normal-case">(target — applied on reinit)</span>
              </label>
              <select 
                value={settings.sampleRate}
                onChange={(e) => set('sampleRate', e.target.value)}
                className="bg-neutral-800 border border-neutral-700 text-neutral-300 text-sm rounded-md p-2 outline-none focus:border-brand"
              >
                <option>44100 Hz</option>
                <option>48000 Hz</option>
                <option>88200 Hz</option>
                <option>96000 Hz</option>
              </select>
            </div>

            <div className="bg-neutral-950 p-4 rounded-lg border border-neutral-800 flex items-start gap-3">
              <ShieldAlert size={16} className="text-red-500 mt-0.5" />
              <div className="flex flex-col gap-1">
                <span className="text-[13px] font-bold text-red-500 uppercase">Note</span>
                <span className="text-[13px] text-neutral-500 uppercase leading-relaxed">
                  Web Audio locks sample rate at context creation. Driver and buffer size changes apply when the engine reinitializes. Lower buffers may cause crackling on slower CPUs.
                </span>
              </div>
            </div>
          </div>
        </div>

        {/* ── Performance ── */}
        <div className="flex flex-col gap-6">
          <div className="flex items-center gap-3 text-blue-400">
            <Cpu size={18} />
            <h3 className="text-sm font-bold uppercase tracking-widest">Performance</h3>
          </div>

          <div className="space-y-4">
            <div className="bg-neutral-950 p-4 rounded-lg border border-neutral-800 flex items-center justify-between">
              <div className="flex flex-col gap-1">
                <span className="text-xs font-bold text-neutral-300 uppercase">Multi-Core Processing</span>
                <span className="text-[13px] text-neutral-500 uppercase">Enable parallel DSP threads</span>
              </div>
              <ToggleSwitch value={settings.multiCore} onChange={v => set('multiCore', v)} />
            </div>

            <div className="bg-neutral-950 p-4 rounded-lg border border-neutral-800 flex items-center justify-between">
              <div className="flex flex-col gap-1">
                <span className="text-xs font-bold text-neutral-300 uppercase">High-Precision Resampling</span>
                <span className="text-[13px] text-neutral-500 uppercase">Better quality, higher CPU usage</span>
              </div>
              <ToggleSwitch value={settings.highPrecision} onChange={v => set('highPrecision', v)} />
            </div>

            <div className="bg-neutral-950 p-4 rounded-lg border border-neutral-800 flex items-center justify-between">
              <div className="flex flex-col gap-1">
                <span className="text-xs font-bold text-neutral-300 uppercase">Oversampling (4x)</span>
                <span className="text-[13px] text-neutral-500 uppercase">Reduce aliasing in saturation</span>
              </div>
              <ToggleSwitch value={settings.oversampling} onChange={v => set('oversampling', v)} />
            </div>

            <div className="flex flex-col gap-2">
              <label className="text-xs font-mono text-neutral-500 uppercase">UI Scaling</label>
              <div className="flex gap-2">
                {['100%', '125%', '150%'].map(scale => (
                  <button
                    key={scale}
                    onClick={() => set('uiScale', scale)}
                    className={`flex-1 py-1 rounded text-[13px] font-bold border transition-all ${
                      settings.uiScale === scale
                        ? 'bg-brand border-brand/50 text-white shadow-lg shadow-brand/20'
