          )}

          {/* Sensitivity (transient mode) */}
          {chopMode === "transient" && (
            <div className="flex items-center gap-2">
              <span className="text-xs font-mono text-neutral-600">
                Sensitivity:
              </span>
              <input
                type="range"
                min={10}
                max={100}
                value={sensitivity}
                onChange={(e) => setSensitivity(parseInt(e.target.value))}
                className="w-20 h-1 bg-neutral-800 appearance-none accent-red-500"
              />
              <button
                onClick={handleAutoChop}
                className="px-2 py-0.5 rounded text-xs font-bold bg-neutral-800 text-neutral-400 hover:text-white"
              >
                <Zap size={10} className="inline mr-1" />
                Detect
              </button>
            </div>
          )}

          {/* Live chop mode instructions */}
          {chopMode === "live" && (
            <div className="flex items-center gap-2">
              <span className="text-xs font-mono text-neutral-600">
                Live: Press pads to mark slices
              </span>
              <span className="text-xs font-mono text-green-400">
                {slicePositions.length} markers
              </span>
            </div>
          )}

          <div className="flex-1" />

          <span className="text-xs font-mono text-neutral-600">
            {sliceCount} regions
          </span>

          {/* Action buttons */}
          <button
            onClick={handleAssignToPads}
            disabled={!buffer || slicePositions.length === 0}
            className="flex items-center gap-1.5 px-4 py-1.5 rounded-lg text-[13px] font-bold uppercase bg-brand text-white hover:opacity-90 transition-all disabled:opacity-30 disabled:cursor-not-allowed shadow-md"
          >
            <Music size={11} /> To Pads
          </button>
          <button
            onClick={handleGoToDrums}
            disabled={!buffer || slicePositions.length === 0}
            className="flex items-center gap-1.5 px-4 py-1.5 rounded-lg text-[13px] font-bold uppercase bg-emerald-600 text-white hover:opacity-90 transition-all disabled:opacity-30 disabled:cursor-not-allowed shadow-md"
          >
            <ChevronRight size={11} /> To Drums
          </button>
          <button
            onClick={handleStemChop}
            disabled={
              !buffer ||
              slicePositions.length === 0 ||
              stemState.status === "separating" ||
              stemState.status === "slicing"
            }
            className="flex items-center gap-1.5 px-4 py-1.5 rounded-lg text-[13px] font-bold uppercase bg-linear-to-r from-purple-600 to-pink-600 text-white hover:opacity-90 transition-all disabled:opacity-30 disabled:cursor-not-allowed shadow-md"
          >
            {stemState.status === "separating" ||
            stemState.status === "slicing" ? (
              <>
                <Loader2 size={10} className="animate-spin" /> {stemState.phase}
              </>
            ) : (
              <>
                <Scissors size={10} /> Stem Chop
              </>
            )}
          </button>
          <button
            onClick={() => {
              setSlicePositions([]);
              setStemState({
                status: "idle",
                progress: 0,
                phase: "",
                programs: [],
              });
            }}
            className="p-1.5 rounded-lg bg-neutral-800 text-neutral-500 hover:text-white hover:bg-neutral-700 transition-colors"
            title="Clear slices"
          >
            <RotateCcw size={12} />
          </button>
        </div>

        {/* Waveform + slice markers */}
        <div className="flex-1 flex flex-col min-h-0 px-4 py-2">
          {buffer ? (
            <>
              <div
                ref={waveformRef}
                className="flex-1 relative bg-neutral-950 rounded-lg border border-neutral-800 overflow-hidden cursor-crosshair min-h-20"
                onClick={chopMode === "manual" ? handleWaveformClick : undefined}
              >
                {/* Colored region backgrounds */}
                {(() => {
                  const all = [0, ...slicePositions, 1];
                  return all.slice(0, -1).map((start, i) => (
                    <div
                      key={i}
                      className="absolute inset-y-0"
                      style={{
                        left: `${start * 100}%`,
                        width: `${(all[i + 1] - start) * 100}%`,
                        backgroundColor:
                          SLICE_COLORS[i % SLICE_COLORS.length] + "10",
                      }}
                    />
                  ));
                })()}

                {/* Waveform bars */}
                <svg
                  className="absolute inset-0 w-full h-full"
                  preserveAspectRatio="none"
                  viewBox={`0 0 ${waveform.length} 100`}
                >
                  {waveform.map((val, i) => (
                    <rect
                      key={i}
                      x={i}
                      y={50 - val * 45}
                      width={0.8}
                      height={val * 90}
                      fill="#ef4444"
                      opacity={0.6}
                    />
                  ))}
                </svg>

                {/* Slice markers (draggable) */}
                {slicePositions.map((pos, i) => (
                  <div
                    key={i}
                    className="absolute inset-y-0 w-0.75 cursor-col-resize group z-10"
                    style={{ left: `calc(${pos * 100}% - 1.5px)` }}
                    onMouseDown={(e) => handleSliceMouseDown(i, e)}
                  >
                    <div className="absolute inset-y-0 w-px left-px bg-white/70 group-hover:bg-white transition-colors" />
                    {/* Handle */}
                    <div className="absolute top-0 left-1/2 -translate-x-1/2 w-3 h-3 rounded-full bg-white border-2 border-neutral-800 group-hover:border-brand transition-colors" />
                    {/* Pad number */}
                    <div className="absolute top-4 left-1/2 -translate-x-1/2 text-[7px] font-bold text-neutral-500">
                      {i + 1}
                    </div>
                  </div>
                ))}

                {/* Flash indicator for live mode */}
                {flashSlice !== null && (
                  <div
                    className="absolute inset-y-0 w-0.5 z-20"
                    style={{
                      left: `calc(${flashSlice * 100}% - 1px)`,
                      backgroundColor: '#00ff00',
                      boxShadow: '0 0 8px #00ff00'
                    }}
                  />
                )}

                {/* Click hint for manual mode */}
                {chopMode === "manual" && slicePositions.length === 0 && (
                  <div className="absolute inset-0 flex items-center justify-center">
                    <span className="text-[13px] text-neutral-600 font-mono">
                      Click to add slice markers
                    </span>
                  </div>
                )}
              </div>
              {slicePositions.length > 0 && (
                <div className="mt-2 bg-neutral-950 rounded-lg border border-neutral-800 p-3">
                  <div className="text-xs font-bold text-neutral-500 uppercase tracking-wider mb-2">Slice Editor</div>
                  <div className="space-y-1">
                    {slicePositions.map((pos, i) => (
                      <div key={i} className="flex items-center gap-2">
                        <span className="text-xs font-mono text-neutral-400 w-6">#{i+1}</span>
                        <input
                          type="range"
                          min="0"
                          max="100"
                          step="0.1"
                          value={pos * 100}
                          onChange={(e) => {
                            const newPos = parseFloat(e.target.value) / 100;
                            const newPositions = [...slicePositions];
                            newPositions[i] = newPos;
                            setSlicePositions(newPositions.sort((a,b) => a - b));
                          }}
                          className="flex-1 h-1 bg-neutral-800 accent-red-500"
                        />
                        <span className="text-xs font-mono text-neutral-400 w-12">{Math.round(pos * 1000) / 10}%</span>
                        <button
                          onClick={() => {
                            setSlicePositions(prev => prev.filter((_, idx) => idx !== i));
                          }}
                          className="p-1 text-neutral-500 hover:text-red-400"
                        >
                          <Trash2 size={12} />
                        </button>
                      </div>
                    ))}
                  </div>
                </div>
              )}

              {/* Saved Programs */}
              {savedPrograms.length > 0 && (
                <div className="mt-2 bg-neutral-950 rounded-lg border border-neutral-800 p-3">
                  <div className="text-xs font-bold text-neutral-500 uppercase tracking-wider mb-2">Saved Programs</div>
                  <div className="space-y-1 max-h-32 overflow-y-auto custom-scrollbar">
                    {savedPrograms.map((program) => (
                      <div key={program.id} className="flex items-center justify-between">
                        <div className="min-w-0">
                          <div className="text-xs font-mono text-neutral-300 truncate">{program.name}</div>
                          <div className="text-[11px] font-mono text-neutral-500">{program.slicePositions.length} slices • {program.fileName}</div>
                        </div>
                        <div className="flex items-center gap-1">
                          <button
                            onClick={() => loadProgram(program)}
                            className="p-1 text-neutral-500 hover:text-green-400"
                            title="Load program"
                          >
                            <RotateCcw size={12} />
                          </button>
                          <button
                            onClick={() => deleteProgram(program.id)}
                            className="p-1 text-neutral-500 hover:text-red-400"
                            title="Delete program"
                          >
                            <Trash2 size={12} />
                          </button>
                        </div>
                      </div>
                    ))}
                  </div>
                </div>
              )}

              {/* Save Program Form */}
              {slicePositions.length > 0 && (
                <div className="mt-2 bg-neutral-950 rounded-lg border border-neutral-800 p-3">
                  <div className="text-xs font-bold text-neutral-500 uppercase tracking-wider mb-2">Save Program</div>
                  <div className="flex items-center gap-2">
                    <input
                      type="text"
                      value={newProgramName}
                      onChange={(e) => setNewProgramName(e.target.value)}
                      placeholder="Program name"
                      className="flex-1 bg-neutral-900 border border-neutral-800 rounded px-2 py-1 text-xs font-mono text-neutral-300 outline-none focus:border-brand"
                    />
                    <button
                      onClick={() => {
                        if (newProgramName.trim()) {
                          saveCurrentProgram(newProgramName.trim());
                          setNewProgramName('');
                        }
                      }}
                      className="flex items-center gap-1 px-3 py-1 bg-brand text-white text-xs font-bold uppercase rounded hover:opacity-90"
                    >
                      <Save size={12} /> Save
                    </button>
                  </div>
                </div>
              )}
            </>
          ) : (
            <div className="flex-1 flex items-center justify-center bg-neutral-950 rounded-lg border border-neutral-800 border-dashed">
              <span className="text-[13px] text-neutral-600 font-mono">
                Load audio to begin chopping
              </span>
            </div>
          )}

          {/* Stem chop progress / results */}
          {stemState.status !== "idle" && (
            <div className="mt-2 flex items-center gap-3 px-3 py-2 bg-neutral-950 rounded border border-neutral-800">
              {(stemState.status === "separating" ||
                stemState.status === "slicing") && (
                <>
                  <Loader2 size={12} className="animate-spin text-purple-400" />
                  <div className="flex-1">
                    <div className="h-1.5 bg-neutral-800 rounded-full overflow-hidden">
                      <div
                        className="h-full bg-linear-to-r from-purple-500 to-pink-500 rounded-full transition-all"
                        style={{ width: `${stemState.progress}%` }}
                      />
                    </div>
                  </div>
                  <span className="text-xs font-mono text-neutral-500">
                    {stemState.phase}
                  </span>
                </>
              )}
              {stemState.status === "done" && (
                <div className="flex flex-col gap-1.5">
                  <span className="text-[13px] font-bold text-emerald-400">
                    Stem programs ready:
                  </span>
                  {stemState.programs.map((p, pi) => (
                    <div key={p.name} className="flex items-center gap-2">
                      <span className="text-xs font-mono text-neutral-400 bg-neutral-900 px-2 py-0.5 rounded min-w-20">
                        {p.name} ({p.slices.length})
                      </span>
                      {(["A", "B", "C", "D"] as const).map((bank) => (
                        <button
                          key={bank}
                          onClick={() => loadProgramToBank(pi, bank)}
                          className={`text-xs font-bold px-1.5 py-0.5 rounded transition-colors ${
                            p.loadedToBank === bank
                              ? "bg-emerald-600 text-white"
                              : "bg-neutral-800 text-neutral-500 hover:bg-neutral-700 hover:text-white"
                          }`}
                        >
                          {p.loadedToBank === bank ? `✓ ${bank}` : bank}
                        </button>
                      ))}
                    </div>
                  ))}
                </div>
              )}
              {stemState.status === "error" && (
                <span className="text-[13px] text-red-400">
                  {stemState.error}
                </span>
              )}
            </div>
          )}
        </div>
      </div>
    </div>
  );
}

import React, { useState, useEffect, useCallback, useRef } from 'react';
import { STORAGE_KEYS } from '../lib/constants';
import { 
  Cpu, 
  Search, 
  RefreshCw, 
  Plus, 
  Settings, 
  ExternalLink, 
  Power, 
  Trash2,
  FolderOpen,
  CheckCircle2,
  AlertCircle,
  Loader2
} from 'lucide-react';
import {
  fetchPlugins,
  addPlugin,
  togglePlugin as apiTogglePlugin,
  deletePlugin as apiDeletePlugin,
  scanPluginsNative,
  isElectron,
  type Plugin,
  type VstScanResult,
} from '../lib/api';

const DEFAULT_PATHS = [
  'C:/Program Files/Common Files/VST3',
  'C:/Program Files/VSTPlugins',
];

const VST_OPTIONS_KEY = STORAGE_KEYS.VST_OPTIONS;

function loadVstOptions(): { scanOnStartup: boolean; sandboxMode: boolean; hiDpi: boolean } {
  try {
    const raw = localStorage.getItem(VST_OPTIONS_KEY);
    if (raw) return { scanOnStartup: true, sandboxMode: true, hiDpi: true, ...JSON.parse(raw) };
  } catch { /* ignore */ }
  return { scanOnStartup: true, sandboxMode: true, hiDpi: true };
}

export function VSTManager() {
  const [searchQuery, setSearchQuery] = useState('');
  const [vstOptions, setVstOptions] = useState(loadVstOptions);
  const [isScanning, setIsScanning] = useState(false);
  const [scanProgress, setScanProgress] = useState(0);
  const [scanStatus, setScanStatus] = useState('');
  const [plugins, setPlugins] = useState<Plugin[]>([]);
  const [isLoading, setIsLoading] = useState(true);
  const [paths, setPaths] = useState<string[]>(DEFAULT_PATHS);
  const [addingPath, setAddingPath] = useState(false);
  const [newPath, setNewPath] = useState('');
  const [browserMode, setBrowserMode] = useState(!isElectron());
  const [manualPluginName, setManualPluginName] = useState('');
  const [manualPluginVendor, setManualPluginVendor] = useState('');
  const [manualPluginType, setManualPluginType] = useState<'VST2' | 'VST3'>('VST3');
  const [manualPluginCategory, setManualPluginCategory] = useState('FX');
  const [showManualForm, setShowManualForm] = useState(false);
  const scanAbortRef = useRef(false);
  // Stable ref so the startup-scan effect can call handleScan without a dep cycle
  const handleScanRef = useRef<() => Promise<void>>(async () => {});

  const loadPlugins = useCallback(async () => {
    try {
      const data = await fetchPlugins();
      setPlugins(data);
    } catch {
      // keep empty on error
    } finally {
      setIsLoading(false);
    }
  }, []);

  useEffect(() => { loadPlugins(); }, [loadPlugins]);

  // Persist vstOptions to localStorage on change
  useEffect(() => {
    try { localStorage.setItem(VST_OPTIONS_KEY, JSON.stringify(vstOptions)); } catch { /* ignore */ }
  }, [vstOptions]);

  // Auto-scan on mount when scanOnStartup is enabled
  useEffect(() => {
    if (vstOptions.scanOnStartup) {
      // Defer until after the initial plugin load settles
      const id = setTimeout(() => { void handleScanRef.current(); }, 500);
      return () => clearTimeout(id);
    }
  // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []);

  const handleScan = async () => {
    if (isScanning) return;
    scanAbortRef.current = false;
    setIsScanning(true);
    setScanProgress(0);
    setScanStatus('Scanning directories...');

    try {
      if (isElectron()) {
        // ── Real scan via Electron IPC + native VST3 addon ──
        setScanProgress(10);
        setScanStatus('Querying native VST host...');
        const rawResults: VstScanResult[] = await scanPluginsNative(paths);

        if (scanAbortRef.current) return;
        setScanProgress(50);
        setScanStatus(`Found ${rawResults.length} plugins. Persisting to database...`);

        // Persist newly found plugins to the server DB (skip duplicates by path)
        const existingPaths = new Set(plugins.map(p => p.path).filter(Boolean));
        let added = 0;
        for (let i = 0; i < rawResults.length; i++) {
          if (scanAbortRef.current) break;
          const r = rawResults[i];
          if (!existingPaths.has(r.path)) {
            try {
              await addPlugin({
                name: r.name,
                vendor: r.vendor || 'Unknown',
                type: r.type,
                category: r.category || 'FX',
                isEnabled: true,
                latency: 0,
                path: r.path,
              } as Omit<Plugin, 'id'>);
              added++;
            } catch {
              // skip if server rejects (e.g. duplicate)
            }
          }
          setScanProgress(50 + Math.round((i / rawResults.length) * 45));
        }

        setScanProgress(100);
        setScanStatus(`Done. ${added} new plugins added.`);
        await loadPlugins();
      } else {
        // ── Browser fallback: REST API scan (server-side filesystem walk) ──
        setScanStatus('Requesting server scan...');
        setScanProgress(20);
        const resp = await fetch('/api/plugins/scan', {
          method: 'POST',
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify({ paths }),
        });
        if (scanAbortRef.current) return;
        if (!resp.ok) throw new Error('Server scan failed');
        setScanProgress(80);
        if (scanAbortRef.current) return;
        await loadPlugins();
        setScanProgress(100);
        setScanStatus('Done.');
      }
    } catch (err) {
      setScanStatus(`Error: ${err instanceof Error ? err.message : String(err)}`);
    } finally {
      setTimeout(() => {
        setIsScanning(false);
        setScanProgress(0);
        setScanStatus('');
      }, 2000);
    }
  };
  // Keep the ref pointing at the latest handleScan closure on every render
  handleScanRef.current = handleScan;

  const togglePlugin = async (id: string) => {
    const plugin = plugins.find(p => p.id === id);
    if (!plugin) return;
    const next = !plugin.isEnabled;
    setPlugins(prev => prev.map(p => p.id === id ? { ...p, isEnabled: next } : p));
    try {
      await apiTogglePlugin(id, next);
    } catch {
      setPlugins(prev => prev.map(p => p.id === id ? { ...p, isEnabled: plugin.isEnabled } : p));
    }
  };

  const removePlugin = async (id: string) => {
    const snapshot = plugins;
    setPlugins(prev => prev.filter(p => p.id !== id));
    try {
      await apiDeletePlugin(id);
    } catch {
      setPlugins(snapshot);
    }
  };

  const handleAddPath = () => {
    const trimmed = newPath.trim();
    if (trimmed && !paths.includes(trimmed)) {
      setPaths(prev => [...prev, trimmed]);
    }
    setNewPath('');
    setAddingPath(false);
  };

  const handleAddManualPlugin = async () => {
    if (!manualPluginName.trim()) return;

    try {
      const newPlugin: Omit<Plugin, 'id'> = {
        name: manualPluginName.trim(),
        vendor: manualPluginVendor.trim() || 'Unknown',
        type: manualPluginType,
        category: manualPluginCategory,
        isEnabled: true,
        latency: 0,
        path: `browser://${manualPluginName.toLowerCase().replace(/\s+/g, '-')}`,
      };

      await addPlugin(newPlugin);
      await loadPlugins();

      // Reset form
      setManualPluginName('');
      setManualPluginVendor('');
      setManualPluginType('VST3');
      setManualPluginCategory('FX');
      setShowManualForm(false);
    } catch (error) {
      console.error('Failed to add manual plugin:', error);
    }
  };

  const filteredPlugins = plugins.filter(p => 
    p.name.toLowerCase().includes(searchQuery.toLowerCase()) || 
    p.vendor.toLowerCase().includes(searchQuery.toLowerCase())
  );

  return (
    <div className="h-full flex flex-col gap-4">
      {/* Header */}
      <div className="flex justify-between items-center bg-bg-surface p-4 rounded-xl border border-border-main shadow-lg">
        <div className="flex items-center gap-4">
          <div className="w-10 h-10 bg-brand/20 rounded-lg flex items-center justify-center border border-brand/30">
            <Cpu className="text-brand" size={20} />
          </div>
           <div>
             <h2 className="text-sm font-bold text-neutral-200 uppercase tracking-widest">VST Plugin Manager</h2>
             <p className="text-[13px] text-neutral-500 font-mono uppercase">
               {isElectron() ? 'Native Host: VST 2.4 / 3.7 Active' : 'Browser Mode: UI Testing Only'}
             </p>
           </div>
        </div>

        <div className="flex items-center gap-3">
          {isScanning && (
            <div className="flex flex-col items-end gap-1 mr-4">
              <span className="text-xs font-mono text-brand uppercase">
                {scanStatus || `Scanning: ${scanProgress}%`}
              </span>
              <div className="w-40 h-1 bg-bg-main rounded-full overflow-hidden">
                <div className="h-full bg-brand transition-all duration-200" style={{ width: `${scanProgress}%` }}></div>
              </div>
            </div>
          )}
           <button 
             onClick={handleScan}
             disabled={isScanning}
             className={`flex items-center gap-2 px-4 py-2 rounded-lg font-bold text-xs uppercase transition-all ${
               isScanning ? 'bg-neutral-800 text-neutral-500' : 'bg-brand hover:opacity-90 text-white shadow-lg shadow-brand/20'
             }`}
           >
             <RefreshCw size={14} className={isScanning ? 'animate-spin' : ''} />
             {isScanning ? 'Scanning...' : isElectron() ? 'Scan for Plugins' : 'Test Server API'}
           </button>
        </div>
      </div>

      <div className="flex-1 flex gap-4 min-h-0">
        {/* Sidebar: Paths & Settings */}
        <div className="w-64 flex flex-col gap-4">
           <div className="bg-bg-surface rounded-xl border border-border-main p-4 flex flex-col gap-4 vignette">
             <div className="flex items-center justify-between">
               <span className="text-[13px] font-bold text-neutral-500 uppercase tracking-widest">
                 {isElectron() ? 'Plugin Paths' : 'Browser Mode'}
               </span>
               <Settings size={12} className="text-neutral-600" />
             </div>

             {!isElectron() && (
               <div className="bg-amber-500/10 border border-amber-500/20 rounded-lg p-3 mb-2">
                 <div className="flex items-center gap-2 mb-1">
                   <AlertCircle size={12} className="text-amber-500" />
                   <span className="text-[13px] font-bold text-amber-500 uppercase">Browser Mode Active</span>
                 </div>
                 <p className="text-xs text-amber-600">
                   Real VST processing requires Electron. You can add manual plugins for UI testing.
                 </p>
               </div>
             )}

             <div className="flex flex-col gap-2">
              {paths.map((p, i) => (
                <div key={i} className="flex items-center gap-2 text-[13px] text-neutral-400 bg-bg-main p-2 rounded border border-border-main group">
                  <FolderOpen size={12} className="text-neutral-600 shrink-0" />
                  <span className="truncate flex-1" title={p}>{p}</span>
                  <button
                    onClick={() => setPaths(prev => prev.filter((_, j) => j !== i))}
                    className="opacity-0 group-hover:opacity-100 text-neutral-600 hover:text-red-400 transition-all"
                    title="Remove path"
                  >
                    ×
                  </button>
                </div>
              ))}
              {addingPath ? (
                <div className="flex gap-1">
                  <input
                    autoFocus
                    value={newPath}
                    onChange={e => setNewPath(e.target.value)}
                    onKeyDown={e => { if (e.key === 'Enter') handleAddPath(); if (e.key === 'Escape') { setAddingPath(false); setNewPath(''); } }}
                    placeholder="C:/Program Files/..."
                    className="flex-1 bg-bg-main border border-brand/50 rounded px-2 py-1 text-[13px] text-neutral-300 outline-none"
                  />
                   <button onClick={handleAddPath} className="text-[13px] px-2 py-1 rounded bg-brand/20 text-brand border border-brand/30 hover:bg-brand/30 transition-colors">
                    Add
                  </button>
                </div>
              ) : (
                <button
                  onClick={() => setAddingPath(true)}
                  className="flex items-center justify-center gap-2 w-full py-2 border border-dashed border-neutral-700 rounded-lg text-[13px] text-neutral-500 hover:border-brand/50 hover:text-brand transition-all"
                >
                  <Plus size={12} /> Add Path
                </button>
              )}
            </div>
          </div>

          <div className="bg-neutral-900 rounded-xl border border-neutral-800 p-4 flex flex-col gap-3 vignette">
            <span className="text-[13px] font-bold text-neutral-500 uppercase tracking-widest">Options</span>
            <div className="flex flex-col gap-2">
              <label className="flex items-center justify-between p-2 bg-neutral-950 rounded border border-neutral-800 cursor-pointer">
                <span className="text-[13px] text-neutral-400">Scan on Startup</span>
                <input type="checkbox" className="accent-blue-500"
                  checked={vstOptions.scanOnStartup}
                  onChange={e => setVstOptions(prev => ({ ...prev, scanOnStartup: e.target.checked }))} />
              </label>
              <label className="flex items-center justify-between p-2 bg-neutral-950 rounded border border-neutral-800 cursor-pointer">
                <span className="text-[13px] text-neutral-400">Sandbox Mode</span>
                <input type="checkbox" className="accent-blue-500"
                  checked={vstOptions.sandboxMode}
