import { describe, it, expect, vi, beforeEach, afterEach } from 'vitest';
import { TBMAudioEngine } from './TBMAudioEngine';

// Mock AudioContext
const mockAudioContext = {
  createGain: vi.fn(() => ({
    connect: vi.fn(),
    disconnect: vi.fn(),
    gain: { 
      value: 1, 
      setValueAtTime: vi.fn(), 
      linearRampToValueAtTime: vi.fn(),
      cancelScheduledValues: vi.fn(),
      setTargetAtTime: vi.fn()
    }
  })),
  createBufferSource: vi.fn(() => ({
    connect: vi.fn(),
    disconnect: vi.fn(),
    start: vi.fn(),
    stop: vi.fn(),
    addEventListener: vi.fn(),
    removeEventListener: vi.fn(),
    buffer: null,
    playbackRate: { value: 1 },
    loop: false,
    onended: null
  })),
  createStereoPanner: vi.fn(() => ({
    connect: vi.fn(),
    disconnect: vi.fn(),
    pan: { value: 0 }
  })),
  createBiquadFilter: vi.fn(() => ({
    connect: vi.fn(),
    disconnect: vi.fn(),
    frequency: { value: 1000 },
    Q: { value: 1 },
    type: 'lowpass'
  })),
  createAnalyser: vi.fn(() => ({
    connect: vi.fn(),
    disconnect: vi.fn(),
    fftSize: 2048,
    frequencyBinCount: 1024,
    getFloatFrequencyData: vi.fn(),
    getByteFrequencyData: vi.fn(),
    getFloatTimeDomainData: vi.fn()
  })),
  createDynamicsCompressor: vi.fn(() => ({
    connect: vi.fn(),
    disconnect: vi.fn(),
    threshold: { value: -24 },
    knee: { value: 30 },
    ratio: { value: 12 },
    attack: { value: 0.003 },
    release: { value: 0.25 }
  })),
  createOscillator: vi.fn(() => ({
    connect: vi.fn(),
    disconnect: vi.fn(),
    start: vi.fn(),
    stop: vi.fn(),
    frequency: { value: 440 },
    type: 'sine'
  })),
  createBuffer: vi.fn((channels, length, sampleRate) => ({
    duration: length / sampleRate,
    sampleRate,
    length,
    numberOfChannels: channels,
    getChannelData: vi.fn(() => new Float32Array(length)),
    copyFromChannel: vi.fn(),
    copyToChannel: vi.fn()
  })),
  decodeAudioData: vi.fn().mockResolvedValue({
    duration: 2.0,
    sampleRate: 44100,
    length: 88200,
    numberOfChannels: 2,
    getChannelData: vi.fn(() => new Float32Array(88200))
  }),
  destination: {},
  sampleRate: 44100,
  currentTime: 1000,
  state: 'running',
  resume: vi.fn().mockResolvedValue(undefined),
  suspend: vi.fn().mockResolvedValue(undefined),
  close: vi.fn().mockResolvedValue(undefined),
  audioWorklet: {
    addModule: vi.fn().mockResolvedValue(undefined)
  }
} as any;

describe('TBMAudioEngine Performance Optimizations', () => {
  let engine: TBMAudioEngine;

  beforeEach(() => {
    vi.clearAllMocks();
    vi.useFakeTimers();
    engine = new TBMAudioEngine(mockAudioContext);
  });

  afterEach(() => {
    vi.useRealTimers();
    engine.dispose();
  });

  describe('reverse buffer cache', () => {
    it('caches reversed buffers to avoid reallocation', () => {
      const mockBuffer = {
        duration: 1.0,
        sampleRate: 44100,
        length: 44100,
        numberOfChannels: 2,
        getChannelData: vi.fn(() => new Float32Array(44100)),
        copyFromChannel: vi.fn(),
        copyToChannel: vi.fn()
      } as unknown as AudioBuffer;

      // First call should create buffer
      const result1 = (engine as any).reverseBuffer(mockBuffer);
      expect(mockAudioContext.createBuffer).toHaveBeenCalledTimes(1);

      // Second call should use cache
      const result2 = (engine as any).reverseBuffer(mockBuffer);
      expect(mockAudioContext.createBuffer).toHaveBeenCalledTimes(1);
      expect(result2).toBe(result1);
    });

    it('caches reversed buffers using WeakMap', () => {
      const createMockBuffer = (length: number) => ({
        duration: length / 44100,
        sampleRate: 44100,
        length,
        numberOfChannels: 2,
        getChannelData: vi.fn(() => new Float32Array(length)),
        copyFromChannel: vi.fn(),
        copyToChannel: vi.fn()
      } as unknown as AudioBuffer);

      // Create multiple unique buffers
      const buffers = Array.from({ length: 25 }, (_, i) => createMockBuffer(1000 + i));

      // Fill cache
      buffers.forEach(buffer => {
        (engine as any).reverseBuffer(buffer);
      });

      // Each unique buffer should create a new reversed buffer
      expect(mockAudioContext.createBuffer).toHaveBeenCalledTimes(25);
      // reverseBufferCache is a WeakMap, no size property
      expect((engine as any).reverseBufferCache).toBeInstanceOf(WeakMap);
    });
  });

  describe('analyser data throttling', () => {
    it('throttles analyser updates to reduce CPU usage', () => {
      const mockAnalyserData = new Uint8Array(1024);
      const mockGetByteFrequencyData = vi.fn((arr: Uint8Array) => {
        arr[0] = 128;
      });

      // Mock analyser
      (engine as any).analyser.getByteFrequencyData = mockGetByteFrequencyData;
      (engine as any).analyserData = mockAnalyserData;

      // First call should update
      const result1 = engine.getAnalyserData();
      expect(mockGetByteFrequencyData).toHaveBeenCalledTimes(1);
      expect(result1[0]).toBe(128);

      // Immediate second call should be throttled
      const result2 = engine.getAnalyserData();
      expect(mockGetByteFrequencyData).toHaveBeenCalledTimes(1);
      expect(result2[0]).toBe(128);

      // After interval, should update again
      vi.advanceTimersByTime(34); // > 33ms interval
      const result3 = engine.getAnalyserData();
      expect(mockGetByteFrequencyData).toHaveBeenCalledTimes(2);
      expect(result3[0]).toBe(128);
    });
  });

  describe('audio node cleanup', () => {
    it('safely cleans up audio nodes with stop method', () => {
      const mockNodeWithStop = {
        stop: vi.fn(),
        disconnect: vi.fn()
      };

      (engine as any).cleanupAudioNode(mockNodeWithStop);
      expect(mockNodeWithStop.stop).toHaveBeenCalled();
