// ─────────────────────────────────────────────────────────────────────────────
// Unified AudioContext integration
//
// Previously this module had its own `getTBMContext()` singleton which created
// a SEPARATE AudioContext from the one in AudioRouter.ts and MixerEngine.ts.
// Web Audio nodes CANNOT connect across different AudioContext instances, so
// TBM→Mixer routing was silently broken.
//
// FIX: We now import getUnifiedAudioContext() from AudioRouter (the single
// source of truth) and delegate to it. getTBMContext() is kept as a thin
// alias for backward compatibility.
// ─────────────────────────────────────────────────────────────────────────────

import { logger } from "./logger";
import {
  DEFAULT_BPM,
  SCHEDULE_AHEAD_S as _SCHEDULE_AHEAD_S,
  TIMER_INTERVAL_MS as _TIMER_INTERVAL_MS,
  BOUNCE_SAMPLE_RATE,
} from "./constants";

// Typed Window augmentation for Safari's webkit-prefixed AudioContext
declare global {
  interface Window {
    webkitAudioContext?: typeof AudioContext;
  }
}

// Dynamic import path — this file lives in modular-studio/tbm-ref/ and
// AudioRouter lives in Studio48-main/src/. When consumed from ModularModules.tsx
// inside Studio48-main, the bundler resolves this correctly.
// If this module is used standalone (without Studio48), we fall back to a local
// context so the TBM app still works on its own.

let _unifiedContextGetter: (() => AudioContext) | null = null;
let _fallbackContext: AudioContext | null = null;

/**
 * Call this early (e.g. from ModularModules.tsx) to wire TBM into the unified
 * AudioContext. After this call, getTBMContext() returns the shared context.
 */
export function setTBMContextProvider(provider: () => AudioContext): void {
  _unifiedContextGetter = provider;
}

/**
 * Returns the AudioContext that TBM should use for all audio operations.
 *
 * If setTBMContextProvider() was called (i.e. TBM is hosted inside the
 * Modular Studio shell), this returns the unified/shared context so that
 * cross-module routing works.
 *
 * If running standalone, it creates and caches its own context as a fallback.
 */
export function getTBMContext(): AudioContext {
  if (_unifiedContextGetter) {
    return _unifiedContextGetter();
  }
  // Standalone fallback — validate lifecycle before creating new context.
  // An AudioContext in "closed" state cannot be reused; replace it.
  // An AudioContext in "suspended" state is still usable (just needs resume).
  if (!_fallbackContext || _fallbackContext.state === "closed") {
    try {
      _fallbackContext = new (
        window.AudioContext || window.webkitAudioContext
      )();
    } catch (err) {
      logger.error("[TBMAudioEngine] Failed to create AudioContext:", err instanceof Error ? err : new Error(String(err)));
      throw err;
    }
  }
  return _fallbackContext;
}

export function disposeTBMContext(): void {
  // Only close the fallback context — the unified context is managed by
  // AudioRouter and must NOT be closed from here.
  if (_fallbackContext && !_unifiedContextGetter) {
    try {
      _fallbackContext.close();
    } catch (_e) {
      /* already closed */
    }
  }
  _fallbackContext = null;
}

// ─────────────────────────────────────────────────────────────────────────────
// Sample / Pad / Pattern types
// ─────────────────────────────────────────────────────────────────────────────

export interface Sample {
  id: string;
  name: string;
  buffer: AudioBuffer | null;
  category: string;
}

export type PadFilterType = "off" | "lp" | "hp" | "bp";

export interface Pad {
  id: number;
  name: string;
  sample: Sample | null;
  volume: number;
  pan: number;
  pitch: number;
  attack: number;
  release: number;
  reverse: boolean;
  start: number;
  end: number;
  /** When true, sample loops until manually stopped */
  loop: boolean;
  /** Filter type applied per-pad; 'off' = bypass */
  filterType: PadFilterType;
  /** Filter cutoff 0–127 (mapped to 20–20000 Hz exponentially) */
  filterCutoff: number;
  /** Filter resonance 0–127 (mapped to Q 0.1–30) */
  filterResonance: number;
  /** Choke group 1–4; null = no choke */
  chokeGroup: number | null;
  /** Per-pad swing amount (0-100) for sequencer timing */
  swing: number;
}

export interface Pattern {
  id: string;
  name: string;
  steps: boolean[][];
  length: number;
}

export interface DrumMachineEngineProps {
  pads?: Pad[];
  onPadTrigger?: (padId: number) => void;
}

// ─────────────────────────────────────────────────────────────────────────────
// TBMAudioEngine
// ─────────────────────────────────────────────────────────────────────────────

export class TBMAudioEngine {
  private context: AudioContext;
  private samples: Map<string, AudioBuffer> = new Map();
  private gainNode: GainNode;
  public masterGain: GainNode;
  private compressor: DynamicsCompressorNode;
  private activeSources: Map<AudioBufferSourceNode, () => void> = new Map();
  private disposed: boolean = false;

  // Choke group tracking: group number → active { source, gain } for fast stop
  private chokeNodes: Map<
    number,
    { source: AudioBufferSourceNode; gain: GainNode }
  > = new Map();

  // Persistent analyser — avoids creating a new AnalyserNode every frame,
  // which was a significant memory/GC overhead in the old code.
  private analyser: AnalyserNode;
  private analyserData: Uint8Array<ArrayBuffer>;

  // Per-pad persistent pan values (padIndex → pan -1..+1)
  private padPans: Map<number, number> = new Map();

  // Per-pad start offset values (padIndex → ratio 0-1)
  private startOffsets: Map<number, number> = new Map();

  // Per-pad persistent bus GainNodes — created lazily; all voices for a pad
  // route through their bus so external nodes (e.g. sidechain worklet) can tap
  // the pad's output without needing to intercept individual short-lived voices.
  private padBusGains: Map<number, GainNode> = new Map();

  // Per-pad volume overrides (padIndex → 0-1)
  private padVolumes: Map<number, number> = new Map();

  // Per-pad filter cutoff overrides (padIndex → 0-127)
  private padFilterCutoffs: Map<number, number> = new Map();

  // Last-triggered velocity per pad (for ModMatrix velocity source)
  public velocityMap: Map<number, number> = new Map();

  // Playback mode: poly allows simultaneous voices, mono/legato stop previous
  private polyMode: "poly" | "mono" | "legato" = "poly";

  // ── LFO engine: two independent LFO oscillators ──
  private lfoNodes: [OscillatorNode, OscillatorNode] | null = null;
  private lfoGains: [GainNode, GainNode] | null = null;
  private lfoPhases: [number, number] = [0, 0];
  private lfoRates: [number, number] = [1, 0.5];
  private lfoShapes: [
    "sine" | "square" | "sawtooth" | "triangle",
    "sine" | "square" | "sawtooth" | "triangle",
  ] = ["sine", "sine"];
  private lfoRafId: number | null = null;
  private lfoStartTime: number = 0;

  // Buffer replacement callbacks (e.g. WaveformVisualizer redraw)
  private bufferReplaceCallbacks: Map<number, (buffer: AudioBuffer) => void> =
    new Map();

  constructor(context: AudioContext) {
    this.context = context;

    logger.info("TBMAudioEngine initialized", {
      sampleRate: context.sampleRate,
      state: context.state,
    });

    this.masterGain = context.createGain();
    this.masterGain.gain.value = 0.8;

    this.compressor = context.createDynamicsCompressor();
    this.compressor.threshold.value = -6;
    this.compressor.knee.value = 30;
    this.compressor.ratio.value = 12;
    this.compressor.attack.value = 0.003;
    this.compressor.release.value = 0.25;

    this.masterGain.connect(this.compressor);
    this.compressor.connect(context.destination);

    this.gainNode = context.createGain();
    this.gainNode.connect(this.masterGain);

    // Persistent analyser connected once — reused on every getAnalyserData() call
    this.analyser = context.createAnalyser();
    this.analyser.fftSize = 2048;
    this.gainNode.connect(this.analyser);
    this.analyserData = new Uint8Array(
      new ArrayBuffer(this.analyser.frequencyBinCount),
    );
  }

  /**
   * Returns the AudioContext this engine is using.
   * Useful for callers that need to check context identity.
   */
  getContext(): AudioContext {
    return this.context;
  }

  /**
   * Returns a reference to the loaded samples map.
   * Used by BounceEngine to access the same sample buffers for offline rendering.
   */
  getSamples(): Map<string, AudioBuffer> {
    return this.samples;
  }

  // Maximum sample file size (50 MB) to prevent memory exhaustion from
  // excessively large fetches.
  private static readonly MAX_SAMPLE_SIZE = 50 * 1024 * 1024;

  async loadSample(id: string, url: string): Promise<void> {
    // ENGINE-6: bail early if disposed before starting async work
    if (this.disposed) return;
    try {
      const response = await fetch(url);
      // ENGINE-2: check response.ok — don't store garbage buffer on HTTP error
      if (!response.ok) {
        logger.error(`Failed to load sample ${id}: HTTP ${response.status}`);
        return;
      }
      // SAFETY: check Content-Length if available to reject oversized responses early
      const contentLength = response.headers.get('Content-Length');
      if (contentLength && parseInt(contentLength, 10) > TBMAudioEngine.MAX_SAMPLE_SIZE) {
        logger.error(`Sample ${id} too large (${contentLength} bytes, max ${TBMAudioEngine.MAX_SAMPLE_SIZE})`);
        return;
      }
      const arrayBuffer = await response.arrayBuffer();
      // Double-check actual size after download (Content-Length can be absent or wrong)
      if (arrayBuffer.byteLength > TBMAudioEngine.MAX_SAMPLE_SIZE) {
        logger.error(`Sample ${id} too large (${arrayBuffer.byteLength} bytes, max ${TBMAudioEngine.MAX_SAMPLE_SIZE})`);
        return;
      }
      // ENGINE-6: bail if disposed during async fetch
      if (this.disposed) return;
      const audioBuffer = await this.context.decodeAudioData(arrayBuffer);
      if (this.disposed) return;
      this.samples.set(id, audioBuffer);
    } catch (error) {
      logger.error(`Failed to load sample ${id}:`, error instanceof Error ? error : new Error(String(error)));
    }
  }

  async loadSampleFromFile(
    id: string,
    file: File,
  ): Promise<AudioBuffer | null> {
    // ENGINE-6: bail early if disposed before starting async work
    if (this.disposed) return null;
    // SAFETY: reject oversized files before reading into memory
    if (file.size > TBMAudioEngine.MAX_SAMPLE_SIZE) {
      logger.error(
        `Sample file ${id} too large (${file.size} bytes, max ${TBMAudioEngine.MAX_SAMPLE_SIZE})`,
      );
      return null;
    }
    try {
      const arrayBuffer = await file.arrayBuffer();
      // ENGINE-6: bail if disposed during async read
      if (this.disposed) return null;
      const audioBuffer = await this.context.decodeAudioData(arrayBuffer);
      if (this.disposed) return null;
      this.samples.set(id, audioBuffer);
      return audioBuffer;
    } catch (error) {
      logger.error(`Failed to load sample ${id}:`, error instanceof Error ? error : new Error(String(error)));
      return null;
    }
  }

  /**
   * Trigger a pad immediately or at a scheduled AudioContext time.
   * @param pad   Pad configuration
   * @param velocity  0-1 velocity
   * @param when  AudioContext.currentTime value to start playback (0 = now)
   */
  triggerPad(pad: Pad, velocity: number = 1, when: number = 0): void {
    if (this.disposed || !pad.sample) {
      logger.warn(
        "Attempted to trigger pad on disposed engine or pad without sample",
        {
          padId: pad.id,
          disposed: this.disposed,
          hasSample: !!pad.sample,
        },
      );
      return;
    }

    const buffer = this.samples.get(pad.sample.id);
    if (!buffer) {
      logger.warn("Sample buffer not found for pad", {
        padId: pad.id,
        sampleId: pad.sample.id,
      });
      return;
    }

    // ── Ensure LFOs are running ──
    if (!this.lfoNodes) this.startLFOs();

    // ── Store last velocity for ModMatrix velocity source ──
    this.velocityMap.set(pad.id, velocity);

    // ── Poly mode: stop active voices if mono/legato ──
    if (this.polyMode === "mono") {
      this.stopAll();
    } else if (this.polyMode === "legato") {
      // ENGINE-4: snapshot and clear the set before scheduling stops, so
      // onended callbacks don't race with new voices being added
      const legatoSnapshot = Array.from(this.activeSources.entries());
      this.activeSources.clear();
      // Short crossfade: ramp existing voices to zero quickly
      legatoSnapshot.forEach(([src, cleanupFn]) => {
        try {
          src.removeEventListener("ended", cleanupFn);
          src.stop(this.context.currentTime + 0.02);
        } catch (_e) {
          /* */
        }
      });
    }

    // ── Choke group: stop any currently-playing pad in the same group ──
    if (pad.chokeGroup !== null) {
      const prev = this.chokeNodes.get(pad.chokeGroup);
      if (prev) {
        try {
          // Fast fade-out (2ms) to avoid click
          const now = this.context.currentTime;
          prev.gain.gain.cancelScheduledValues(now);
          prev.gain.gain.setValueAtTime(prev.gain.gain.value, now);
          prev.gain.gain.linearRampToValueAtTime(0, now + 0.002);
          // Schedule stop slightly after fade
          prev.source.stop(now + 0.003);
        } catch (_e) {
          /* already stopped */
        }
        this.activeSources.delete(prev.source);
      }
    }

    const source = this.context.createBufferSource();

    // ── ADSR envelope via GainNode automation ──
    const padGain = this.context.createGain();
    const volumeOverride = this.padVolumes.get(pad.id);
    const effectiveVolume =
      volumeOverride !== undefined ? volumeOverride : pad.volume;
    const targetGain = effectiveVolume * velocity;
    // ENGINE-3: clamp scheduled time to at least now — prevents silent ADSR
    // failure when `when` is in the past (e.g. after tab suspend/resume)
    const startTime = Math.max(
      when > 0 ? when : this.context.currentTime,
      this.context.currentTime,
    );

    // Attack: ramp from 0 to target over pad.attack seconds
    padGain.gain.setValueAtTime(0, startTime);
    padGain.gain.linearRampToValueAtTime(targetGain, startTime + pad.attack);

    const padPan = this.context.createStereoPanner();
    const panOverride = this.padPans.get(pad.id);
    padPan.pan.value = panOverride !== undefined ? panOverride : pad.pan;

    source.playbackRate.value = Math.pow(2, pad.pitch / 12);

    // Reverse must be applied BEFORE start() — cannot change buffer after playback begins
    const playBuffer = pad.reverse ? this.reverseBuffer(buffer) : buffer;
    source.buffer = playBuffer;

    // ── Loop mode ──
    source.loop = pad.loop;

    // ── Build signal chain: source → [filter] → padGain → padPan → gainNode ──
    let lastNode: AudioNode = source;

    // ── Per-pad filter (BiquadFilterNode) ──
    let filterNode: BiquadFilterNode | null = null;
    if (pad.filterType !== "off") {
      filterNode = this.context.createBiquadFilter();
      // Map filter type
      switch (pad.filterType) {
        case "lp":
          filterNode.type = "lowpass";
          break;
        case "hp":
          filterNode.type = "highpass";
          break;
        case "bp":
          filterNode.type = "bandpass";
          break;
      }
      // Map cutoff 0–127 → 20–20000 Hz (exponential), allow override
      const cutoffOverride = this.padFilterCutoffs.get(pad.id);
      const effectiveCutoff =
        cutoffOverride !== undefined ? cutoffOverride : pad.filterCutoff;
      const minFreq = 20;
      const maxFreq = 20000;
      filterNode.frequency.value =
        minFreq * Math.pow(maxFreq / minFreq, effectiveCutoff / 127);
      // Map resonance 0–127 → Q 0.1–30
      filterNode.Q.value = 0.1 + (pad.filterResonance / 127) * 29.9;

      lastNode.connect(filterNode);
      lastNode = filterNode;
    }

    lastNode.connect(padGain);
    padGain.connect(padPan);
    // Route through persistent per-pad bus so external nodes (e.g. sidechain
    // worklet) can tap this pad's output without intercepting short-lived voices.
    const padBus = this._getOrCreatePadBus(pad.id);
    padPan.connect(padBus);

    // ── Schedule start with optional sub-range (start offset override takes priority) ──
    let sampleDuration: number | undefined;
    const startOffsetOverride = this.startOffsets.get(pad.id);
    const effectiveStart =
      startOffsetOverride !== undefined ? startOffsetOverride : pad.start;

    if (effectiveStart > 0 || pad.end < 1) {
      if (!pad.loop) source.loop = false;
      const startOffset = effectiveStart * playBuffer.duration;
      const endOffset = pad.end * playBuffer.duration;
      sampleDuration = endOffset - startOffset;
      source.start(startTime, startOffset, pad.loop ? undefined : sampleDuration);
    } else {
      source.start(startTime);
      sampleDuration = playBuffer.duration;
    }

    // ── Release envelope: schedule gain ramp-to-zero before sample ends ──
    // (only for non-looping one-shots where we know the end time)
    if (!pad.loop && pad.release > 0 && sampleDuration !== undefined) {
      const adjustedDuration = sampleDuration / Math.pow(2, pad.pitch / 12);
      const releaseStart = startTime + adjustedDuration - pad.release;
      if (releaseStart > startTime + pad.attack) {
        padGain.gain.setValueAtTime(targetGain, releaseStart);
        padGain.gain.linearRampToValueAtTime(0, releaseStart + pad.release);
      }
    }

    // ── Track choke group source ──
    if (pad.chokeGroup !== null) {
      this.chokeNodes.set(pad.chokeGroup, { source, gain: padGain });
    }

    const cleanup = () => {
      if (this.disposed) return;
      this.activeSources.delete(source);
      // Clear choke tracking if this source is still the active one for the group
      if (pad.chokeGroup !== null) {
        const current = this.chokeNodes.get(pad.chokeGroup);
        if (current?.source === source) {
          this.chokeNodes.delete(pad.chokeGroup);
        }
      }
      this.cleanupAudioNode(source);
      this.cleanupAudioNode(padGain);
      this.cleanupAudioNode(padPan);
      if (filterNode) {
        this.cleanupAudioNode(filterNode);
      }
    };

    // Use only one handler to avoid cleanup() firing twice
    source.addEventListener("ended", cleanup, { once: true });

    this.activeSources.set(source, cleanup);
  }

  // Cache reversed buffers keyed by the original AudioBuffer object itself
  // (WeakMap avoids key-collision bugs and auto-evicts when buffer is GC'd)
  private reverseBufferCache = new WeakMap<AudioBuffer, AudioBuffer>();
  private lastAnalyserUpdate = 0;
  private analyserUpdateInterval = 33; // ~30fps

  /** Helper to safely cleanup audio nodes */
  private cleanupAudioNode(node: AudioNode): void {
    try {
      if ('stop' in node && typeof node.stop === 'function') {
        node.stop();
      }
    } catch (_e) {
      /* already stopped */
    }
    try {
      node.disconnect();
    } catch (_e) {
      /* already disconnected */
    }
  }

  private reverseBuffer(buffer: AudioBuffer): AudioBuffer {
    const cached = this.reverseBufferCache.get(buffer);
    if (cached) return cached;

    const reversed = this.context.createBuffer(
      buffer.numberOfChannels,
      buffer.length,
      buffer.sampleRate,
    );

    for (let channel = 0; channel < buffer.numberOfChannels; channel++) {
      const data = buffer.getChannelData(channel);
      const reversedData = reversed.getChannelData(channel);
      for (let i = 0; i < buffer.length; i++) {
        reversedData[i] = data[buffer.length - 1 - i];
      }
    }

    this.reverseBufferCache.set(buffer, reversed);
    return reversed;
  }

  setMasterVolume(value: number): void {
    this.masterGain.gain.setValueAtTime(value, this.context.currentTime);
  }

  stopAll(): void {
    // Snapshot and clear BEFORE stopping, so onended callbacks
    // (which delete from activeSources) don't race with new pads.
    const snapshot = Array.from(this.activeSources.entries());
    this.activeSources.clear();
    for (const [source, cleanup] of snapshot) {
      try {
        // Remove the 'ended' event listener before stopping to prevent
        // the cleanup callback from firing during stopAll (it tries to
        // delete from activeSources which we already cleared).
        source.removeEventListener("ended", cleanup);
        this.cleanupAudioNode(source);
      } catch (_e) {
        // Source may have already stopped
      }
    }
  }

  /**
   * Returns frequency data from the persistent analyser node.
   *
   * This reuses a single AnalyserNode and a single Uint8Array, avoiding the
   * old pattern of creating + connecting + disconnecting a new analyser on
   * every call (which caused GC pressure and transient node leaks).
   */
  getAnalyserData(): Uint8Array<ArrayBuffer> {
    if (this.disposed) return new Uint8Array(new ArrayBuffer(0));

    // Throttle analyser updates to ~30fps to reduce CPU usage
    const now = Date.now();
    if (now - this.lastAnalyserUpdate < this.analyserUpdateInterval) {
      return this.analyserData;
    }

    this.lastAnalyserUpdate = now;
    this.analyser.getByteFrequencyData(this.analyserData);
    return this.analyserData;
  }

  /**
   * Expose the persistent AnalyserNode so external components (e.g. SpectrumAnalyzer)
   * can tap into the engine's audio signal without creating a separate AudioContext.
   */
  getAnalyser(): AnalyserNode {
    return this.analyser;
  }

  /**
   * Update a pad's ADSR values. These are stored by caller in the Pad object;
   * this method exists as a convenience for WaveformVisualizer and other components
   * to confirm the engine accepts all four parameters.
   * (Actual ADSR values are read from the Pad object on each triggerPad call.)
   */
  updatePadADSR(
    _padIndex: number,
    _adsr: { a: number; d: number; s: number; r: number },
  ): void {
    // ADSR is read live from the Pad config on triggerPad — no separate storage needed.
    // This method signature is provided so components can call it without type errors.
  }

  /** Register a callback that fires when replacePadBuffer is called for a given pad. */
  onBufferReplace(
    padIndex: number,
    callback: (buffer: AudioBuffer) => void,
  ): void {
    this.bufferReplaceCallbacks.set(padIndex, callback);
  }

  /** Remove a previously registered buffer-replace callback. */
  offBufferReplace(padIndex: number): void {
    this.bufferReplaceCallbacks.delete(padIndex);
  }

  /**
   * Set persistent pan for a pad (-1..+1). Applied on next triggerPad call.
   * The pad.pan value in the Pad object is the base; this overrides it.
   */
  setPadPan(padIndex: number, pan: number): void {
    this.padPans.set(padIndex, Math.max(-1, Math.min(1, pan)));
  }

  /**
   * Set start offset ratio (0-1) for a pad. Applied on next triggerPad call.
   * 0 = start from beginning, 0.5 = start from 50% through the buffer.
   */
  setPadStartOffset(padIndex: number, offset: number): void {
    this.startOffsets.set(padIndex, Math.max(0, Math.min(1, offset)));
  }

  /** Override pad volume (0-1). Applied on next triggerPad call. */
  setPadVolume(padIndex: number, volume: number): void {
    this.padVolumes.set(padIndex, Math.max(0, Math.min(1, volume)));
  }

  /** Override pad filter cutoff (0-127). Applied on next triggerPad call. */
  setPadFilterCutoff(padIndex: number, cutoff: number): void {
    this.padFilterCutoffs.set(padIndex, Math.max(0, Math.min(127, cutoff)));
  }

  /**
   * Get (or lazily create) the persistent bus GainNode for a pad.
   * All triggered voices for that pad connect through this node, so external
   * nodes (e.g. a sidechain AudioWorklet) can tap the pad's signal.
   */
  private _getOrCreatePadBus(padIndex: number): GainNode {
    let bus = this.padBusGains.get(padIndex);
    if (!bus) {
      bus = this.context.createGain();
      bus.gain.value = 1;
      bus.connect(this.gainNode);
      this.padBusGains.set(padIndex, bus);
    }
    return bus;
  }

  /**
   * Return the persistent output GainNode (bus) for a pad so external nodes
   * (e.g. a sidechain compressor AudioWorklet) can connect to it.
   * Returns null if no bus has been created yet (pad never triggered).
   * A pad that has never been triggered has no bus — callers should trigger the
   * pad at least once, or call getPadOutputNode after the first triggerPad.
   */
  getPadOutputNode(padIndex: number): GainNode | null {
    // Ensure the bus exists even before the first trigger so the sidechain can
    // connect before any audio plays.
    return this._getOrCreatePadBus(padIndex);
  }

  /**
   * Set playback mode.
   * - poly: all voices play simultaneously (default)
   * - mono: stop all active sources before triggering a new one
   * - legato: same as mono but with a short crossfade instead of hard stop
   */
  setPolyMode(mode: "poly" | "mono" | "legato"): void {
    this.polyMode = mode;
  }

  /**
   * Replace the AudioBuffer associated with a pad's current sample.
   * Used by denoise and resample operations to "print" FX into the buffer.
   * Fires any registered onBufferReplace callback so WaveformVisualizer redraws.
   */
  replacePadBuffer(
    padIndex: number,
    buffer: AudioBuffer,
    pads?: { id: number; sample: { id: string } | null }[],
  ): void {
    // If pads array supplied, use it to find the sampleId
    if (pads) {
      const pad = pads[padIndex];
      if (pad?.sample?.id) {
        this.samples.set(pad.sample.id, buffer);
      }
    } else {
      // Fallback: store under a synthetic key and fire the callback
      const syntheticId = `pad-replaced-${padIndex}`;
      this.samples.set(syntheticId, buffer);
    }
    this.bufferReplaceCallbacks.get(padIndex)?.(buffer);
  }

  // ── LFO Engine ──

  /** Start both LFO oscillators (call after AudioContext is running). */
  private startLFOs(): void {
    if (this.lfoNodes || this.disposed) return;

    const lfo0 = this.context.createOscillator();
    lfo0.type = this.lfoShapes[0];
    lfo0.frequency.value = this.lfoRates[0];

    const lfo1 = this.context.createOscillator();
    lfo1.type = this.lfoShapes[1];
    lfo1.frequency.value = this.lfoRates[1];

    // Connect to silent gain nodes (we read phase via rAF, not AudioParam)
    // ENGINE-5: connect the silent gain nodes to destination so the graph
    // stays alive and GC does not collect the LFO oscillator nodes.
    const g0 = this.context.createGain();
    g0.gain.value = 0;
    const g1 = this.context.createGain();
    g1.gain.value = 0;

    lfo0.connect(g0);
    lfo1.connect(g1);
    g0.connect(this.context.destination);
    g1.connect(this.context.destination);

    lfo0.start();
    lfo1.start();

    this.lfoNodes = [lfo0, lfo1];
    this.lfoGains = [g0, g1];
    this.lfoStartTime = this.context.currentTime;

    // Drive phase counters via rAF
    const tick = () => {
      // SAFETY: check disposed at the TOP of the callback to avoid
      // scheduling another frame on a disposed engine
      if (this.disposed) {
        this.lfoRafId = null;
        return;
      }
      const t = this.context.currentTime - this.lfoStartTime;
      this.lfoPhases[0] = (t * this.lfoRates[0]) % 1;
      this.lfoPhases[1] = (t * this.lfoRates[1]) % 1;
      this.lfoRafId = requestAnimationFrame(tick);
    };
    this.lfoRafId = requestAnimationFrame(tick);
  }

  /**
   * Get normalized LFO phase (0-1) for LFO index 0 or 1.
   * Used by ModMatrix to animate the LFO visualizer.
   */
  getLfoPhase(index: 0 | 1): number {
    // Ensure LFOs are running only if needed
    if (!this.lfoNodes && this.needsLFO()) this.startLFOs();
    return this.lfoPhases[index] ?? 0;
  }

  /** Check if LFOs are needed (called by any component using LFOs) */
  private needsLFO(): boolean {
    // Check if any component is actively using LFOs
    // For now, always return true to maintain compatibility
    // In future, track LFO usage with a counter
    return true;
  }

  /** Set LFO rate in Hz. */
  setLfoRate(index: 0 | 1, hz: number): void {
    this.lfoRates[index] = Math.max(0.01, hz);
    if (this.lfoNodes) {
      this.lfoNodes[index].frequency.setValueAtTime(
        this.lfoRates[index],
        this.context.currentTime,
      );
    }
  }

  /** Set LFO waveform shape. */
  setLfoShape(
    index: 0 | 1,
    shape: "sine" | "square" | "sawtooth" | "triangle",
  ): void {
    this.lfoShapes[index] = shape;
    if (this.lfoNodes) {
      this.lfoNodes[index].type = shape;
    }
  }

  dispose(): void {
    if (this.disposed) return;
    this.disposed = true;

    logger.info("TBMAudioEngine disposing");

    if (this.lfoRafId !== null) cancelAnimationFrame(this.lfoRafId);
    if (this.lfoNodes) {
      try {
        this.lfoNodes[0].stop();
      } catch (_e) {
        /* */
      }
      try {
        this.lfoNodes[1].stop();
      } catch (_e) {
        /* */
      }
      try {
        this.lfoNodes[0].disconnect();
      } catch (_e) {
        /* */
      }
      try {
        this.lfoNodes[1].disconnect();
      } catch (_e) {
        /* */
      }
    }
    if (this.lfoGains) {
      try {
        this.lfoGains[0].disconnect();
      } catch (_e) {
        /* */
      }
      try {
        this.lfoGains[1].disconnect();
      } catch (_e) {
        /* */
      }
    }

    this.stopAll();
    this.samples.clear();

    try {
      this.analyser.disconnect();
    } catch (_e) {
      /* ignore */
    }
    try {
      this.masterGain.disconnect();
    } catch (_e) {
      /* ignore */
    }
    try {
      this.compressor.disconnect();
    } catch (_e) {
      /* ignore */
    }
    try {
      this.gainNode.disconnect();
    } catch (_e) {
      /* ignore */
    }

    // Disconnect per-pad bus GainNodes
    for (const bus of this.padBusGains.values()) {
      try {
        bus.disconnect();
      } catch (_e) {
        /* ignore */
      }
    }
    this.padBusGains.clear();

    // ENGINE-1: Clear all remaining Maps to prevent stale references after disposal
    this.velocityMap.clear();
    this.padPans.clear();
    this.startOffsets.clear();
    this.padVolumes.clear();
    this.padFilterCutoffs.clear();
    this.bufferReplaceCallbacks.clear();
    this.chokeNodes.clear();
    // Drop reversed-buffer cache so GC can reclaim buffers
    this.reverseBufferCache = new WeakMap();
  }
}

export function createTBMAudioEngine(): TBMAudioEngine {
  const context = getTBMContext();
  return new TBMAudioEngine(context);
}

// ─────────────────────────────────────────────────────────────────────────────
// SynthEngine
// ─────────────────────────────────────────────────────────────────────────────

export interface SynthSettings {
  type: "sine" | "square" | "sawtooth" | "triangle";
  frequency: number;
  attack: number;
  decay: number;
  sustain: number;
  release: number;
  filterFreq: number;
  filterQ: number;
  distortion: number;
}

export class SynthEngine {
  private context: AudioContext;
  private masterGain: GainNode;
  private activeVoices: Map<
    number,
    {
      osc: OscillatorNode;
      gain: GainNode;
      filter: BiquadFilterNode;
      timeoutId: number;
    }
  > = new Map();
  private nextVoiceId = 0;
  private disposed: boolean = false;

  constructor(context: AudioContext) {
    this.context = context;
    this.masterGain = context.createGain();
    this.masterGain.gain.value = 0.5;
    this.masterGain.connect(context.destination);
  }

  /**
   * Returns the AudioContext this synth engine is using.
   */
  getContext(): AudioContext {
    return this.context;
  }

  noteOn(note: number, settings: SynthSettings, velocity: number = 1): number {
    if (this.disposed) return -1;

    // ENGINE-7: wrap voice ID at 2^31 - 1 to prevent unsafe integer overflow
    const voiceId = this.nextVoiceId;
    this.nextVoiceId = (this.nextVoiceId + 1) & 0x7fffffff;

    const osc = this.context.createOscillator();
    osc.type = settings.type;
    osc.frequency.value = this.midiToFreq(note);

    const filter = this.context.createBiquadFilter();
    filter.type = "lowpass";
    filter.frequency.value = settings.filterFreq;
    filter.Q.value = settings.filterQ;

    const gain = this.context.createGain();
    const now = this.context.currentTime;

    // Attack: ramp from 0 to peak (velocity)
    // Decay: ramp from peak down to sustain level
    gain.gain.setValueAtTime(0, now);
    gain.gain.linearRampToValueAtTime(velocity, now + settings.attack);
    gain.gain.linearRampToValueAtTime(
      velocity * settings.sustain,
      now + settings.attack + settings.decay,
    );

    osc.connect(filter);
    filter.connect(gain);
    gain.connect(this.masterGain);

    osc.start();

    const timeoutId = window.setTimeout(
      () => {
        // Safety net: if noteOff was never called (e.g. MIDI message lost),
        // stop the oscillator after attack+decay to prevent it running forever.
        if (this.activeVoices.has(voiceId)) {
          this.noteOff(voiceId, settings);
        }
      },
      (settings.attack + settings.decay + 30) * 1000, // 30s grace after AD phase
    );

    this.activeVoices.set(voiceId, { osc, gain, filter, timeoutId });
    return voiceId;
  }

  noteOff(voiceId: number, settings: SynthSettings): void {
    const voice = this.activeVoices.get(voiceId);
    if (!voice) return;

    // Cancel any pending timeout
    clearTimeout(voice.timeoutId);

    const now = this.context.currentTime;
    voice.gain.gain.cancelScheduledValues(now);
    voice.gain.gain.setValueAtTime(voice.gain.gain.value, now);
    voice.gain.gain.linearRampToValueAtTime(0, now + settings.release);

    const timeoutId = window.setTimeout(
      () => {
        if (this.disposed) return;
        try {
          voice.osc.stop();
        } catch (_e) {
          /* ignore */
        }
        try {
          voice.osc.disconnect();
        } catch (_e) {
          /* ignore */
        }
        try {
          voice.gain.disconnect();
        } catch (_e) {
          /* ignore */
        }
        try {
          voice.filter.disconnect();
        } catch (_e) {
          /* ignore */
        }
        this.activeVoices.delete(voiceId);
      },
      settings.release * 1000 + 100,
    );

    voice.timeoutId = timeoutId;
  }

  private midiToFreq(note: number): number {
    return 440 * Math.pow(2, (note - 69) / 12);
  }

  setMasterVolume(value: number): void {
    this.masterGain.gain.setValueAtTime(value, this.context.currentTime);
  }

  dispose(): void {
    if (this.disposed) return;
    this.disposed = true;

    this.activeVoices.forEach((voice) => {
      clearTimeout(voice.timeoutId);
      try {
        voice.osc.stop();
      } catch (_e) {
        /* ignore */
      }
      try {
        voice.osc.disconnect();
      } catch (_e) {
        /* ignore */
      }
      try {
        voice.gain.disconnect();
      } catch (_e) {
        /* ignore */
      }
      try {
        voice.filter.disconnect();
      } catch (_e) {
        /* ignore */
      }
    });
    this.activeVoices.clear();
    try {
      this.masterGain.disconnect();
    } catch (_e) {
      /* ignore */
    }
  }
}

export function createSynthEngine(): SynthEngine {
  const context = getTBMContext();
  return new SynthEngine(context);
}

// ─────────────────────────────────────────────────────────────────────────────
// Sequencer
// ─────────────────────────────────────────────────────────────────────────────

export interface SequencerState {
  isPlaying: boolean;
  bpm: number;
  currentStep: number;
  currentBeat: number;
  swing: number;
}

export class Sequencer {
  private engine: TBMAudioEngine;
  private context: AudioContext;
  private timerId: number | null = null;
  private patterns: Map<string, boolean[][]> = new Map();
  private currentPattern: string = "";
  private pads: Pad[] = [];
  private state: SequencerState = {
    isPlaying: false,
    bpm: DEFAULT_BPM,
    currentStep: 0,
    currentBeat: 0,
    swing: 0,
  };
  private onStep: ((step: number) => void) | null = null;
  private disposed: boolean = false;
  private pendingRafId: number | null = null;

  // Guard against race condition: if play() is called while a context.resume()
  // promise is still pending, a second scheduler could be started.
  private playRequestId: number = 0;

  // ── Mute / Solo state ──
  private muteMap: boolean[] = [];
  private soloSet: Set<number> = new Set();

  // ── Humanize ──
  private humanizeAmount: number = 0; // 0-1

  // ── Look-ahead scheduling state ──
  // We schedule audio events ahead of real-time using AudioContext.currentTime,
  // then use a coarse JS timer to keep the scheduler fed. This gives
  // sample-accurate timing while still driving the UI step indicator.
  private nextStepTime: number = 0; // AudioContext time of the next step
  private readonly SCHEDULE_AHEAD_S = _SCHEDULE_AHEAD_S;
  private readonly TIMER_INTERVAL_MS = _TIMER_INTERVAL_MS;

  constructor(engine: TBMAudioEngine, context: AudioContext) {
    this.engine = engine;
    this.context = context;
  }

  setPads(pads: Pad[]): void {
    this.pads = pads;
  }

  setPattern(id: string, steps: boolean[][]): void {
    this.patterns.set(id, steps);
    if (!this.currentPattern) {
      this.currentPattern = id;
    }
  }

  /** Return the pattern grid for the given id (defaults to current pattern) */
  getPattern(id?: string): boolean[][] | undefined {
    return this.patterns.get(id ?? this.currentPattern);
  }

  /** Return the current BPM */
  getBpm(): number {
    return this.state.bpm;
  }

  play(): void {
    if (this.disposed || this.state.isPlaying) return;

    // ENGINE-9: clear any lingering timer from a previous play/stop cycle
    // to prevent double-scheduling on rapid start/stop
    if (this.timerId !== null) {
      clearTimeout(this.timerId);
      this.timerId = null;
    }

    // Bump request counter so stale resume callbacks become no-ops
    const requestId = ++this.playRequestId;

    // ENGINE-10: await context resume so nextStepTime is set AFTER the context
    // is running — prevents a burst of past-timestamped events on resume
    if (this.context.state === "suspended") {
      this.context.resume().then(() => {
        if (this.disposed || this.state.isPlaying) return;
        if (requestId !== this.playRequestId) return; // stale callback
        this.state.isPlaying = true;
        this.nextStepTime = this.context.currentTime;
        this.scheduler();
      }).catch(() => {
        // If resume fails, start anyway — context may already be running
        if (this.disposed || this.state.isPlaying) return;
        if (requestId !== this.playRequestId) return; // stale callback
        this.state.isPlaying = true;
        this.nextStepTime = this.context.currentTime;
        this.scheduler();
      });
      return;
    }

    this.state.isPlaying = true;
    this.nextStepTime = this.context.currentTime;
    this.scheduler();
  }

  stop(): void {
    this.state.isPlaying = false;
    if (this.timerId !== null) {
      clearTimeout(this.timerId);
      this.timerId = null;
    }
    if (this.pendingRafId !== null) {
      cancelAnimationFrame(this.pendingRafId);
      this.pendingRafId = null;
    }
    this.state.currentStep = 0;
    this.state.currentBeat = 0;
    this.engine.stopAll();
  }

  setBpm(bpm: number): void {
    // Guard against NaN/Infinity — Math.max/min propagate NaN
    if (!Number.isFinite(bpm)) return;
    this.state.bpm = Math.max(20, Math.min(300, bpm));
  }

  setSwing(swing: number): void {
    this.state.swing = swing;
  }

  /**
   * Update mute/solo state from the DrumMachine UI.
   * @param muteMap  Array of booleans — true = muted for that pad index
   * @param soloSet  Set of pad indices that are solo'd. If non-empty, only those pads play.
   */
  setMuteState(muteMap: boolean[], soloSet: Set<number>): void {
    this.muteMap = muteMap;
    this.soloSet = soloSet;
  }

  /**
   * Set humanize amount (0-1).
   * Applies random timing and velocity variation to each scheduled step.
   */
  setHumanize(amount: number): void {
    this.humanizeAmount = Math.max(0, Math.min(1, amount));
  }

  /**
   * Look-ahead scheduler: schedules all steps whose audio time falls within
   * the look-ahead window, then sets a coarse JS timer to call itself again.
   * Audio events are pinned to AudioContext.currentTime so they fire with
   * sample-accurate precision regardless of JS timer jitter.
   */
  private scheduler(): void {
    if (this.disposed || !this.state.isPlaying) return;

    const deadline = this.context.currentTime + this.SCHEDULE_AHEAD_S;

    while (this.nextStepTime < deadline) {
      this.scheduleStep(this.nextStepTime);

      // Calculate the duration of one 16th-note step (seconds)
      // SAFETY: clamp BPM to >= 1 to prevent division by zero or Infinity
      const safeBpm = Math.max(1, this.state.bpm);
      const stepDurationS = 60 / safeBpm / 4;
      // Apply swing: delay odd steps by a fraction of one step duration
      const swingOffsetS =
        this.state.currentStep % 2 === 1
          ? (this.state.swing / 100) * stepDurationS * 0.5
          : 0;

      this.nextStepTime += stepDurationS + swingOffsetS;

      // Notify UI of the CURRENT step (before advancing) — use rAF to coalesce with next paint
      const step = this.state.currentStep;
      if (this.onStep) {
        const cb = this.onStep;
        this.pendingRafId = requestAnimationFrame(() => {
          this.pendingRafId = null;
          // Guard: sequencer may have been stopped or disposed between when the rAF was
          // queued and when it fires. Calling a stale callback would trigger
          // setState on a potentially unmounted component or reset the step indicator
          // after stop() has already cleared it.
          if (!this.disposed && this.state.isPlaying) cb(step);
        });
      }

      // Advance step counter AFTER UI notification
      // ENGINE-11: use the actual pattern step count instead of hardcoded 16
      // SAFETY: clamp patternLength to >= 1 to prevent NaN/Infinity from modulo 0
      const pattern = this.patterns.get(this.currentPattern);
      const patternLength = Math.max(1, pattern?.[0]?.length ?? 16);
      this.state.currentStep = (this.state.currentStep + 1) % patternLength;
      this.state.currentBeat = Math.floor(this.state.currentStep / 4);
    }

    // Compensate for timer drift: calculate when the next scheduler should run
    // based on AudioContext time, not wall clock time
    const now = this.context.currentTime;
    const nextSchedulerTime = this.nextStepTime - this.SCHEDULE_AHEAD_S;
    const timeUntilNextRun = Math.max(0, (nextSchedulerTime - now) * 1000);

    this.timerId = window.setTimeout(
      () => this.scheduler(),
      Math.min(this.TIMER_INTERVAL_MS, timeUntilNextRun),
    );
  }

  /** Schedule audio for a single step at the given AudioContext time. */
  private scheduleStep(when: number): void {
    const pattern = this.patterns.get(this.currentPattern);
    if (!pattern) return;

    const hasSolo = this.soloSet.size > 0;
    const stepDurationS = 60 / Math.max(1, this.state.bpm) / 4;

    pattern.forEach((padSteps, padIndex) => {
      if (!padSteps[this.state.currentStep] || !this.pads[padIndex]) return;

      // Mute/Solo logic: if any track is solo'd, only play solo'd tracks.
      // Otherwise, skip muted tracks.
      if (hasSolo) {
        if (!this.soloSet.has(padIndex)) return;
      } else {
        if (this.muteMap[padIndex]) return;
      }

      // ── Humanize: randomize timing and velocity ──
      let hitWhen = when;
      let hitVelocity = 1;
      if (this.humanizeAmount > 0) {
        const timingOffset =
          (Math.random() - 0.5) * 2 * this.humanizeAmount * stepDurationS * 0.5;
        hitWhen = Math.max(when, when + timingOffset);
        hitVelocity =
          1 -
          this.humanizeAmount * 0.3 +
          Math.random() * this.humanizeAmount * 0.6;
        hitVelocity = Math.max(0.1, Math.min(1, hitVelocity));
      }

      // Apply per-pad swing for odd steps (1, 3, 5, etc.)
      const pad = this.pads[padIndex];
      if (pad.swing && this.state.currentStep % 2 === 1) {
        const swingOffsetS = (pad.swing / 100) * stepDurationS * 0.5;
        hitWhen += swingOffsetS;
      }

      this.engine.triggerPad(pad, hitVelocity, hitWhen);
    });
  }

  setOnStep(callback: (step: number) => void): void {
    this.onStep = callback;
  }

  getState(): SequencerState {
    return { ...this.state };
  }

  dispose(): void {
    if (this.disposed) return;
    this.disposed = true;

    this.stop();
    this.patterns.clear();
    this.onStep = null;
  }
}

export function createSequencer(engine: TBMAudioEngine): Sequencer {
  // Reuse the same context as the engine — guaranteed to be the unified context
  const context = getTBMContext();
  return new Sequencer(engine, context);
}

// ─────────────────────────────────────────────────────────────────────────────
// DJ Engine — Deck, Scratch, Crossfader, Effects, Vinyl Simulation
//
// Architecture built for Web Audio API with classic DJ software algorithms.
// Key algorithms: alpha-beta filter scratching, crossfader curves,
// 3-band EQ, vinyl physics simulation, BPM sync.
// ─────────────────────────────────────────────────────────────────────────────

// ── Types ──

export type CrossfaderCurve = "linear" | "exponential" | "s_curve" | "hard_cut";
export type DJEffectType =
  | "echo"
  | "reverb"
  | "distortion"
  | "flanger"
  | "bitcrusher"
  | "autowah";

export interface DeckState {
  isPlaying: boolean;
  isScratching: boolean;
  /** Playback position in seconds */
  position: number;
  /** Current playback rate (1.0 = normal, negative = reverse) */
  playbackRate: number;
  /** BPM detected or user-set */
  bpm: number;
  /** Volume 0-1 */
  volume: number;
  /** EQ gains in dB: [low, mid, high] */
  eqGains: [number, number, number];
  /** Cue point positions in seconds */
  cuePoints: number[];
  /** Loop region [start, end] in seconds, null if no loop */
  loopRegion: [number, number] | null;
  /** Whether a buffer is loaded */
  hasTrack: boolean;
  /** Duration of loaded track in seconds */
  duration: number;
}

export interface VinylSimConfig {
  /** 0-1: higher = heavier platter, more resistance to speed changes */
  inertia: number;
  /** 0-1: higher = more friction when hand released, faster stop */
  friction: number;
  /** 0-1: amount of pitch warble on slow speeds */
  pitchDrift: number;
  /** 0-1: vinyl surface noise level */
  noiseLevel: number;
  /** 0-1: crackle rate */
  crackleRate: number;
  /** 0-1: drive/saturation amount */
  drive: number;
  /** 0-1: wear simulation amount */
  wear: number;
}

export interface ScratchEvent {
  type:
    | "forward"
    | "backward"
    | "fader_open"
    | "fader_close"
    | "hold"
    | "chirp"
    | "tear"
    | "stutter"
    | "one_shot";
  startBeat: number;
  durationBeats: number;
  speedMultiplier: number;
  faderPosition: number;
  stutterOverride?: { enabled: boolean; rate: string; dutyPercent: number };
  pitchOffsetSemitones?: number;
  gain?: number;
}

// ── 3-Band EQ ──

export class ThreeBandEQ {
  private context: AudioContext;
  private lowShelf: BiquadFilterNode;
  private midPeak: BiquadFilterNode;
  private highShelf: BiquadFilterNode;
  readonly input: BiquadFilterNode;
  readonly output: BiquadFilterNode;

  constructor(context: AudioContext) {
    this.context = context;

    // Low shelf: boosts/cuts below ~300Hz
    this.lowShelf = context.createBiquadFilter();
    this.lowShelf.type = "lowshelf";
    this.lowShelf.frequency.value = 300;
    this.lowShelf.gain.value = 0;

    // Mid peaking: centered at ~1kHz
    this.midPeak = context.createBiquadFilter();
    this.midPeak.type = "peaking";
    this.midPeak.frequency.value = 1000;
    this.midPeak.Q.value = 0.7;
    this.midPeak.gain.value = 0;

    // High shelf: boosts/cuts above ~3kHz
    this.highShelf = context.createBiquadFilter();
    this.highShelf.type = "highshelf";
    this.highShelf.frequency.value = 3000;
    this.highShelf.gain.value = 0;

    // Chain: low → mid → high
    this.lowShelf.connect(this.midPeak);
    this.midPeak.connect(this.highShelf);

    this.input = this.lowShelf;
    this.output = this.highShelf;
  }

  /** Set EQ gains in dB: [low, mid, high], range roughly -24 to +24 */
  setGains(low: number, mid: number, high: number): void {
    const now = this.context.currentTime;
    this.lowShelf.gain.setValueAtTime(low, now);
    this.midPeak.gain.setValueAtTime(mid, now);
    this.highShelf.gain.setValueAtTime(high, now);
  }

  getGains(): [number, number, number] {
    return [
      this.lowShelf.gain.value,
      this.midPeak.gain.value,
      this.highShelf.gain.value,
    ];
  }

  dispose(): void {
    try {
      this.lowShelf.disconnect();
    } catch (_e) {
      /* */
    }
    try {
      this.midPeak.disconnect();
    } catch (_e) {
      /* */
    }
    try {
      this.highShelf.disconnect();
    } catch (_e) {
      /* */
    }
  }
}

// ── DJ Effects Chain ──

export interface DJEffectSlot {
  type: DJEffectType;
  enabled: boolean;
  wetDry: number;
  params: Record<string, number>;
}

export class DJEffectsChain {
  private context: AudioContext;
  private slots: DJEffectSlotNode[] = [];
  private inputNode: GainNode;
  private outputNode: GainNode;
  readonly input: GainNode;
  readonly output: GainNode;

  constructor(context: AudioContext, slotCount: number = 4) {
    this.context = context;

    this.inputNode = context.createGain();
    this.outputNode = context.createGain();
    this.input = this.inputNode;
    this.output = this.outputNode;

    // Initialize empty slots — pass-through by default
    for (let i = 0; i < slotCount; i++) {
      this.slots.push(new DJEffectSlotNode(context));
    }

    // Chain slots: input → slot0 → slot1 → ... → output
    this.rebuildChain();
  }

  private rebuildChain(): void {
    // Disconnect everything
    try {
      this.inputNode.disconnect();
    } catch (_e) {
      /* */
    }
    for (const slot of this.slots) {
      try {
        slot.output.disconnect();
      } catch (_e) {
        /* */
      }
    }

    if (this.slots.length === 0) {
      this.inputNode.connect(this.outputNode);
      return;
    }

    this.inputNode.connect(this.slots[0].input);
    for (let i = 0; i < this.slots.length - 1; i++) {
      this.slots[i].output.connect(this.slots[i + 1].input);
    }
    this.slots[this.slots.length - 1].output.connect(this.outputNode);
  }

  setSlotEffect(
    index: number,
    type: DJEffectType,
    params?: Record<string, number>,
  ): void {
    if (index < 0 || index >= this.slots.length) return;
    this.slots[index].setEffect(type, params);
    // ENGINE-16: do NOT call rebuildChain() here — setEffect() only changes
    // the slot's internal dry/wet routing; the inter-slot connections are
    // stable and rebuilding them causes an audible glitch on every FX change.
    // rebuildChain() is only needed if slots are added or removed.
  }

  setSlotEnabled(index: number, enabled: boolean): void {
    if (index < 0 || index >= this.slots.length) return;
    this.slots[index].setEnabled(enabled);
  }

  setSlotWetDry(index: number, wetDry: number): void {
    if (index < 0 || index >= this.slots.length) return;
    this.slots[index].setWetDry(wetDry);
  }

  setSlotParam(index: number, param: string, value: number): void {
    if (index < 0 || index >= this.slots.length) return;
    this.slots[index].setParam(param, value);
  }

  getSlotState(index: number): DJEffectSlot | null {
    if (index < 0 || index >= this.slots.length) return null;
    return this.slots[index].getState();
  }

  dispose(): void {
    try {
      this.inputNode.disconnect();
    } catch (_e) {
      /* */
    }
    try {
      this.outputNode.disconnect();
    } catch (_e) {
      /* */
    }
    for (const slot of this.slots) slot.dispose();
    this.slots = [];
  }
}

/** A single effect slot with dry/wet parallel routing */

// Typed metadata storage for effect nodes — replaces unsafe (node as any).__property pattern
interface EffectNodeMeta {
  echoFeedback?: GainNode;
  flangerLFO?: OscillatorNode;
  flangerLFOGain?: GainNode;
}
const effectNodeMeta = new WeakMap<AudioNode, EffectNodeMeta>();

class DJEffectSlotNode {
  private context: AudioContext;
  private dryGain: GainNode;
  private wetGain: GainNode;
  private effectNodes: AudioNode[] = [];
  private effectType: DJEffectType | null = null;
  private enabled: boolean = false;
  private wetDry: number = 0.5;
  private params: Record<string, number> = {};
  readonly input: GainNode;
  readonly output: GainNode;

  constructor(context: AudioContext) {
    this.context = context;
    this.input = context.createGain();
    this.output = context.createGain();
    this.dryGain = context.createGain();
    this.wetGain = context.createGain();

    // Default: 100% dry (pass-through)
    this.dryGain.gain.value = 1;
    this.wetGain.gain.value = 0;

    // Dry path: input → dryGain → output
    this.input.connect(this.dryGain);
    this.dryGain.connect(this.output);
  }

  setEffect(type: DJEffectType, params?: Record<string, number>): void {
    this.clearEffect();
    this.effectType = type;
    this.params = params ?? {};

    // Rebuild dry/wet routing
    try {
      this.input.disconnect();
    } catch (_e) {
      /* */
    }
    try {
      this.dryGain.disconnect();
    } catch (_e) {
      /* */
    }
    try {
      this.wetGain.disconnect();
    } catch (_e) {
      /* */
    }

    // Dry path
    this.input.connect(this.dryGain);
    this.dryGain.connect(this.output);

    // Build wet effect chain
    const chain = this.buildEffectChain(type);
    this.effectNodes = chain;

    if (chain.length > 0) {
      // Wet path: input → chain[0] → ... → chain[n] → wetGain → output
      this.input.connect(chain[0]);
      for (let i = 0; i < chain.length - 1; i++) {
        chain[i].connect(chain[i + 1] as AudioNode);
      }
      chain[chain.length - 1].connect(this.wetGain);
      this.wetGain.connect(this.output);
    }

    this.updateWetDry();
  }

  private buildEffectChain(type: DJEffectType): AudioNode[] {
    const ctx = this.context;
    const p = this.params;

    switch (type) {
      case "echo": {
        const delay = ctx.createDelay(2.0);
        delay.delayTime.value = (p.delayMs ?? 125) / 1000;
        const feedback = ctx.createGain();
        // Clamp feedback to < 1.0 to prevent self-oscillation and dangerous volume buildup
        feedback.gain.value = Math.min(p.feedback ?? 0.35, 0.95);
        const outputGain = ctx.createGain();
        outputGain.gain.value = 1;
        // delay → feedback → delay (feedback loop)
        delay.connect(feedback);
        feedback.connect(delay);
        delay.connect(outputGain);
        // ENGINE-14: store feedback GainNode reference for real-time updates
        effectNodeMeta.set(delay, { echoFeedback: feedback });
        return [delay, outputGain];
      }
      case "reverb": {
        // Convolution reverb with generated impulse response
        const convolver = ctx.createConvolver();
        const irLength = ctx.sampleRate * (1 + (p.roomSize ?? 0.3) * 3);
        const irBuffer = ctx.createBuffer(2, irLength, ctx.sampleRate);
        for (let ch = 0; ch < 2; ch++) {
          const data = irBuffer.getChannelData(ch);
          const damping = p.damping ?? 0.5;
          for (let i = 0; i < irLength; i++) {
            data[i] =
              (Math.random() * 2 - 1) *
              Math.pow(1 - i / irLength, 1 + damping * 3);
          }
        }
        convolver.buffer = irBuffer;
        return [convolver];
      }
      case "distortion": {
        // Waveshaper distortion
        const shaper = ctx.createWaveShaper();
        const drive = p.drive ?? 1.4;
        const samples = 44100;
        const curve = new Float32Array(samples);
        for (let i = 0; i < samples; i++) {
          const x = (i * 2) / samples - 1;
          curve[i] = ((Math.PI + drive) * x) / (Math.PI + drive * Math.abs(x));
        }
        shaper.curve = curve;
        shaper.oversample = "4x";

        // Post-distortion tone filter
        const tone = ctx.createBiquadFilter();
        tone.type = "lowpass";
        tone.frequency.value = 2000 + (p.tone ?? 0.6) * 8000;
        tone.Q.value = 0.7;

        shaper.connect(tone);
        return [shaper, tone];
      }
      case "flanger": {
        const delay = ctx.createDelay(0.02);
        delay.delayTime.value = 0.005;
        const lfo = ctx.createOscillator();
        lfo.type = "sine";
        lfo.frequency.value = p.rateHz ?? 0.4;
        const lfoGain = ctx.createGain();
        lfoGain.gain.value = (p.depth ?? 0.5) * 0.003;
        lfo.connect(lfoGain);
        lfoGain.connect(delay.delayTime);
        lfo.start();

        const feedback = ctx.createGain();
        // ENGINE-15: clamp flanger feedback strictly below 1.0 to prevent self-oscillation
        feedback.gain.value = Math.min(Math.max(p.feedback ?? 0.4, -0.95), 0.95);
        delay.connect(feedback);
        feedback.connect(delay);

        // Store LFO for disposal
        effectNodeMeta.set(delay, { flangerLFO: lfo, flangerLFOGain: lfoGain });

        return [delay];
      }
      case "bitcrusher": {
        // Bitcrusher via WaveShaperNode (quantization effect)
        // For true bitcrushing we'd need AudioWorklet, but this gives a similar lo-fi feel
        const shaper = ctx.createWaveShaper();
        const bits = p.bits ?? 12;
        const steps = Math.pow(2, bits);
        const samples = 44100;
        const curve = new Float32Array(samples);
        for (let i = 0; i < samples; i++) {
          const x = (i * 2) / samples - 1;
          curve[i] = Math.round(x * steps) / steps;
        }
        shaper.curve = curve;

        // Sample rate reduction via lowpass
        const srReduction = p.sampleRateReduction ?? 1.0;
        const lpf = ctx.createBiquadFilter();
        lpf.type = "lowpass";
        lpf.frequency.value = (ctx.sampleRate / 2) * srReduction;

        shaper.connect(lpf);
        return [shaper, lpf];
      }
      case "autowah": {
        // Envelope follower → bandpass filter
        const bp = ctx.createBiquadFilter();
        bp.type = "bandpass";
        bp.frequency.value =
          (p.freqMin ?? 400) +
          ((p.freqMax ?? 3000) - (p.freqMin ?? 400)) * (p.sensitivity ?? 0.7);
        bp.Q.value = 5;
        return [bp];
      }
      default:
        return [];
    }
  }

  setEnabled(enabled: boolean): void {
    this.enabled = enabled;
    this.updateWetDry();
  }

  setWetDry(wetDry: number): void {
    this.wetDry = Math.max(0, Math.min(1, wetDry));
    this.updateWetDry();
  }

  setParam(param: string, value: number): void {
    this.params[param] = value;
    // For real-time param changes on echo delay, reverb, etc.
    this.updateEffectParam(param, value);
  }

  private updateEffectParam(param: string, value: number): void {
    if (!this.effectType || this.effectNodes.length === 0) return;
    const now = this.context.currentTime;

    switch (this.effectType) {
      case "echo": {
        const delay = this.effectNodes[0] as DelayNode;
        if (param === "delayMs")
          delay.delayTime.setValueAtTime(value / 1000, now);
        // ENGINE-14: handle real-time echo feedback changes
        if (param === "feedback") {
          // effectNodes layout: [delay, outputGain]; feedback GainNode is
          // connected internally. We need to find it via the delay's connections.
          // Since we stored it in buildEffectChain as delay→feedback→delay,
          // we access it via a stored reference on the delay node.
          const feedbackGain = effectNodeMeta.get(delay)?.echoFeedback;
          if (feedbackGain) {
            feedbackGain.gain.setValueAtTime(Math.min(value, 0.95), now);
          }
        }
        break;
      }
      case "distortion": {
        if (param === "tone" && this.effectNodes[1]) {
          (this.effectNodes[1] as BiquadFilterNode).frequency.setValueAtTime(
            2000 + value * 8000,
            now,
          );
        }
        break;
      }
      case "flanger": {
        const delay = this.effectNodes[0] as DelayNode;
        if (param === "rateHz") {
          const lfo = effectNodeMeta.get(delay)?.flangerLFO;
          if (lfo) lfo.frequency.setValueAtTime(value, now);
        }
        if (param === "depth") {
          const lfoGain = effectNodeMeta.get(delay)?.flangerLFOGain;
          if (lfoGain) lfoGain.gain.setValueAtTime(value * 0.003, now);
        }
        break;
      }
      default:
        break;
    }
  }

  private updateWetDry(): void {
    const now = this.context.currentTime;
    if (!this.enabled || !this.effectType) {
      this.dryGain.gain.setValueAtTime(1, now);
      this.wetGain.gain.setValueAtTime(0, now);
    } else {
      this.dryGain.gain.setValueAtTime(1 - this.wetDry, now);
      this.wetGain.gain.setValueAtTime(this.wetDry, now);
    }
  }

  getState(): DJEffectSlot {
    return {
      type: this.effectType ?? "echo",
      enabled: this.enabled,
      wetDry: this.wetDry,
      params: { ...this.params },
    };
  }

  private clearEffect(): void {
    for (const node of this.effectNodes) {
      try {
        // Stop oscillators (flanger LFO) using typed metadata
        const meta = effectNodeMeta.get(node);
        if (meta?.flangerLFO) {
          try {
            meta.flangerLFO.stop();
          } catch (_e) {
            /* */
          }
          try {
            meta.flangerLFO.disconnect();
          } catch (_e) {
            /* */
          }
        }
        if (meta?.flangerLFOGain) {
          try {
            meta.flangerLFOGain.disconnect();
          } catch (_e) {
            /* */
          }
        }
        // Clean up echo feedback reference
        if (meta?.echoFeedback) {
          try {
            meta.echoFeedback.disconnect();
          } catch (_e) {
            /* */
          }
        }
        // Remove metadata entry
        effectNodeMeta.delete(node);
        node.disconnect();
      } catch (_e) {
        /* */
      }
    }
    this.effectNodes = [];
    this.effectType = null;
  }

  dispose(): void {
    this.clearEffect();
    try {
      this.input.disconnect();
    } catch (_e) {
      /* */
    }
    try {
      this.output.disconnect();
    } catch (_e) {
      /* */
    }
    try {
      this.dryGain.disconnect();
    } catch (_e) {
      /* */
    }
    try {
      this.wetGain.disconnect();
    } catch (_e) {
      /* */
    }
  }
}

// ── Crossfader ──

export class CrossfaderEngine {
  private context: AudioContext;
  private gainA: GainNode;
  private gainB: GainNode;
  private curve: CrossfaderCurve = "exponential";
  private position: number = 0.5; // 0 = full A, 1 = full B

  readonly inputA: GainNode;
  readonly inputB: GainNode;
  readonly output: GainNode;

  constructor(context: AudioContext) {
    this.context = context;

    this.gainA = context.createGain();
    this.gainB = context.createGain();
    this.output = context.createGain();
    this.inputA = this.gainA;
    this.inputB = this.gainB;

    this.gainA.connect(this.output);
    this.gainB.connect(this.output);

    this.applyPosition();
  }

  setPosition(position: number): void {
    this.position = Math.max(0, Math.min(1, position));
    this.applyPosition();
  }

  getPosition(): number {
    return this.position;
  }

  setCurve(curve: CrossfaderCurve): void {
    this.curve = curve;
    this.applyPosition();
  }

  getCurve(): CrossfaderCurve {
    return this.curve;
  }

  /**
   * Calculate gain values for A and B channels based on crossfader position and curve.
   * Standard DJ crossfader curve implementations (linear, equal-power, hard-cut).
   */
  private applyPosition(): void {
    const p = this.position;
    let gainAVal: number;
    let gainBVal: number;

    switch (this.curve) {
      case "linear":
        gainAVal = 1 - p;
        gainBVal = p;
        break;

      case "exponential":
        // Power curve: constant power crossfade
        gainAVal = Math.cos(p * Math.PI * 0.5);
        gainBVal = Math.sin(p * Math.PI * 0.5);
        break;

      case "s_curve":
        // S-curve: both channels at full in the center, fade at edges
        gainAVal = p <= 0.5 ? 1 : Math.cos((p - 0.5) * Math.PI);
        gainBVal = p >= 0.5 ? 1 : Math.sin(p * Math.PI);
        break;

      case "hard_cut":
        // Hard cut: instant transition at center point
        gainAVal = p < 0.5 ? 1 : 0;
        gainBVal = p >= 0.5 ? 1 : 0;
        break;

      default:
        gainAVal = 1 - p;
        gainBVal = p;
    }

    const now = this.context.currentTime;
    // Use setTargetAtTime for smooth crossfader movement (2ms time constant)
    this.gainA.gain.setTargetAtTime(gainAVal, now, 0.002);
    this.gainB.gain.setTargetAtTime(gainBVal, now, 0.002);
  }

  dispose(): void {
    try {
      this.gainA.disconnect();
    } catch (_e) {
      /* */
    }
    try {
      this.gainB.disconnect();
    } catch (_e) {
      /* */
    }
    try {
      this.output.disconnect();
    } catch (_e) {
      /* */
    }
  }
}

// ── Vinyl Simulation ──

export class VinylSimulation {
  private context: AudioContext;
  private noiseSource: AudioBufferSourceNode | null = null;
  private noiseGain: GainNode;
  private noiseFilter: BiquadFilterNode;
  private driftLFO: OscillatorNode | null = null;
  private driftGain: GainNode;
  private crackleTimer: number | null = null;
  private crackleGain: GainNode;
  private driveShaper: WaveShaperNode;
  private config: VinylSimConfig;
  readonly noiseOutput: GainNode;
  private disposed: boolean = false;
  // Pre-allocated crackle impulse buffer pool
  private _cracklePool: AudioBuffer[] | null = null;
  private _cracklePoolIdx: number = 0;

  constructor(context: AudioContext, config?: Partial<VinylSimConfig>) {
    this.context = context;
    this.config = {
      inertia: 0.72,
      friction: 0.85,
      pitchDrift: 0.003,
      noiseLevel: 0.3,
      crackleRate: 0.04,
      drive: 0,
      wear: 0,
      ...config,
    };

    // Noise output — mix this into the deck output
    this.noiseGain = context.createGain();
    this.noiseGain.gain.value = 0;

    this.noiseFilter = context.createBiquadFilter();
    this.noiseFilter.type = "bandpass";
    this.noiseFilter.frequency.value = 1500;
    this.noiseFilter.Q.value = 0.5;

    // Drive waveshaper: sits between filter and output gain.
    // When drive = 0 the curve is linear (passthrough).
    this.driveShaper = context.createWaveShaper();
    this.driveShaper.oversample = "2x";
    this.buildDriveCurve(this.config.drive);

    this.noiseFilter.connect(this.driveShaper);
    this.driveShaper.connect(this.noiseGain);
    this.noiseOutput = this.noiseGain;

    // Drift LFO — connect to playbackRate externally
    this.driftGain = context.createGain();
    this.driftGain.gain.value = 0;

    // Crackle gain
    this.crackleGain = context.createGain();
    this.crackleGain.gain.value = 0;
    this.crackleGain.connect(this.noiseGain);
  }

  /** Start vinyl noise and crackle. Call after AudioContext is running. */
  start(): void {
    if (this.disposed) return;

    // ENGINE-18: stop any previously running sources before creating new ones
    // to prevent duplicate noise when start() is called more than once
    this.stop();

    // Generate noise buffer (2 seconds of white noise)
    const bufferLength = this.context.sampleRate * 2;
    const noiseBuffer = this.context.createBuffer(
      1,
      bufferLength,
      this.context.sampleRate,
    );
    const data = noiseBuffer.getChannelData(0);
    for (let i = 0; i < bufferLength; i++) {
      data[i] = Math.random() * 2 - 1;
    }

    this.noiseSource = this.context.createBufferSource();
    this.noiseSource.buffer = noiseBuffer;
    this.noiseSource.loop = true;
    this.noiseSource.connect(this.noiseFilter);
    this.noiseSource.start();

    // Drift LFO
    this.driftLFO = this.context.createOscillator();
    this.driftLFO.type = "sine";
    this.driftLFO.frequency.value = 0.7;
    this.driftLFO.connect(this.driftGain);
    this.driftLFO.start();

    // Crackle — periodic random impulses
    this.startCrackle();

    this.applyConfig();
  }

  private startCrackle(): void {
    if (this.disposed || this.config.crackleRate <= 0) return;

    const scheduleNext = () => {
      if (this.disposed) return;
      // Random interval based on crackle rate
      const interval =
        (1000 / Math.max(0.01, this.config.crackleRate * 10)) *
        (0.5 + Math.random());
      this.crackleTimer = window.setTimeout(() => {
        if (this.disposed) return;
        this.playCrackle();
        scheduleNext();
      }, interval);
    };
    scheduleNext();
  }

  private playCrackle(): void {
    if (this.disposed) return;
    const ctx = this.context;
    const now = ctx.currentTime;

    // Re-use a pool of short noise buffers instead of allocating a new one
    // per impulse to reduce GC pressure.
    if (!this._cracklePool) {
      const poolSize = 8;
      this._cracklePool = [];
      for (let i = 0; i < poolSize; i++) {
        const len = Math.floor(ctx.sampleRate * 0.003); // ~3ms max
        this._cracklePool.push(ctx.createBuffer(1, len, ctx.sampleRate));
      }
      this._cracklePoolIdx = 0;
    }

    const pool = this._cracklePool;
    const buffer = pool[this._cracklePoolIdx % pool.length];
    this._cracklePoolIdx = (this._cracklePoolIdx + 1) % pool.length;

    // Fill with random noise (varies per use)
    const data = buffer.getChannelData(0);
    const usedLen = Math.max(1, Math.floor(data.length * (0.33 + Math.random() * 0.67)));
    for (let i = 0; i < data.length; i++) {
      data[i] = i < usedLen ? (Math.random() * 2 - 1) * (1 - i / usedLen) : 0;
    }

    const source = ctx.createBufferSource();
    source.buffer = buffer;
    const gain = ctx.createGain();
    gain.gain.setValueAtTime(this.config.crackleRate * 0.3, now);
    gain.gain.linearRampToValueAtTime(0, now + 0.005);

    source.connect(gain);
    gain.connect(this.noiseGain);
    source.start(now);
    source.addEventListener(
      "ended",
      () => {
        try {
          source.disconnect();
        } catch (_e) {
          /* */
        }
        try {
          gain.disconnect();
        } catch (_e) {
          /* */
        }
      },
      { once: true },
    );
  }

  /** Get the drift LFO GainNode — connect to AudioBufferSourceNode.playbackRate */
  getDriftOutput(): GainNode {
    return this.driftGain;
  }

  setConfig(config: Partial<VinylSimConfig>): void {
    const prevCrackleRate = this.config.crackleRate;
    Object.assign(this.config, config);
    this.applyConfig();
    // Restart crackle timer if rate changed significantly
    if (Math.abs(this.config.crackleRate - prevCrackleRate) > 0.001) {
      if (this.crackleTimer !== null) {
        clearTimeout(this.crackleTimer);
        this.crackleTimer = null;
      }
      this.startCrackle();
    }
  }

  getConfig(): VinylSimConfig {
    return { ...this.config };
  }

  /** Build a soft-clip waveshaper curve. drive 0 = linear, drive 1 = heavy saturation. */
  private buildDriveCurve(drive: number): void {
    const n = 256;
    const curve = new Float32Array(n);
    const amount = Math.max(0, Math.min(1, drive)) * 50 + 1;
    for (let i = 0; i < n; i++) {
      const x = (i * 2) / n - 1;
      curve[i] = ((Math.PI + amount) * x) / (Math.PI + amount * Math.abs(x));
    }
    this.driveShaper.curve = curve;
  }

  private applyConfig(): void {
    const now = this.context.currentTime;
    // Noise level: config.noiseLevel maps to gain
    this.noiseGain.gain.setValueAtTime(this.config.noiseLevel * 0.15, now);
    // Drift amount
    this.driftGain.gain.setValueAtTime(this.config.pitchDrift, now);
    // Wear: lower bandpass frequency + wider Q → more rumble, duller surface noise
    const wearAmount = Math.max(0, Math.min(1, this.config.wear));
    const freq = 1500 - wearAmount * 1100; // 1500 Hz (new) → 400 Hz (worn)
    const q = 0.5 + wearAmount * 1.5; // 0.5 (clean) → 2.0 (resonant rumble)
    this.noiseFilter.frequency.setValueAtTime(freq, now);
    this.noiseFilter.Q.setValueAtTime(q, now);
    // Boost noise level slightly with wear (old vinyl is louder)
    const wearNoiseBoost = 1 + wearAmount * 0.6;
    this.noiseGain.gain.setValueAtTime(
      this.config.noiseLevel * 0.15 * wearNoiseBoost,
      now,
    );
    // Drive: update waveshaper curve
    this.buildDriveCurve(this.config.drive);
  }

  /**
   * Apply vinyl physics to compute the next velocity.
   * Uses an alpha-beta filter with platter inertia model.
   *
   * @param currentVelocity Current playback rate
   * @param targetVelocity  Desired playback rate (from user input)
   * @param isHeld          Whether user is actively touching/controlling
   * @param dt              Time delta in seconds
   * @returns New velocity value
   */
  computeVelocity(
    currentVelocity: number,
    targetVelocity: number,
    isHeld: boolean,
    dt: number,
  ): number {
    if (isHeld) {
      // Inertia: lerp toward target velocity. Higher inertia = slower response.
      const lerpFactor = 1 - this.config.inertia;
      return currentVelocity + (targetVelocity - currentVelocity) * lerpFactor;
    } else {
      // Friction: exponential decay toward 0. Higher friction = faster stop.
      const decay = Math.pow(1 - this.config.friction, dt * 60);
      const v = currentVelocity * decay;
      // Stop threshold
      if (Math.abs(v) < 0.001) return 0;
      return v;
    }
  }

  stop(): void {
    if (this.crackleTimer !== null) {
      clearTimeout(this.crackleTimer);
      this.crackleTimer = null;
    }
    try {
      this.noiseSource?.stop();
    } catch (_e) {
      /* */
    }
    try {
      this.noiseSource?.disconnect();
    } catch (_e) {
      /* */
    }
    try {
      this.driftLFO?.stop();
    } catch (_e) {
      /* */
    }
    try {
      this.driftLFO?.disconnect();
    } catch (_e) {
      /* */
    }
    this.noiseSource = null;
    this.driftLFO = null;
  }

  dispose(): void {
    if (this.disposed) return;
    this.disposed = true;
    this.stop();
    try {
      this.noiseGain.disconnect();
    } catch (_e) {
      /* */
    }
    try {
      this.noiseFilter.disconnect();
    } catch (_e) {
      /* */
    }
    try {
      this.driveShaper.disconnect();
    } catch (_e) {
      /* */
    }
    try {
      this.driftGain.disconnect();
    } catch (_e) {
      /* */
    }
    try {
      this.crackleGain.disconnect();
    } catch (_e) {
      /* */
    }
  }
}

// ── Scratch Engine ──
// Implements an alpha-beta filter for scratch position tracking.

export class ScratchEngineCore {
  // Alpha-beta filter state
  private position: number = 0;
  private velocity: number = 0;
  private alpha: number = 0.125;
  private beta: number;
  private readonly intervalsPerRevolution: number = 128;
  private readonly rpm: number = 33.333;

  constructor(
    alpha: number = 0.125,
    intervalsPerRevolution: number = 128,
    rpm: number = 33.333,
  ) {
    this.alpha = alpha;
    this.beta = alpha / 32;
    this.intervalsPerRevolution = intervalsPerRevolution;
    this.rpm = rpm;
  }

  /**
   * Process a scratch position measurement.
   * Alpha-beta filter tracks position and velocity from platter input.
   *
   * @param measurement  Raw position input (e.g. from mouse drag delta or jog wheel)
   * @param dt           Time delta in seconds since last update
   * @returns            Playback rate to apply to the AudioBufferSourceNode
   */
  process(measurement: number, dt: number): number {
    if (dt <= 0) return this.velocity;

    // Alpha-beta filter update
    // prediction step
    this.position += this.velocity * dt;

    // correction step
    const residual = measurement - this.position;
    this.position += this.alpha * residual;
    this.velocity += (this.beta / dt) * residual;

    // Convert velocity to playback rate
    // velocity is in "intervals per second" — normalize to a playback rate
    const revolutionsPerSecond = this.rpm / 60;
    const intervalsPerSecond =
      revolutionsPerSecond * this.intervalsPerRevolution;
    return this.velocity / intervalsPerSecond;
  }

  /** Reset filter state */
  reset(): void {
    this.position = 0;
    this.velocity = 0;
  }

  /** Get current scratch position */
  getPosition(): number {
    return this.position;
  }

  /** Get current velocity as playback rate */
  getVelocity(): number {
    const revolutionsPerSecond = this.rpm / 60;
    const intervalsPerSecond =
      revolutionsPerSecond * this.intervalsPerRevolution;
    return this.velocity / intervalsPerSecond;
  }

  /** Directly set the raw velocity (for programmatic scratch patterns) */
  setVelocity(rate: number): void {
    const revolutionsPerSecond = this.rpm / 60;
    const intervalsPerSecond =
      revolutionsPerSecond * this.intervalsPerRevolution;
    this.velocity = rate * intervalsPerSecond;
  }
}

// ── DJ Deck ──

export class DJDeck {
  private context: AudioContext;
  private source: AudioBufferSourceNode | null = null;
  private buffer: AudioBuffer | null = null;
  private deckGain: GainNode;
  readonly eq: ThreeBandEQ;
  readonly effects: DJEffectsChain;
  readonly output: GainNode;

  // Playback state
  private playing: boolean = false;
  private scratching: boolean = false;
  private startTime: number = 0; // AudioContext time when playback started
  private startOffset: number = 0; // Position in buffer when playback started (seconds)
  private currentRate: number = 1.0;
  private bpm: number = DEFAULT_BPM;
  private volume: number = 0.8;

  // Cue points (seconds into the buffer)
  private cuePoints: number[] = [];
  private loopRegion: [number, number] | null = null;

  // Scratch engine
  readonly scratch: ScratchEngineCore;

  // Vinyl simulation
  readonly vinyl: VinylSimulation;

  private disposed: boolean = false;

  constructor(context: AudioContext) {
    this.context = context;

    // Signal chain: source → EQ → effects → deckGain → output
    this.eq = new ThreeBandEQ(context);
    this.effects = new DJEffectsChain(context);
    this.deckGain = context.createGain();
    this.deckGain.gain.value = this.volume;
    this.output = context.createGain();

    this.eq.output.connect(this.effects.input);
    this.effects.output.connect(this.deckGain);
    this.deckGain.connect(this.output);

    // Scratch engine
    this.scratch = new ScratchEngineCore();

    // Vinyl simulation
    this.vinyl = new VinylSimulation(context);
    // Mix vinyl noise into deck output
    this.vinyl.noiseOutput.connect(this.output);
  }

  /** Load an AudioBuffer into this deck */
  loadBuffer(buffer: AudioBuffer): void {
    this.stop();
    this.buffer = buffer;
    this.startOffset = 0;
    this.cuePoints = [];
    this.loopRegion = null;
  }

  /** Load audio from a File object */
  async loadFile(file: File): Promise<AudioBuffer | null> {
    try {
      const arrayBuffer = await file.arrayBuffer();
      if (this.disposed) return null;
      const audioBuffer = await this.context.decodeAudioData(arrayBuffer);
      if (this.disposed) return null;
      this.loadBuffer(audioBuffer);
      return audioBuffer;
    } catch (err) {
      logger.error("[DJDeck] Failed to load file:", err instanceof Error ? err : new Error(String(err)));
      return null;
    }
  }

  /** Load audio from a URL */
  async loadUrl(url: string): Promise<AudioBuffer | null> {
    try {
      const response = await fetch(url);
      if (this.disposed) return null;
      if (!response.ok) {
        // ENGINE-33: redact the URL to avoid leaking auth tokens in logs
        let safeUrl: string;
        try {
          const parsed = new URL(url);
          safeUrl = `${parsed.origin}${parsed.pathname}`;
        } catch {
          safeUrl = "[invalid URL]";
        }
        logger.error(`[DJDeck] HTTP ${response.status} loading URL: ${safeUrl}`);
        return null;
      }
      const arrayBuffer = await response.arrayBuffer();
      if (this.disposed) return null;
      const audioBuffer = await this.context.decodeAudioData(arrayBuffer);
      if (this.disposed) return null;
      this.loadBuffer(audioBuffer);
      return audioBuffer;
    } catch (err) {
      logger.error("[DJDeck] Failed to load URL:", err instanceof Error ? err : new Error(String(err)));
      return null;
    }
  }

  /** Start or resume playback */
  play(): void {
    if (this.disposed || !this.buffer || this.playing) return;

    this.createAndStartSource(this.startOffset);
    this.playing = true;
    this.vinyl.start();
  }

  /** Pause playback, saving current position */
  pause(): void {
    if (!this.playing || !this.source) return;

    // Calculate current position
    this.startOffset = this.getCurrentPosition();

    this.stopSource();
    this.playing = false;
    // ENGINE-19: stop vinyl simulation on pause to prevent source node leaks
    this.vinyl.stop();
  }

  /** Stop playback, reset to cue point or beginning */
  stop(): void {
    this.stopSource();
    this.playing = false;
    this.scratching = false;
    this.startOffset = 0;
    this.vinyl.stop();
  }

  /** Jump to a cue point (by index) */
  jumpToCue(index: number): void {
    if (index < 0 || index >= this.cuePoints.length) return;
    const wasPlaying = this.playing;
    this.stopSource();
    this.startOffset = this.cuePoints[index];
    if (wasPlaying) this.play();
  }

  /** Set a cue point at the current position or a specific time */
  setCuePoint(time?: number): void {
    const t = time ?? this.getCurrentPosition();
    // ENGINE-22: cap cue points to prevent unbounded array growth
    const MAX_CUE_POINTS = 16;
    if (this.cuePoints.length < MAX_CUE_POINTS) {
      this.cuePoints.push(t);
    }
  }

  /** Set loop region */
  setLoop(start: number, end: number): void {
    this.loopRegion = [start, end];
    if (this.source) {
      this.source.loop = true;
      this.source.loopStart = start;
      this.source.loopEnd = end;
    }
  }

  /** Clear loop region */
  clearLoop(): void {
    this.loopRegion = null;
    if (this.source) {
      this.source.loop = false;
    }
  }

  /** Set playback rate (affects pitch unless key lock is on). Negative rates are not supported. */
  setPlaybackRate(rate: number): void {
    // Web Audio API playbackRate must be positive. Clamp to a small positive value.
    const safeRate = Math.max(0.01, Math.abs(rate));
    this.currentRate = safeRate;
    if (this.source) {
      this.source.playbackRate.setValueAtTime(
        safeRate,
        this.context.currentTime,
      );
    }
  }

  /** Set volume (0-1) */
  setVolume(vol: number): void {
    this.volume = Math.max(0, Math.min(1, vol));
    this.deckGain.gain.setTargetAtTime(
      this.volume,
      this.context.currentTime,
      0.005,
    );
  }

  /** Set BPM (for sync calculations) */
  setBpm(bpm: number): void {
    this.bpm = Math.max(20, Math.min(300, bpm));
  }

  /** Begin scratch mode — disconnect normal playback, use scratch engine */
  startScratch(): void {
    this.scratching = true;
    this.scratch.reset();
  }

  /** End scratch mode — resume normal playback */
  endScratch(): void {
    this.scratching = false;
    // Restore the playback rate to the pre-scratch value so playback
    // doesn't stay at the last scratch speed.
    if (this.source) {
      this.source.playbackRate.setValueAtTime(
        this.currentRate,
        this.context.currentTime,
      );
    }
  }

  /**
   * Process scratch input. Call this from rAF or pointer event handlers.
   * @param measurement  Scratch position input (mouse delta, jog wheel value)
   * @param dt           Time delta in seconds
   */
  processScratch(measurement: number, dt: number): void {
    if (!this.scratching || !this.source) return;
    const rate = this.scratch.process(measurement, dt);
    this.source.playbackRate.setValueAtTime(
      Math.max(0.001, Math.abs(rate)),
      this.context.currentTime,
    );
  }

  /** Get current playback position in seconds */
  getCurrentPosition(): number {
    if (!this.playing || !this.source) return this.startOffset;

    // During scratch mode the playbackRate is being driven by the scratch
    // engine, so the simple elapsed = dt * rate formula is inaccurate.
    // Fall back to the last known offset (updated on pause/stop).
    if (this.scratching) return this.startOffset;

    const elapsed =
      (this.context.currentTime - this.startTime) * this.currentRate;
    const duration = this.buffer?.duration ?? 0;
    if (duration <= 0) return 0;

    if (this.loopRegion) {
      const loopLength = this.loopRegion[1] - this.loopRegion[0];
      // ENGINE-21: guard against degenerate loop (zero or negative length)
      if (loopLength <= 0) return this.startOffset;
      const pos = this.startOffset + elapsed;
      if (pos >= this.loopRegion[1]) {
        return this.loopRegion[0] + ((pos - this.loopRegion[0]) % loopLength);
      }
      return pos;
    }

    return Math.min(this.startOffset + elapsed, duration);
  }

  /** Get the deck's full state for UI binding */
  getState(): DeckState {
    return {
      isPlaying: this.playing,
      isScratching: this.scratching,
      position: this.getCurrentPosition(),
      playbackRate: this.currentRate,
      bpm: this.bpm,
      volume: this.volume,
      eqGains: this.eq.getGains(),
      cuePoints: [...this.cuePoints],
      loopRegion: this.loopRegion
        ? ([...this.loopRegion] as [number, number])
        : null,
      hasTrack: this.buffer !== null,
      duration: this.buffer?.duration ?? 0,
    };
  }

  /** Get the loaded AudioBuffer (for waveform rendering) */
  getBuffer(): AudioBuffer | null {
    return this.buffer;
  }

  // ── Private helpers ──

  private createAndStartSource(offset: number): void {
    if (!this.buffer) return;

    this.source = this.context.createBufferSource();
    this.source.buffer = this.buffer;
    this.source.playbackRate.value = Math.abs(this.currentRate);

    if (this.loopRegion) {
      this.source.loop = true;
      this.source.loopStart = this.loopRegion[0];
      this.source.loopEnd = this.loopRegion[1];
    }

    // Connect vinyl drift LFO to playback rate for subtle pitch warble
    this.vinyl.getDriftOutput().connect(this.source.playbackRate);

    this.source.connect(this.eq.input);

    this.startTime = this.context.currentTime;
    this.startOffset = offset;
    this.source.start(0, offset);

    // Handle track end — capture the source reference so the closure doesn't
    // read `this.source` which may have been replaced by a subsequent play()
    // call before this 'ended' event fires.
    const capturedSource = this.source;
    capturedSource.addEventListener(
      "ended",
      () => {
        if (!this.disposed && this.playing && !capturedSource.loop) {
          this.playing = false;
          this.startOffset = 0;
        }
      },
      { once: true },
    );
  }

  private stopSource(): void {
    if (this.source) {
      try {
        this.source.stop();
      } catch (_e) {
        /* */
      }
      try {
        this.source.disconnect();
      } catch (_e) {
        /* */
      }
      this.source = null;
    }
  }

  dispose(): void {
    if (this.disposed) return;
    this.disposed = true;
    this.stop();
    this.eq.dispose();
    this.effects.dispose();
    this.vinyl.dispose();
    try {
      this.deckGain.disconnect();
    } catch (_e) {
      /* */
    }
    try {
      this.output.disconnect();
    } catch (_e) {
      /* */
    }
  }
}

// ── Auto-Scratch Renderer ──

export class AutoScratchRenderer {
  private context: AudioContext;
  /** Cache for the reversed version of a source buffer. */
  private reversedCache = new WeakMap<AudioBuffer, AudioBuffer>();

  constructor(context: AudioContext) {
    this.context = context;
  }

  /** Create a sample-reversed copy of a buffer (cached per source). */
  private getReversedBuffer(
    buffer: AudioBuffer,
    sampleRate: number,
  ): AudioBuffer {
    let rev = this.reversedCache.get(buffer);
    if (rev) return rev;
    rev = new AudioBuffer({
      numberOfChannels: buffer.numberOfChannels,
      length: buffer.length,
      sampleRate,
    });
    for (let ch = 0; ch < buffer.numberOfChannels; ch++) {
      const src = buffer.getChannelData(ch);
      const dst = rev.getChannelData(ch);
      for (let i = 0; i < buffer.length; i++) {
        dst[i] = src[buffer.length - 1 - i];
      }
    }
    this.reversedCache.set(buffer, rev);
    return rev;
  }

  /**
   * Render a scratch pattern to an AudioBuffer.
   * Drives playhead through scratch events at the given BPM.
   *
   * @param sourceBuffer   Source audio to scratch
   * @param events         Scratch event pattern
   * @param bpm            Tempo for timing
   * @param intensity      Scaling factor for speed/gain
   * @param swing          Swing amount (0-100). Delays every other sub-beat.
   * @returns              Rendered AudioBuffer with the scratched audio
   */
  async render(
    sourceBuffer: AudioBuffer,
    events: ScratchEvent[],
    bpm: number,
    intensity: "low" | "medium" | "high" = "medium",
    swing: number = 0,
  ): Promise<AudioBuffer> {
    const beatDurationS = 60 / bpm;
    const intensityScale = { low: 0.7, medium: 1.0, high: 1.35 }[intensity];
    const gainScale = { low: 0.8, medium: 1.0, high: 1.15 }[intensity];

    // Swing: fraction of a 16th-note to delay even 16th-notes (0 = straight, 1 = full triplet)
    const swingFraction = Math.max(0, Math.min(1, swing / 100));
    const sixteenthBeat = 0.25; // 1/4 of a beat

    // Calculate total duration from events
    let maxEndBeat = 0;
    for (const ev of events) {
      maxEndBeat = Math.max(maxEndBeat, ev.startBeat + ev.durationBeats);
    }
    const totalDurationS = maxEndBeat * beatDurationS;

    // Use OfflineAudioContext for non-realtime rendering
    const sampleRate = sourceBuffer.sampleRate;
    const totalSamples = Math.ceil(totalDurationS * sampleRate);
    const offline = new OfflineAudioContext(
      sourceBuffer.numberOfChannels,
      Math.max(1, totalSamples),
      sampleRate,
    );

    // For each scratch event, schedule audio playback
    for (const ev of events) {
      if (
        ev.type === "fader_open" ||
        ev.type === "fader_close" ||
        ev.type === "hold"
      )
        continue;

      // Swing quantize: shift every other 16th-note position forward
      let eventBeat = ev.startBeat;
      if (swingFraction > 0) {
        const sixteenthIndex = Math.round(eventBeat / sixteenthBeat);
        if (sixteenthIndex % 2 === 1) {
          // Odd 16th-note — delay by swing amount (up to half a 16th-note)
          eventBeat += swingFraction * sixteenthBeat * 0.5;
        }
      }

      const startTimeS = eventBeat * beatDurationS;
      const durationS = ev.durationBeats * beatDurationS;
      const speed = ev.speedMultiplier * intensityScale;
      const faderGain = ev.faderPosition * (ev.gain ?? 1) * gainScale;

      if (faderGain <= 0) continue;

      // Use reversed buffer for backward events so they actually play in reverse
      const isBackward = ev.type === "backward" || speed < 0;
      const buf = isBackward
        ? this.getReversedBuffer(sourceBuffer, sampleRate)
        : sourceBuffer;

      const source = offline.createBufferSource();
      source.buffer = buf;

      // Per-event pitch offset: shift playback rate by semitones
      const pitchShift = ev.pitchOffsetSemitones
        ? Math.pow(2, ev.pitchOffsetSemitones / 12)
        : 1;
      source.playbackRate.value = (Math.abs(speed) || 0.001) * pitchShift;

      const gain = offline.createGain();
      gain.gain.value = faderGain;

      // Apply stutter if enabled
      if (ev.stutterOverride?.enabled) {
        const stutterDivMs: Record<string, number> = {
          "8n": (beatDurationS * 1000) / 2,
          "16n": (beatDurationS * 1000) / 4,
          "32n": (beatDurationS * 1000) / 8,
          "64n": (beatDurationS * 1000) / 16,
        };
        const cycleMs =
          stutterDivMs[ev.stutterOverride.rate] ?? beatDurationS * 250;
        const cycleSec = cycleMs / 1000;
        const dutyFraction = (ev.stutterOverride.dutyPercent ?? 50) / 100;
        const onTime = cycleSec * dutyFraction;

        // Schedule gain automation for stutter
        let t = startTimeS;
        const endTime = startTimeS + durationS;
        while (t < endTime) {
          gain.gain.setValueAtTime(faderGain, t);
          gain.gain.setValueAtTime(0, Math.min(t + onTime, endTime));
          t += cycleSec;
        }
      }

      source.connect(gain);
      gain.connect(offline.destination);
      source.start(startTimeS, 0, durationS);
    }

    return offline.startRendering();
  }
}

// ── BPM Detection ──

export class BPMDetector {
  /**
   * Simple onset-based BPM detection.
   * Analyzes energy peaks in the audio buffer to estimate tempo.
   *
   * @param buffer   AudioBuffer to analyze
   * @returns        Estimated BPM
   */
  static detect(buffer: AudioBuffer): number {
    const data = buffer.getChannelData(0);
    const sampleRate = buffer.sampleRate;

    // Downsample by computing energy in windows
    const windowSize = Math.floor(sampleRate * 0.01); // 10ms windows
    const energies: number[] = [];
    for (let i = 0; i < data.length; i += windowSize) {
      let energy = 0;
      const end = Math.min(i + windowSize, data.length);
      for (let j = i; j < end; j++) {
        energy += data[j] * data[j];
      }
      energies.push(energy / (end - i));
    }

    // Find onsets: points where energy increases significantly
    const onsets: number[] = [];
    const threshold = 1.5;
    let localAvg = energies[0] ?? 0;
    const decayFactor = 0.99;

    for (let i = 1; i < energies.length; i++) {
      if (energies[i] > localAvg * threshold && energies[i] > 0.001) {
        onsets.push(i);
        // ENGINE-24: clamp the skip amount so we don't advance i past energies.length
        // (which would make energies[i] undefined and corrupt localAvg)
        const skip = Math.floor((sampleRate * 0.05) / windowSize);
        i += Math.min(skip, energies.length - i - 1);
      }
      localAvg = localAvg * decayFactor + energies[i] * (1 - decayFactor);
    }

    if (onsets.length < 2) return 120; // Default

    // Calculate inter-onset intervals
    const intervals: number[] = [];
    for (let i = 1; i < onsets.length; i++) {
      intervals.push(((onsets[i] - onsets[i - 1]) * windowSize) / sampleRate);
    }

    // Find the most common interval using histogram binning
    const binWidth = 0.01; // 10ms bins
    const bins = new Map<number, number>();
    for (const interval of intervals) {
      const bin = Math.round(interval / binWidth);
      bins.set(bin, (bins.get(bin) ?? 0) + 1);
    }

    let bestBin = 0;
    let bestCount = 0;
    bins.forEach((count, bin) => {
      if (count > bestCount) {
        bestCount = count;
        bestBin = bin;
      }
    });

    const avgInterval = bestBin * binWidth;
    if (avgInterval <= 0) return 120;

    let bpm = 60 / avgInterval;

    // Normalize to reasonable range (60-180)
    while (bpm < 60) bpm *= 2;
    while (bpm > 180) bpm /= 2;

    return Math.round(bpm * 10) / 10;
  }

  /**
   * Detect intro/outro boundaries.
   * Scans from start/end for the first point above the threshold.
   * Threshold: -60 dBFS.
   */
  static detectBoundaries(
    buffer: AudioBuffer,
    thresholdDb: number = -60,
  ): { introEnd: number; outroStart: number } {
    const data = buffer.getChannelData(0);
    const threshold = Math.pow(10, thresholdDb / 20);
    const sampleRate = buffer.sampleRate;
    const windowSize = Math.floor(sampleRate * 0.01);

    // Scan from start
    let introEnd = 0;
    for (let i = 0; i < data.length; i += windowSize) {
      let rms = 0;
      const end = Math.min(i + windowSize, data.length);
      for (let j = i; j < end; j++) {
        rms += data[j] * data[j];
      }
      rms = Math.sqrt(rms / (end - i));
      if (rms > threshold) {
        introEnd = i / sampleRate;
        break;
      }
    }

    // Scan from end
    let outroStart = buffer.duration;
    for (let i = data.length - windowSize; i >= 0; i -= windowSize) {
      let rms = 0;
      const end = Math.min(i + windowSize, data.length);
      for (let j = i; j < end; j++) {
        rms += data[j] * data[j];
      }
      rms = Math.sqrt(rms / (end - i));
      if (rms > threshold) {
        outroStart = Math.min(end / sampleRate, buffer.duration);
        break;
      }
    }

    return { introEnd, outroStart };
  }
}

// ── DJ Engine (Orchestrator) ──

export class DJEngine {
  private _context: AudioContext;
  readonly deckA: DJDeck;
  readonly deckB: DJDeck;
  readonly crossfader: CrossfaderEngine;
  private masterGain: GainNode;
  private masterCompressor: DynamicsCompressorNode;
  readonly autoScratch: AutoScratchRenderer;
  private disposed: boolean = false;

  // Sync state
  private syncEnabled: boolean = false;
  private syncLeader: "A" | "B" = "A";

  /** Public read-only access to the underlying AudioContext */
  get context(): AudioContext {
    return this._context;
  }

  constructor(context?: AudioContext) {
    this._context = context ?? getTBMContext();

    // Create decks
    this.deckA = new DJDeck(this.context);
    this.deckB = new DJDeck(this.context);

    // Create crossfader
    this.crossfader = new CrossfaderEngine(this.context);

    // Connect decks through crossfader
    this.deckA.output.connect(this.crossfader.inputA);
    this.deckB.output.connect(this.crossfader.inputB);

    // Master chain: crossfader → compressor → master gain → destination
    this.masterCompressor = this.context.createDynamicsCompressor();
    this.masterCompressor.threshold.value = -6;
    this.masterCompressor.knee.value = 30;
    this.masterCompressor.ratio.value = 4;
    this.masterCompressor.attack.value = 0.003;
    this.masterCompressor.release.value = 0.25;

    this.masterGain = this.context.createGain();
    this.masterGain.gain.value = 0.85;

    this.crossfader.output.connect(this.masterCompressor);
    this.masterCompressor.connect(this.masterGain);
    this.masterGain.connect(this.context.destination);

    // Auto-scratch renderer
    this.autoScratch = new AutoScratchRenderer(this.context);
  }

  /** Get the AudioContext */
  getContext(): AudioContext {
    return this.context;
  }

  /** Set master volume (0-1) */
  setMasterVolume(vol: number): void {
    this.masterGain.gain.setTargetAtTime(
      Math.max(0, Math.min(1, vol)),
      this.context.currentTime,
      0.005,
    );
  }

  /** Get master GainNode (for connecting analyser, etc.) */
  getMasterGain(): GainNode {
    return this.masterGain;
  }

  // ── Sync ──

  /** Enable BPM sync between decks */
  enableSync(leader: "A" | "B" = "A"): void {
    this.syncEnabled = true;
    this.syncLeader = leader;
    this.performSync();

    // Start periodic sync so drift is continuously corrected
    this.startSyncTimer();
  }

  /** Disable sync */
  disableSync(): void {
    this.syncEnabled = false;
    this.stopSyncTimer();
  }

  private syncTimerId: number | null = null;

  private startSyncTimer(): void {
    this.stopSyncTimer();
    // Re-sync every 500ms to keep follower locked to leader BPM
    this.syncTimerId = window.setInterval(() => {
      this.performSync();
    }, 500);
  }

  private stopSyncTimer(): void {
    if (this.syncTimerId !== null) {
      clearInterval(this.syncTimerId);
      this.syncTimerId = null;
    }
  }

  /** Perform sync: match follower BPM to leader BPM */
  private performSync(): void {
    if (!this.syncEnabled) return;

    const leaderDeck = this.syncLeader === "A" ? this.deckA : this.deckB;
    const followerDeck = this.syncLeader === "A" ? this.deckB : this.deckA;

    const leaderState = leaderDeck.getState();
    const followerState = followerDeck.getState();

    if (leaderState.bpm > 0 && followerState.bpm > 0) {
      // Calculate playback rate ratio to match BPM
      const ratio = leaderState.bpm / followerState.bpm;

      // Detect double-time: if ratio is close to 2x or 0.5x, use that
      let adjustedRatio = ratio;
      if (ratio > 1.8 && ratio < 2.2) adjustedRatio = 2;
      else if (ratio > 0.45 && ratio < 0.55) adjustedRatio = 0.5;

      followerDeck.setPlaybackRate(adjustedRatio);
      // Also update the follower's stored BPM so the UI reflects the synced tempo
      followerDeck.setBpm(leaderState.bpm);
    }
  }

  /** Get sync state */
  isSyncEnabled(): boolean {
    return this.syncEnabled;
  }

  getSyncLeader(): "A" | "B" {
    return this.syncLeader;
  }

  dispose(): void {
    if (this.disposed) return;
    this.disposed = true;

    this.stopSyncTimer();
    this.deckA.dispose();
    this.deckB.dispose();
    this.crossfader.dispose();

    try {
      this.masterCompressor.disconnect();
    } catch (_e) {
      /* */
    }
    try {
      this.masterGain.disconnect();
    } catch (_e) {
      /* */
    }
  }
}

/** Factory function to create a DJ engine instance */
export function createDJEngine(): DJEngine {
  return new DJEngine();
}

// ─────────────────────────────────────────────────────────────────────────────
// VstInsertChain
//
// Wraps one AudioWorkletNode ('vst-insert-processor') and handles the
// main-thread relay that bridges the worklet's processBlock messages to
// window.vstBridge.processBlock (Electron N-API).
//
// Usage:
//   const chain = await VstInsertChain.create(audioContext);
//   sourceNode.connect(chain.input);
//   chain.output.connect(destinationNode);
//
//   chain.setInstances(['instanceId1', 'instanceId2']);
//   chain.dispose();
// ─────────────────────────────────────────────────────────────────────────────

export class VstInsertChain {
  /** AudioWorkletNode wrapping the vst-insert-processor */
  private workletNode: AudioWorkletNode;

  /** Pass-through gain used as the public input handle */
  readonly input: GainNode;

  /** Pass-through gain used as the public output handle */
  readonly output: GainNode;

  private context: AudioContext;
  private disposed: boolean = false;

  private constructor(
    context: AudioContext,
    workletNode: AudioWorkletNode,
    input: GainNode,
    output: GainNode,
  ) {
    this.context = context;
    this.workletNode = workletNode;
    this.input = input;
    this.output = output;

    // Relay processBlock requests from the worklet to vstBridge and send back results
    this.workletNode.port.onmessage = (ev: MessageEvent) => {
      this._handleWorkletMessage(ev.data);
    };
  }

  /**
   * Async factory — registers the AudioWorklet module if not already registered,
   * then creates and returns a VstInsertChain instance.
   *
   * @param context   AudioContext to create nodes in
   * @param workletUrl  URL to vst-insert-processor.js (default: /src/worklets/vst-insert-processor.js)
   */
  static async create(
    context: AudioContext,
    workletUrl: string = "/src/worklets/vst-insert-processor.js",
  ): Promise<VstInsertChain> {
    // AudioWorklet.addModule() is idempotent — safe to call multiple times
    try {
      await context.audioWorklet.addModule(workletUrl);
    } catch (err) {
      logger.warn("[VstInsertChain] AudioWorklet module load failed:", undefined, err instanceof Error ? err : new Error(String(err)));
      // Return a passthrough chain (no VST processing) rather than throwing
      const input = context.createGain();
      const output = context.createGain();
      const stub = {
        port: { onmessage: null, postMessage: () => {} },
        // ENGINE-32: stub must implement disconnect() to avoid throws on dispose()
        disconnect: () => {},
        connect: () => {},
      } as unknown as AudioWorkletNode;
      input.connect(output);
      return new VstInsertChain(context, stub, input, output);
    }

    const workletNode = new AudioWorkletNode(context, "vst-insert-processor", {
      numberOfInputs: 1,
      numberOfOutputs: 1,
      outputChannelCount: [2],
    });

    const input = context.createGain();
    const output = context.createGain();

    // Signal chain: input (gain) → workletNode → output (gain)
    input.connect(workletNode);
    workletNode.connect(output);

    return new VstInsertChain(context, workletNode, input, output);
  }

  /**
   * Set the ordered list of VST instance IDs to process through.
   * Pass an empty array to bypass all VST processing (dry signal passes through).
   */
  setInstances(instanceIds: string[]): void {
    if (this.disposed) return;
    this.workletNode.port.postMessage({ type: "setInstances", instanceIds });
  }

  /**
   * Handle a processBlock message from the AudioWorkletProcessor.
   * Calls window.vstBridge.processBlock on the main thread and posts the result back.
   */
  private _handleWorkletMessage(msg: {
    type: string;
    id: number;
    instanceId: string;
    inputL: ArrayBuffer;
    inputR: ArrayBuffer;
    blockSize: number;
  }): void {
    if (msg.type !== "processBlock") return;

    const bridge = (window as Window & { vstBridge?: Window["vstBridge"] })
      .vstBridge;

    if (!bridge) {
      // No native bridge — return the input unmodified
      this.workletNode.port.postMessage(
        {
          type: "processResult",
          id: msg.id,
          outputL: msg.inputL,
          outputR: msg.inputR,
        },
        [msg.inputL, msg.inputR],
      );
      return;
    }

    // ENGINE-26: guard against detached ArrayBuffers — if byteLength is 0,
    // the buffer was already transferred/detached; return zeros instead of
    // letting the Float32Array constructor throw.
    let inputL: Float32Array;
    let inputR: Float32Array;
    try {
      if (msg.inputL.byteLength === 0 || msg.inputR.byteLength === 0) {
        throw new Error("detached");
      }
      inputL = new Float32Array(msg.inputL);
      inputR = new Float32Array(msg.inputR);
    } catch (_e) {
      // Return silence on detached buffer
      const blockSize = msg.blockSize || 128;
      const silence = new Float32Array(blockSize);
      const silenceL = silence.buffer.slice(0);
      const silenceR = silence.buffer.slice(0);
      this.workletNode.port.postMessage(
        { type: "processResult", id: msg.id, outputL: silenceL, outputR: silenceR },
        [silenceL, silenceR],
      );
      return;
    }

    bridge
      .processBlock(msg.instanceId, inputL, inputR, msg.blockSize)
      .then((result) => {
        if (this.disposed) return;
        this.workletNode.port.postMessage(
          {
            type: "processResult",
            id: msg.id,
            outputL: result.outputL,
            outputR: result.outputR,
          },
          [result.outputL, result.outputR],
        );
      })
      .catch(() => {
        if (this.disposed) return;
        // ENGINE-31: use Float32Array.slice() to copy only the used portion
        // of the typed array, rather than .buffer.slice(0) which copies the
        // full backing ArrayBuffer (which may be larger than blockSize samples)
        const dryL = inputL.slice().buffer;
        const dryR = inputR.slice().buffer;
        this.workletNode.port.postMessage(
          { type: "processResult", id: msg.id, outputL: dryL, outputR: dryR },
          [dryL, dryR],
        );
      });
  }

  dispose(): void {
    if (this.disposed) return;
    this.disposed = true;
    try {
      this.workletNode.port.onmessage = null;
    } catch (_e) {
      /* */
    }
    try {
      this.workletNode.disconnect();
    } catch (_e) {
      /* */
    }
    try {
      this.input.disconnect();
    } catch (_e) {
      /* */
    }
    try {
      this.output.disconnect();
    } catch (_e) {
      /* */
    }
  }
}

// ---------------------------------------------------------------------------
// BounceEngine
//
// Renders the current TBM sequencer pattern to WAV audio using
// OfflineAudioContext. Supports:
//   - Configurable length in bars or seconds
//   - 48 kHz / 24-bit BWF WAV output (per SPEC.md)
//   - Per-stem rendering (e.g. drums, bass, melodic, all)
//   - Progress callback for UI feedback
//
// Modelled after AutoScratchRenderer.render() — same offline rendering
// pattern but for the full drum machine sequencer.
// ---------------------------------------------------------------------------

export interface BounceConfig {
  /** Number of bars to render (ignored if durationSeconds is set) */
  bars: number;
  /** Explicit duration in seconds (overrides bars) */
  durationSeconds?: number;
  /** BPM for the bounce */
  bpm: number;
  /** Sample rate — default 48000 per SPEC */
  sampleRate?: number;
  /** Bit depth for WAV encoding — default 24 per SPEC */
  bitDepth?: 16 | 24 | 32;
  /** Number of output channels — default 2 (stereo) */
  channels?: number;
  /** Optional pad index filter — only render these pads. null = all pads. */
  padFilter?: number[] | null;
  /** Stem label for manifest metadata */
  stemName?: string;
  /** Global swing amount (0-100). Delays odd 16th steps. Default 0. */
  swing?: number;
  /** Humanize amount (0-1). Applies random timing/velocity offsets. Default 0. */
  humanize?: number;
  /** Per-pad swing overrides keyed by pad index (0-100). */
  padSwing?: Record<number, number>;
}

export interface BounceResult {
  /** Rendered AudioBuffer */
  buffer: AudioBuffer;
  /** WAV-encoded Blob (BWF WAV) */
  wav: Blob;
  /** Stem name label */
  stemName: string;
  /** Duration in seconds actually rendered */
  durationSeconds: number;
  /** Peak amplitude (0-1) */
  peakAmplitude: number;
  /** RMS level in dBFS */
  rmsDbfs: number;
}

export class BounceEngine {
  private samples: Map<string, AudioBuffer>;

  constructor(samples: Map<string, AudioBuffer>) {
    // Clone the reference — these are the loaded sample buffers from TBMAudioEngine
    this.samples = samples;
  }

  /**
   * Render a sequencer pattern to a WAV Blob.
   *
   * @param pads       Current pad configuration
   * @param pattern    Step pattern (boolean[][] — [padIndex][step])
   * @param config     Bounce configuration
   * @param onProgress Optional progress callback (0-1)
   * @returns          BounceResult with AudioBuffer + WAV Blob
   */
  async render(
    pads: Pad[],
    pattern: boolean[][],
    config: BounceConfig,
    onProgress?: (progress: number) => void,
  ): Promise<BounceResult> {
    const sampleRate = config.sampleRate ?? BOUNCE_SAMPLE_RATE;
    const bitDepth = config.bitDepth ?? 24;
    const channels = config.channels ?? 2;
    const stemName = config.stemName ?? "all";

    // Calculate total duration
    // 1 bar = 4 beats at the given BPM, 16 steps per bar (16th notes)
    // SAFETY: clamp BPM to sane range to prevent division by zero or Infinity
    const safeBpm = Number.isFinite(config.bpm)
      ? Math.max(20, Math.min(300, config.bpm))
      : 120;
    const secondsPerBeat = 60 / safeBpm;
    const secondsPerBar = secondsPerBeat * 4;
    const totalDurationS =
      config.durationSeconds ?? config.bars * secondsPerBar;
    const totalSamples = Math.ceil(totalDurationS * sampleRate);

    if (totalSamples <= 0) {
      throw new Error("Bounce duration must be > 0");
    }

    onProgress?.(0.05);

    // Create OfflineAudioContext for non-realtime rendering
    const offline = new OfflineAudioContext(channels, totalSamples, sampleRate);

    // Build a compressor on the offline context (mirrors TBMAudioEngine chain)
    const masterGain = offline.createGain();
    masterGain.gain.value = 0.8;

    const compressor = offline.createDynamicsCompressor();
    compressor.threshold.value = -6;
    compressor.knee.value = 30;
    compressor.ratio.value = 12;
    compressor.attack.value = 0.003;
    compressor.release.value = 0.25;

    masterGain.connect(compressor);
    compressor.connect(offline.destination);

    onProgress?.(0.1);

    // Schedule all steps across the full bounce duration
    // Use the actual pattern length instead of hardcoding 16
    const stepsPerBar = pattern?.[0]?.length ?? 16;
    const stepDurationS = secondsPerBeat / 4; // 16th note duration
    const totalSteps = Math.ceil(totalDurationS / stepDurationS);

    let scheduledCount = 0;
    const totalToSchedule = totalSteps * pads.length;
    const globalSwing = config.swing ?? 0;
    const humanizeAmount = config.humanize ?? 0;
    const padSwing = config.padSwing ?? {};

    for (let stepIndex = 0; stepIndex < totalSteps; stepIndex++) {
      const patternStep = stepIndex % stepsPerBar;
      let when = stepIndex * stepDurationS;

      // Apply swing: delay odd 16th-note steps
      if (patternStep % 2 === 1 && globalSwing > 0) {
        when += (globalSwing / 100) * stepDurationS * 0.5;
      }

      // Stop scheduling if we've gone past the bounce duration
      if (when >= totalDurationS) break;

      for (let padIndex = 0; padIndex < pads.length; padIndex++) {
        scheduledCount++;

        // Apply pad filter if specified
        if (config.padFilter && !config.padFilter.includes(padIndex)) continue;

        // Check if this step is active
        if (!pattern[padIndex] || !pattern[padIndex][patternStep]) continue;

        const pad = pads[padIndex];
        if (!pad?.sample) continue;

        const buffer = this.samples.get(pad.sample.id);
        if (!buffer) continue;

        // Per-pad swing (additive to global)
        let padWhen = when;
        const perPadSwing = padSwing[padIndex];
        if (perPadSwing && patternStep % 2 === 1) {
          padWhen += (perPadSwing / 100) * stepDurationS * 0.5;
        }

        // Humanize: random timing offset (up to ±15ms) and velocity scaling
        let humanizeTimeOffset = 0;
        let humanizeVelocityScale = 1;
        if (humanizeAmount > 0) {
          humanizeTimeOffset = (Math.random() * 2 - 1) * 0.015 * humanizeAmount;
          humanizeVelocityScale = 1 + (Math.random() * 2 - 1) * 0.15 * humanizeAmount;
        }
        padWhen = Math.max(0, padWhen + humanizeTimeOffset);

        // Re-sample the buffer to match offline context sample rate if needed
        const playBuffer = pad.reverse
          ? this._reverseBuffer(buffer, sampleRate)
          : buffer;

        const source = offline.createBufferSource();
        source.buffer = playBuffer;
        source.playbackRate.value = Math.pow(2, pad.pitch / 12);
        source.loop = pad.loop;

        // ADSR envelope
        const padGain = offline.createGain();
        const targetGain = pad.volume * humanizeVelocityScale;
        padGain.gain.setValueAtTime(0, padWhen);
        padGain.gain.linearRampToValueAtTime(targetGain, padWhen + pad.attack);

        // Panning
        const padPan = offline.createStereoPanner();
        padPan.pan.value = pad.pan;

        // Build signal chain: source -> [filter] -> padGain -> padPan -> masterGain
        let lastNode: AudioNode = source;

        // Per-pad filter
        if (pad.filterType !== "off") {
          const filterNode = offline.createBiquadFilter();
          switch (pad.filterType) {
            case "lp":
              filterNode.type = "lowpass";
              break;
            case "hp":
              filterNode.type = "highpass";
              break;
            case "bp":
              filterNode.type = "bandpass";
              break;
          }
          const minFreq = 20;
          const maxFreq = 20000;
          filterNode.frequency.value =
            minFreq * Math.pow(maxFreq / minFreq, pad.filterCutoff / 127);
          filterNode.Q.value = 0.1 + (pad.filterResonance / 127) * 29.9;
          lastNode.connect(filterNode);
          lastNode = filterNode;
        }

        lastNode.connect(padGain);
        padGain.connect(padPan);
        padPan.connect(masterGain);

        // Schedule start with optional sub-range
        let sampleDuration: number | undefined;
        if (pad.start > 0 || pad.end < 1) {
          const startOffset = pad.start * playBuffer.duration;
          const endOffset = pad.end * playBuffer.duration;
          sampleDuration = endOffset - startOffset;
          source.start(
            padWhen,
            startOffset,
            pad.loop ? undefined : sampleDuration,
          );
        } else {
          source.start(padWhen);
          sampleDuration = playBuffer.duration;
        }

        // Release envelope
        if (!pad.loop && pad.release > 0 && sampleDuration !== undefined) {
          const adjustedDuration = sampleDuration / Math.pow(2, pad.pitch / 12);
          const releaseStart = padWhen + adjustedDuration - pad.release;
          if (releaseStart > padWhen + pad.attack) {
            padGain.gain.setValueAtTime(targetGain, releaseStart);
            padGain.gain.linearRampToValueAtTime(0, releaseStart + pad.release);
          }
        }
      }

      // Report progress during scheduling phase (10% - 40%)
      if (stepIndex % 16 === 0) {
        onProgress?.(0.1 + (scheduledCount / totalToSchedule) * 0.3);
      }
    }

    onProgress?.(0.4);

    // Render the offline context
    const renderedBuffer = await offline.startRendering();

    onProgress?.(0.85);

    // Analyze loudness
    const { peakAmplitude, rmsDbfs } =
      BounceEngine._analyzeLoudness(renderedBuffer);

    // Encode to WAV
    const wavBlob = BounceEngine.encodeWav(renderedBuffer, bitDepth);

    onProgress?.(1.0);

    return {
      buffer: renderedBuffer,
      wav: wavBlob,
      stemName,
      durationSeconds: totalDurationS,
      peakAmplitude,
      rmsDbfs,
    };
  }

  /**
   * Render multiple stems in one pass.
   * Each stem definition specifies which pad indices belong to it.
   */
  async renderStems(
    pads: Pad[],
    pattern: boolean[][],
    stemConfigs: Array<{ name: string; padIndices: number[] }>,
    baseConfig: BounceConfig,
    onProgress?: (
      stemIndex: number,
      stemName: string,
      progress: number,
    ) => void,
  ): Promise<BounceResult[]> {
    const results: BounceResult[] = [];

    for (let i = 0; i < stemConfigs.length; i++) {
      const stem = stemConfigs[i];
      const result = await this.render(
        pads,
        pattern,
        { ...baseConfig, padFilter: stem.padIndices, stemName: stem.name },
        (p) => onProgress?.(i, stem.name, p),
      );
      results.push(result);
    }

    return results;
  }

  /** Reverse an AudioBuffer (for bounce context, may differ in sample rate) */
  private _reverseBuffer(buffer: AudioBuffer, _sampleRate: number): AudioBuffer {
    // ENGINE-27: use the source buffer's own sampleRate, NOT the bounce context
    // sampleRate, to avoid pitch-shifting the reversed sample. The offline
    // context will handle any necessary resampling.
    const reversed = new AudioBuffer({
      numberOfChannels: buffer.numberOfChannels,
      length: buffer.length,
      sampleRate: buffer.sampleRate,
    });
    for (let ch = 0; ch < buffer.numberOfChannels; ch++) {
      const data = buffer.getChannelData(ch);
      const dst = reversed.getChannelData(ch);
      for (let i = 0; i < buffer.length; i++) {
        dst[i] = data[buffer.length - 1 - i];
      }
    }
    return reversed;
  }

  /**
   * Analyze peak amplitude and RMS loudness of an AudioBuffer.
   */
  static _analyzeLoudness(buffer: AudioBuffer): {
    peakAmplitude: number;
    rmsDbfs: number;
  } {
    let peak = 0;
    let sumSquares = 0;
    let totalSamples = 0;

    for (let ch = 0; ch < buffer.numberOfChannels; ch++) {
      const data = buffer.getChannelData(ch);
      for (let i = 0; i < data.length; i++) {
        const abs = Math.abs(data[i]);
        if (abs > peak) peak = abs;
        sumSquares += data[i] * data[i];
        totalSamples++;
      }
    }

    const rms = totalSamples > 0 ? Math.sqrt(sumSquares / totalSamples) : 0;
    const rmsDbfs = rms > 0 ? 20 * Math.log10(rms) : -Infinity;

    return { peakAmplitude: peak, rmsDbfs };
  }

  /**
   * Encode an AudioBuffer to a WAV Blob (BWF-compatible).
   *
   * Supports 16-bit, 24-bit, and 32-bit float encoding.
   * Uses manual RIFF/WAV header construction (same pattern as
   * VinylScratchPro.tsx scratch clip export).
   */
  static encodeWav(buffer: AudioBuffer, bitDepth: 16 | 24 | 32 = 24): Blob {
    const numChannels = buffer.numberOfChannels;
    const sampleRate = buffer.sampleRate;
    const length = buffer.length;
    const isFloat = bitDepth === 32;
    const bytesPerSample = bitDepth / 8;
    const blockAlign = numChannels * bytesPerSample;
    const dataSize = length * blockAlign;
    // RIFF header (12) + fmt chunk (24 for non-float / 26 for float + fact) + data chunk header (8)
    const fmtChunkSize = isFloat ? 18 : 16;
    const factChunkSize = isFloat ? 12 : 0; // fact chunk: 4 (id) + 4 (size) + 4 (samples)
    const headerSize = 12 + (8 + fmtChunkSize) + factChunkSize + 8;
    const totalSize = headerSize + dataSize;

    const arrayBuffer = new ArrayBuffer(totalSize);
    const view = new DataView(arrayBuffer);
    let offset = 0;

    // Helper: write ASCII string
    const writeString = (s: string) => {
      for (let i = 0; i < s.length; i++) {
        view.setUint8(offset++, s.charCodeAt(i));
      }
    };

    // RIFF header
    writeString("RIFF");
    view.setUint32(offset, totalSize - 8, true);
    offset += 4;
    writeString("WAVE");

    // fmt sub-chunk
    writeString("fmt ");
    view.setUint32(offset, fmtChunkSize, true);
    offset += 4;
    view.setUint16(offset, isFloat ? 3 : 1, true);
    offset += 2; // format: 1 = PCM, 3 = IEEE float
    view.setUint16(offset, numChannels, true);
    offset += 2;
    view.setUint32(offset, sampleRate, true);
    offset += 4;
    view.setUint32(offset, sampleRate * blockAlign, true);
    offset += 4; // byte rate
    view.setUint16(offset, blockAlign, true);
    offset += 2;
    view.setUint16(offset, bitDepth, true);
    offset += 2;

    if (isFloat) {
      // cbSize = 0 for IEEE float extended format
      view.setUint16(offset, 0, true);
      offset += 2;
      // fact chunk (required for non-PCM)
      writeString("fact");
      view.setUint32(offset, 4, true);
      offset += 4;
      view.setUint32(offset, length, true);
      offset += 4;
    }

    // data sub-chunk
    writeString("data");
    view.setUint32(offset, dataSize, true);
    offset += 4;

    // Interleave channel data and write samples
    const channelData: Float32Array[] = [];
    for (let ch = 0; ch < numChannels; ch++) {
      channelData.push(buffer.getChannelData(ch));
    }

    for (let i = 0; i < length; i++) {
      for (let ch = 0; ch < numChannels; ch++) {
        const sample = channelData[ch][i];

        if (isFloat) {
          // 32-bit IEEE float
          view.setFloat32(offset, sample, true);
          offset += 4;
        } else if (bitDepth === 24) {
          // 24-bit signed integer
          const clamped = Math.max(-1, Math.min(1, sample));
          const intVal = Math.round(clamped * 8388607); // 2^23 - 1
          view.setUint8(offset, intVal & 0xff);
          view.setUint8(offset + 1, (intVal >> 8) & 0xff);
          view.setUint8(offset + 2, (intVal >> 16) & 0xff);
          offset += 3;
        } else {
          // 16-bit signed integer
          const clamped = Math.max(-1, Math.min(1, sample));
          const intVal = Math.round(clamped * 32767); // 2^15 - 1
          view.setInt16(offset, intVal, true);
          offset += 2;
        }
      }
    }

    return new Blob([arrayBuffer], { type: "audio/wav" });
  }
}

