import { z } from 'zod/v4';

/** Base URL for all API calls – proxied by Vite in dev, same-origin in prod. */
const BASE = '/api';

// ── Electron IPC bridge (injected by electron-preload.js via contextBridge) ──
// When running inside Electron, window.vstBridge is available.
// When running in a plain browser (dev server), it is undefined.

declare global {
  interface Window {
    vstBridge?: {
      scan: (searchPaths: string[]) => Promise<VstScanResult[]>;
      loadPlugin: (pluginPath: string) => Promise<LoadedPluginInfo>;
      unloadPlugin: (instanceId: string) => Promise<{ ok: boolean }>;
      getParams: (instanceId: string) => Promise<ParamInfo[]>;
      setParam: (instanceId: string, paramIndex: number, value: number) => Promise<{ ok: boolean }>;
      processBlock: (
        instanceId: string,
        inputL: Float32Array,
        inputR: Float32Array,
        blockSize: number,
      ) => Promise<{ outputL: ArrayBuffer; outputR: ArrayBuffer }>;
      /** Open the native GUI window for a loaded plugin (Electron only). */
      openGui: (pluginPath: string) => Promise<void>;
    };
    /** Non-VST Electron features (folder dialog, etc.) */
    tbmBridge?: {
      /** Open a native folder-picker dialog. Returns selected path or null if cancelled. */
      openFolderDialog: () => Promise<string | null>;
    };
  }
}

/** Raw result returned by the native addon scan */
export interface VstScanResult {
  path: string;
  name: string;
  vendor: string;
  type: 'VST2' | 'VST3';
  category: string;
  numInputs: number;
  numOutputs: number;
}

/** Returned by vstBridge.loadPlugin() */
export interface LoadedPluginInfo {
  instanceId: string;
  name: string;
  vendor: string;
  type: 'VST2' | 'VST3';
  numInputs: number;
  numOutputs: number;
  numParams: number;
  sampleRate: number;
  blockSize: number;
}

/** Single parameter descriptor */
export interface ParamInfo {
  index: number;
  id: number;
  name: string;
  shortName: string;
  units: string;
  defaultValue: number;
  currentValue: number;
  stepCount: number;
}

/** Default VST search paths (Windows) */
export const DEFAULT_VST_PATHS = [
  'C:/Program Files/Common Files/VST3',
  'C:/Program Files/VSTPlugins',
  'C:/Program Files/Steinberg/VSTPlugins',
  'C:/Program Files (x86)/Common Files/VST3',
  'C:/Program Files (x86)/VSTPlugins',
];

/**
 * Scan for VST plugins using the Electron IPC bridge (native addon).
 * Falls back to an empty array if not running in Electron.
 */
export async function scanPluginsNative(searchPaths: string[] = DEFAULT_VST_PATHS): Promise<VstScanResult[]> {
  if (!window.vstBridge) return [];
  return window.vstBridge.scan(searchPaths);
}

/**
 * Load a plugin via the native addon and return instance info.
 * Throws if not running in Electron or if loading fails.
 */
export async function loadPluginNative(pluginPath: string): Promise<LoadedPluginInfo> {
  if (!window.vstBridge) throw new Error('vstBridge not available (not running in Electron)');
  return window.vstBridge.loadPlugin(pluginPath);
}

export async function unloadPluginNative(instanceId: string): Promise<{ ok: boolean }> {
  if (!window.vstBridge) return { ok: false };
  return window.vstBridge.unloadPlugin(instanceId);
}

export async function getPluginParamsNative(instanceId: string): Promise<ParamInfo[]> {
  if (!window.vstBridge) return [];
  return window.vstBridge.getParams(instanceId);
}

export async function setPluginParamNative(
  instanceId: string,
  paramIndex: number,
  value: number,
): Promise<{ ok: boolean }> {
  if (!window.vstBridge) return { ok: false };
  return window.vstBridge.setParam(instanceId, paramIndex, value);
}

export async function processBlockNative(
  instanceId: string,
  inputL: Float32Array,
  inputR: Float32Array,
  blockSize: number,
): Promise<{ outputL: Float32Array; outputR: Float32Array }> {
  if (!window.vstBridge) {
    return { outputL: inputL, outputR: inputR };
  }
  const result = await window.vstBridge.processBlock(instanceId, inputL, inputR, blockSize);
  return {
    outputL: new Float32Array(result.outputL),
    outputR: new Float32Array(result.outputR),
  };
}

/** True when running inside Electron (preload bridge is present) */
export const isElectron = (): boolean => typeof window !== 'undefined' && !!window.vstBridge;



/**
 * @deprecated No callers — use `validatedRequest()` instead, which validates
 * the response body against a Zod schema and prevents shape mismatches from
 * silently propagating through the app.
 */
async function request<T>(path: string, options?: RequestInit): Promise<T> {
  const res = await fetch(`${BASE}${path}`, {
    headers: { 'Content-Type': 'application/json' },
    ...options,
  });
  if (!res.ok) {
    const body = await res.text().catch(() => res.statusText);
    throw new Error(`API ${options?.method ?? 'GET'} ${path} → ${res.status}: ${body}`);
  }
  return res.json() as Promise<T>;
}

/**
 * Like `request`, but validates the response body against a Zod schema at
 * runtime.  This prevents shape mismatches between client and server from
 * silently propagating through the app.
 */
async function validatedRequest<T>(
  schema: z.ZodType<T>,
  path: string,
  options?: RequestInit,
): Promise<T> {
  const res = await fetch(`${BASE}${path}`, {
    headers: { 'Content-Type': 'application/json' },
    ...options,
  });
  if (!res.ok) {
    const body = await res.text().catch(() => res.statusText);
    throw new Error(`API ${options?.method ?? 'GET'} ${path} → ${res.status}: ${body}`);
  }
  const json: unknown = await res.json();
  return schema.parse(json);
}

