/** Versioned project snapshot saved to / loaded from a .tbm file. */
export interface TBMProjectFile {
  /** Format version — increment when the schema changes. */
  version: 1;
  /** BPM at time of save. */
  bpm: number;
  /** Global swing amount (0–100). */
  swing: number;
  /** Active project key, e.g. "Cm" or "F#". */
  key: string;
  /** Active A/B state. */
  abState: 'A' | 'B';
  /** Per-pad state snapshot (name, sample info, volume, pan, adsr, etc.). */
  pads: Array<{
    index: number;
    sampleName?: string;
    volume: number;
    pan: number;
    filterCutoff: number;
  }>;
  /** Step-sequencer pattern: outer array = 16 tracks, inner = 16 boolean steps. */
  pattern: boolean[][];
  /** ADSR envelope settings at save time. */
