import { useEffect, useRef, useState } from 'react';

export interface AudioMeterData {
  inputLevel: number; // 0-100
  outputLevel: number; // 0-100
  stereoWidth: number; // 0-100
  phaseCorrelation: number; // -1 to +1
  limiterGainReduction: number; // 0-100
}

export function useAudioAnalysis(analyserNode: AnalyserNode | null): AudioMeterData {
  const [data, setData] = useState<AudioMeterData>({
    inputLevel: 0,
    outputLevel: 0,
    stereoWidth: 50,
    phaseCorrelation: 0.7,
    limiterGainReduction: 0
  });

  const animationFrameRef = useRef<number>(undefined);
  const dataArrayRef = useRef<Float32Array | null>(null);
  const lastUpdateRef = useRef<number>(0);

  useEffect(() => {
    if (!analyserNode) return;

    analyserNode.fftSize = 2048;
    analyserNode.smoothingTimeConstant = 0.8;
    const bufferLength = analyserNode.frequencyBinCount;
    dataArrayRef.current = new Float32Array(bufferLength);

    const updateMeters = () => {
      if (!analyserNode || !dataArrayRef.current) return;

      const now = Date.now();
      // Throttle updates to ~30fps
      if (now - lastUpdateRef.current < 33) {
        animationFrameRef.current = requestAnimationFrame(updateMeters);
        return;
      }
      lastUpdateRef.current = now;

      // Get time domain data for RMS calculation
      analyserNode.getFloatTimeDomainData(dataArrayRef.current);

      // Calculate RMS (Root Mean Square) for input level
      let sum = 0;
      for (let i = 0; i < dataArrayRef.current.length; i++) {
        sum += dataArrayRef.current[i] * dataArrayRef.current[i];
      }
      const rms = Math.sqrt(sum / dataArrayRef.current.length);

      // Convert RMS to dB, then to 0-100 scale
      // RMS of 1.0 = 0dB, RMS of 0.0001 = -80dB
      const db = 20 * Math.log10(Math.max(rms, 0.0001));
      const inputLevel = Math.max(0, Math.min(100, (db + 80) * (100 / 80)));

      // NOTE: Stereo width and phase correlation are approximations.
      // A single AnalyserNode receives a downmixed mono signal, so true L/R
      // separation is not available here. We derive a "spectral variation"
      // metric from adjacent sample pairs as a proxy for stereo width.
      // For true stereo metering, wire separate AnalyserNodes to L and R
      // channels via a ChannelSplitterNode.

      // Approximate stereo-like variation from adjacent sample pairs
      let diffSum = 0;
      let pairCount = 0;
      const len = dataArrayRef.current.length;
      for (let i = 0; i < len - 1; i += 2) {
        diffSum += Math.abs(dataArrayRef.current[i] - dataArrayRef.current[i + 1]);
        pairCount++;
      }
      const avgDiff = pairCount > 0 ? diffSum / pairCount : 0;
      // Scale to 0-100 (empirical: max adjacent-sample diff rarely exceeds 0.4 in music)
      const stereoWidth = Math.max(0, Math.min(100, (avgDiff / 0.4) * 100));

      // Phase correlation approximation (mono signal self-correlation of odd/even samples).
      // With a true stereo setup this would be Σ(L·R) / √(Σ(L²)·Σ(R²)).
      let crossSum = 0;
      let oddSqSum = 0;
      let evenSqSum = 0;
      const halfLength = Math.floor(len / 2);
      for (let i = 0; i < halfLength; i++) {
        const odd = dataArrayRef.current[i * 2];
        const even = dataArrayRef.current[i * 2 + 1];
        crossSum += odd * even;
        oddSqSum += odd * odd;
        evenSqSum += even * even;
      }
      const denom = Math.sqrt(oddSqSum * evenSqSum);
      const phaseCorrelation = denom > 0 ? crossSum / denom : 0;

      // Limiter gain reduction: simulate based on peak levels
      let peak = 0;
      for (let i = 0; i < dataArrayRef.current.length; i++) {
        peak = Math.max(peak, Math.abs(dataArrayRef.current[i]));
      }
      // Apply "limiter" when peak > 0.9
      const limiterGainReduction = peak > 0.9 ? Math.min(100, (peak - 0.9) * 1000) : 0;

      // Output level: derived from input with simulated processing headroom.
      // This is an approximation — a real output meter would tap a post-processing node.
      const outputLevel = Math.min(100, inputLevel * 0.95 + (inputLevel > 5 ? 3 : 0));

      setData({
        inputLevel,
        outputLevel,
        stereoWidth,
        phaseCorrelation: isNaN(phaseCorrelation) ? 0.7 : Math.max(-1, Math.min(1, phaseCorrelation)),
        limiterGainReduction
      });

      animationFrameRef.current = requestAnimationFrame(updateMeters);
    };

    animationFrameRef.current = requestAnimationFrame(updateMeters);

    return () => {
      if (animationFrameRef.current != null) {
        cancelAnimationFrame(animationFrameRef.current);
      }
    };
  }, [analyserNode]);

  return data;
}

import { SynthSettings } from './TBMAudioEngine';

export interface BandInstrument {
  id: string;
  name: string;
  color: string;
  baseNote: number; // MIDI note number
  octaveRange: number; // Number of octaves to span
  settings: SynthSettings;
  rhythmPattern: number[]; // 16-step pattern (0-1 probability)
  noteDensity: number; // 0-1 scale
  harmonyType: 'unison' | 'thirds' | 'fifths' | 'octave' | 'triad' | 'seventh' | 'ninth';
}

export interface BandPerformance {
  bpm: number;
  groove: number; // 0-100 swing amount
  intensity: number; // 0-100 velocity/aggression
  complexity: number; // 0-100 note density/variation
  key: string; // e.g., 'C'
  scale: string; // e.g., 'major'
  chords: string[]; // chord progression
}

export class BandSynthesizer {
  private context: AudioContext;
  private masterGain: GainNode;
  private activeVoices: Map<string, { osc: OscillatorNode; gain: GainNode; filter: BiquadFilterNode; timeoutId: number }> = new Map();
  private nextVoiceId = 0;
  private scheduledNotes: Map<number, { voiceId: number; stopTime: number }> = new Map();
  private isPlaying = false;
  private currentBeat = 0;
  private beatInterval: number | null = null;
  private instruments: BandInstrument[] = [];
  private performance: BandPerformance;

  constructor(context: AudioContext, performance: BandPerformance) {
    this.context = context;
    this.performance = performance;
    this.masterGain = context.createGain();
    this.masterGain.gain.value = 0.3;
    this.masterGain.connect(context.destination);

    // Define instrument presets
    this.instruments = this.createInstrumentPresets();
  }

  private createInstrumentPresets(): BandInstrument[] {
    return [
      {
        id: 'piano',
        name: 'Piano',
        color: '#8b5cf6',
        baseNote: 60, // C4
        octaveRange: 2,
        settings: {
          type: 'sine',
          frequency: 440,
          attack: 0.02,
          decay: 0.1,
          sustain: 0.7,
          release: 0.3,
          filterFreq: 2000,
          filterQ: 1,
          distortion: 0
        },
        rhythmPattern: [1, 0, 0.8, 0, 0.6, 0, 0.8, 0, 1, 0, 0.7, 0, 0.9, 0, 0.5, 0],
        noteDensity: 0.7,
        harmonyType: 'triad'
      },
      {
        id: 'bass',
        name: 'Bass',
        color: '#10b981',
        baseNote: 36, // C2
        octaveRange: 1,
        settings: {
          type: 'sawtooth',
          frequency: 110,
          attack: 0.05,
          decay: 0.2,
          sustain: 0.8,
          release: 0.1,
          filterFreq: 800,
          filterQ: 2,
          distortion: 0.1
        },
        rhythmPattern: [1, 0, 0, 0, 0.8, 0, 0, 0, 1, 0, 0, 0, 0.7, 0, 0, 0],
        noteDensity: 0.4,
        harmonyType: 'unison'
      },
      {
        id: 'guitar',
        name: 'Guitar',
        color: '#f59e0b',
        baseNote: 48, // C3
        octaveRange: 2,
        settings: {
          type: 'triangle',
          frequency: 220,
          attack: 0.1,
          decay: 0.3,
          sustain: 0.6,
          release: 0.4,
          filterFreq: 1500,
          filterQ: 1.5,
          distortion: 0.2
        },
        rhythmPattern: [0.3, 0, 0.7, 0, 0.5, 0, 0.8, 0, 0.4, 0, 0.6, 0, 0.9, 0, 0.5, 0],
        noteDensity: 0.6,
        harmonyType: 'fifths'
      },
      {
        id: 'strings',
        name: 'Strings',
        color: '#3b82f6',
        baseNote: 60, // C4
        octaveRange: 3,
        settings: {
          type: 'sine',
          frequency: 440,
          attack: 0.3,
          decay: 0.5,
          sustain: 0.9,
          release: 1.0,
          filterFreq: 3000,
          filterQ: 0.5,
          distortion: 0
        },
        rhythmPattern: [0.1, 0, 0.2, 0, 0.1, 0, 0.3, 0, 0.2, 0, 0.1, 0, 0.4, 0, 0.2, 0],
        noteDensity: 0.3,
        harmonyType: 'seventh'
      },
      {
        id: 'brass',
        name: 'Brass',
        color: '#ef4444',
        baseNote: 60, // C4
        octaveRange: 2,
        settings: {
          type: 'square',
          frequency: 440,
          attack: 0.2,
          decay: 0.4,
          sustain: 0.8,
          release: 0.3,
          filterFreq: 1200,
          filterQ: 1.2,
          distortion: 0.1
        },
        rhythmPattern: [0.8, 0, 0, 0, 0.6, 0, 0, 0, 0.9, 0, 0, 0, 0.7, 0, 0, 0],
        noteDensity: 0.4,
        harmonyType: 'triad'
      },
      {
        id: 'drums',
        name: 'Drums',
        color: '#ec4899',
        baseNote: 36, // C2 (kick)
        octaveRange: 3,
        settings: {
          type: 'sawtooth',
          frequency: 110,
          attack: 0.01,
          decay: 0.1,
          sustain: 0,
          release: 0.05,
          filterFreq: 200,
          filterQ: 5,
          distortion: 0.3
        },
        rhythmPattern: [1, 0.3, 0.8, 0.2, 1, 0.4, 0.9, 0.3, 1, 0.2, 0.7, 0.1, 1, 0.3, 0.8, 0.2],
        noteDensity: 0.8,
        harmonyType: 'unison'
      }
    ];
  }

  private playNote(note: number, instrument: BandInstrument, velocity: number, duration: number, startDelay: number = 0): string {
    const voiceId = `voice_${this.nextVoiceId++}`;

    const osc = this.context.createOscillator();
    osc.type = instrument.settings.type;
    osc.frequency.value = 440 * Math.pow(2, (note - 69) / 12);

    const filter = this.context.createBiquadFilter();
    filter.type = "lowpass";
    filter.frequency.value = instrument.settings.filterFreq;
    filter.Q.value = instrument.settings.filterQ;

    const gain = this.context.createGain();
    const now = this.context.currentTime + startDelay;

    // Apply velocity scaling
    const peakGain = velocity * 0.5;
    const sustainGain = peakGain * instrument.settings.sustain;

    // ADSR envelope
    gain.gain.setValueAtTime(0, now);
    gain.gain.linearRampToValueAtTime(peakGain, now + instrument.settings.attack);
    gain.gain.linearRampToValueAtTime(
      sustainGain,
      now + instrument.settings.attack + instrument.settings.decay
    );

    osc.connect(filter);
    filter.connect(gain);
    gain.connect(this.masterGain);

    osc.start(now);

    // Schedule note off
    const stopTime = now + duration;
    const timeoutId = window.setTimeout(() => {
      this.stopNote(voiceId, instrument.settings);
    }, duration * 1000);

    this.activeVoices.set(voiceId, { osc, gain, filter, timeoutId });
    return voiceId;
  }

  private stopNote(voiceId: string, settings: SynthSettings): void {
    const voice = this.activeVoices.get(voiceId);
    if (!voice) return;

    clearTimeout(voice.timeoutId);

    const now = this.context.currentTime;
    voice.gain.gain.cancelScheduledValues(now);
    voice.gain.gain.setValueAtTime(voice.gain.gain.value, now);
    voice.gain.gain.linearRampToValueAtTime(0, now + settings.release);

    const cleanupTimeout = window.setTimeout(() => {
      try {
        voice.osc.stop();
        voice.osc.disconnect();
        voice.gain.disconnect();
        voice.filter.disconnect();
      } catch (_e) {
        /* ignore */
      }
      this.activeVoices.delete(voiceId);
    }, settings.release * 1000 + 100);

    voice.timeoutId = cleanupTimeout;
  }

  private getChordNotes(rootNote: number, harmonyType: BandInstrument['harmonyType']): number[] {
    switch (harmonyType) {
      case 'unison':
        return [rootNote];
      case 'thirds':
        return [rootNote, rootNote + 4]; // Major third
      case 'fifths':
        return [rootNote, rootNote + 7]; // Perfect fifth
      case 'octave':
        return [rootNote, rootNote + 12];
      case 'triad':
        return [rootNote, rootNote + 4, rootNote + 7]; // Major triad
      case 'seventh':
        return [rootNote, rootNote + 4, rootNote + 7, rootNote + 10]; // Dominant 7th
      case 'ninth':
        return [rootNote, rootNote + 4, rootNote + 7, rootNote + 10, rootNote + 14]; // Dominant 9th
      default:
        return [rootNote];
    }
  }

  private getNoteForStep(step: number, instrument: BandInstrument, chordRoot: number): number | null {
    // Apply rhythm pattern probability
    const patternProb = instrument.rhythmPattern[step % 16];
    const shouldPlay = Math.random() < (patternProb * (this.performance.complexity / 100));

    if (!shouldPlay) return null;

    // Calculate note based on instrument range and chord
    const octaveOffset = Math.floor(Math.random() * instrument.octaveRange);
    const baseNote = instrument.baseNote + (octaveOffset * 12);

    // Get chord notes for harmony
    const chordNotes = this.getChordNotes(chordRoot, instrument.harmonyType);
    const noteIndex = Math.floor(Math.random() * chordNotes.length);

    return baseNote + (chordNotes[noteIndex] - 60); // Transpose from C4 reference
  }

  private scheduleBeat(): void {
    if (!this.isPlaying) return;

    const stepMs = (60000 / this.performance.bpm) / 4; // 16th notes
    const now = this.context.currentTime;
    const step = this.currentBeat % 16;

    // Apply groove/swing: delay odd steps by up to 20ms
    const swingDelayS = step % 2 === 1
      ? (this.performance.groove / 100) * 0.02
      : 0;

    // Guard: if the chord progression is empty we cannot safely derive a chord
    // root — % 0 produces NaN which propagates into getMidiNoteFromChord and
    // eventually crashes on chordName.replace(). Skip note generation but keep
    // the beat clock running so playback can resume once chords are assigned.
    if (this.performance.chords.length === 0) {
      this.currentBeat++;
      this.beatInterval = window.setTimeout(() => this.scheduleBeat(), stepMs);
      return;
    }

    // Get current chord from progression (4 bars = 64 steps)
    const progressionStep = Math.floor(this.currentBeat / 16) % this.performance.chords.length;
    const chordName = this.performance.chords[progressionStep];
    const chordRoot = this.getMidiNoteFromChord(chordName);

    // Play each active instrument
    this.instruments.forEach(instrument => {
      const note = this.getNoteForStep(step, instrument, chordRoot);
      if (note !== null) {
        // Calculate velocity with intensity factor
        const baseVelocity = 0.5 + (this.performance.intensity / 100) * 0.5;
        const velocity = baseVelocity * (0.7 + Math.random() * 0.3);

        // Calculate note duration based on style
        const duration = stepMs * 2 / 1000; // 8th note duration

        this.playNote(note, instrument, velocity, duration, swingDelayS);
      }
    });

    this.currentBeat++;

    // Schedule next beat
    this.beatInterval = window.setTimeout(() => {
      this.scheduleBeat();
    }, stepMs);
  }

  private getMidiNoteFromChord(chordName: string): number {
    // Simple mapping: C=60, C#=61, D=62, etc.
    const noteMap: Record<string, number> = {
      'C': 60, 'C#': 61, 'Db': 61, 'D': 62, 'D#': 63, 'Eb': 63,
      'E': 64, 'F': 65, 'F#': 66, 'Gb': 66, 'G': 67, 'G#': 68,
      'Ab': 68, 'A': 69, 'A#': 70, 'Bb': 70, 'B': 71
    };

    const root = chordName.replace(/[^A-G#b]/g, '');
    return noteMap[root] || 60;
  }

  start(instrumentIds: string[], analysis: { tempo: number; key: string; scale: string; chords: string[] }): void {
    if (this.isPlaying) return;

    this.isPlaying = true;
    this.currentBeat = 0;

    // Update performance with analysis
    this.performance = {
      ...this.performance,
      bpm: analysis.tempo,
      key: analysis.key,
      scale: analysis.scale,
      chords: analysis.chords
    };

    // Reset instruments to the full set, then filter to the active ones.
    // Previously this permanently removed instruments from the list,
    // so subsequent calls with different instruments would fail.
    this.instruments = this.createInstrumentPresets().filter(
      inst => instrumentIds.includes(inst.id)
    );

    // Start scheduling
    this.scheduleBeat();
  }

  stop(): void {
    if (!this.isPlaying) return;

    this.isPlaying = false;
    if (this.beatInterval !== null) {
      clearTimeout(this.beatInterval);
      this.beatInterval = null;
    }

    // Stop all active voices using default fallback settings.
    // Voice IDs are formatted as "voice_<N>" (numeric), not instrument IDs,
    // so we use a safe fallback for the release envelope.
    const fallbackSettings: SynthSettings = {
      type: 'sine',
      frequency: 440,
      attack: 0.1,
      decay: 0.1,
      sustain: 0.7,
      release: 0.2,
      filterFreq: 1000,
      filterQ: 1,
      distortion: 0,
    };

    for (const voiceId of Array.from(this.activeVoices.keys())) {
      this.stopNote(voiceId, fallbackSettings);
    }
    // Do NOT call this.activeVoices.clear() here. stopNote() schedules a
    // cleanup timeout that calls this.activeVoices.delete(voiceId) once the
    // release envelope finishes. Calling clear() immediately would orphan those
    // timeouts — the oscillators would keep running until the page is unloaded.
  }

  updatePerformance(performance: Partial<BandPerformance>): void {
    this.performance = { ...this.performance, ...performance };
  }

  updateInstrumentVolume(instrumentId: string, volume: number): void {
    const instrument = this.instruments.find(inst => inst.id === instrumentId);
    if (instrument) {
      // Adjust settings based on volume
      instrument.settings.sustain = volume / 100;
    }
  }

  dispose(): void {
    this.stop();
    this.masterGain.disconnect();
  }
}

import { describe, it, expect, vi, beforeEach } from 'vitest';
import { detectKeyFromBuffer, createKeyDetector, midiNoteToKey } from './keyDetection';

describe('keyDetection', () => {
  beforeEach(() => {
    vi.clearAllMocks();
  });

  describe('midiNoteToKey', () => {
    it('maps MIDI note 60 (C4) to CM', () => {
      expect(midiNoteToKey(60)).toBe('CM');
