/**
 * Production-grade logging system for TBM
 * Supports multiple log levels, structured logging, and optional remote reporting
 */

export type LogLevel = 'debug' | 'info' | 'warn' | 'error' | 'critical';

export interface LogEntry {
  timestamp: string;
  level: LogLevel;
  message: string;
  context?: Record<string, any>;
  error?: Error;
  component?: string;
  sessionId?: string;
}

export interface LoggerConfig {
  minLevel: LogLevel;
  enableConsole: boolean;
  enableRemote: boolean;
  remoteEndpoint?: string;
  sessionId?: string;
  component?: string;
}

const LEVEL_WEIGHTS: Record<LogLevel, number> = {
  debug: 0,
  info: 1,
  warn: 2,
  error: 3,
  critical: 4
};

class Logger {
  private config: LoggerConfig;
  private buffer: LogEntry[] = [];
  private readonly MAX_BUFFER_SIZE = 1000;
  private remoteQueue: LogEntry[] = [];
  private readonly MAX_REMOTE_QUEUE_SIZE = 500;
  private isSending = false;

  constructor(config: Partial<LoggerConfig> = {}) {
    this.config = {
      minLevel: 'info',
      enableConsole: true,
      enableRemote: false,
      sessionId: this.generateSessionId(),
      ...config
    };
  }

  private generateSessionId(): string {
    return `tbm-${Date.now()}-${Math.random().toString(36).substring(2, 11)}`;
  }

  private shouldLog(level: LogLevel): boolean {
    return LEVEL_WEIGHTS[level] >= LEVEL_WEIGHTS[this.config.minLevel];
  }

  private formatMessage(entry: LogEntry): string {
    const time = new Date(entry.timestamp).toISOString().split('T')[1].split('.')[0];
    const level = entry.level.toUpperCase().padEnd(7);
    const component = entry.component ? `[${entry.component}]` : '[TBM]';
    const ctx = entry.context ? ` ${JSON.stringify(entry.context)}` : '';
    const error = entry.error ? `\n  Error: ${entry.error.message}\n  Stack: ${entry.error.stack}` : '';

    return `${time} ${level} ${component} ${entry.message}${ctx}${error}`;
  }

  private async sendToRemote(entry: LogEntry): Promise<void> {
    if (!this.config.enableRemote || !this.config.remoteEndpoint) {
      return;
    }

    this.remoteQueue.push(entry);

    // Cap queue size to prevent unbounded memory growth on persistent network failure
    if (this.remoteQueue.length > this.MAX_REMOTE_QUEUE_SIZE) {
      // Drop oldest entries
      this.remoteQueue.splice(0, this.remoteQueue.length - this.MAX_REMOTE_QUEUE_SIZE);
    }

    if (this.isSending || this.remoteQueue.length < 5) {
      return;
    }

    this.isSending = true;
    try {
      const batch = this.remoteQueue.splice(0, 10);

      // Custom replacer: Error objects have non-enumerable properties (message,
      // stack, name) that JSON.stringify silently drops, producing `{}`.
      // Serialize them explicitly so remote logging captures useful data.
      const replacer = (_key: string, value: unknown) => {
        if (value instanceof Error) {
          return {
            name: value.name,
            message: value.message,
            stack: value.stack,
          };
        }
        return value;
      };

      const response = await fetch(this.config.remoteEndpoint!, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          sessionId: this.config.sessionId,
          entries: batch
        }, replacer)
      });

      if (!response.ok) {
        console.warn('Failed to send logs to remote:', response.status);
        // Requeue failed entries
        this.remoteQueue.unshift(...batch);
      }
    } catch (error) {
      console.warn('Error sending logs to remote:', error);
      // Keep entries in queue for retry
    } finally {
      this.isSending = false;
    }
  }

  public log(level: LogLevel, message: string, options: {
    context?: Record<string, any>;
    error?: Error;
    component?: string;
  } = {}): void {
    if (!this.shouldLog(level)) {
      return;
    }

    const entry: LogEntry = {
      timestamp: new Date().toISOString(),
      level,
      message,
      context: options.context,
      error: options.error,
      component: options.component || this.config.component,
      sessionId: this.config.sessionId
    };

    // Add to buffer (circular)
    this.buffer.push(entry);
    if (this.buffer.length > this.MAX_BUFFER_SIZE) {
      this.buffer.shift();
    }

    // Console output
    if (this.config.enableConsole) {
      const formatted = this.formatMessage(entry);
      switch (level) {
        case 'debug':
          console.debug(formatted);
          break;
        case 'info':
          console.info(formatted);
          break;
        case 'warn':
          console.warn(formatted);
          break;
        case 'error':
        case 'critical':
          console.error(formatted);
          break;
      }
    }

    // Remote logging (async, non-blocking)
    if (level === 'error' || level === 'critical') {
      this.sendToRemote(entry).catch(() => {
        // Silently fail - we already logged to console
      });
    }
  }

  // Public API
  debug(message: string, context?: Record<string, any>): void {
    this.log('debug', message, { context });
  }

  info(message: string, context?: Record<string, any>): void {
    this.log('info', message, { context });
  }

  warn(message: string, context?: Record<string, any>, error?: Error): void {
    this.log('warn', message, { context, error });
  }

  error(message: string, error?: Error, context?: Record<string, any>): void {
    this.log('error', message, { context, error });
  }

  critical(message: string, error?: Error, context?: Record<string, any>): void {
    this.log('critical', message, { context, error });
  }

  // Component-specific logger
  component(name: string): ComponentLogger {
    return new ComponentLogger(this, name);
  }

  // Get recent logs (for debugging UI)
  getRecentLogs(count: number = 50): LogEntry[] {
    return this.buffer.slice(-count);
  }

  // Clear logs
  clear(): void {
    this.buffer = [];
  }

  // Update config
  updateConfig(config: Partial<LoggerConfig>): void {
    this.config = { ...this.config, ...config };
  }
}

class ComponentLogger {
  constructor(private parent: Logger, private componentName: string) {}

  debug(message: string, context?: Record<string, any>): void {
    this.parent.log('debug', message, { context, component: this.componentName });
  }

  info(message: string, context?: Record<string, any>): void {
    this.parent.log('info', message, { context, component: this.componentName });
  }

  warn(message: string, context?: Record<string, any>, error?: Error): void {
    this.parent.log('warn', message, { context, error, component: this.componentName });
  }

  error(message: string, error?: Error, context?: Record<string, any>): void {
    this.parent.log('error', message, { context, error, component: this.componentName });
  }

  critical(message: string, error?: Error, context?: Record<string, any>): void {
    this.parent.log('critical', message, { context, error, component: this.componentName });
  }
}

// Global logger instance
const globalLogger = new Logger({
  minLevel: (typeof process !== 'undefined' && process.env?.NODE_ENV === 'production') ? 'warn' : 'debug',
  enableConsole: true,
  enableRemote: false,
  component: 'TBM'
});

export { globalLogger as logger };
export default globalLogger;

