/**
 * Comprehensive state persistence for TBM
 * Handles serialization, deserialization, and auto-recovery of application state
 */

import { Pad } from "./TBMAudioEngine";
import { logger } from "./logger";
import {
  DEFAULT_BPM,
  DEFAULT_SWING,
  MIXER_CHANNELS,
  PLAYBACK_SAMPLE_RATE,
  DEFAULT_BUFFER_SIZE,
  MAX_BACKUP_COUNT as _MAX_BACKUP_COUNT,
  STORAGE_KEYS,
} from "./constants";

export interface TBMProjectState {
  version: string;
  timestamp: string;

  // UI State
  activeTab: string;
  projectKey: string;
  activeState: "A" | "B";
  bpm: number;
  swing: number;

  // Audio State
  pads: SerializedPad[];
  sequencerPatterns: Record<string, boolean[][]>;
  pianoRollNotes: Record<string, any[]>;
  mixerSettings: MixerSettings;
  effectParameters: EffectParameters;

  // Settings
  audioSettings: AudioSettings;
  midiSettings: MidiSettings;
  uiSettings: UISettings;
}

export interface SerializedPad {
  index: number;
  sampleId: string | null;
  sampleUrl: string | null;
  sampleData?: string; // Base64 encoded for small samples
  volume: number;
  pan: number;
  pitch: number;
