// Storage keys (from centralized constants)
const PROJECT_STATE_KEY = STORAGE_KEYS.PROJECT_STATE;
const AUTO_SAVE_KEY = STORAGE_KEYS.AUTO_SAVE;
const RECOVERY_BACKUP_KEY = STORAGE_KEYS.RECOVERY_BACKUP;
const MAX_BACKUP_COUNT = _MAX_BACKUP_COUNT;

/**
 * Serialize current application state
 */
export async function serializeState(
  pads: Pad[],
  sequencerPatterns: Record<string, boolean[][]>,
  pianoRollNotes: Record<string, any[]>,
  uiState: {
    activeTab: string;
    projectKey: string;
    activeState: "A" | "B";
    bpm: number;
    swing: number;
  },
  mixerSettings: MixerSettings,
  effectParameters: EffectParameters,
  settings: {
    audio: AudioSettings;
    midi: MidiSettings;
    ui: UISettings;
  },
): Promise<TBMProjectState> {
  try {
    // Serialize pads
    const serializedPads: SerializedPad[] = pads.map((pad, index) => ({
      index,
      sampleId: pad.sample?.id || null,
      sampleUrl: null, // Not stored in Pad interface
      volume: pad.volume ?? 1,
      pan: pad.pan ?? 0,
      pitch: pad.pitch ?? 0,
      adsr: {
        attack: pad.attack ?? 0,
        decay: 0, // Not in Pad interface
        sustain: 1, // Not in Pad interface
        release: pad.release ?? 0,
      },
      filter: {
        type:
          pad.filterType === "off"
            ? "off"
            : pad.filterType === "lp"
              ? "lowpass"
              : pad.filterType === "hp"
                ? "highpass"
                : pad.filterType === "bp"
                  ? "bandpass"
                  : pad.filterType,
        cutoff: pad.filterCutoff ?? 20000,
        resonance: pad.filterResonance ?? 0,
      },
      effects: {
        reverbSend: 0, // Not in Pad interface
        delaySend: 0, // Not in Pad interface
        distortion: 0, // Not in Pad interface
        bitcrush: 0, // Not in Pad interface
      },
    }));

    const state: TBMProjectState = {
      version: "1.0.0",
      timestamp: new Date().toISOString(),
      activeTab: uiState.activeTab,
      projectKey: uiState.projectKey,
      activeState: uiState.activeState,
      bpm: uiState.bpm,
      swing: uiState.swing,
      pads: serializedPads,
      sequencerPatterns,
      pianoRollNotes,
      mixerSettings,
      effectParameters,
      audioSettings: settings.audio,
      midiSettings: settings.midi,
      uiSettings: settings.ui,
    };

    return state;
  } catch (error) {
    logger.error("Failed to serialize state", error as Error);
    throw error;
  }
}

/**
 * Deserialize state and apply to application
 */
export function deserializeState(state: TBMProjectState): {
  pads: Partial<Pad>[];
  sequencerPatterns: Record<string, boolean[][]>;
  pianoRollNotes: Record<string, any[]>;
  uiState: {
    activeTab: string;
    projectKey: string;
    activeState: "A" | "B";
    bpm: number;
    swing: number;
  };
  mixerSettings: MixerSettings;
  effectParameters: EffectParameters;
  settings: {
    audio: AudioSettings;
    midi: MidiSettings;
    ui: UISettings;
  };
} {
  try {
    // Convert serialized pads back to partial Pad objects
    const pads: Partial<Pad>[] = (state.pads || []).map((serializedPad) => ({
      id: serializedPad.index,
      name: `Pad ${serializedPad.index + 1}`,
      sample: serializedPad.sampleId
        ? {
            id: serializedPad.sampleId,
            name: `Sample ${serializedPad.sampleId}`,
            buffer: null,
            category: "unknown",
          }
        : null,
      volume: serializedPad.volume,
      pan: serializedPad.pan,
      pitch: serializedPad.pitch,
      attack: serializedPad.adsr?.attack ?? 0,
      release: serializedPad.adsr?.release ?? 0,
      reverse: false,
      start: 0,
      end: 1,
      loop: false,
      filterType:
        serializedPad.filter?.type === "off"
          ? "off"
          : serializedPad.filter?.type === "lowpass" || serializedPad.filter?.type === "lp"
            ? "lp"
            : serializedPad.filter?.type === "highpass" || serializedPad.filter?.type === "hp"
              ? "hp"
              : serializedPad.filter?.type === "bandpass" || serializedPad.filter?.type === "bp"
                ? "bp"
                : "off",
      filterCutoff: serializedPad.filter?.cutoff ?? 20000,
      filterResonance: serializedPad.filter?.resonance ?? 0,
      chokeGroup: null,
      swing: 0,
    }));

    return {
      pads,
      sequencerPatterns: state.sequencerPatterns || {},
      pianoRollNotes: state.pianoRollNotes || {},
      uiState: {
        activeTab: state.activeTab || "sampler",
        projectKey: state.projectKey || "Cm",
        activeState: state.activeState || "A",
        bpm: state.bpm ?? DEFAULT_BPM,
        swing: state.swing ?? DEFAULT_SWING,
      },
      mixerSettings: state.mixerSettings || getDefaultMixerSettings(),
      effectParameters: state.effectParameters || getDefaultEffectParameters(),
      settings: {
        audio: state.audioSettings || getDefaultAudioSettings(),
        midi: state.midiSettings || getDefaultMidiSettings(),
        ui: state.uiSettings || getDefaultUISettings(),
      },
    };
  } catch (error) {
    logger.error("Failed to deserialize state", error as Error);
    throw error;
  }
}

/**
 * Save state to localStorage with backup
 */
export function saveState(state: TBMProjectState, isAutoSave = false): void {
  try {
    const key = isAutoSave ? AUTO_SAVE_KEY : PROJECT_STATE_KEY;
    const serialized = JSON.stringify(state);

    // Create backup of the PREVIOUS state before overwriting, so the backup
    // protects against a bad save (not a duplicate of the new data).
    if (!isAutoSave) {
      const previousRaw = localStorage.getItem(PROJECT_STATE_KEY);
      if (previousRaw) {
        try {
          const previousState = JSON.parse(previousRaw) as TBMProjectState;
          createBackup(previousState);
        } catch {
          // Previous data is corrupt — still back up the new state as a fallback
          createBackup(state);
        }
      } else {
        // First save: create backup of the initial state
        createBackup(state);
      }
    }

    try {
      localStorage.setItem(key, serialized);
    } catch (e: unknown) {
      // Handle QuotaExceededError: try clearing old backups first, then retry
      if (
        e instanceof DOMException &&
        (e.name === "QuotaExceededError" || e.code === 22)
      ) {
        logger.warn(
          "localStorage quota exceeded, clearing backups and retrying",
          {
            serializedSize: serialized.length,
          },
        );
        try {
          localStorage.removeItem(RECOVERY_BACKUP_KEY);
          localStorage.setItem(key, serialized);
        } catch (retryError) {
          logger.error(
            "Failed to save state even after clearing backups",
            retryError as Error,
          );
          return;
        }
      } else {
        throw e;
      }
    }

    logger.info(`State saved${isAutoSave ? " (auto-save)" : ""}`, {
      timestamp: state.timestamp,
      size: serialized.length,
    });
  } catch (error) {
    logger.error("Failed to save state", error as Error);
  }
}

/**
 * Load state from localStorage
 */
export function loadState(isAutoSave = false): TBMProjectState | null {
  try {
    const key = isAutoSave ? AUTO_SAVE_KEY : PROJECT_STATE_KEY;
    const serialized = localStorage.getItem(key);

    if (!serialized) {
      return null;
    }

    const parsed = JSON.parse(serialized);

    // Runtime structural validation — reject data that doesn't match expected shape
    if (typeof parsed !== "object" || parsed === null) {
      logger.warn("Stored state is not an object, discarding");
      return null;
    }
    if (typeof parsed.timestamp !== "string") {
      logger.warn("Stored state missing timestamp, discarding");
      return null;
    }

    const state = parsed as TBMProjectState;

    // Sanitize numeric fields (mirrors importState logic)
    if (typeof state.bpm !== "number" || !Number.isFinite(state.bpm)) {
      state.bpm = DEFAULT_BPM;
    } else {
      state.bpm = Math.max(20, Math.min(300, state.bpm));
    }
    if (typeof state.swing !== "number" || !Number.isFinite(state.swing)) {
      state.swing = DEFAULT_SWING;
    } else {
      state.swing = Math.max(0, Math.min(100, state.swing));
    }

    // Validate state version
    if (!state.version || state.version !== "1.0.0") {
      logger.warn("State version mismatch, attempting migration");
      return migrateState(state);
    }

    logger.info(`State loaded${isAutoSave ? " (auto-save)" : ""}`, {
      timestamp: state.timestamp,
      version: state.version,
    });

    return state;
  } catch (error) {
    logger.error("Failed to load state", error as Error);
    return null;
  }
}

/**
 * Create recovery backup
 */
function createBackup(state: TBMProjectState): void {
  try {
    const backups = getBackups();
    backups.unshift({
      timestamp: state.timestamp,
      state: JSON.parse(JSON.stringify(state)), // Deep clone
    });

    // Keep only latest backups
    if (backups.length > MAX_BACKUP_COUNT) {
      backups.length = MAX_BACKUP_COUNT;
    }

    const serialized = JSON.stringify(backups);
    try {
      localStorage.setItem(RECOVERY_BACKUP_KEY, serialized);
    } catch (e: unknown) {
      if (
        e instanceof DOMException &&
        (e.name === "QuotaExceededError" || e.code === 22)
      ) {
        // Reduce backup count and retry
        logger.warn(
          "localStorage quota exceeded during backup, reducing backup count",
        );
        while (backups.length > 1) {
          backups.pop();
          try {
            localStorage.setItem(RECOVERY_BACKUP_KEY, JSON.stringify(backups));
            return;
          } catch {
            // Keep reducing
          }
        }
        // If even 1 backup doesn't fit, clear backups entirely
        localStorage.removeItem(RECOVERY_BACKUP_KEY);
        logger.warn("Could not store any backups due to quota limits");
      } else {
        throw e;
      }
    }
  } catch (error) {
    logger.error("Failed to create backup", error as Error);
  }
}

/**
 * Get all recovery backups
 */
export function getBackups(): Array<{
  timestamp: string;
  state: TBMProjectState;
}> {
  try {
    const serialized = localStorage.getItem(RECOVERY_BACKUP_KEY);
    return serialized ? JSON.parse(serialized) : [];
  } catch {
    return [];
  }
}

/**
 * Restore from specific backup
 */
export function restoreBackup(timestamp: string): TBMProjectState | null {
  try {
    const backups = getBackups();
    const backup = backups.find((b) => b.timestamp === timestamp);

    if (backup) {
      saveState(backup.state, false);
      return backup.state;
    }

    return null;
  } catch (error) {
    logger.error("Failed to restore backup", error as Error, { timestamp });
    return null;
  }
}

/**
 * Clear all saved state
 */
export function clearState(): void {
  try {
    localStorage.removeItem(PROJECT_STATE_KEY);
    localStorage.removeItem(AUTO_SAVE_KEY);
    localStorage.removeItem(RECOVERY_BACKUP_KEY);
    logger.info("All state cleared");
  } catch (error) {
    logger.error("Failed to clear state", error as Error);
  }
}

/**
 * Get storage usage information
 */
export function getStorageInfo(): {
  totalSize: number;
  itemCount: number;
  backupsCount: number;
} {
  try {
    let totalSize = 0;
    let itemCount = 0;

    for (let i = 0; i < localStorage.length; i++) {
      const key = localStorage.key(i);
      if (key && key.startsWith("tbm_")) {
        const value = localStorage.getItem(key);
        if (value) {
          totalSize += key.length + value.length;
          itemCount++;
        }
      }
    }

    const backups = getBackups();

    return {
      totalSize,
      itemCount,
      backupsCount: backups.length,
    };
  } catch {
    return {
      totalSize: 0,
      itemCount: 0,
      backupsCount: 0,
    };
  }
}

/**
 * State migration for future versions
 */
function migrateState(oldState: any): TBMProjectState {
  // Sanitize BPM/swing the same way importState does
  let bpm = DEFAULT_BPM;
  if (typeof oldState.bpm === "number" && Number.isFinite(oldState.bpm)) {
    bpm = Math.max(20, Math.min(300, oldState.bpm));
  }
  let swing = DEFAULT_SWING;
  if (typeof oldState.swing === "number" && Number.isFinite(oldState.swing)) {
    swing = Math.max(0, Math.min(100, oldState.swing));
  }

  // Basic migration - preserve what we can
  return {
    version: "1.0.0",
    timestamp: new Date().toISOString(),
    activeTab: oldState.activeTab || "sampler",
    projectKey: oldState.projectKey || "Cm",
    activeState: oldState.activeState || "A",
    bpm,
    swing,
    pads: oldState.pads || [],
    sequencerPatterns: oldState.sequencerPatterns || {},
    pianoRollNotes: oldState.pianoRollNotes || {},
    mixerSettings: oldState.mixerSettings || getDefaultMixerSettings(),
    effectParameters: oldState.effectParameters || getDefaultEffectParameters(),
    audioSettings: oldState.audioSettings || getDefaultAudioSettings(),
    midiSettings: oldState.midiSettings || getDefaultMidiSettings(),
    uiSettings: oldState.uiSettings || getDefaultUISettings(),
  };
}

