/**
 * Export state as downloadable file
 */
export function exportState(state: TBMProjectState): void {
  try {
    const serialized = JSON.stringify(state, null, 2);
    const blob = new Blob([serialized], { type: "application/json" });
    const url = URL.createObjectURL(blob);

    const a = document.createElement("a");
    a.href = url;
    a.download = `tbm-project-${new Date().toISOString().split("T")[0]}.tbm`;
    document.body.appendChild(a);
    a.click();
    document.body.removeChild(a);

    URL.revokeObjectURL(url);

    logger.info("State exported", { size: serialized.length });
  } catch (error) {
    logger.error("Failed to export state", error as Error);
  }
}

/**
 * Import state from file
 */
export function importState(file: File): Promise<TBMProjectState> {
  return new Promise((resolve, reject) => {
    try {
      const reader = new FileReader();

      reader.onload = (event) => {
        try {
          const content = event.target?.result as string;

          // Guard against null result from FileReader
          if (!content) {
            throw new Error("File read returned empty result");
          }

          // Guard against absurdly large files (> 50 MB) before parsing
          if (content.length > 50 * 1024 * 1024) {
            throw new Error("TBM project file is too large (> 50 MB)");
          }

          const state = JSON.parse(content) as TBMProjectState;

          // Validate basic structure
          if (typeof state !== "object" || state === null) {
            throw new Error("Invalid TBM project file: root must be an object");
          }
          if (typeof state.version !== "string" || !state.version) {
            throw new Error("Invalid TBM project file: missing version");
          }
          if (typeof state.timestamp !== "string" || !state.timestamp) {
            throw new Error("Invalid TBM project file: missing timestamp");
          }

          // Sanitize numeric fields to safe ranges so downstream code never
          // receives Infinity / NaN / negative values that break audio nodes.
          if (typeof state.bpm === "number") {
            state.bpm = Math.max(
              20,
              Math.min(300, isFinite(state.bpm) ? state.bpm : 120),
            );
          } else {
            state.bpm = 120;
          }

          if (typeof state.swing === "number") {
            state.swing = Math.max(
              0,
              Math.min(100, isFinite(state.swing) ? state.swing : 0),
            );
          } else {
            state.swing = 0;
          }

          // Cap activeTab to a known safe length to prevent injection via very
          // long strings; actual value validation happens in the caller.
          if (
            typeof state.activeTab === "string" &&
            state.activeTab.length > 64
          ) {
            state.activeTab = state.activeTab.slice(0, 64);
          }

          // Ensure pads is an array (not some attacker-supplied object)
          if (!Array.isArray(state.pads)) {
            state.pads = [];
          }

          resolve(state);
        } catch (error) {
          reject(error);
        }
      };

      reader.onerror = () => {
        reject(new Error("Failed to read file"));
      };

      reader.readAsText(file);
    } catch (error) {
      reject(error);
    }
  });
}

